// German V2 A2 Units (7-12)
// Split from units-german-v2.js for maintainability

const GERMAN_V2_A2 = [
{n:7,lang:"de",srcLang:"en",track:"v2",title:"Der Arztbesuch",sub:"First cold, pharmacy visit, four-minute doctor, Beipackzettel",icon:"🤧",level:"A2.1",color:"#7B5EE8",lessons:[
{id:"deu_r7l1",title:"Die Apotheke",icon:"🤧",xp:15,board:true,steps:[
{type:"intro",title:"Die Apotheke",desc:"Verumius wacht krank auf. Kopfschmerzen, Husten, Schnupfen. Er braucht Hilfe, aber wohin? Zeit, die deutsche Apotheke zu entdecken.",goals:["Lerne 8 wichtige Wörter rund um Gesundheit und Krankheit","Verstehe den Unterschied zwischen Apotheke, Arzt und Krankenhaus","Begleite Verumius bei seinem ersten Apothekenbesuch in Berlin"]},
{type:"story",speaker:"narrator",mood:"miserable",art:"berlin_apartment_rain",trg:"Es ist Montagmorgen in Berlin. Der Regen trommelt gegen das Fenster. Verumius liegt im Bett. Sein Kopf tut weh, seine Nase läuft, und er hustet seit zwei Stunden. Er greift nach seinem Handy und tippt: 'Apotheke in der Nähe'. Ein rotes A leuchtet auf der Karte. Fünfhundert Meter. Er zieht seine Jacke an und geht raus in den Regen.",src:"It's Monday morning in Berlin. The rain drums against the window. Verumius is lying in bed. His head hurts, his nose is running, and he's been coughing for two hours. He reaches for his phone and types: 'Pharmacy nearby'. A red A lights up on the map. Five hundred meters. He puts on his jacket and goes out into the rain."},
{type:"teach",trg:"die Apotheke",src:"the pharmacy",note:"Feminine noun. Look for the red A sign on German streets.\nNot a drugstore: only medicines, no groceries.",example:"A: Entschuldigung, wo ist die nächste Apotheke?\nB: Gleich um die Ecke, neben dem Supermarkt.\nA: Ist sie jetzt geöffnet?\nB: Ja, bis achtzehn Uhr.",exampleSrc:"A: Excuse me, where is the nearest pharmacy?\nB: Right around the corner, next to the supermarket.\nA: Is it open now?\nB: Yes, until six o'clock.",funFact:"The word Apotheke comes from ancient Greek 'apotheke' (storage room). German pharmacies display a red gothic A and are strictly regulated. You cannot buy aspirin at a supermarket in Germany."},
{type:"teach",trg:"die Grippe",src:"the flu, the cold",note:"Feminine noun. Eine Grippe haben = to have the flu.\nErkältung is a milder cold, Grippe is more serious.",example:"A: Du siehst nicht gut aus. Was ist los?\nB: Ich habe eine Grippe. Seit drei Tagen.\nA: Warst du schon beim Arzt?\nB: Nein, ich gehe erst mal in die Apotheke.",exampleSrc:"A: You don't look well. What's wrong?\nB: I have the flu. For three days.\nA: Have you been to the doctor yet?\nB: No, I'll go to the pharmacy first.",funFact:"Germans take Grippe seriously. The Grippewelle (flu wave) is a national news topic every winter. Companies track sick days from flu, and doctors hand out Krankschreibungen (sick notes) generously."},
{type:"teach",trg:"der Schmerz",src:"the pain",note:"Masculine noun. Plural: die Schmerzen.\nCompounds: Kopfschmerzen (headache), Bauchschmerzen (stomachache), Halsschmerzen (sore throat).",example:"A: Wo haben Sie Schmerzen?\nB: Ich habe starke Kopfschmerzen.\nA: Seit wann?\nB: Seit gestern Abend. Und auch Halsschmerzen.",exampleSrc:"A: Where do you have pain?\nB: I have a strong headache.\nA: Since when?\nB: Since yesterday evening. And also a sore throat.",funFact:"German builds body pain words like LEGO: body part + Schmerzen. Kopf (head) + Schmerzen = Kopfschmerzen. Zahn (tooth) + Schmerzen = Zahnschmerzen. Once you know Schmerzen, you can describe pain anywhere."},
{type:"mc",q:"Verumius hat Kopfschmerzen und Husten. Wohin geht er zuerst?",opts:["In die Apotheke","In den Supermarkt","In die Schule","In das Kino"],ans:"In die Apotheke",hint:"Look for the red A on German streets. It's where you buy medicine."},
{type:"teach",trg:"husten",src:"to cough",note:"Regular verb. Ich huste, du hustest, er hustet.\nDer Husten (noun) = the cough.\nHustensaft = cough syrup.",example:"A: Sie husten ja ganz schrecklich!\nB: Ja, ich huste seit zwei Tagen.\nA: Hier, nehmen Sie diesen Hustensaft.\nB: Danke, wie oft muss ich ihn nehmen?",exampleSrc:"A: You're coughing terribly!\nB: Yes, I've been coughing for two days.\nA: Here, take this cough syrup.\nB: Thanks, how often do I need to take it?",funFact:"Hustensaft (cough syrup) is one of Germany's favorite pharmacy purchases. Germans also love Hustenbonbons (cough drops). The brand Ricola, though Swiss, is everywhere in German pharmacies."},
{type:"teach",trg:"die Gesundheit",src:"health",note:"Feminine noun. Also what Germans say when someone sneezes!\nGesund = healthy. Gesundheit = health/healthiness.",example:"A: Hatschiii!\nB: Gesundheit!\nA: Danke. Meine Gesundheit ist gerade nicht so gut.\nB: Gute Besserung! Trink viel Tee.",exampleSrc:"A: Achoo!\nB: Bless you! (lit: Health!)\nA: Thanks. My health isn't so great right now.\nB: Get well soon! Drink lots of tea.",funFact:"Gesundheit! after a sneeze is used worldwide, even in English. It literally means 'health!' as a wish. Germans also say 'Gute Besserung' (good improvement) when someone is sick, similar to 'get well soon'."},
{type:"fb",s:"Meine {1} ist nicht gut. Ich habe Kopfschmerzen und Husten.",a:["Gesundheit"],opts:["Gesundheit","Apotheke","Grippe","Schmerz"],hint:"This word means health. Germans also say it when you sneeze.",sSrc:"My health is not good. I have a headache and a cough."},
{type:"story",speaker:"narrator",mood:"anxious",art:"berlin_apotheke_counter",trg:"Verumius steht in der Apotheke. Alles ist weiß und sauber. Hinter dem Tresen steht eine Frau im weißen Kittel. Sie lächelt freundlich. 'Guten Tag, wie kann ich Ihnen helfen?' Verumius öffnet den Mund, aber die Worte kommen langsam. Er ist nervös. Was, wenn sie ihn nicht versteht?",src:"Verumius stands in the pharmacy. Everything is white and clean. Behind the counter stands a woman in a white coat. She smiles warmly. 'Good day, how can I help you?' Verumius opens his mouth, but the words come slowly. He's nervous. What if she doesn't understand him?"},
{type:"teach",trg:"das Krankenhaus",src:"the hospital",note:"Neuter noun. Literally: krank (sick) + Haus (house) = sick house.\nIns Krankenhaus gehen = to go to the hospital.",example:"A: Soll ich ins Krankenhaus gehen?\nB: Nein, das ist nur eine Grippe.\nA: Wann muss man ins Krankenhaus?\nB: Nur bei einem Notfall. Gehen Sie erst zum Arzt.",exampleSrc:"A: Should I go to the hospital?\nB: No, it's just a flu.\nA: When do you have to go to the hospital?\nB: Only in an emergency. Go to the doctor first.",funFact:"Krankenhaus is a beautiful German compound: kranken (sick) + Haus (house). German loves building words this way. A Krankenwagen (sick wagon) is an ambulance. A Krankenschwester (sick sister) is a nurse."},
{type:"teach",trg:"nervös",src:"nervous",note:"Adjective. Same form for all genders.\nIch bin nervös = I am nervous.\nCognate with English 'nervous' and French 'nerveux'.",example:"A: Du siehst nervös aus. Alles okay?\nB: Ja, ich bin nur nervös. Mein Deutsch ist nicht so gut.\nA: Keine Sorge! Ich verstehe Sie sehr gut.\nB: Wirklich? Das freut mich!",exampleSrc:"A: You look nervous. Everything okay?\nB: Yes, I'm just nervous. My German isn't so good.\nA: Don't worry! I understand you very well.\nB: Really? That makes me happy!",funFact:"Nervös is a cognate, almost identical to English 'nervous'. It entered German from French 'nerveux' in the 18th century. When in doubt in German, try the English word with a German accent. It works more often than you think."},
{type:"mc",q:"Wo kaufst du Medizin, wenn du krank bist?",opts:["In der Apotheke","Im Krankenhaus","Im Supermarkt","In der Schule"],ans:"In der Apotheke",hint:"It has a red A sign and a pharmacist in a white coat."},
{type:"teach",trg:"schlimm",src:"bad, severe, serious",note:"Adjective. Schlimmer (worse), am schlimmsten (worst).\nNicht so schlimm = not so bad.\nDas ist schlimm = that's bad/serious.",example:"A: Wie geht es Ihnen? Ist es schlimm?\nB: Nein, nicht so schlimm. Nur Husten und Schnupfen.\nA: Gut. Hier ist ein Tee und Hustensaft.\nB: Danke! Wird es schlimmer ohne Medizin?",exampleSrc:"A: How are you? Is it bad?\nB: No, not so bad. Just cough and a runny nose.\nA: Good. Here is a tea and cough syrup.\nB: Thanks! Does it get worse without medicine?",funFact:"'Nicht so schlimm' (not so bad) is one of the most useful German phrases. Germans use it to downplay almost anything. Spilled coffee? Nicht so schlimm. Missed the bus? Nicht so schlimm. It's the German equivalent of 'no worries'."},
{type:"fb",s:"Verumius ist {1}, weil er zum ersten Mal in einer deutschen Apotheke ist.",a:["nervös"],opts:["nervös","schlimm","krank","husten"],hint:"This feeling comes when you do something for the first time.",sSrc:"Verumius is nervous because it is his first time in a German pharmacy."},
{type:"tip",title:"Apotheke, Arzt oder Krankenhaus?",text:"Germany has a clear system for health care:\n\n1. Die Apotheke (pharmacy): For mild problems. Cough, cold, headache. No appointment needed. The pharmacist gives advice and medicine.\n\n2. Der Arzt (doctor): For anything that lasts more than a few days or feels serious. You need a Termin (appointment) or go to the Notaufnahme (emergency room) of a practice.\n\n3. Das Krankenhaus (hospital): Only for emergencies or when a doctor sends you. Broken bones, surgery, severe illness.\n\nMost Germans go to the Apotheke first. The pharmacist often solves the problem without a doctor visit.",deepDive:"German pharmacists (Apotheker) study for 4 years at university. They are highly trained and can recommend specific medicines. Unlike many countries, you cannot buy painkillers like ibuprofen at a supermarket in Germany. Even aspirin requires a pharmacy visit. This makes the Apotheke the first stop for most health issues."},
{type:"mc",q:"Du hast seit einer Woche starke Kopfschmerzen. Sie werden schlimmer. Wohin gehst du?",opts:["Zum Arzt","In die Apotheke","Ins Krankenhaus","In den Supermarkt"],ans:"Zum Arzt",hint:"A week of worsening pain needs more than pharmacy advice."},
{type:"drag_fill",s:"Ich habe eine {1} und habe {2}. Es ist nicht so {3}.",blanks:{"1":"Grippe","2":"Husten","3":"schlimm"},pool:["Grippe","Husten","schlimm","Apotheke","nervös","Schmerz"],hint:"I have a flu and have a cough. It's not so bad.",sSrc:"I have a flu and have a cough. It is not so bad."},
{type:"match",pairs:[{trg:"die Apotheke",src:"the pharmacy"},{trg:"die Grippe",src:"the flu"},{trg:"der Schmerz",src:"the pain"},{trg:"husten",src:"to cough"},{trg:"die Gesundheit",src:"health"},{trg:"das Krankenhaus",src:"the hospital"},{trg:"nervös",src:"nervous"},{trg:"schlimm",src:"bad, severe"}]},
{type:"mc",q:"Was passiert in der Geschichte? Verumius wacht auf und ...",opts:["Er ist krank und geht in die Apotheke","Er geht ins Krankenhaus mit dem Krankenwagen","Er bleibt im Bett und schläft den ganzen Tag","Er geht zum Arzt und bekommt eine Spritze"],ans:"Er ist krank und geht in die Apotheke",hint:"Remember the red A on his phone map and the rainy walk."}
]},

{id:"deu_r7l2",title:"Mein Körper tut weh",icon:"🏥",xp:15,board:true,steps:[
{type:"intro",title:"Mein Körper tut weh",desc:"Verumius ist in der Apotheke. Er muss erklären, was ihm wehtut. Lerne Körperteile und Apothekenvokabular.",goals:["Körperteile benennen","Apothekenprodukte kennen","Schmerzen ausdrücken mit 'mir tut ... weh'"]},
{type:"teach",trg:"der Körper",src:"the body",note:"Masculine. Related to English 'corpse' and 'corps'.",example:"A: Geht es Ihnen gut?\nB: Nein, mein ganzer Körper tut weh.\nA: Oh nein. Was haben Sie gemacht?\nB: Ich war gestern im Fitnessstudio.",exampleSrc:"A: Are you alright?\nB: No, my whole body hurts.\nA: Oh no. What did you do?\nB: I was at the gym yesterday.",funFact:"Körper comes from Latin 'corpus'. The same root gives us 'corporation' in English, a 'body' of people working together."},
{type:"teach",trg:"der Hals",src:"the throat / neck",note:"Masculine. Covers both throat and neck in German.",example:"A: Was fehlt Ihnen?\nB: Mir tut der Hals weh.\nA: Seit wann?\nB: Seit zwei Tagen. Ich kann kaum schlucken.",exampleSrc:"A: What's wrong?\nB: My throat hurts.\nA: Since when?\nB: For two days. I can barely swallow.",funFact:"Germans say 'Hals- und Beinbruch!' (break your neck and leg) to wish someone good luck. It comes from a Yiddish expression meaning 'success and blessing'."},
{type:"teach",trg:"der Magen",src:"the stomach",note:"Masculine. Used for the organ, not the belly area (that's 'der Bauch').",example:"A: Möchten Sie etwas essen?\nB: Nein danke, mein Magen tut weh.\nA: Haben Sie etwas Schlechtes gegessen?\nB: Vielleicht. Das Sushi gestern war komisch.",exampleSrc:"A: Would you like to eat something?\nB: No thanks, my stomach hurts.\nA: Did you eat something bad?\nB: Maybe. The sushi yesterday was strange.",funFact:"'Magengrummeln' is the German word for stomach rumbling. Germans love compound nouns for very specific body sounds."},
{type:"mc",q:"Welches Wort bedeutet 'throat'?",opts:["der Magen","der Hals","der Körper","der Schmerz"],ans:"der Hals",hint:"This body part connects your head to your shoulders and helps you swallow."},
{type:"teach",trg:"das Ohr",src:"the ear",note:"Neuter. Plural: die Ohren. One of the few body parts that changes in plural.",example:"A: Mein Ohr tut so weh!\nB: Das linke oder das rechte?\nA: Das linke. Ich höre schlecht.\nB: Gehen Sie zum Arzt. Das klingt nach einer Entzündung.",exampleSrc:"A: My ear hurts so much!\nB: The left one or the right one?\nA: The left one. I can't hear well.\nB: Go to the doctor. That sounds like an infection.",funFact:"'Ohrwurm' (ear worm) is the German word for a catchy song stuck in your head. English borrowed this word directly from German!"},
{type:"teach",trg:"der Rücken",src:"the back",note:"Masculine. Very common complaint. 'Rückenschmerzen' means back pain.",example:"A: Können Sie mir helfen? Mein Rücken tut weh.\nB: Sitzen Sie viel am Schreibtisch?\nA: Ja, den ganzen Tag.\nB: Ich empfehle Ihnen diese Creme.",exampleSrc:"A: Can you help me? My back hurts.\nB: Do you sit at a desk a lot?\nA: Yes, all day long.\nB: I recommend this cream to you.",funFact:"Back pain (Rückenschmerzen) is the number one reason Germans visit a doctor. Germany even has a special 'Rückenschule' (back school) for prevention."},
{type:"teach",trg:"der Zahn",src:"the tooth",note:"Masculine. Plural: die Zähne. Notice the umlaut change in plural!",example:"A: Au! Mein Zahn tut weh!\nB: Welcher Zahn?\nA: Hier hinten. Seit drei Tagen.\nB: Sie brauchen einen Zahnarzt, keine Apotheke.",exampleSrc:"A: Ow! My tooth hurts!\nB: Which tooth?\nA: Back here. For three days.\nB: You need a dentist, not a pharmacy.",funFact:"The German word for dentist is 'Zahnarzt', literally 'tooth doctor'. Germans are famous for their dental care. Children get a 'Zahnfee' (tooth fairy) just like in English."},
{type:"fb",s:"Mir tut der {1} weh. Ich kann kaum schlucken.",a:["Hals"],opts:["Hals","Magen","Rücken","Zahn"],hint:"Which body part makes it hard to swallow.",sSrc:"My throat hurts. I can barely swallow."},
{type:"tip",title:"Mir tut ... weh / Mir tun ... weh",text:"To say something hurts, use this pattern:\n\nSingular: Mir tut der Hals weh.\nPlural: Mir tun die Ohren weh.\n\n'Mir' = to me (dative)\n'tut/tun' = does/do\n'weh' = sore/painful\n\nThe body part is the subject, so the verb matches IT:\n- der Zahn tut weh (one tooth)\n- die Zähne tun weh (multiple teeth)\n\nCompound pain words: Kopfschmerzen, Halsschmerzen, Bauchschmerzen, Rückenschmerzen.",deepDive:{title:"Seit + dative: how long symptoms last",text:"Seit is a time preposition meaning 'since' or 'for'. It takes the DATIVE case.\n\nSeit + einem Tag = for a day\nSeit + einer Woche = for a week\nSeit + gestern = since yesterday\n\nIch habe seit zwei Tagen Kopfschmerzen.\n(I have had a headache for two days.)\n\nGerman uses PRESENT tense with seit where English uses the present perfect."}},
{type:"mc",q:"Verumius sagt: 'Mir tun die ___ weh.' Was passt, wenn er nichts hören kann?",opts:["Ohr","Ohren","Ohrs","Ohre"],ans:"Ohren",hint:"Plural form needed after 'die'. This word adds -en in plural."},
{type:"teach",trg:"die Tablette",src:"the tablet / pill",note:"Feminine. Plural: die Tabletten. Take with water!",example:"A: Ich habe Kopfschmerzen.\nB: Nehmen Sie diese Tabletten.\nA: Wie viele pro Tag?\nB: Zwei Tabletten, morgens und abends.",exampleSrc:"A: I have a headache.\nB: Take these tablets.\nA: How many per day?\nB: Two tablets, morning and evening.",funFact:"Germans are Europe's biggest consumers of herbal medicine. Many prefer 'pflanzliche Tabletten' (herbal tablets) over synthetic pills."},
{type:"teach",trg:"das Medikament",src:"the medication / medicine",note:"Neuter. More formal than 'Medizin'. Used for specific prescribed drugs.",example:"A: Brauche ich ein Medikament?\nB: Ja, ich verschreibe Ihnen etwas.\nA: Ist das Medikament stark?\nB: Nein, nehmen Sie es dreimal am Tag.",exampleSrc:"A: Do I need medication?\nB: Yes, I'll prescribe you something.\nA: Is the medication strong?\nB: No, take it three times a day.",funFact:"Germany has over 18,000 pharmacies (Apotheken). By law, most medications can only be sold in pharmacies, not in supermarkets like in other countries."},
{type:"teach",trg:"das Rezept",src:"the prescription",note:"Neuter. Same word also means 'recipe' for cooking!",example:"A: Ich brauche ein Medikament gegen Halsschmerzen.\nB: Haben Sie ein Rezept vom Arzt?\nA: Nein, leider nicht.\nB: Dann kann ich Ihnen nur diese Tabletten geben.",exampleSrc:"A: I need medication for a sore throat.\nB: Do you have a prescription from the doctor?\nA: No, unfortunately not.\nB: Then I can only give you these tablets.",funFact:"In German, 'Rezept' means both 'prescription' and 'recipe'. Context tells you which one. 'Ein Rezept vom Arzt' = prescription. 'Ein Rezept für Kuchen' = recipe."},
{type:"mc",q:"Verumius fragt in der Apotheke nach Medizin. Die Apothekerin fragt: 'Haben Sie ein ___ vom Arzt?'",opts:["Medikament","Tablette","Rezept","Creme"],ans:"Rezept",hint:"The pharmacist wants to know if a doctor authorized this."},
{type:"teach",trg:"die Creme",src:"the cream / ointment",note:"Feminine. Pronounced like 'Krehm'. Used for skin and pain relief.",example:"A: Mein Rücken tut so weh.\nB: Versuchen Sie diese Creme.\nA: Hilft die Creme schnell?\nB: Ja, reiben Sie sie zweimal am Tag ein.",exampleSrc:"A: My back hurts so much.\nB: Try this cream.\nA: Does the cream work quickly?\nB: Yes, rub it in twice a day.",funFact:"Nivea, one of the world's most famous cream brands, was invented in Hamburg in 1911. The name comes from Latin 'niveus' meaning 'snow-white'."},
{type:"teach",trg:"der Patient",src:"the patient (male)",note:"Masculine noun. Plural: die Patienten.\nFeminine form: die Patientin.",example:"A: Der Patient wartet schon eine Stunde.\nB: Ja, der Arzt hat heute viele Patienten.\nA: Wie heißt der Patient?\nB: Verumius. Er hat die Grippe.",exampleSrc:"A: The patient has been waiting for an hour.\nB: Yes, the doctor has many patients today.\nA: What is the patient's name?\nB: Verumius. He has the flu.",funFact:"In Germany, patients get a yellow Krankschreibung (sick note) from the doctor. One copy goes to the employer, one to the insurance company, and one is for the patient. The system is paper-based to this day."},
{type:"teach",trg:"die Krankschreibung",src:"the sick note",note:"Feminine noun. Compound: krank (sick) + Schreibung (writing).\nOfficially: Arbeitsunfähigkeitsbescheinigung (28 letters!).",example:"A: Ich bin seit drei Tagen krank.\nB: Hast du eine Krankschreibung?\nA: Ja, der Arzt hat mir eine gegeben.\nB: Gut, schick sie an deinen Chef.",exampleSrc:"A: I have been sick for three days.\nB: Do you have a sick note?\nA: Yes, the doctor gave me one.\nB: Good, send it to your boss.",funFact:"The official German term is 'Arbeitsunfähigkeitsbescheinigung' (certificate of inability to work), often abbreviated AU. It is one of the longest commonly used German words. Everyone just says Krankschreibung instead."},
{type:"teach",trg:"der Krankenwagen",src:"the ambulance",note:"Masculine noun. Compound: Kranken (sick people) + Wagen (vehicle).\nLiterally: the sick-wagon.",example:"A: Ruf den Krankenwagen!\nB: Ist es so schlimm?\nA: Ja, der Patient kann nicht stehen.\nB: Okay, ich rufe sofort an: 112.",exampleSrc:"A: Call the ambulance!\nB: Is it that bad?\nA: Yes, the patient cannot stand.\nB: Okay, I will call right away: 112.",funFact:"112 is the emergency number for ambulance and fire in Germany (and all of Europe). Police is 110. German ambulances are staffed with Rettungssanitäter (paramedics) and often an emergency doctor (Notarzt) as well."},
{type:"teach",trg:"stark",src:"strong",note:"Adjective. Comparative: stärker. Superlative: am stärksten.\nNote the umlaut in comparative and superlative!",example:"A: Ich habe starke Kopfschmerzen.\nB: Seit wann? Sind die Schmerzen sehr stark?\nA: Ja, ziemlich stark. Seit gestern.",exampleSrc:"A: I have a strong headache.\nB: Since when? Is the pain very strong?\nA: Yes, pretty strong. Since yesterday.",funFact:"'Stark' also means 'great' or 'awesome' in slang: 'Das war echt stark!' = That was really awesome! Like English 'strong move.' In grammar, 'starke Verben' (strong verbs) are irregular verbs that change their vowel."},
{type:"fb",s:"Der Arzt gibt Verumius ein {1} für die Apotheke.",a:["Rezept"],opts:["Rezept","Medikament","Tablette","Creme"],hint:"A piece of paper from the doctor that the pharmacy needs to see.",sSrc:"The doctor gives Verumius a prescription for the pharmacy."},
{type:"drag_fill",s:"Mir {1} der Rücken {2}. Ich brauche eine Creme.",blanks:{"1":"tut","2":"weh"},pool:["tut","weh","tun","ist","gut","hat"],hint:"Singular body part uses the singular verb form. The pain word goes at the end.",sSrc:"My back hurts. I need a cream."},
{type:"match",pairs:[{trg:"der Körper",src:"body"},{trg:"der Hals",src:"throat/neck"},{trg:"der Magen",src:"stomach"},{trg:"das Ohr",src:"ear"},{trg:"der Rücken",src:"back"},{trg:"der Zahn",src:"tooth"},{trg:"die Tablette",src:"tablet/pill"},{trg:"das Medikament",src:"medication"},{trg:"das Rezept",src:"prescription"},{trg:"die Creme",src:"cream"}]},
{type:"mc",q:"Verumius hat Rückenschmerzen und geht in die Apotheke. Was braucht er?",opts:["eine Creme","einen Zahn","ein Ohr","einen Hals"],ans:"eine Creme",hint:"For back pain, you apply something to the skin."}
]}
,

// Unit 7, Lesson 3: Beim Hausarzt
// Story: Verumius visits the Hausarzt. 4-minute appointment. Doctor speaks fast.
// Grammar: Perfekt with haben (formal intro), Dative case full paradigm
{id:"deu_r7l3",title:"Beim Hausarzt",icon:"\uD83D\uDC68\u200D\u2695\uFE0F",xp:15,board:true,steps:[
{type:"intro",title:"Beim Hausarzt",desc:"Verumius finally has his doctor's appointment. But German doctors are fast. Very fast. Four minutes fast.",goals:["Learn 8 new medical vocabulary words","Understand Perfekt with haben (past tense)","Learn the full dative case paradigm"]},
{type:"story",speaker:"narrator",mood:"nervous",art:"de-arztpraxis",trg:"Verumius sitzt im Wartezimmer. Endlich ruft die Sprechstundenhilfe seinen Namen. Er geht in das Behandlungszimmer. Der Arzt tippt schon auf seinem Computer.",src:"Verumius sits in the waiting room. Finally the receptionist calls his name. He goes into the treatment room. The doctor is already typing on his computer."},
{type:"story",speaker:"doctor",trg:"Guten Tag. Setzen Sie sich. Krankenkassenkarte bitte. Was fehlt Ihnen?",src:"Good day. Sit down. Insurance card please. What's the matter with you?"},
{type:"story",speaker:"verumius",mood:"confused",trg:"Ich... ich f\u00fchle mich nicht gut. Ich habe Halsschmerzen und...",src:"I... I don't feel well. I have a sore throat and..."},
{type:"story",speaker:"doctor",trg:"Mund auf. Hmm. Haben Sie Fieber gehabt? Husten? Seit wann?",src:"Open your mouth. Hmm. Have you had a fever? Cough? Since when?"},
{type:"teach",trg:"der Besuch",src:"the visit",note:"Masculine noun. Plural: die Besuche. Also means 'visitor.'",example:"A: Wie war der Besuch beim Arzt?\nB: Der Besuch war sehr kurz.\nA: Wie kurz?\nB: Vier Minuten!",exampleSrc:"A: How was the visit to the doctor?\nB: The visit was very short.\nA: How short?\nB: Four minutes!",funFact:"'Besuch' comes from 'besuchen' (to visit). Germans use it for both the act of visiting AND the person visiting. 'Wir haben Besuch' means 'We have visitors.'"},
{type:"teach",trg:"die Sprechstunde",src:"consultation hours",note:"Feminine noun. Compound: Sprech (speaking) + Stunde (hour).",example:"A: Wann hat der Arzt Sprechstunde?\nB: Die Sprechstunde ist von 8 bis 12.\nA: Und am Nachmittag?\nB: Nur mit Termin.",exampleSrc:"A: When does the doctor have consultation hours?\nB: Consultation hours are from 8 to 12.\nA: And in the afternoon?\nB: Only with an appointment.",funFact:"German doctors have fixed Sprechstunden. You show up, take a number, and wait. No appointment needed for the morning slot. This surprises many foreigners!"},
{type:"teach",trg:"die Krankenkasse",src:"the health insurance",note:"Feminine. Compound: Krank (sick) + Kasse (cash register/fund).",example:"A: Haben Sie eine Krankenkasse?\nB: Ja, ich bin bei der AOK.\nA: Gut. Krankenkassenkarte bitte.\nB: Hier, bitte.",exampleSrc:"A: Do you have health insurance?\nB: Yes, I'm with the AOK.\nA: Good. Insurance card please.\nB: Here you go.",funFact:"In Germany, health insurance is mandatory. The word literally means 'sick-cash-register.' About 90% of Germans are in the public system. The card is the first thing the receptionist asks for."},
{type:"teach",trg:"die Krankheit",src:"the illness / disease",note:"Feminine. From 'krank' (sick) + '-heit' (suffix like English '-ness').",example:"A: Was ist die Krankheit?\nB: Ich habe eine Erk\u00e4ltung.\nA: Das ist nicht schlimm.\nB: Aber ich f\u00fchle mich sehr schlecht!",exampleSrc:"A: What is the illness?\nB: I have a cold.\nA: That's not serious.\nB: But I feel very bad!",funFact:"The suffix '-heit' turns adjectives into nouns, just like English '-ness.' Krank to Krankheit, gesund to Gesundheit, sch\u00f6n to Sch\u00f6nheit (beauty). Once you know this trick, you can build dozens of nouns."},
{type:"teach",trg:"untersuchen",src:"to examine",note:"Inseparable verb: ich untersuche, er untersucht. Prefix 'unter-' stays attached.",example:"A: Der Arzt untersucht mich jetzt.\nB: Was untersucht er?\nA: Meinen Hals und meine Ohren.\nB: Das geht schnell.",exampleSrc:"A: The doctor is examining me now.\nB: What is he examining?\nA: My throat and my ears.\nB: That goes quickly.",funFact:"'Unter' means 'under,' so 'untersuchen' literally means 'to look under.' Like a detective investigating. The past participle has NO ge-: 'untersucht,' not 'geuntersucht.' Inseparable prefixes block 'ge-.'"},
{type:"teach",trg:"sich f\u00fchlen",src:"to feel (reflexive)",note:"Reflexive verb: ich f\u00fchle mich, du f\u00fchlst dich, er f\u00fchlt sich.",example:"A: Wie f\u00fchlen Sie sich?\nB: Ich f\u00fchle mich nicht gut.\nA: Seit wann?\nB: Seit drei Tagen.",exampleSrc:"A: How do you feel?\nB: I don't feel well.\nA: Since when?\nB: For three days.",funFact:"German uses 'sich' (myself/yourself) where English just says 'feel.' You don't just feel bad, you feel YOURSELF bad. 'Ich f\u00fchle mich krank' means I feel myself sick. Many body and emotion verbs are reflexive in German."},
{type:"teach",trg:"fallen",src:"to fall",note:"Irregular: ich falle, du f\u00e4llst, er f\u00e4llt. Stem change a to \u00e4.",example:"A: Ich bin gestern gefallen.\nB: Oh nein! Wo bist du gefallen?\nA: Auf der Treppe.\nB: Hast du dich verletzt?",exampleSrc:"A: I fell yesterday.\nB: Oh no! Where did you fall?\nA: On the stairs.\nB: Did you hurt yourself?",funFact:"'Fallen' uses 'sein' in the Perfekt (ich BIN gefallen), not 'haben.' Why? Because it is a movement verb. Movement verbs like gehen, kommen, fallen, fahren always use 'sein.' You will learn this distinction soon."},
{type:"teach",trg:"endlich",src:"finally / at last",note:"Adverb expressing relief that something happened after a long wait.",example:"A: Endlich bin ich dran!\nB: Wie lange hast du gewartet?\nA: Zwei Stunden!\nB: Das ist normal beim Hausarzt.",exampleSrc:"A: Finally it's my turn!\nB: How long did you wait?\nA: Two hours!\nB: That's normal at the GP.",funFact:"'Endlich' comes from 'Ende' (end). It carries emotional relief, not just sequence. 'Endlich!' by itself is an exclamation: 'At last!' Germans also say 'Na endlich!' for a stronger 'About time!'"},
{type:"tip",title:"Perfekt with haben: Talking About the Past",text:"German has a past tense called Perfekt. It uses TWO parts:\n\nhaben (conjugated) + Partizip II (at the end)\n\nRegular verbs: ge- + stem + -t\nmachen \u2192 gemacht, kaufen \u2192 gekauft, h\u00f6ren \u2192 geh\u00f6rt\n\nIrregular verbs: ge- + stem + -en (often with vowel change)\nnehmen \u2192 genommen, sprechen \u2192 gesprochen, trinken \u2192 getrunken\n\nExamples:\nIch habe Medikamente gekauft. (I bought medicine.)\nEr hat den Hals untersucht. (He examined the throat.)\n\nThe Partizip II always goes to the END of the sentence.",deepDive:"Inseparable prefix verbs (be-, er-, ver-, ent-, unter-) do NOT get ge-:\nbesuchen \u2192 besucht, untersuchen \u2192 untersucht, verstehen \u2192 verstanden.\n\nSeparable prefix verbs put ge- in the MIDDLE:\neinkaufen \u2192 eingekauft, aufmachen \u2192 aufgemacht.\n\nSome verbs use 'sein' instead of 'haben' for movement and state-change verbs like gehen, fallen, kommen. You will learn those in the next lesson."},
{type:"verb_table",title:"Perfekt with haben",groups:[{label:"haben conjugation",rows:[{pronoun:"ich",form:"habe",src:"I have"},{pronoun:"du",form:"hast",src:"you have"},{pronoun:"er/sie/es",form:"hat",src:"he/she/it has"},{pronoun:"wir",form:"haben",src:"we have"},{pronoun:"ihr",form:"habt",src:"you all have"},{pronoun:"sie/Sie",form:"haben",src:"they/you formal have"}]},{label:"Partizip II examples",rows:[{pronoun:"machen",form:"gemacht",src:"made/done"},{pronoun:"kaufen",form:"gekauft",src:"bought"},{pronoun:"h\u00f6ren",form:"geh\u00f6rt",src:"heard"},{pronoun:"nehmen",form:"genommen",src:"taken"},{pronoun:"sprechen",form:"gesprochen",src:"spoken"},{pronoun:"trinken",form:"getrunken",src:"drunk"}]}],note:"Regular: ge- + stem + -t. Irregular: ge- + changed stem + -en. Partizip II goes to the END."},
{type:"verb_table",title:"Irregular Partizip II Forms",label:"ge + changed stem + en",groups:[{label:"Key strong verbs",rows:[{pronoun:"schreiben",form:"geschrieben",src:"written"},{pronoun:"trinken",form:"getrunken",src:"drunk"},{pronoun:"essen",form:"gegessen",src:"eaten"},{pronoun:"lesen",form:"gelesen",src:"read"},{pronoun:"nehmen",form:"genommen",src:"taken"},{pronoun:"schlafen",form:"geschlafen",src:"slept"}]}],note:"These Partizip II forms end in -en, not -t.\nThe stem vowel changes. Memorize as vocabulary."},
{type:"verb_table",title:"Verbs Without ge- in Partizip II",label:"No ge- for these groups",groups:[{label:"-ieren verbs (no ge-)",rows:[{pronoun:"telefonieren",form:"telefoniert",src:"telephoned"},{pronoun:"studieren",form:"studiert",src:"studied"},{pronoun:"fotografieren",form:"fotografiert",src:"photographed"},{pronoun:"reparieren",form:"repariert",src:"repaired"}]},{label:"Inseparable prefix verbs (no ge-)",rows:[{pronoun:"besuchen",form:"besucht",src:"visited"},{pronoun:"erzählen",form:"erzählt",src:"told"},{pronoun:"verstehen",form:"verstanden",src:"understood"},{pronoun:"erklären",form:"erklärt",src:"explained"}]}],note:"Neither group uses ge-.\nInseparable prefixes: be-, er-, ver-, ent-, ge-, zer-."},
{type:"mc",q:"'Ich habe Tabletten gekauft.' What does this sentence mean?",opts:["I am buying tablets.","I bought tablets.","I will buy tablets.","I want to buy tablets."],ans:"I bought tablets.",hint:"The sentence uses haben + Partizip II, which describes a completed action."},
{type:"fb",s:"Er hat den Arzt {1}.",a:["besucht"],opts:["besucht","gebesucht","besuchen","besuchte"],hint:"Inseparable prefix verbs form their Partizip II without ge-.",sSrc:"He visited the doctor."},
{type:"mc",q:"Which is the correct Partizip II of 'machen'?",opts:["gemacht","gemachen","gegemacht","macht"],ans:"gemacht",hint:"Regular verbs follow the pattern ge- + stem + -t."},
{type:"tip",title:"The Dative Case: Giving, Showing, Telling",text:"German has four cases. You know Nominativ (subject) and Akkusativ (direct object). Now: Dativ.\n\nDativ answers: to whom? for whom?\n\nThe articles change:\nder \u2192 dem (masculine)\ndie \u2192 der (feminine)\ndas \u2192 dem (neuter)\ndie (plural) \u2192 den + -n on noun\n\nExamples:\nDer Arzt gibt dem Mann ein Rezept. (The doctor gives the man a prescription.)\nIch sage der Frau meinen Namen. (I tell the woman my name.)\nEr hilft dem Kind. (He helps the child.)",deepDive:"Common verbs that ALWAYS take dative:\nhelfen (to help): Ich helfe dem Arzt.\ngeben (to give): Er gibt dem Patienten Tabletten.\nzeigen (to show): Sie zeigt dem Kind das Buch.\nsagen (to say to): Ich sage der Frau die Adresse.\ngefallen (to please): Das gef\u00e4llt dem Mann.\n\nAlso after these prepositions: mit (with), bei (at/near), von (from), zu (to), nach (after), seit (since), aus (out of)."},
{type:"verb_table",title:"Dative Article Changes",label:"Definite article: der/die/das to dative",groups:[{label:"Nominative (for comparison)",rows:[{pronoun:"",form:"Maskulin / Feminin / Neutrum / Plural",src:""},{pronoun:"der/die/das/die",form:"der Vater / die Mutter / das Kind / die Kinder",src:""}]},{label:"Dative: dem/der/dem/den+n",rows:[{pronoun:"",form:"Maskulin / Feminin / Neutrum / Plural",src:""},{pronoun:"dem/der/dem/den",form:"dem Vater / der Mutter / dem Kind / den Kindern",src:""}]}],note:"Masculine and neuter both use dem.\nFeminine uses der.\nPlural uses den and nouns often add -n.",deepDive:{title:"Memory trick for dative articles",text:"Masculine and neuter BOTH become dem in the dative.\nFeminine becomes der, the same as the masculine nominative.\n\nA mnemonic for the three cases:\nNominative: der die das\nAccusative: den die das (only masculine changes)\nDative: dem der dem den\n\nDative is the only case where plural gets a special form (den + noun -n or -en)."}},
{type:"verb_table",title:"Indefinite Article in Dative",label:"ein/eine/ein to einem/einer/einem",groups:[{label:"Nominative (for comparison)",rows:[{pronoun:"",form:"Maskulin / Feminin / Neutrum",src:""},{pronoun:"ein/eine/ein",form:"ein Freund / eine Freundin / ein Kind",src:""}]},{label:"Dative: einem/einer/einem",rows:[{pronoun:"",form:"Maskulin / Feminin / Neutrum",src:""},{pronoun:"einem/einer/einem",form:"einem Freund / einer Freundin / einem Kind",src:""}]}],note:"Masculine and neuter: einem.\nFeminine: einer.\nParallel to the definite article pattern.",deepDive:{title:"Kein in the dative",text:"Kein (no/not a) follows the same pattern as ein:\nkeinem Freund, keiner Freundin, keinem Kind, keinen Kindern.\n\nOnce you learn einem/einer/einem, you automatically know keinem/keiner/keinem too."}},
{type:"mc",q:"'Der Arzt gibt ___ Mann ein Rezept.' Which article fills the blank?",opts:["dem","den","der","das"],ans:"dem",hint:"The man receives the prescription. This is the to-whom case for a masculine noun."},
{type:"fb",s:"Ich erkl\u00e4re {1} \u00c4rztin die Krankheit.",a:["der"],opts:["der","die","dem","den"],hint:"\u00c4rztin is feminine. Think about what 'die' becomes in the dative case.",sSrc:"I explain the illness to the female doctor."},
{type:"mc",q:"Verumius says: 'Ich habe endlich die Sprechstunde gefunden!' What does 'endlich' express?",opts:["All of a sudden","With deep regret","Finally, relieved","Probably not yet"],ans:"Finally, relieved",hint:"This word comes from 'Ende' and expresses that something took a long time."},
{type:"fb",s:"Wie {1} Sie sich heute?",a:["f\u00fchlen"],opts:["f\u00fchlen","fallen","finden","fahren"],hint:"Which reflexive verb asks about someone's physical state.",sSrc:"How do you feel today?"},
{type:"match",pairs:[{trg:"der Besuch",src:"the visit"},{trg:"die Krankenkasse",src:"health insurance"},{trg:"untersuchen",src:"to examine"},{trg:"sich f\u00fchlen",src:"to feel"},{trg:"endlich",src:"finally"},{trg:"die Krankheit",src:"illness"}]},
{type:"drag_fill",s:"Verumius {1} dem Arzt die Krankenkassenkarte {2}.",blanks:{"1":"hat","2":"gegeben"},pool:["hat","gegeben","ist","geben","dem","den"],hint:"Past tense with haben: conjugated haben + Partizip II at the end.",sSrc:"Verumius gave the insurance card to the doctor."}
]}
,

// ─── L4: Was hat der Arzt gesagt? (Grammar) ───
{id:"deu_r7l4",title:"Was hat der Arzt gesagt?",icon:"📋",xp:20,board:true,steps:[
{type:"intro",title:"Was hat der Arzt gesagt?",desc:"Verumius tries to remember what the doctor said. Conjunctions, modal verbs in past tense, and dative verbs. Plus: the world's longest Beipackzettel.",goals:["Use dass, weil, wenn, and als in sentences","Conjugate modal verbs in Präteritum","Recognize verbs that take dative objects"]},
{type:"teach",trg:"dass",src:"that (conjunction)",note:"Sends the verb to the END of the clause.\ndass + subject + ... + verb (last).",example:"A: Was hat der Arzt gesagt?\nB: Er hat gesagt, dass du mehr schlafen musst.\nA: Mehr schlafen? Das ist das beste Rezept!\nB: Ja, und weniger Kaffee trinken.",exampleSrc:"A: What did the doctor say?\nB: He said that you need to sleep more.\nA: More sleep? That's the best prescription!\nB: Yes, and drink less coffee.",funFact:"In a dass-clause, the conjugated verb jumps to the very end. Germans hear the verb last and still understand everything. Their brains are wired for suspense."},
{type:"teach",trg:"weil",src:"because",note:"Also sends the verb to the END.\nweil + subject + ... + verb (last).",example:"A: Warum bist du beim Arzt?\nB: Weil ich starke Kopfschmerzen habe.\nA: Seit wann?\nB: Seit drei Tagen. Es wird nicht besser.",exampleSrc:"A: Why are you at the doctor's?\nB: Because I have strong headaches.\nA: Since when?\nB: For three days. It's not getting better.",funFact:"'Weil' and 'denn' both mean 'because,' but 'weil' kicks the verb to the end while 'denn' keeps normal word order. Two words, same meaning, different grammar."},
{type:"teach",trg:"wenn",src:"when / if (repeated or hypothetical)",note:"For repeated events or conditions.\nwenn + subject + ... + verb (last).",example:"A: Wann nimmst du die Tabletten?\nB: Wenn ich Kopfschmerzen habe.\nA: Und wenn du keine hast?\nB: Dann bin ich froh!",exampleSrc:"A: When do you take the tablets?\nB: When I have headaches.\nA: And when you don't?\nB: Then I'm happy!",funFact:"'Wenn' does double duty: 'when' for repeated events and 'if' for conditions. 'Wenn es regnet, bleibe ich zu Hause' can mean both 'When it rains' and 'If it rains.' Context decides."},
{type:"teach",trg:"als",src:"when (past, single event)",note:"Only for ONE specific moment in the past.\nals + subject + ... + verb (last).",example:"A: Was ist passiert?\nB: Als ich beim Arzt war, hat er mich untersucht.\nA: Und was hat er gefunden?\nB: Er hat gesagt, es ist nur eine Erkältung.",exampleSrc:"A: What happened?\nB: When I was at the doctor's, he examined me.\nA: And what did he find?\nB: He said it's just a cold.",funFact:"The wenn/als distinction trips up every learner. Simple rule: one specific past moment = als. Everything else (repeated past, present, future, hypothetical) = wenn. 'Als ich Kind war' = When I was a child (one era)."},
{type:"mc",q:"Verumius says: 'Ich bin müde, ___ ich nicht gut geschlafen habe.' Which conjunction means 'because'?",opts:["dass","weil","wenn","als"],ans:"weil",hint:"He is giving a reason for being tired."},
{type:"fb",s:"Er hat gesagt, {1} ich mehr Wasser trinken soll.",a:["dass"],opts:["dass","weil","wenn","als"],hint:"The doctor reported something. Which conjunction introduces reported speech.",sSrc:"He said that I should drink more water."},
{type:"mc",q:"'Als ich beim Arzt war, hat er mich untersucht.' Why is 'als' correct here?",opts:["It describes a repeated habit","It describes a single past event","It introduces a condition","It gives a reason"],ans:"It describes a single past event",hint:"The doctor visit happened once, at a specific earlier time."},
{type:"verb_table",title:"Modal Verbs: Präteritum (Simple Past)",groups:[{label:"können (could)",rows:[{pronoun:"ich",form:"konnte",src:"I could"},{pronoun:"du",form:"konntest",src:"you could"},{pronoun:"er/sie/es",form:"konnte",src:"he/she/it could"},{pronoun:"wir",form:"konnten",src:"we could"},{pronoun:"ihr",form:"konntet",src:"you all could"},{pronoun:"sie/Sie",form:"konnten",src:"they/you (formal) could"}]},{label:"müssen (had to)",rows:[{pronoun:"ich",form:"musste",src:"I had to"},{pronoun:"du",form:"musstest",src:"you had to"},{pronoun:"er/sie/es",form:"musste",src:"he/she/it had to"},{pronoun:"wir",form:"mussten",src:"we had to"},{pronoun:"ihr",form:"musstet",src:"you all had to"},{pronoun:"sie/Sie",form:"mussten",src:"they/you (formal) had to"}]},{label:"wollen (wanted to)",rows:[{pronoun:"ich",form:"wollte",src:"I wanted to"},{pronoun:"du",form:"wolltest",src:"you wanted to"},{pronoun:"er/sie/es",form:"wollte",src:"he/she/it wanted to"},{pronoun:"wir",form:"wollten",src:"we wanted to"},{pronoun:"ihr",form:"wolltet",src:"you all wanted to"},{pronoun:"sie/Sie",form:"wollten",src:"they/you (formal) wanted to"}]},{label:"dürfen (was allowed to)",rows:[{pronoun:"ich",form:"durfte",src:"I was allowed to"},{pronoun:"du",form:"durftest",src:"you were allowed to"},{pronoun:"er/sie/es",form:"durfte",src:"he/she/it was allowed to"},{pronoun:"wir",form:"durften",src:"we were allowed to"},{pronoun:"ihr",form:"durftet",src:"you all were allowed to"},{pronoun:"sie/Sie",form:"durften",src:"they/you (formal) were allowed to"}]},{label:"sollen (was supposed to)",rows:[{pronoun:"ich",form:"sollte",src:"I was supposed to"},{pronoun:"du",form:"solltest",src:"you were supposed to"},{pronoun:"er/sie/es",form:"sollte",src:"he/she/it was supposed to"},{pronoun:"wir",form:"sollten",src:"we were supposed to"},{pronoun:"ihr",form:"solltet",src:"you all were supposed to"},{pronoun:"sie/Sie",form:"sollten",src:"they/you (formal) were supposed to"}]}],note:"Pattern: drop umlaut, add -te. konnte/musste/wollte/durfte/sollte. ich and er/sie/es forms are identical (no -st, no -t)."},
{type:"tip",title:"Why Modals Prefer Präteritum",text:"In spoken German, most verbs use Perfekt for the past:\n'Ich habe gegessen.' (I ate.)\n\nBut modal verbs almost always use Präteritum:\n'Ich konnte nicht schlafen.' (I couldn't sleep.)\nNOT: 'Ich habe nicht schlafen können.'\n\nWhy? The Perfekt of modals is clumsy: double infinitives at the end.\nPräteritum is shorter and cleaner. Germans just prefer it.",deepDive:"The technical term is Ersatzinfinitiv. When a modal has a dependent infinitive, Perfekt requires a double infinitive construction: 'Ich habe schlafen können.' This sounds overly formal and bookish. In everyday speech, 'Ich konnte schlafen' wins every time. The same applies to werden, lassen, sehen, hören, and helfen with infinitives."},
{type:"mc",q:"'Ich ___ gestern nicht schlafen.' Which Präteritum form of 'können' fits?",opts:["konnte","gekonnt","kann","könnte"],ans:"konnte",hint:"Simple past of 'können' for ich. No umlaut in past tense."},
{type:"fb",s:"Er {1} zum Arzt gehen, weil er krank war.",a:["musste"],opts:["musste","muss","gemusst","müsste"],hint:"Simple past of 'müssen' for er. The umlaut disappears in past tense.",sSrc:"He had to go to the doctor because he was sick."},
{type:"mc",q:"'Wir ___ am Wochenende nicht arbeiten.' Which is the Präteritum of 'dürfen' for wir?",opts:["durften","dürfen","gedurft","dürften"],ans:"durften",hint:"Simple past of dürfen, plural form. Ends in -ten."},
{type:"tip",title:"Verbs with Dative: Who Benefits?",text:"Some German verbs take a DATIVE object instead of accusative.\nThink of them as 'benefit/affect' verbs:\n\nhelfen + dative: Ich helfe DIR. (I help you.)\ngefallen + dative: Das gefällt MIR. (I like that.)\ngehören + dative: Das gehört IHM. (That belongs to him.)\nschmecken + dative: Das schmeckt UNS. (That tastes good to us.)\nfehlen + dative: Du fehlst MIR. (I miss you.)\nwehtun + dative: Der Kopf tut MIR weh. (My head hurts.)\n\nAll these describe something happening TO someone.",deepDive:"The pattern: these verbs describe an experience or benefit directed at a person, not an action performed on an object. 'Helfen' does not change the person, it benefits them. 'Gefallen' describes the experience OF someone. English hides this, but German marks it with dative case: mir, dir, ihm, ihr, uns, euch, ihnen."},
{type:"verb_table",title:"Dative Pronouns",label:"Personal pronouns in the dative case",groups:[{label:"Singular",rows:[{pronoun:"1st sing.",form:"ich / mich / mir",src:"I / me (acc) / me (dat)"},{pronoun:"2nd sing. (informal)",form:"du / dich / dir",src:"you / you (acc) / you (dat)"},{pronoun:"3rd masc.",form:"er / ihn / ihm",src:"he / him (acc) / him (dat)"},{pronoun:"3rd fem.",form:"sie / sie / ihr",src:"she / her (acc) / her (dat)"},{pronoun:"3rd neut.",form:"es / es / ihm",src:"it / it (acc) / it (dat)"}]},{label:"Plural",rows:[{pronoun:"1st pl.",form:"wir / uns / uns",src:"we / us (acc) / us (dat)"},{pronoun:"2nd pl. (informal)",form:"ihr / euch / euch",src:"you all / you (acc) / you (dat)"},{pronoun:"3rd pl. / formal",form:"sie/Sie / sie/Sie / ihnen/Ihnen",src:"they/you / them/you (acc) / them/you (dat)"}]}],note:"Formal Sie (dative) = Ihnen (capital I).\nuns and euch are the same for accusative and dative.",deepDive:{title:"A shortcut: uns and euch do double duty",text:"Uns is both accusative and dative for wir (we).\nEuch is both accusative and dative for ihr (you all).\n\nEr sieht uns. (He sees us, accusative)\nEr hilft uns. (He helps us, dative)\n\nSame form, context makes the case clear."}},
{type:"mc",q:"'Der Arzt hilft ___.' Which pronoun completes this correctly?",opts:["mir","mich","ich","mein"],ans:"mir",hint:"Helfen takes a dative object. What is the dative form of 'ich'?"},
{type:"fb",s:"Das Medikament schmeckt {1} nicht.",a:["mir"],opts:["mir","mich","ich","mein"],hint:"Schmecken takes dative. First person singular dative pronoun.",sSrc:"The medication does not taste good to me."},
{type:"teach",trg:"dringend",src:"urgent / urgently",note:"Used as adjective or adverb.\ndringend = urgent(ly).",example:"A: Ist es dringend?\nB: Ja, sehr dringend! Ich brauche sofort einen Arzt.\nA: Okay, kommen Sie mit!\nB: Danke, das ist sehr nett.",exampleSrc:"A: Is it urgent?\nB: Yes, very urgent! I need a doctor immediately.\nA: Okay, come with me!\nB: Thanks, that's very kind.",funFact:"'Dringend' comes from 'dringen' (to press/penetrate). Something urgent is literally 'pressing' on you. English 'urgent' comes from Latin urgere (to press). Same metaphor, different language family."},
{type:"teach",trg:"selbst",src:"self / oneself",note:"Adds emphasis: 'ich selbst' = I myself.\nAlso means 'even': 'Selbst der Arzt war krank.'",example:"A: Wer hat das Rezept gelesen?\nB: Ich selbst! Es war zehn Seiten lang.\nA: Zehn Seiten? Das ist ja ein Roman!\nB: Selbst die Apothekerin hat gelacht.",exampleSrc:"A: Who read the prescription?\nB: I myself! It was ten pages long.\nA: Ten pages? That's a novel!\nB: Even the pharmacist laughed.",funFact:"'Selbst' at the start of a sentence means 'even.' 'Selbst Verumius hat das verstanden' = Even Verumius understood that. After a pronoun it means 'oneself': 'Er hat es selbst gemacht' = He did it himself."},
{type:"teach",trg:"dabei",src:"with it / at the same time / present",note:"da + bei. 'Ich war dabei' = I was there/present.\n'Er hat dabei gelacht' = He laughed while doing it.",example:"A: Hattest du den Beipackzettel dabei?\nB: Ja, ich hatte ihn dabei.\nA: Und? Hast du alles gelesen?\nB: Nein, ich bin dabei eingeschlafen!",exampleSrc:"A: Did you have the medication insert with you?\nB: Yes, I had it with me.\nA: And? Did you read everything?\nB: No, I fell asleep while doing it!",funFact:"German has dozens of 'da-words': dabei, dafür, damit, darauf, darin, darüber, darunter. They replace 'preposition + es/das' for things (not people). 'Dabei' = 'bei dem' compressed."},
{type:"teach",trg:"darauf",src:"on it / thereupon / after that",note:"da + auf. 'Darauf steht eine Warnung' = There is a warning on it.\n'Ich freue mich darauf' = I'm looking forward to it.",example:"A: Was steht auf dem Beipackzettel?\nB: Darauf steht: nicht mit Kaffee einnehmen.\nA: Kein Kaffee?! Das ist schlimmer als die Krankheit!\nB: Darauf habe ich gewartet. Dein Gesicht!",exampleSrc:"A: What does the medication insert say?\nB: On it says: do not take with coffee.\nA: No coffee?! That's worse than the illness!\nB: I was waiting for that. Your face!",funFact:"'Darauf' is used with verbs that take 'auf': warten auf (wait for), sich freuen auf (look forward to), achten auf (pay attention to). 'Ich warte darauf' = I'm waiting for it. You cannot say 'Ich warte auf es.'"},
{type:"mc",q:"'Verumius konnte den Beipackzettel nicht lesen, ___ er zu lang war.' Which conjunction fits?",opts:["dass","weil","als","wenn"],ans:"weil",hint:"He is giving the reason he could not read it."},
{type:"drag_fill",s:"Der Arzt sagte, {1} Verumius mehr Wasser trinken {2}.",blanks:{"1":"dass","2":"sollte"},pool:["dass","weil","sollte","konnte","wenn","musste"],hint:"Reported speech uses a conjunction that sends the verb to the end.",sSrc:"The doctor said that Verumius should drink more water."},
{type:"fb",s:"Als ich beim Arzt war, {1} ich lange warten.",a:["musste"],opts:["musste","muss","konnte","sollte"],hint:"Past tense of 'have to.' He had no choice but to wait.",sSrc:"When I was at the doctor's, I had to wait a long time."},
{type:"match",pairs:[{trg:"dass",src:"that (conjunction)"},{trg:"weil",src:"because"},{trg:"wenn",src:"when / if"},{trg:"als",src:"when (past, single)"},{trg:"dringend",src:"urgent"},{trg:"selbst",src:"self / even"},{trg:"dabei",src:"with it / present"},{trg:"darauf",src:"on it / thereupon"}]}
]}
,

{id:"deu_r7l5",title:"Vorsicht ist besser",icon:"💊",xp:15,board:true,steps:[
{type:"intro",title:"Vorsicht ist besser",desc:"Neue Wörter rund um Vorsicht, Unfälle und Selbstfürsorge. Wiederholung: Perfekt, Dativ und Präteritum der Modalverben.",goals:["9 neue Wörter lernen","Perfekt mit haben wiederholen","Dativ und modale Präteritumformen üben"]},
{type:"teach",trg:"der Unfall",src:"the accident",note:"Plural: die Unfälle.\nUnfall = un (bad) + Fall (fall/case).",example:"A: Was ist gestern passiert?\nB: Mein Nachbar hatte einen Unfall.\nA: Oh nein! Ist er verletzt?\nB: Nein, zum Glück nicht schlimm.",exampleSrc:"A: What happened yesterday?\nB: My neighbor had an accident.\nA: Oh no! Is he hurt?\nB: No, luckily not bad.",funFact:"Germans are legally required to carry a first-aid kit (Verbandskasten) in their car at all times."},
{type:"teach",trg:"die Angst",src:"the fear, anxiety",note:"Angst haben vor + Dativ = to be afraid of.\nNo plural in everyday use.",example:"A: Hast du Angst vor dem Zahnarzt?\nB: Ja, ein bisschen.\nA: Ich auch! Aber der Arzt ist sehr nett.\nB: Das stimmt, er erklärt alles gut.",exampleSrc:"A: Are you afraid of the dentist?\nB: Yes, a little.\nA: Me too! But the doctor is very nice.\nB: That's true, he explains everything well.",funFact:"The word Angst was borrowed directly into English and is used in psychology worldwide."},
{type:"teach",trg:"die Ahnung",src:"the idea, clue",note:"keine Ahnung = no idea (very common phrase).\nAhnung haben von + Dativ = to know about.",example:"A: Weißt du, wo die Apotheke ist?\nB: Keine Ahnung, sorry.\nA: Ich frage mal den Mann dort.\nB: Gute Idee, der wohnt hier bestimmt.",exampleSrc:"A: Do you know where the pharmacy is?\nB: No idea, sorry.\nA: I'll ask that man over there.\nB: Good idea, he probably lives here.",funFact:"Keine Ahnung is one of the top 10 most-used phrases in casual German conversation."},
{type:"teach",trg:"der Apparat",src:"the device, apparatus",note:"Also used for phone: am Apparat = on the line.\nPlural: die Apparate.",example:"A: Was ist das für ein Apparat?\nB: Damit misst der Arzt den Blutdruck.\nA: Ah, das kenne ich vom Krankenhaus.\nB: Genau, der ist ganz normal.",exampleSrc:"A: What kind of device is that?\nB: The doctor measures blood pressure with it.\nA: Ah, I know that from the hospital.\nB: Exactly, it's completely normal.",funFact:"When answering the phone in Germany, people traditionally say their last name, not Hallo."},
{type:"teach",trg:"sich ausruhen",src:"to rest (oneself)",note:"Reflexive: Ich ruhe mich aus.\nSeparable prefix: aus + ruhen.",example:"A: Du siehst müde aus.\nB: Ja, ich muss mich ausruhen.\nA: Leg dich auf das Sofa.\nB: Danke, das mache ich.",exampleSrc:"A: You look tired.\nB: Yes, I need to rest.\nA: Lie down on the sofa.\nB: Thanks, I'll do that.",funFact:"German doctors can write you a Krankschreibung (sick note) that legally excuses you from work, even for minor illnesses."},
{type:"teach",trg:"sich verletzen",src:"to injure (oneself)",note:"Reflexive: Ich habe mich verletzt.\nPerfekt: hat sich verletzt (haben).",example:"A: Warum hast du einen Verband?\nB: Ich habe mich beim Sport verletzt.\nA: Das tut mir leid. Warst du beim Arzt?\nB: Ja, es ist nicht so schlimm.",exampleSrc:"A: Why do you have a bandage?\nB: I injured myself during sports.\nA: I'm sorry. Did you go to the doctor?\nB: Yes, it's not that bad.",funFact:"Germany has over 27,000 sports clubs, and sports injuries are one of the most common reasons for doctor visits."},
{type:"teach",trg:"aufpassen",src:"to watch out, to be careful",note:"Separable: Pass auf!\nAufpassen auf + Akkusativ = to look after.",example:"A: Die Straße ist glatt heute.\nB: Danke, ich passe auf.\nA: Gestern ist dort jemand gefallen.\nB: Oh, dann gehe ich ganz langsam.",exampleSrc:"A: The street is slippery today.\nB: Thanks, I'll be careful.\nA: Someone fell there yesterday.\nB: Oh, then I'll walk very slowly.",funFact:"Pass auf! is one of the first warning phrases German children learn, often shouted by parents near roads."},
{type:"teach",trg:"sich beeilen",src:"to hurry (oneself)",note:"Reflexive: Beeil dich! = Hurry up!\nPerfekt: hat sich beeilt.",example:"A: Die Sprechstunde endet um vier!\nB: Dann müssen wir uns beeilen.\nA: Hast du die Krankenkarte dabei?\nB: Ja, die ist in meiner Tasche.",exampleSrc:"A: Office hours end at four!\nB: Then we need to hurry.\nA: Do you have the insurance card with you?\nB: Yes, it's in my bag.",funFact:"Being late to a doctor's appointment in Germany can mean losing your slot entirely, so Beeilen is taken seriously."},
{type:"teach",trg:"manchmal",src:"sometimes",note:"Position: manchmal can start or follow the verb.\nManchmal gehe ich ... / Ich gehe manchmal ...",example:"A: Gehst du oft zum Arzt?\nB: Nein, nur manchmal.\nA: Ich gehe manchmal wegen Rückenschmerzen.\nB: Das kenne ich, das ist nicht schön.",exampleSrc:"A: Do you go to the doctor often?\nB: No, only sometimes.\nA: I sometimes go because of back pain.\nB: I know that, it's not nice.",funFact:"Germans visit the doctor an average of 10 times per year, one of the highest rates in Europe."},
{type:"tip",title:"Reflexive Verben im Perfekt",text:"Reflexive verbs use haben in the Perfekt.\nThe reflexive pronoun stays:\n\nIch habe mich ausgeruht.\nEr hat sich verletzt.\nWir haben uns beeilt.\n\nWord order: subject + haben + reflexive pronoun + ... + Partizip II.",deepDive:{title:"Separable reflexive verbs in Perfekt",text:"In the Perfekt tense, separable reflexive verbs combine the ge- prefix with the rest:\n\nsich anziehen: Ich habe mich angezogen.\nsich ausziehen: Ich habe mich ausgezogen.\n\nThe ge- goes between the separable prefix and the stem: an+ge+zogen = angezogen."}},
{type:"mc",q:"Ich habe ___ beim Kochen verletzt.",opts:["mich","mir","sich","uns"],ans:"mich",hint:"First person singular reflexive in accusative case."},
{type:"fb",s:"Gestern {1} ich einen Unfall.",a:"hatte",opts:["hatte","habe","bin","war"],hint:"Präteritum of haben, first person singular.",sSrc:"Yesterday I had an accident."},
{type:"mc",q:"Er musste sich ___.",opts:["beeilen","beeilt","zu beeilen","beeilte"],ans:"beeilen",hint:"After a modal verb, use the infinitive form."},
{type:"fb",s:"Pass {1}! Die Straße ist nass.",a:"auf",opts:["auf","an","aus","ab"],hint:"Which separable prefix means to watch out.",sSrc:"Watch out! The road is wet."},
{type:"mc",q:"Hast du Angst ___ dem Krankenhaus?",opts:["vor","für","mit","bei"],ans:"vor",hint:"Angst haben requires a specific dative preposition."},
{type:"fb",s:"Ich habe keine {1}, wo die Apotheke ist.",a:"Ahnung",opts:["Ahnung","Angst","Idee","Apparat"],hint:"Common phrase meaning you have no clue at all.",sSrc:"I have no idea where the pharmacy is."},
{type:"drag_fill",s:"Sie {1} sich gestern beim Sport {2}.",blanks:{"1":"hat","2":"verletzt"},pool:["hat","sich","verletzt","ist","verletzen"],hint:"Perfekt of sich verletzen uses haben.",sSrc:"She injured herself during sports yesterday."},
{type:"mc",q:"Manchmal ___ ich mich nach der Arbeit aus.",opts:["ruhe","ruhen","ausruhe","ruht"],ans:"ruhe",hint:"Separable verb: the prefix goes to the end in main clauses."},
{type:"teach",trg:"schwanger",src:"pregnant",note:"Adjective. Sie ist schwanger = She is pregnant. No comparative form used.",example:"A: Hast du gehört? Lisa ist schwanger!\nB: Wirklich? Das ist wunderbar!\nA: Ja, sie bekommt das Baby im Sommer.\nB: Herzlichen Glückwunsch an sie!",exampleSrc:"A: Did you hear? Lisa is pregnant!\nB: Really? That is wonderful!\nA: Yes, she is having the baby in the summer.\nB: Congratulations to her!",funFact:"In Germany, pregnant women get a Mutterpass (maternity record book) from their doctor. They carry it everywhere. Employers must provide 14 weeks of paid maternity leave (Mutterschutz), and firing a pregnant employee is illegal."},
{type:"match",pairs:[{trg:"der Unfall",src:"the accident"},{trg:"die Angst",src:"the fear"},{trg:"aufpassen",src:"to watch out"},{trg:"sich beeilen",src:"to hurry"},{trg:"manchmal",src:"sometimes"}]},
{type:"fb",s:"Der Arzt hat einen neuen {1} für den Blutdruck.",a:"Apparat",opts:["Apparat","Rezept","Tablette","Besuch"],hint:"A device used for measuring something medical.",sSrc:"The doctor has a new device for blood pressure."},
{type:"teach",trg:"bleiben",src:"to stay / to remain",note:"Irregular: ich bleibe, du bleibst. Perfekt: ist geblieben (with sein!).",example:"A: Wie lange bleibst du in Berlin?\nB: Ich weiß noch nicht. Vielleicht für immer.\nA: Das wäre schön!",exampleSrc:"A: How long are you staying in Berlin?\nB: I don't know yet. Maybe forever.\nA: That would be nice!",funFact:"Bleiben uses sein in Perfekt because staying is a state change: you were elsewhere, now you remain. 'Ich bin geblieben' not 'Ich habe geblieben.'"}
]},

// ─── L6: Der Beipackzettel (Story Climax) ───
{id:"deu_r7l6",title:"Der Beipackzettel",icon:"\uD83D\uDCDC",xp:20,board:true,steps:[
{type:"intro",title:"Der Beipackzettel",desc:"Verumius unfolds the medication insert. And unfolds it. And keeps unfolding it. German compound nouns have never been scarier.",goals:["Read a Beipackzettel (medication insert)","Combine Perfekt, dative, and modal Präteritum in sentences","Use weil and dass clauses with complex grammar"]},
{type:"story",speaker:"narrator",mood:"comedic",art:"de-beipackzettel",trg:"Verumius nimmt die Tabletten aus der Tüte. Er sieht den Beipackzettel. Er faltet ihn auf. Und faltet. Und faltet. Das Papier ist jetzt größer als der Tisch.",src:"Verumius takes the tablets out of the bag. He sees the medication insert. He unfolds it. And unfolds. And unfolds. The paper is now bigger than the table."},
{type:"story",speaker:"verumius",mood:"panic",trg:"Was?! Nebenwirkungen: Kopfschmerzen, Bauchschmerzen, Müdigkeit, Schwindel, Übelkeit... Das sind mehr Wörter als in meinem ganzen Deutschkurs!",src:"What?! Side effects: headaches, stomach aches, tiredness, dizziness, nausea... That's more words than in my entire German course!"},
{type:"story",speaker:"hildi",mood:"laughing",trg:"Verumius, du musst nicht alles lesen! Nimm einfach die Tablette und ruf mich an, wenn etwas passiert.",src:"Verumius, you don't have to read everything! Just take the tablet and call me if something happens."},
{type:"teach",trg:"passieren",src:"to happen",note:"Regular verb. Perfekt: ist passiert (uses sein!).",example:"A: Was ist passiert?\nB: Ich bin hingefallen und habe mir den Arm wehgetan.",exampleSrc:"A: What happened?\nB: I fell and hurt my arm.",funFact:"'Passieren' comes from French 'passer.' In German it only means 'to happen,' never 'to pass by.' For passing, Germans say 'vorbeigehen.'"},
{type:"teach",trg:"rufen",src:"to call (out) / to shout",note:"Irregular: ruft, rief, hat gerufen. Not for phone calls (that is 'anrufen').",example:"A: Wer hat meinen Namen gerufen?\nB: Das war der Arzt. Er hat dich gerufen.",exampleSrc:"A: Who called my name?\nB: That was the doctor. He called you.",funFact:"'Rufen' is calling OUT, like shouting across a room. For phone calls, Germans add 'an': 'anrufen.' Hildi says 'ruf mich an' because she means by phone."},
{type:"teach",trg:"sich setzen",src:"to sit down (reflexive)",note:"Reflexive: Ich setze mich. Perfekt: hat sich gesetzt. Dative with location: auf den Stuhl.",example:"A: Bitte setzen Sie sich!\nB: Danke, ich habe mich schon gesetzt.",exampleSrc:"A: Please sit down!\nB: Thanks, I already sat down.",funFact:"German distinguishes sitting DOWN (sich setzen, movement) from sitting (sitzen, position). 'Setz dich!' means get into the chair. 'Sitz!' is what you say to a dog already in place."},
{type:"teach",trg:"weinen",src:"to cry",note:"Regular verb. Perfekt: hat geweint.",example:"A: Warum hast du geweint?\nB: Weil der Film so traurig war.",exampleSrc:"A: Why did you cry?\nB: Because the film was so sad.",funFact:"'Weinen' is related to English 'whine,' but in German it means full crying with tears, not complaining. For complaining, Germans say 'jammern.'"},
{type:"teach",trg:"sich aufregen",src:"to get upset / to get worked up",note:"Separable + reflexive: Ich rege mich auf. Perfekt: hat sich aufgeregt.",example:"A: Reg dich nicht auf!\nB: Ich kann mich nicht beruhigen, weil ich den Beipackzettel gelesen habe!",exampleSrc:"A: Don't get upset!\nB: I can't calm down because I read the medication insert!",funFact:"'Auf' (up) + 'regen' (to stir). Getting upset literally means stirring yourself UP. 'Aufregen' is one of the most common reflexive verbs in everyday German."},
{type:"teach",trg:"sogar",src:"even (adverb)",note:"Adds emphasis or surprise. Placed before the word it emphasizes.",example:"A: Kannst du den Beipackzettel lesen?\nB: Sogar mein Arzt versteht ihn nicht!",exampleSrc:"A: Can you read the medication insert?\nB: Even my doctor doesn't understand it!",funFact:"'Sogar' comes from 'so' + 'gar' (completely). It is the standard word for 'even' in surprising contexts. Sogar Hildi hat gelacht. Even Hildi laughed."},
{type:"mc",q:"Hildi sagt: 'Ruf mich an, wenn etwas passiert.' Was bedeutet 'passiert'?",opts:["happens","passes by","calls","hurts"],ans:"happens",hint:"Think about unexpected events, not physical movement."},
{type:"fb",s:"Was ist gestern {1}?",a:["passiert"],opts:["passiert","gerufen","gesetzt","geweint"],hint:"Which Perfekt participle uses sein, not haben.",sSrc:"What happened yesterday?"},
{type:"mc",q:"Verumius hat sich aufgeregt, weil er den Beipackzettel gelesen hat. What was Verumius?",opts:["tired","upset","hungry","happy"],ans:"upset",hint:"Reading a comically long medical insert stirred him up."},
{type:"drag_fill",s:"Verumius {1} sich auf den Stuhl {2}, weil er müde {3}.",blanks:{"1":"hat","2":"gesetzt","3":"war"},pool:["hat","gesetzt","war","ist","gerufen","hatte"],hint:"Perfekt of sich setzen (hat + past participle) plus Präteritum of sein.",sSrc:"Verumius sat down on the chair because he was tired."},
{type:"fb",s:"Der Arzt hat den Patienten {1}.",a:["gerufen"],opts:["gerufen","geweint","passiert","gesetzt"],hint:"Which participle means 'called out for someone'.",sSrc:"The doctor called the patient."},
{type:"mc",q:"'Sogar der Apotheker konnte den Beipackzettel nicht verstehen.' Was bedeutet 'sogar'?",opts:["always","never","even","almost"],ans:"even",hint:"This word adds surprise, emphasizing how unexpected it is."},
{type:"drag_fill",s:"Ich habe {1}, weil der Arzt mir {2} hat, dass ich {3} musste.",blanks:{"1":"geweint","2":"gesagt","3":"warten"},pool:["geweint","gesagt","warten","gerufen","passiert","konnte"],hint:"Perfekt of weinen, then Perfekt of sagen, then a modal infinitive at the end.",sSrc:"I cried because the doctor told me that I had to wait."},
{type:"mc",q:"Verumius konnte den Beipackzettel nicht lesen, weil die Wörter zu lang waren. Why couldn't he read it?",opts:["Because the words were too long","Because he lost his glasses","Because it was in English","Because the doctor took it away"],ans:"Because the words were too long",hint:"The weil clause explains the reason with an adjective about length."},
{type:"fb",s:"Sie hat sich so {1}, dass sie sogar geweint hat.",a:["aufgeregt"],opts:["aufgeregt","gesetzt","passiert","gerufen"],hint:"Which separable verb participle means 'got worked up'.",sSrc:"She got so upset that she even cried."},
{type:"drag_fill",s:"Hildi {1} Verumius {2}, weil er sich nicht {3} {4}.",blanks:{"1":"hat","2":"gerufen","3":"beruhigen","4":"konnte"},pool:["hat","gerufen","beruhigen","konnte","ist","passiert"],hint:"Perfekt of rufen in the main clause, then weil sends the modal to the end.",sSrc:"Hildi called Verumius because he could not calm himself down."},
{type:"match",pairs:[{trg:"passieren",src:"to happen"},{trg:"rufen",src:"to call out"},{trg:"sich setzen",src:"to sit down"},{trg:"weinen",src:"to cry"},{trg:"sich aufregen",src:"to get upset"},{trg:"sogar",src:"even"}]}
]}
,

{id:"deu_r7l7",title:"Alles klar?",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Alles klar?",desc:"Zeit für den großen Test! Alles aus Lektion 1 bis 6 kommt jetzt zusammen: Körperteile, Arztbesuch, Perfekt, Modalverben im Präteritum, Dativ und Nebensätze.",goals:["Vokabeln aus L1-L6 wiederholen","Grammatik kombinieren","Alles zusammen anwenden"]},
{type:"mc",q:"Ich habe gestern eine Tablette ___.",opts:["genommen","nehmen","genommt","genahmt"],ans:"genommen",hint:"Nehmen ist ein starkes Verb mit unregelmäßigem Partizip."},
{type:"fb",s:"Er {1} nicht zum Arzt gehen.",a:"konnte",opts:["konnte","kann","gekonnt","könnte"],hint:"Modalverb in der Vergangenheit, Präteritum.",sSrc:"He could not go to the doctor."},
{type:"mc",q:"Was bedeutet 'die Sprechstunde'?",opts:["Office hours","Emergency room","Pharmacy aisle","Waiting room"],ans:"Office hours",hint:"Der Arzt hat bestimmte Zeiten für Patienten."},
{type:"drag_fill",s:"Ich habe {1} Arzt gesagt, {2} mein Hals wehtut.",blanks:{1:"dem",2:"dass"},pool:["dem","der","dass","weil","den"],hint:"Dativ nach sagen + Nebensatz mit Verb am Ende.",sSrc:"I told the doctor that my throat hurts."},
{type:"fb",s:"Die Ärztin hat mich gründlich {1}.",a:"untersucht",opts:["untersucht","untersuchen","untersuchte","unterforscht"],hint:"Perfekt von untersuchen: hat ge...t? Nein, un- ist untrennbar!",sSrc:"The doctor examined me thoroughly."},
{type:"mc",q:"Welcher Satz ist richtig?",opts:["Ich musste im Krankenhaus bleiben, weil ich Grippe hatte.","Ich musste im Krankenhaus bleiben, weil ich hatte Grippe.","Ich musste im Krankenhaus bleiben, weil ich Grippe gehabt.","Ich musste im Krankenhaus bleiben, weil hatte ich Grippe."],ans:"Ich musste im Krankenhaus bleiben, weil ich Grippe hatte.",hint:"Nach weil steht das konjugierte Verb am Satzende."},
{type:"fb",s:"Der Schmerz im Rücken tut {1} sehr weh.",a:"mir",opts:["mir","mich","ich","mein"],hint:"Wehtun braucht den Dativ der Person.",sSrc:"The pain in my back hurts me a lot."},
{type:"mc",q:"Er ___ sich gestern beim Sport verletzt.",opts:["hat","ist","wird","hatte"],ans:"hat",hint:"Reflexive Verben bilden das Perfekt immer mit haben."},
{type:"drag_fill",s:"Sie {1} gestern in der Apotheke eine Creme {2}.",blanks:{1:"hat",2:"gekauft"},pool:["hat","ist","gekauft","kaufen","gekaufen"],hint:"Perfekt mit haben. Kaufen ist regelmäßig: ge...t.",sSrc:"She bought a cream at the pharmacy yesterday."},
{type:"mc",q:"Mein Magen tut weh. Ich glaube, ich habe etwas Schlechtes ___.",opts:["gegessen","gegesst","geessen","essen"],ans:"gegessen",hint:"Starkes Verb! Denk an die dritte Stammform."},
{type:"fb",s:"Sie {1} als Kind keine Medikamente nehmen.",a:"durfte",opts:["durfte","darf","gedurft","dürfte"],hint:"Dürfen in der Vergangenheit, einfache Erzählung.",sSrc:"As a child, she was not allowed to take medication."},
{type:"drag_fill",s:"Der Arzt hat {1} Patientin erklärt, {2} sie sich ausruhen {3}.",blanks:{1:"der",2:"dass",3:"soll"},pool:["der","dem","dass","weil","soll","muss"],hint:"Dativ feminin + dass-Nebensatz mit Verb am Ende.",sSrc:"The doctor explained to the patient that she should rest."},
{type:"mc",q:"Wähle die richtige Kombination: Er ist nervös, ___ er keine Ahnung hat, ___ passiert ist.",opts:["weil ... was","dass ... was","weil ... dass","wenn ... weil"],ans:"weil ... was",hint:"Grund mit weil, dann eine indirekte Frage."},
{type:"fb",s:"Ich sollte mich nicht so {1}.",a:"aufregen",opts:["aufregen","aufgeregt","aufregt","aufzuregen"],hint:"Nach Modalverben steht der Infinitiv.",sSrc:"I should not get so worked up."},
{type:"mc",q:"Er hat dem Kind geholfen, weil es ___ hat.",opts:["geweint","weinen","geweinen","geweaint"],ans:"geweint",hint:"Weinen ist regelmäßig: ge...t."},
{type:"drag_fill",s:"Wir {1} den Krankenwagen rufen, {2} der Unfall sehr schlimm {3}.",blanks:{1:"mussten",2:"weil",3:"war"},pool:["mussten","müssen","weil","dass","war","ist"],hint:"Präteritum von müssen + weil mit Verb am Ende.",sSrc:"We had to call the ambulance because the accident was very bad."},
{type:"fb",s:"Pass auf dich {1}!",a:"auf",opts:["auf","an","aus","um"],hint:"Trennbares Verb! Welches Präfix gehört hierher.",sSrc:"Take care of yourself!"},
{type:"mc",q:"Die Gesundheit ___ den Menschen am wichtigsten.",opts:["ist","hat","wird","macht"],ans:"ist",hint:"Welches Verb passt zu einem Zustand wie Gesundheit?"},
{type:"drag_fill",s:"Er {1} sich endlich {2}, weil er manchmal zu viel {3} hat.",blanks:{1:"hat",2:"ausgeruht",3:"gearbeitet"},pool:["hat","ist","ausgeruht","ausruhen","gearbeitet","arbeiten"],hint:"Reflexive verb: which auxiliary? Then past participle forms for resting and working.",sSrc:"He finally rested because he had sometimes worked too much."},
{type:"mc",q:"Der Zahnarzt hat ___ Mädchen gesagt, dass es keine Angst haben soll.",opts:["dem","das","der","den"],ans:"dem",hint:"Sagen braucht den Dativ. Mädchen ist Neutrum."},
{type:"fb",s:"Sie wollte sich {1}, aber sie konnte den Arzt nicht erreichen.",a:"beeilen",opts:["beeilen","beeilt","beeilte","beeilen sich"],hint:"Nach Modalverben kommt der Infinitiv ohne sich davor.",sSrc:"She wanted to hurry, but she could not reach the doctor."},
{type:"match",pairs:[{trg:"die Krankenkasse",src:"health insurance"},{trg:"das Rezept",src:"prescription"},{trg:"die Grippe",src:"the flu"},{trg:"der Besuch",src:"the visit"},{trg:"dringend",src:"urgent"},{trg:"sogar",src:"even"}]}
]},

{id:"deu_r7l8",title:"Gute Besserung",icon:"🍵",xp:15,board:true,steps:[
{type:"intro",title:"Gute Besserung",desc:"Verumius wakes up feeling better. Hildi left chicken soup at his door with a note. Time to recover, reflect on German healthcare, and learn a few last words.",goals:["Learn adjectives for health and state","Discover German healthcare culture","Review the full unit vocabulary"]},
{type:"teach",trg:"gesund",src:"healthy",note:"The opposite of krank. Germans say 'Bleib gesund!' as a farewell wish.",example:"A: Bist du wieder gesund?\nB: Ja, ich bin wieder gesund. Die Suppe hat geholfen.\nA: Das freut mich! Bleib gesund!\nB: Danke, du auch!",exampleSrc:"A: Are you healthy again?\nB: Yes, I'm healthy again. The soup helped.\nA: I'm glad! Stay healthy!\nB: Thanks, you too!",funFact:"'Gesundheit!' is what Germans say when someone sneezes. It literally means 'health!' and is used worldwide."},
{type:"teach",trg:"fit",src:"fit",note:"Same word as English. Used for physical fitness and general well-being.",example:"A: Ich fühle mich wieder fit.\nB: Wirklich? Gestern warst du noch so krank.\nA: Die frische Luft hilft sehr.\nB: Typisch deutsch! Frische Luft heilt alles.",exampleSrc:"A: I feel fit again.\nB: Really? Yesterday you were still so sick.\nA: The fresh air helps a lot.\nB: Typical German! Fresh air heals everything.",funFact:"Germans genuinely believe fresh air (frische Luft) cures almost anything. Open windows in winter are completely normal, even in hospitals."},
{type:"teach",trg:"wach",src:"awake",note:"From the verb 'wachen' (to be awake). Wach werden means to wake up.",example:"A: Bist du schon wach?\nB: Ja, ich bin seit sechs Uhr wach.\nA: So früh? Du warst doch krank!\nB: Ich konnte nicht mehr schlafen.",exampleSrc:"A: Are you already awake?\nB: Yes, I've been awake since six o'clock.\nA: So early? You were sick!\nB: I couldn't sleep anymore.",funFact:"Germany runs on early mornings. Many bakeries open at 5:30 AM, and construction noise is legally allowed from 7 AM."},
{type:"teach",trg:"schwach",src:"weak",note:"The opposite of stark (strong). Describes physical weakness or a faint feeling.",example:"A: Ich fühle mich noch etwas schwach.\nB: Das ist normal nach einer Erkältung.\nA: Wann werde ich wieder stark?\nB: Ruh dich aus und iss die Suppe!",exampleSrc:"A: I still feel a bit weak.\nB: That's normal after a cold.\nA: When will I be strong again?\nB: Rest and eat the soup!",funFact:"The German word for weakness, 'Schwäche,' also means a soft spot. 'Schokolade ist meine Schwäche' means chocolate is my weakness."},
{type:"teach",trg:"gefährlich",src:"dangerous",note:"From Gefahr (danger). Very common in warnings and safety signs across Germany.",example:"A: Ist es gefährlich, mit Fieber zu arbeiten?\nB: Ja, das ist sehr gefährlich!\nA: Mein Chef sagt, ich soll kommen.\nB: Dein Arzt sagt nein. Der Arzt gewinnt.",exampleSrc:"A: Is it dangerous to work with a fever?\nB: Yes, that's very dangerous!\nA: My boss says I should come.\nB: Your doctor says no. The doctor wins.",funFact:"In Germany, if your doctor writes you a Krankschreibung (sick note), your employer cannot force you to work. Sick leave is a protected right."},
{type:"teach",trg:"furchtbar",src:"terrible",note:"From Furcht (fear). Used for something truly awful, stronger than schlecht.",example:"A: Wie war die Nacht?\nB: Furchtbar. Ich hatte Kopfschmerzen und Fieber.\nA: Das klingt wirklich schlimm.\nB: Aber heute geht es mir besser.",exampleSrc:"A: How was the night?\nB: Terrible. I had a headache and fever.\nA: That sounds really bad.\nB: But today I feel better.",funFact:"Germans love intensifiers. 'Furchtbar' (terrible) is often used positively too: 'furchtbar nett' means terribly nice, like 'awfully kind' in English."},
{type:"teach",trg:"plötzlich",src:"suddenly",note:"An adverb describing something unexpected. Very common in storytelling.",example:"A: Was ist passiert?\nB: Ich war im Büro und plötzlich war mir schwindelig.\nA: Plötzlich? Einfach so?\nB: Ja, von einer Sekunde auf die andere.",exampleSrc:"A: What happened?\nB: I was at the office and suddenly I felt dizzy.\nA: Suddenly? Just like that?\nB: Yes, from one second to the next.",funFact:"German has wonderful adverbs for time: plötzlich (suddenly), allmählich (gradually), gelegentlich (occasionally), and augenblicklich (instantaneously, literally 'in the blink of an eye')."},
{type:"teach",trg:"hoffentlich",src:"hopefully",note:"From Hoffnung (hope). Always placed at the start or middle of a sentence.",example:"A: Hoffentlich geht es dir bald besser.\nB: Danke! Hoffentlich kann ich morgen arbeiten.\nA: Nicht zu schnell! Erst gesund werden.\nB: Du klingst wie meine Mutter!",exampleSrc:"A: Hopefully you'll feel better soon.\nB: Thanks! Hopefully I can work tomorrow.\nA: Not too fast! Get healthy first.\nB: You sound like my mother!",funFact:"Hoffentlich is one of those German words that packs a whole English phrase into one word. Another example: Fingerspitzengefühl means intuitive sensitivity (literally: fingertip feeling)."},
{type:"teach",trg:"niemand",src:"nobody",note:"The opposite of jemand (somebody). Used as a pronoun in the subject or object position.",example:"A: War jemand an der Tür?\nB: Niemand. Aber da steht eine Suppe!\nA: Von wem ist die?\nB: Da liegt ein Zettel: 'Gute Besserung. Frau Schreiber.'",exampleSrc:"A: Was somebody at the door?\nB: Nobody. But there's a soup!\nA: Who is it from?\nB: There's a note: 'Get well soon. Frau Schreiber.'",funFact:"Hildi Schreiber left soup without knocking. In Germany, neighbours often help quietly without making a fuss. It is considered polite not to make someone feel indebted."},
{type:"tip",title:"Deutsche Gesundheitskultur",text:"German healthcare culture has a few surprises:\n\n\u2022 Krankschreibung: Your doctor gives you a sick note and you stay home. No guilt.\n\u2022 Kur: A multi-week health retreat at a spa town, sometimes covered by insurance.\n\u2022 Frische Luft: Germans open windows year-round. Fresh air is considered medicine.\n\u2022 Hühnersuppe: Chicken soup is the universal German home remedy, just like everywhere else.\n\u2022 Apotheke vs. Drogerie: Prescription medicine only at the Apotheke (pharmacy). Shampoo and vitamins at the Drogerie (drugstore).",deepDive:"Germany has universal healthcare through the Gesetzliche Krankenversicherung (statutory health insurance). About 90% of the population is covered. Employees and employers split the cost. Doctor visits have no co-pay. The system dates back to 1883 under Otto von Bismarck, making it one of the oldest national healthcare systems in the world."},
{type:"mc",q:"Hildi hat Suppe vor die Tür gestellt. Was steht auf dem Zettel?",opts:["Gute Besserung","Guten Appetit","Viel Glück","Herzlichen Glückwunsch"],ans:"Gute Besserung",hint:"This is what Germans say to someone who is sick."},
{type:"fb",s:"Ich fühle mich heute wieder {1}.",a:"gesund",opts:["gesund","krank","schwach","gefährlich"],hint:"The opposite of sick, the goal of recovery.",sSrc:"I feel healthy again today."},
{type:"mc",q:"Was bedeutet 'furchtbar'?",opts:["terrible","dangerous","suddenly","hopefully"],ans:"terrible",hint:"Think of the root word Furcht, which means fear."},
{type:"fb",s:"Hoffentlich kann ich morgen wieder {1}.",a:"arbeiten",opts:["arbeiten","schlafen","husten","niesen"],hint:"What you do at the office or workplace.",sSrc:"Hopefully I can work again tomorrow."},
{type:"mc",q:"Verumius öffnet das Fenster. Warum?",opts:["Frische Luft hilft bei Krankheit","Er hat Besuch","Das Fenster ist kaputt","Er will rausgehen"],ans:"Frische Luft hilft bei Krankheit",hint:"A very German belief about recovery and health."},
{type:"fb",s:"{1} hat an der Tür geklopft.",a:"Niemand",opts:["Niemand","Jemand","Hildi","Der Arzt"],hint:"The soup appeared with no one knocking.",sSrc:"Nobody knocked on the door."},
{type:"mc",q:"Plötzlich war mir schwindelig. Was bedeutet 'plötzlich'?",opts:["suddenly","slowly","hopefully","always"],ans:"suddenly",hint:"It describes something happening without warning."},
{type:"drag_fill",s:"Gestern war ich {1}, aber heute bin ich wieder {2}.",blanks:{"1":"krank","2":"fit"},pool:["krank","fit","schwach","wach","gefährlich"],hint:"From illness yesterday to feeling good today.",sSrc:"Yesterday I was sick, but today I am fit again."},
{type:"match",pairs:[{trg:"gesund",src:"healthy"},{trg:"schwach",src:"weak"},{trg:"gefährlich",src:"dangerous"},{trg:"furchtbar",src:"terrible"},{trg:"plötzlich",src:"suddenly"},{trg:"hoffentlich",src:"hopefully"}]},
{type:"mc",q:"Was ist eine Krankschreibung?",opts:["Ein Dokument vom Arzt für den Chef","Ein Rezept für Medizin","Eine Rechnung vom Krankenhaus","Ein Brief an die Familie"],ans:"Ein Dokument vom Arzt für den Chef",hint:"It tells your employer why you cannot come to work."}
]}
]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 8: Müllprofessor
// Story: Wrong bin, recycling lecture, Abendbrot discovery, Mia intro
// CEFR: A2.1 - Wechselpräpositionen, weil-clause, comparatives, superlatives
// ═══════════════════════════════════════════════════════════════
{n:8,lang:"de",srcLang:"en",track:"v2",title:"Müllprofessor",sub:"Recycling lecture, Abendbrot discovery, meeting Mia",icon:"♻️",level:"A2.1",color:"#7B5EE8",lessons:[
{id:"deu_r8l1",title:"Der falsche Eimer",icon:"♻️",xp:15,board:true,steps:[
{type:"intro",title:"Der falsche Eimer",desc:"Verumius steht im Hinterhof vor sechs bunten Mülltonnen. Er hat einen Joghurtbecher in der Hand. Hildi kommt um die Ecke und ihr Gesicht wird blass.",goals:["10 neue Wörter rund um Müll, Natur und Nachbarschaft","Deutsche Mülltrennung verstehen","Adjektive: sauber, schmutzig, schädlich, nützlich"]},
{type:"teach",trg:"der Müll",src:"waste, trash",note:"Uncountable noun. Used without article in general statements:\nMüll trennen = to separate waste.",example:"A: Was machst du da mit dem Joghurtbecher?\nB: Ich werfe ihn in den Müll.\nA: In welchen Müll? Das ist der falsche Eimer!\nB: Es gibt mehr als einen Eimer?",exampleSrc:"A: What are you doing with that yogurt cup?\nB: I'm throwing it in the trash.\nA: In which trash? That's the wrong bin!\nB: There's more than one bin?",funFact:"Germany recycles about 67% of its waste, making it one of the top recyclers in the world. The word Müll comes from Middle High German mul (dust, rubble)."},
{type:"teach",trg:"der Nachbar",src:"neighbor (male)",note:"Plural: die Nachbarn.\nWeak noun (n-Deklination): den Nachbarn, dem Nachbarn.",example:"A: Wer ist der Mann im dritten Stock?\nB: Das ist unser Nachbar, Herr Fischer.\nA: Er sieht streng aus.\nB: Er kontrolliert die Mülltonnen jeden Morgen.",exampleSrc:"A: Who is the man on the third floor?\nB: That's our neighbor, Herr Fischer.\nA: He looks strict.\nB: He checks the trash bins every morning.",funFact:"In Germany, neighbors often share a Hausordnung (house rules) that includes quiet hours and cleaning schedules for shared spaces."},
{type:"teach",trg:"die Nachbarin",src:"neighbor (female)",note:"Plural: die Nachbarinnen.\nFeminine form of der Nachbar. Add -in for feminine.",example:"A: Kennst du die Nachbarin im Erdgeschoss?\nB: Ja, das ist Frau Braun. Sie ist sehr nett.\nA: Sie hat mir gestern Kuchen gebracht.\nB: Sie bringt allen neuen Bewohnern Kuchen!",exampleSrc:"A: Do you know the neighbor on the ground floor?\nB: Yes, that's Frau Braun. She's very nice.\nA: She brought me cake yesterday.\nB: She brings cake to all new residents!",funFact:"The suffix -in turns masculine job titles and roles into feminine ones: der Lehrer becomes die Lehrerin, der Arzt becomes die Ärztin."},
{type:"teach",trg:"die Natur",src:"nature",note:"No plural in this meaning.\nCommon compound: der Naturschutz (nature protection).",example:"A: Warum trennst du den Müll so genau?\nB: Es ist gut für die Natur.\nA: Stimmt. Plastik im Wald ist schlimm.\nB: Genau! Die Natur braucht unsere Hilfe.",exampleSrc:"A: Why do you separate the trash so carefully?\nB: It's good for nature.\nA: True. Plastic in the forest is terrible.\nB: Exactly! Nature needs our help.",funFact:"Germany has over 100 Naturschutzgebiete (nature reserves). The Pfand system returns deposits on bottles to reduce waste in nature."},
{type:"teach",trg:"die Pflanze",src:"plant",note:"Plural: die Pflanzen.\nRelated verb: pflanzen = to plant.",example:"A: Was ist das auf deinem Balkon?\nB: Das sind meine Pflanzen. Tomaten und Kräuter.\nA: Die sehen toll aus!\nB: Danke! Pflanzen machen mich glücklich.",exampleSrc:"A: What's that on your balcony?\nB: Those are my plants. Tomatoes and herbs.\nA: They look great!\nB: Thanks! Plants make me happy.",funFact:"Germans love their Balkonpflanzen (balcony plants). The most popular is the Geranie (geranium), seen on balconies across Bavaria and beyond."},
{type:"teach",trg:"sauber",src:"clean",note:"Adjective. Opposite: schmutzig.\nDie Wohnung ist sauber = The apartment is clean.",example:"A: Ist die Küche sauber?\nB: Ja, ich habe gerade geputzt.\nA: Und der Hinterhof?\nB: Der Hinterhof ist auch sauber. Alles in Ordnung!",exampleSrc:"A: Is the kitchen clean?\nB: Yes, I just cleaned.\nA: And the courtyard?\nB: The courtyard is also clean. Everything's fine!",funFact:"Kehrwoche is a tradition in southwestern Germany where neighbors take turns cleaning shared spaces like stairwells and sidewalks on a weekly rotation."},
{type:"teach",trg:"schmutzig",src:"dirty",note:"Adjective. Opposite: sauber.\nDie Schuhe sind schmutzig = The shoes are dirty.",example:"A: Warum sind deine Hände so schmutzig?\nB: Ich habe im Garten gearbeitet.\nA: Du musst sie waschen vor dem Essen!\nB: Ja, ja, ich gehe schon ins Bad.",exampleSrc:"A: Why are your hands so dirty?\nB: I worked in the garden.\nA: You need to wash them before eating!\nB: Yeah, yeah, I'm heading to the bathroom.",funFact:"The German word Schmutzfink (literally dirty finch) is a playful insult for someone who is messy or untidy. Parents often use it with children."},
{type:"teach",trg:"schädlich",src:"harmful",note:"Adjective with umlaut from Schaden (damage).\nPlastik ist schädlich für die Umwelt.",example:"A: Ist Plastik wirklich so schlimm?\nB: Ja, Plastik ist sehr schädlich für die Natur.\nA: Was kann ich besser machen?\nB: Nimm eine Stofftasche zum Einkaufen!",exampleSrc:"A: Is plastic really that bad?\nB: Yes, plastic is very harmful to nature.\nA: What can I do better?\nB: Take a cloth bag for shopping!",funFact:"Since 2022, Germany has banned single-use plastic items like straws, plates, and cutlery. Shops charge for plastic bags to reduce schädlich waste."},
{type:"teach",trg:"nützlich",src:"useful",note:"Adjective from Nutzen (use, benefit).\nOpposite: nutzlos (useless).",example:"A: Mülltrennung ist so kompliziert!\nB: Aber es ist sehr nützlich für die Umwelt.\nA: Welche Tonne ist für Glas?\nB: Die grüne. Komm, ich zeige es dir!",exampleSrc:"A: Recycling is so complicated!\nB: But it's very useful for the environment.\nA: Which bin is for glass?\nB: The green one. Come, I'll show you!",funFact:"The word nützlich comes from the Middle High German nuz (useful). German has many adjective pairs: nützlich/nutzlos, schädlich/harmlos, sauber/schmutzig."},
{type:"teach",trg:"die Tür",src:"door",note:"Plural: die Türen.\nRelated: die Haustür (front door), die Autotür (car door).",example:"A: Wo ist die Tür zum Hinterhof?\nB: Geh durch die Küche, dann links.\nA: Die Tür klemmt ein bisschen.\nB: Ja, drück etwas fester. Sie ist alt.",exampleSrc:"A: Where is the door to the courtyard?\nB: Go through the kitchen, then left.\nA: The door is stuck a bit.\nB: Yes, push a little harder. It's old.",funFact:"In Germany, front doors often lock automatically when closed. Forgetting your keys means calling a Schlüsseldienst (locksmith), which can cost 100 euros or more at night!"},
{type:"tip",title:"Willkommen im Mülltrennung-Land!",text:"Germany takes recycling very seriously. Most buildings have color-coded bins:\n\n- Gelbe Tonne: packaging (plastic, metal, cartons)\n- Blaue Tonne: paper and cardboard\n- Braune/Grüne Tonne: organic waste (Biomüll)\n- Schwarze/Graue Tonne: non-recyclable waste (Restmüll)\n- Glascontainer: glass (sorted by color!)\n- Pfandflaschen: bottles with deposit (return to the shop)\n\nPutting waste in the wrong bin can upset your Nachbarn. Hildi is not the only one watching!",deepDive:"The Pfand (deposit) system is uniquely German. You pay 8-25 cents extra on bottles and cans, then return them to machines in supermarkets. Some people collect Pfandflaschen from public bins as income. Mülltrennung is taught in schools and taken very seriously by most Germans."},
{type:"mc",q:"Verumius steht im Hinterhof. Was hat er in der Hand?",opts:["Einen Joghurtbecher","Eine Zeitung","Ein Glas Wasser","Einen Apfel"],ans:"Einen Joghurtbecher",hint:"Denk an die Szene am Anfang der Lektion."},
{type:"mc",q:"Wie sagt man 'neighbor (female)' auf Deutsch?",opts:["die Nachbarin","der Nachbar","die Nachbarschaft","die Nachbarn"],ans:"die Nachbarin",hint:"Weibliche Formen enden oft mit einer bestimmten Silbe."},
{type:"fb",s:"Plastik ist sehr {1} für die Natur.",a:"schädlich",opts:["schädlich","nützlich","sauber","schmutzig"],hint:"Das Gegenteil von harmlos oder hilfreich.",sSrc:"Plastic is very harmful for nature."},
{type:"fb",s:"Die Küche ist {1}. Ich habe gerade geputzt.",a:"sauber",opts:["sauber","schmutzig","schädlich","nützlich"],hint:"Das Gegenteil von schmutzig beschreibt diesen Zustand.",sSrc:"The kitchen is clean. I just cleaned."},
{type:"mc",q:"Was gehört in die gelbe Tonne?",opts:["Plastik und Metall","Papier und Kartons","Glas und Flaschen","Obst und Gemüse"],ans:"Plastik und Metall",hint:"Diese Tonne ist für Material, das man im Supermarkt als Verpackung findet."},
{type:"fb",s:"Geh durch die {1} zum Hinterhof.",a:"Tür",opts:["Tür","Pflanze","Natur","Nachbarin"],hint:"Man öffnet und schließt sie, um einen Raum zu betreten.",sSrc:"Go through the door to the courtyard."},
{type:"match",pairs:[{trg:"der Müll",src:"waste/trash"},{trg:"die Pflanze",src:"plant"},{trg:"sauber",src:"clean"},{trg:"schmutzig",src:"dirty"},{trg:"nützlich",src:"useful"}]},
{type:"teach",trg:"die Mülltrennung",src:"waste separation / recycling",note:"Feminine. Compound: Müll (waste) + Trennung (separation). The cornerstone of German environmental culture.",example:"A: Was ist Mülltrennung?\nB: Man sortiert den Müll in verschiedene Tonnen.\nA: Ist das wirklich so wichtig?\nB: In Deutschland ist es Pflicht!",exampleSrc:"A: What is waste separation?\nB: You sort waste into different bins.\nA: Is that really so important?\nB: In Germany it is mandatory!",funFact:"Germany introduced the Grüner Punkt (Green Dot) system in 1991, making it one of the first countries to require manufacturers to pay for packaging recycling. Mülltrennung is taught in schools from age six."},
{type:"mc",q:"Hildi sagt: 'Mülltrennung ist sehr ... für die Umwelt.'",opts:["nützlich","schmutzig","schädlich","sauber"],ans:"nützlich",hint:"Ein positives Adjektiv, das Vorteil oder Nutzen beschreibt."},
{type:"fb",s:"Mein {1} kontrolliert die Mülltonnen jeden Morgen.",a:"Nachbar",opts:["Nachbar","Nachbarin","Natur","Müll"],hint:"Ein Mann, der im selben Gebäude wohnt wie du.",sSrc:"My neighbor checks the trash bins every morning."},
{type:"drag_fill",s:"Die {1} im Garten sind {2}, aber die Schuhe sind {3}.",blanks:{"1":"Pflanzen","2":"sauber","3":"schmutzig"},pool:["Pflanzen","sauber","schmutzig","schädlich","Müll"],hint:"Erst die grünen Dinge im Boden, dann zwei gegensätzliche Adjektive.",sSrc:"The plants in the garden are clean, but the shoes are dirty."},
{type:"mc",q:"Verumius wirft den Joghurtbecher in den falschen Eimer. Hildi wird blass. Warum?",opts:["Recycling ist hier sehr wichtig","Der Becher ist viel zu groß","Hildi mag diesen Joghurt nicht","Es gibt nur einen einzigen Eimer"],ans:"Recycling ist hier sehr wichtig",hint:"Deutsche nehmen die Mülltrennung sehr ernst."}
]},

{id:"deu_r8l2",title:"In der Küche",icon:"🍽️",xp:15,board:true,steps:[
{type:"intro",title:"In der Küche",desc:"Hildi shows you around her kitchen and apartment. Learn the words for cutlery, dishes, and parts of the home.",goals:["12 kitchen and home vocabulary words","Articles: der, die, das with every noun","Talk about rooms and objects in a German home"]},
{type:"teach",trg:"die Gabel",src:"the fork",note:"die Gabel (feminine). Plural: die Gabeln.",example:"A: Wo ist die Gabel?\nB: Die Gabel liegt neben dem Teller.\nA: Danke! Ich brauche sie für den Salat.\nB: Hier, nimm diese Gabel.",exampleSrc:"A: Where is the fork?\nB: The fork is next to the plate.\nA: Thanks! I need it for the salad.\nB: Here, take this fork.",funFact:"The word Gabel comes from Old High German 'gabala' meaning a forked stick. Forks only became common table utensils in Germany in the 17th century."},
{type:"teach",trg:"der Löffel",src:"the spoon",note:"der Löffel (masculine). Plural: die Löffel.",example:"A: Hast du einen Löffel für mich?\nB: Ja, hier ist ein Löffel.\nA: Der ist aber groß!\nB: Das ist ein Suppenlöffel.",exampleSrc:"A: Do you have a spoon for me?\nB: Yes, here is a spoon.\nA: That one is big though!\nB: That is a soup spoon.",funFact:"Germans distinguish between Teelöffel (teaspoon), Esslöffel (tablespoon), and Suppenlöffel (soup spoon). Recipes always specify which Löffel to use."},
{type:"teach",trg:"das Messer",src:"the knife",note:"das Messer (neuter). Plural: die Messer.",example:"A: Dieses Messer ist sehr scharf.\nB: Ja, pass auf! Es ist neu.\nA: Wo hast du es gekauft?\nB: Im Geschäft am Marktplatz.",exampleSrc:"A: This knife is very sharp.\nB: Yes, be careful! It is new.\nA: Where did you buy it?\nB: At the shop on the market square.",funFact:"Solingen, a city in western Germany, is called the 'City of Blades' and has been the world capital of knife and blade production since medieval times."},
{type:"teach",trg:"der Teller",src:"the plate",note:"der Teller (masculine). Plural: die Teller.",example:"A: Kannst du die Teller auf den Tisch stellen?\nB: Wie viele Teller brauchen wir?\nA: Vier Teller, bitte.\nB: Gut, ich hole sie aus dem Schrank.",exampleSrc:"A: Can you put the plates on the table?\nB: How many plates do we need?\nA: Four plates, please.\nB: Good, I will get them from the cupboard.",funFact:"In many German households, each family member has their own designated Teller, Tasse, and Glas. Using someone else's is a minor social faux pas."},
{type:"mc",q:"Was ist 'die Gabel' auf Englisch?",opts:["the fork","the spoon","the knife","the plate"],ans:"the fork",hint:"Think of the utensil with prongs"},
{type:"fb",s:"Der {1} liegt neben dem Messer.",a:"Löffel",opts:["Löffel","Gabel","Fenster","Keller"],hint:"The rounded utensil for soup.",sSrc:"The spoon is next to the knife."},
{type:"teach",trg:"der Topf",src:"the pot",note:"der Topf (masculine). Plural: die Töpfe. Note the umlaut in plural.",example:"A: Was kochst du in dem Topf?\nB: Ich mache eine Suppe.\nA: Der Topf ist sehr groß!\nB: Ja, es gibt Suppe für alle.",exampleSrc:"A: What are you cooking in the pot?\nB: I am making a soup.\nA: The pot is very big!\nB: Yes, there is soup for everyone.",funFact:"Germans often say 'Jeder Topf findet seinen Deckel' (every pot finds its lid), meaning there is a perfect match for everyone. It is the German equivalent of 'there is someone for everyone.'"},
{type:"teach",trg:"das Geschirr",src:"the dishes",note:"das Geschirr (neuter). Used as a collective noun. No common plural form.",example:"A: Wer spült heute das Geschirr?\nB: Du bist dran! Ich habe gestern gespült.\nA: Okay, aber die Spülmaschine ist voll.\nB: Dann spül bitte mit der Hand.",exampleSrc:"A: Who is washing the dishes today?\nB: It is your turn! I washed yesterday.\nA: Okay, but the dishwasher is full.\nB: Then please wash by hand.",funFact:"'Geschirr' originally meant equipment or harness (for horses). The meaning narrowed over centuries to specifically mean tableware. Horse harness is still called 'Pferdegeschirr.'"},
{type:"teach",trg:"die Lampe",src:"the lamp",note:"die Lampe (feminine). Plural: die Lampen.",example:"A: Die Lampe in der Küche ist kaputt.\nB: Schon wieder? Ich kaufe eine neue.\nA: Nimm eine LED-Lampe.\nB: Gute Idee, die sind besser für die Umwelt.",exampleSrc:"A: The lamp in the kitchen is broken.\nB: Again? I will buy a new one.\nA: Get an LED lamp.\nB: Good idea, they are better for the environment.",funFact:"Germans are serious about lighting. Many apartments come without ceiling lamps. New tenants must buy and install their own. Moving often means packing your Lampen."},
{type:"mc",q:"Hildi kocht Suppe. Was braucht sie?",opts:["einen Topf","einen Teller","eine Gabel","ein Messer"],ans:"einen Topf",hint:"Think about what you cook soup inside"},
{type:"teach",trg:"der Stuhl",src:"the chair",note:"der Stuhl (masculine). Plural: die Stühle. Note the umlaut.",example:"A: Ist dieser Stuhl frei?\nB: Ja, setz dich! Der Stuhl ist bequem.\nA: Oh ja, sehr bequem.\nB: Den habe ich vom Flohmarkt.",exampleSrc:"A: Is this chair free?\nB: Yes, sit down! The chair is comfortable.\nA: Oh yes, very comfortable.\nB: I got it from the flea market.",funFact:"Germans love their flea markets (Flohmärkte). Buying second-hand furniture, especially Stühle and Tische, is extremely common and not considered cheap but rather environmentally conscious."},
{type:"teach",trg:"das Fenster",src:"the window",note:"das Fenster (neuter). Plural: die Fenster.",example:"A: Kannst du das Fenster öffnen?\nB: Ja, es ist warm hier drin.\nA: Frische Luft tut gut.\nB: In fünf Minuten mache ich es wieder zu.",exampleSrc:"A: Can you open the window?\nB: Yes, it is warm in here.\nA: Fresh air feels good.\nB: In five minutes I will close it again.",funFact:"Germans practice 'Stoßlüften': opening windows wide for 5 to 10 minutes to exchange all the air, then closing them. Leaving windows cracked (gekippt) all day is considered wasteful and bad for heating."},
{type:"teach",trg:"der Keller",src:"the basement",note:"der Keller (masculine). Plural: die Keller.",example:"A: Wo sind die alten Bücher?\nB: Die sind im Keller.\nA: Ist der Keller groß?\nB: Ja, jeder Mieter hat seinen eigenen Keller.",exampleSrc:"A: Where are the old books?\nB: They are in the basement.\nA: Is the basement big?\nB: Yes, every tenant has their own basement.",funFact:"In German apartment buildings, each tenant typically gets their own locked Kellerabteil (basement compartment) for storage. It is included in the rent and is standard in almost all buildings."},
{type:"fb",s:"Mach bitte das {1} auf, es ist warm.",a:"Fenster",opts:["Fenster","Geschirr","Keller","Stuhl"],hint:"You open this to let fresh air in.",sSrc:"Please open the window, it is warm."},
{type:"teach",trg:"das Erdgeschoss",src:"the ground floor",note:"das Erdgeschoss (neuter). Literally: earth + floor. Abbreviated EG.",example:"A: In welchem Stockwerk wohnst du?\nB: Ich wohne im Erdgeschoss.\nA: Oh, das ist praktisch.\nB: Ja, keine Treppen!",exampleSrc:"A: On which floor do you live?\nB: I live on the ground floor.\nA: Oh, that is practical.\nB: Yes, no stairs!",funFact:"In Germany the Erdgeschoss is floor 0, not floor 1. The first floor above ground is called 'erstes Obergeschoss' (1. OG). This confuses many English speakers in elevators."},
{type:"teach",trg:"das Stockwerk",src:"the floor / story (of a building)",note:"das Stockwerk (neuter). Plural: die Stockwerke. Synonym: die Etage.",example:"A: Wie viele Stockwerke hat das Haus?\nB: Es hat vier Stockwerke.\nA: Und Hildi wohnt im dritten?\nB: Genau, im dritten Stockwerk.",exampleSrc:"A: How many floors does the building have?\nB: It has four floors.\nA: And Hildi lives on the third?\nB: Exactly, on the third floor.",funFact:"The word Stockwerk comes from 'Stock' (stick/staff). Medieval builders marked each floor level with a staff during construction. The marks became the name for the floors themselves."},
{type:"teach",trg:"die Etage",src:"the floor / story (of a building)",note:"Feminine noun. Plural: die Etagen. Borrowed from French.\nSynonym of Stockwerk but more common in everyday speech.",example:"A: Auf welcher Etage wohnst du?\nB: Auf der zweiten Etage.\nA: Gibt es einen Aufzug?\nB: Nein, leider nur Treppen.",exampleSrc:"A: On which floor do you live?\nB: On the second floor.\nA: Is there an elevator?\nB: No, unfortunately only stairs.",funFact:"Etage comes from French 'etage.' In everyday German, Etage and Stockwerk are interchangeable, but Etage sounds slightly more elegant. Department stores use Etage: 'Damenabteilung, dritte Etage.'"},
{type:"teach",trg:"der Flur",src:"the hallway / corridor",note:"Masculine noun. Plural: die Flure.\nThe space inside an apartment connecting rooms.",example:"A: Wo hängt die Jacke?\nB: Im Flur, neben der Tür.\nA: Der Flur ist aber dunkel.\nB: Ja, die Lampe ist kaputt.",exampleSrc:"A: Where is the jacket hanging?\nB: In the hallway, next to the door.\nA: The hallway is quite dark.\nB: Yes, the lamp is broken.",funFact:"In traditional German apartments, the Flur is the first room you enter. Germans always take off their shoes in the Flur. Keeping outdoor shoes on inside is a social faux pas in most German homes."},
{type:"teach",trg:"das Brett",src:"the board / plank / shelf",note:"Neuter noun. Plural: die Bretter.\nUsed in many compounds: Schneidebrett (cutting board), Schwarzes Brett (notice board).",example:"A: Wo ist das Schneidebrett?\nB: Das Brett liegt auf dem Tisch.\nA: Ah, danke. Ich schneide das Brot.\nB: Pass auf, das Brett rutscht leicht.",exampleSrc:"A: Where is the cutting board?\nB: The board is on the table.\nA: Ah, thanks. I will cut the bread.\nB: Be careful, the board slides easily.",funFact:"'Schwarzes Brett' (black board) is the German term for a notice board or bulletin board. Every university, office, and apartment building has one. 'Brettspiel' means board game."},
{type:"teach",trg:"stellen",src:"to put / to place (upright)",note:"Regular: ich stelle, du stellst. Always implies standing position.\nLegen = put down flat. Stellen = put upright.",example:"A: Wo soll ich die Teller stellen?\nB: Stell sie bitte in den Schrank.\nA: Und die Gläser?\nB: Die auch. Stell alles in den Schrank.",exampleSrc:"A: Where should I put the plates?\nB: Put them in the cupboard, please.\nA: And the glasses?\nB: Those too. Put everything in the cupboard.",funFact:"German has different verbs for putting things: stellen (put upright, like a bottle), legen (put flat, like a book), setzen (put sitting), hängen (put hanging). English just uses 'put' for all of them!"},
{type:"teach",trg:"fernsehen",src:"to watch TV",note:"Separable verb: ich sehe fern, du siehst fern.\nFrom fern (far) + sehen (to see) = 'far-seeing'.\nder Fernseher = the TV set.",example:"A: Was machst du heute Abend?\nB: Ich sehe fern. Es gibt einen guten Film.\nA: Welchen Fernseher hast du?\nB: Einen alten, aber er funktioniert gut.",exampleSrc:"A: What are you doing tonight?\nB: I am watching TV. There is a good movie on.\nA: Which TV do you have?\nB: An old one, but it works well.",funFact:"'Fernsehen' literally means 'far-seeing.' The first German TV broadcast was in 1935. Today, ARD and ZDF are public channels funded by the Rundfunkbeitrag (broadcasting fee) that every household pays: 18.36 euros per month."},
{type:"tip",title:"Abendbrot: Die deutsche Küchentradition",text:"Germans traditionally eat a cold dinner called Abendbrot (evening bread). The family gathers in the kitchen, sets out bread, cheese, cold cuts, and pickles.\n\nNo cooking needed. Everything goes on a Teller with a Messer and Gabel.\n\nThis tradition is why German kitchens often have a small Tisch with Stühle for casual family meals, separate from a formal Esszimmer (dining room).",deepDive:{title:"Why cold dinner?",text:"Abendbrot comes from times when the main hot meal was cooked at midday while the family was home. The evening meal was simple: bread with toppings.\n\nToday supermarkets sell sliced bread and deli meats specifically marketed for Abendbrot. When Germans say 'Wir essen Abendbrot', they mean this cold meal tradition.\n\nRegional variation: in southern Germany, the cold evening meal is sometimes called Brotzeit. In the north, Abendbrot is standard."}},
{type:"mc",q:"Was ist das Erdgeschoss?",opts:["The ground floor","The basement","The attic","The second floor"],ans:"The ground floor",hint:"Think about the literal meaning: Erd = earth"},
{type:"mc",q:"Hildi sagt: 'Das Geschirr ist schmutzig.' Was meint sie?",opts:["The dishes are dirty","The kitchen is dirty","The glass is broken","The spoon is missing"],ans:"The dishes are dirty",hint:"Geschirr is the collective word for plates, cups, bowls"},
{type:"fb",s:"Jeder Mieter hat seinen eigenen {1}.",a:"Keller",opts:["Keller","Stuhl","Löffel","Teller"],hint:"The storage space below the building.",sSrc:"Every tenant has their own basement."},
{type:"mc",q:"Hildis Haus hat vier Etagen. Was ist ein anderes Wort dafür?",opts:["Stockwerke","Fenster","Keller","Stühle"],ans:"Stockwerke",hint:"Each level of a building from ground to roof."},
{type:"match",pairs:[{trg:"die Gabel",src:"the fork"},{trg:"der Löffel",src:"the spoon"},{trg:"das Messer",src:"the knife"},{trg:"der Teller",src:"the plate"},{trg:"der Topf",src:"the pot"},{trg:"das Geschirr",src:"the dishes"}]},
{type:"match",pairs:[{trg:"die Lampe",src:"the lamp"},{trg:"der Stuhl",src:"the chair"},{trg:"das Fenster",src:"the window"},{trg:"der Keller",src:"the basement"},{trg:"das Erdgeschoss",src:"the ground floor"},{trg:"das Stockwerk",src:"the floor/story"}]},
{type:"mc",q:"Du brauchst etwas zum Schneiden. Was nimmst du?",opts:["das Messer","die Gabel","den Löffel","den Teller"],ans:"das Messer",hint:"The sharp tool used for cutting food"},
{type:"fb",s:"Setz dich auf den {1}, er ist sehr bequem.",a:"Stuhl",opts:["Stuhl","Teller","Topf","Keller"],hint:"The piece of furniture you sit on.",sSrc:"Sit down on the chair, it is very comfortable."},
{type:"drag_fill",s:"In der Küche stehen ein {1}, vier {2} und eine {3}.",blanks:{"1":"Topf","2":"Teller","3":"Lampe"},pool:["Topf","Teller","Lampe","Keller","Messer"],hint:"Think about what belongs in a kitchen.",sSrc:"In the kitchen there is a pot, four plates, and a lamp."},
{type:"teach",trg:"sortieren",src:"to sort",note:"Regular: ich sortiere. Müll sortieren = to sort trash.",example:"A: Wie sortiert man den Müll richtig?\nB: Plastik in den gelben Sack, Papier in die blaue Tonne.\nA: Und Glas?",exampleSrc:"A: How do you sort the trash correctly?\nB: Plastic in the yellow bag, paper in the blue bin.\nA: And glass?",funFact:"Germans sort trash into up to 6 categories. Getting it wrong can earn you a stern look from your neighbors."},
{type:"teach",trg:"niedrig",src:"low",note:"Opposite of hoch (high). Niedrige Preise = low prices.",example:"A: Ist die Miete hier niedrig?\nB: Nein, Berlin wird immer teurer.\nA: Das stimmt leider.",exampleSrc:"A: Is the rent low here?\nB: No, Berlin is getting more expensive.\nA: That is unfortunately true.",funFact:"Niedrig comes from Old German 'nidar' (down). Related to English 'nether' as in Netherlands (low lands)."}
]}
,

{id:"deu_r8l3",title:"Mülltrennung",icon:"📊",xp:15,board:true,steps:[
{type:"intro",title:"Mülltrennung",desc:"Hildi pulls out her recycling chart and gives a full lecture on household waste sorting. Mia arrives mid-lesson. Learn household chore words, and get your first formal look at Wechselpräpositionen and comparatives.",goals:["10 household vocabulary words","Wechselpräpositionen: accusative vs. dative","Comparatives with -er + als"]},
{type:"teach",trg:"der Haushalt",src:"the household",note:"der Haushalt (masculine). Plural: die Haushalte.",example:"A: Wer macht den Haushalt bei euch?\nB: Hildi und ich teilen alles.\nA: Das ist gut so.\nB: Ja, ein guter Haushalt braucht Teamarbeit.",exampleSrc:"A: Who does the housework at your place?\nB: Hildi and I share everything.\nA: That is good.\nB: Yes, a good household needs teamwork.",funFact:"Haushalt also means 'budget' in politics. The Bundeshaushalt is Germany's federal budget. Same word, very different context."},
{type:"teach",trg:"die Heizung",src:"the heating",note:"die Heizung (feminine). Plural: die Heizungen.",example:"A: Ist dir kalt? Ich mache die Heizung an.\nB: Ja bitte, es ist so kalt heute.\nA: Die Heizung braucht ein paar Minuten.\nB: Kein Problem, ich warte.",exampleSrc:"A: Are you cold? I will turn on the heating.\nB: Yes please, it is so cold today.\nA: The heating needs a few minutes.\nB: No problem, I will wait.",funFact:"German tenants must pay a yearly Heizkostenabrechnung (heating cost bill). Landlords are required by law to provide heating from October 1 to April 30."},
{type:"teach",trg:"die Reinigung",src:"the cleaning",note:"die Reinigung (feminine). Also means 'dry cleaner' (die chemische Reinigung).",example:"A: Heute ist Reinigung dran.\nB: Die ganze Wohnung?\nA: Ja, Küche und Bad zuerst.\nB: Dann fange ich mit dem Bad an.",exampleSrc:"A: Today it is time for cleaning.\nB: The whole apartment?\nA: Yes, kitchen and bathroom first.\nB: Then I will start with the bathroom.",funFact:"Many German apartment buildings have a Putzplan (cleaning schedule) in the hallway. Tenants take turns cleaning the shared staircase. Missing your turn is a serious social offense."},
{type:"teach",trg:"die Wäsche",src:"the laundry",note:"die Wäsche (feminine). No common plural. Covers both dirty and clean laundry.",example:"A: Wo ist mein blaues Hemd?\nB: Das ist noch in der Wäsche.\nA: Kannst du die Wäsche heute waschen?\nB: Ja, ich hänge sie dann auf den Balkon.",exampleSrc:"A: Where is my blue shirt?\nB: It is still in the laundry.\nA: Can you wash the laundry today?\nB: Yes, I will hang it on the balcony then.",funFact:"Most German apartments do not have dryers. Hanging laundry on a Wäscheständer (drying rack) or the balcony is standard. Some buildings ban hanging laundry on balconies facing the street."},
{type:"mc",q:"Die Wohnung ist schmutzig. Was brauchen wir?",opts:["eine Reinigung","eine Heizung","eine Wäsche","einen Haushalt"],ans:"eine Reinigung",hint:"The word for the act of making things clean"},
{type:"teach",trg:"aufräumen",src:"to tidy up",note:"aufräumen (separable). Ich räume auf. Past: aufgeräumt.",example:"A: Hildi, dein Zimmer ist so unordentlich!\nB: Ich weiß. Ich räume später auf.\nA: Das sagst du immer!\nB: Okay, okay, ich räume jetzt auf.",exampleSrc:"A: Hildi, your room is so messy!\nB: I know. I will tidy up later.\nA: You always say that!\nB: Okay, okay, I will tidy up now.",funFact:"Aufräumen is one of the first verbs German children learn. 'Aufräumen!' (Tidy up!) is a one-word command heard in every German household with kids."},
{type:"teach",trg:"putzen",src:"to clean",note:"putzen (regular). Ich putze. Past: geputzt. Stronger than aufräumen: scrubbing, not just tidying.",example:"A: Wer putzt heute das Bad?\nB: Ich putze das Bad, du putzt die Küche.\nA: Das ist fair.\nB: Hildi putzt nie. Das stört mich.",exampleSrc:"A: Who is cleaning the bathroom today?\nB: I clean the bathroom, you clean the kitchen.\nA: That is fair.\nB: Hildi never cleans. That bothers me.",funFact:"Kehrwoche (sweeping week) is a tradition in Swabia where residents must sweep the sidewalk and staircase on their assigned week. Neglecting it can lead to actual complaints from neighbors."},
{type:"teach",trg:"aufmachen",src:"to open",note:"aufmachen (separable). Ich mache auf. Past: aufgemacht. Casual synonym of öffnen.",example:"A: Mach bitte die Tür auf!\nB: Moment, ich komme.\nA: Mia steht draußen.\nB: Oh, ich mache sofort auf!",exampleSrc:"A: Please open the door!\nB: One moment, I am coming.\nA: Mia is standing outside.\nB: Oh, I will open right away!",funFact:"Aufmachen is the everyday word. Öffnen sounds more formal. A shop sign says 'Geöffnet' (open), never 'Aufgemacht.' But at home you always say 'Mach die Tür auf.'"},
{type:"teach",trg:"zumachen",src:"to close",note:"zumachen (separable). Ich mache zu. Past: zugemacht. Casual synonym of schließen.",example:"A: Mach bitte das Fenster zu.\nB: Warum? Es ist so warm.\nA: Hildi sagt, die Heizung läuft.\nB: Ach so. Ich mache es zu.",exampleSrc:"A: Please close the window.\nB: Why? It is so warm.\nA: Hildi says the heating is running.\nB: Oh I see. I will close it.",funFact:"Zumachen literally means 'to make shut.' Germans pair auf/zu for open/close in casual speech: aufmachen/zumachen, aufdrehen/zudrehen (twist open/shut for taps and bottles)."},
{type:"fb",s:"Ich {1} heute die ganze Wohnung auf.",a:"räume",opts:["räume","putze","mache","hänge"],hint:"The separable verb for tidying, minus its prefix.",sSrc:"I tidy the whole apartment up today."},
{type:"tip",title:"Wechselpräpositionen: Richtung oder Ort?",text:"Nine prepositions change case depending on meaning:\nan, auf, hinter, in, neben, über, unter, vor, zwischen\n\nAkkusativ = direction (Wohin? Where to?)\nIch stelle den Eimer IN DEN Flur. (into the hallway)\n\nDativ = location (Wo? Where?)\nDer Eimer steht IM Flur. (in the hallway)\n\nKey contractions:\nin + dem = im (location)\nin + das = ins (direction)\nan + dem = am (location)\nan + das = ans (direction)",deepDive:"Think of it this way: if something is MOVING to a new position, use accusative. If something is STAYING in one position, use dative.\n\nVerbs that signal direction (accusative): stellen, legen, hängen, setzen, stecken\nVerbs that signal location (dative): stehen, liegen, hängen, sitzen, stecken\n\nNotice hängen and stecken appear in both lists. Context determines the case:\nIch hänge das Bild an die Wand. (I hang the picture onto the wall. Direction.)\nDas Bild hängt an der Wand. (The picture hangs on the wall. Location.)"},
{type:"tip",title:"Quick Memory Aid: Wo vs Wohin",text:"Ask yourself:\nWo? = WHERE is it? Describes a STATE. Use DATIVE.\nWohin? = WHERE TO? Describes MOVEMENT. Use ACCUSATIVE.\n\nDative = sitting still.\nAccusative = on the move.",deepDive:{title:"Static vs dynamic: the universal test",text:"This test works for ALL nine Wechselpräpositionen. If nothing is changing position, use dative. If something is moving to a new position, use accusative.\n\nWo ist das Buch? Auf dem Tisch. (dative)\nWohin legst du das Buch? Auf den Tisch. (accusative)"}},
{type:"tip",title:"Dative Articles for Wo?",text:"When Wo? triggers dative:\n\nder Tisch (m) → auf DEM Tisch\ndie Wand (f) → an DER Wand\ndas Bett (n) → unter DEM Bett\ndie Bücher (pl) → zwischen DEN Büchern\n\nMasculine and neuter: dem.\nFeminine: der.\nPlural: den + noun adds -n ending.",deepDive:{title:"Why does plural add -n?",text:"In dative plural, nouns gain an -n suffix: die Bücher becomes den Büchern. This -n ending is one of the last remnants of Old High German noun declension."}},
{type:"tip",title:"Accusative Articles for Wohin?",text:"When Wohin? triggers accusative:\n\nder Tisch (m) → auf DEN Tisch\ndie Wand (f) → an DIE Wand\ndas Bett (n) → unter DAS Bett\ndie Stühle (pl) → zwischen DIE Stühle\n\nMasculine CHANGES: der → den.\nFeminine and neuter: same as nominative.\nPlural: die (same as nominative).",deepDive:{title:"Why does only masculine change in accusative?",text:"Proto-Germanic had more case distinctions that eroded over centuries. Masculine retained the den form because it was the most phonetically distinct."}},
{type:"tip",title:"The Verb Pair Logic",text:"State verbs (Wo? + dative):\nstehen = to stand (already there)\nliegen = to lie flat (already there)\nsitzen = to sit (already there)\n\nAction verbs (Wohin? + accusative):\nstellen = to place upright (movement)\nlegen = to lay flat (movement)\nsetzen / sich setzen = to seat / sit down (movement)\n\nState verb = dative. Action verb = accusative.",deepDive:{title:"How to tell them apart",text:"The action verb always has a DIRECT OBJECT being moved:\nIch stelle den Eimer in den Flur.\nThe state verb describes where something already IS:\nDer Eimer steht im Flur.\n\nIf you can ask 'what am I moving?' it is the action verb (accusative).\nIf you can ask 'where is it?' it is the state verb (dative)."}},
{type:"teach",trg:"stehen",src:"to stand (location)",pos:"verb",gender:null,note:"Irregular: ich stehe, du stehst, er steht. Past: gestanden (mit haben).\nDescribes WHERE something is standing (state, dative).",example:"A: Wo steht der Eimer?\nB: Er steht im Flur.\nA: Und die Flaschen?\nB: Die stehen neben dem Eimer.",exampleSrc:"A: Where is the bucket standing?\nB: It is standing in the hallway.\nA: And the bottles?\nB: They are standing next to the bucket.",funFact:"Stehen is one of the oldest Germanic verbs, related to English 'stand,' Latin 'stare,' and Greek 'histemi.' All share the Proto-Indo-European root *steh2."},
{type:"teach",trg:"liegen",src:"to lie / be lying flat",pos:"verb",gender:null,note:"Irregular: ich liege, du liegst, er liegt. Past: gelegen (mit haben).\nDescribes WHERE something is lying (state, dative).",example:"A: Wo liegt das Buch?\nB: Es liegt auf dem Tisch.\nA: Und die Zeitung?\nB: Die liegt unter dem Buch.",exampleSrc:"A: Where is the book lying?\nB: It is lying on the table.\nA: And the newspaper?\nB: It is lying under the book.",funFact:"Liegen and English 'lie' are cognates from Proto-Germanic *ligjan. German keeps the distinction between liegen (to be lying) and legen (to lay something down)."},
{type:"teach",trg:"legen",src:"to lay / place flat",pos:"verb",gender:null,note:"Regular: ich lege, du legst, er legt. Past: gelegt (mit haben).\nDescribes moving something to a flat position (action, accusative).",example:"A: Wohin soll ich das Buch legen?\nB: Leg es auf den Tisch.\nA: Und die Zeitung?\nB: Leg sie neben das Buch.",exampleSrc:"A: Where should I put the book?\nB: Put it on the table.\nA: And the newspaper?\nB: Put it next to the book.",funFact:"The liegen/legen pair is parallel to English lie/lay. Legen always needs a direct object. Liegen never has one."},
{type:"teach",trg:"sitzen",src:"to sit / be sitting",pos:"verb",gender:null,note:"Irregular: ich sitze, du sitzt, er sitzt. Past: gesessen (mit haben).\nDescribes WHERE someone is sitting (state, dative).",example:"A: Wo sitzt du?\nB: Ich sitze auf dem Sofa.\nA: Und Hildi?\nB: Sie sitzt am Schreibtisch.",exampleSrc:"A: Where are you sitting?\nB: I am sitting on the sofa.\nA: And Hildi?\nB: She is sitting at the desk.",funFact:"Sitzen is related to English 'sit' and Latin 'sedere.' The past participle gesessen shows the old strong verb vowel change: i to e."},
{type:"teach",trg:"sich setzen",src:"to sit down (reflexive)",pos:"verb",gender:null,note:"Regular: ich setze mich, du setzt dich, er setzt sich.\nDescribes the action of sitting down (movement, accusative).",example:"A: Bitte setzen Sie sich!\nB: Danke, ich setze mich hierhin.\nA: Möchten Sie etwas trinken?\nB: Ja, gerne.",exampleSrc:"A: Please sit down!\nB: Thank you, I will sit down here.\nA: Would you like something to drink?\nB: Yes, please.",funFact:"'Bitte setzen Sie sich!' is one of the most common polite phrases in German. You hear it at the doctor, in meetings, and at restaurants."},
{type:"tip",title:"Two hängens: One Word, Two Functions",text:"hängen (intransitive) = to be hanging (state):\nDas Bild hängt an der Wand. (dative)\n\nhängen (transitive) = to hang up (action):\nIch hänge das Bild an die Wand. (accusative)\n\nTest: if there is a direct object being moved, it is the action version.",deepDive:{title:"Strong vs weak forms of hängen",text:"The intransitive hängen is a strong verb in the past: hing, gehangen.\nThe transitive hängen is weak: hängte, gehängt.\n\nIn spoken German, many people use gehängt for both. But in writing and exams, the distinction matters."}},
{type:"tip",title:"The Core Four Contractions",text:"in + dem = im (dative, location)\nin + das = ins (accusative, direction)\nan + dem = am (dative, location)\nan + das = ans (accusative, direction)\n\nThese are NOT optional in normal speech.\nim Zimmer, ins Kino, am Bahnhof, ans Meer.",deepDive:{title:"Are there more contractions in German?",text:"Full list of common contractions: im, ins, am, ans, aufs, vors, hinters, unters, übers. For A2, master im/ins/am/ans first.\n\nNote: beim (bei + dem) and zum (zu + dem) are also mandatory contractions, but those use dative-only prepositions."}},
{type:"tip",title:"Feminine Has NO Contraction",text:"in die Küche, an die Wand, in die Schule, an die Tür.\n\nFeminine (die) has no contracted form.\nOnly masculine/neuter in dative get im/am.\nOnly neuter in accusative gets ins/ans.\n\nFeminine accusative: always 'in die', 'an die' in full.",deepDive:{title:"Why no feminine contraction?",text:"Masculine and neuter share 'dem' in the dative, which contracts easily to 'im/am'. Feminine has 'der' in the dative. 'In der' does not contract because the r sound resists blending."}},
{type:"tip",title:"The Full Positional Verb System",text:"State (Wo? + dative):\nstehen, liegen, sitzen, hängen (intransitive)\n\nAction (Wohin? + accusative):\nstellen, legen, setzen / sich setzen, hängen (transitive)\n\nMemory key: the action verb always takes a direct object.",deepDive:{title:"One more pair: stecken",text:"Stecken works like hängen: both 'to be stuck' (state) and 'to stick/put' (action).\nDer Schlüssel steckt im Schloss. (Dative.)\nIch stecke den Schlüssel ins Schloss. (Accusative.)\nUnlike hängen, stecken uses the same forms for both meanings."}},
{type:"teach",trg:"hängen",src:"to hang",note:"hängen (mixed). Direction: Ich hänge (acc). Location: Es hängt (dat). Past: gehängt (active) / gehangen (state).",example:"A: Wo soll ich die Wäsche hängen?\nB: Häng sie auf den Balkon.\nA: Die Wäsche hängt schon auf dem Balkon.\nB: Dann häng sie ins Bad.",exampleSrc:"A: Where should I hang the laundry?\nB: Hang it onto the balcony.\nA: The laundry is already hanging on the balcony.\nB: Then hang it in the bathroom.",funFact:"Hängen is the textbook example of Wechselpräpositionen. It even changes its past participle: gehängt when YOU hang something, gehangen when something just hangs there."},
{type:"teach",trg:"stören",src:"to disturb",note:"stören (regular). Ich störe. Past: gestört. 'Das stört mich' = that bothers me.",example:"A: Störe ich gerade?\nB: Nein, komm rein, Mia!\nA: Hildi gibt eine Müllvorlesung.\nB: Ha! Das stört mich nicht, ich höre gerne zu.",exampleSrc:"A: Am I disturbing right now?\nB: No, come in, Mia!\nA: Hildi is giving a trash lecture.\nB: Ha! That does not bother me, I like to listen.",funFact:"'Bitte nicht stören' (please do not disturb) appears on hotel doors across Germany. Stören is also used in electronics: Störung means interference or malfunction. 'Wir bitten um Entschuldigung für die Störung' is the classic German train delay announcement."},
{type:"mc",q:"Hildi hängt die Wäsche auf den Balkon. Warum Akkusativ?",opts:["Die Wäsche bewegt sich dorthin","Die Wäsche ist schon dort","Der Balkon ist maskulin","Hängen braucht immer Akkusativ"],ans:"Die Wäsche bewegt sich dorthin",hint:"Think about movement versus staying put"},
{type:"fb",s:"Die Wäsche hängt schon auf {1} Balkon.",a:"dem",opts:["dem","den","der","das"],hint:"Location, not direction: which case.",sSrc:"The laundry is already hanging on the balcony."},
{type:"mc",q:"Ich stelle den Eimer ... Flur. (direction)",opts:["in den","im","in der","ins"],ans:"in den",hint:"Direction needs accusative: der Flur becomes ..."},
{type:"tip",title:"Komparativ: Vergleichen mit -er + als",text:"To compare two things in German, add -er to the adjective:\nschnell (fast) becomes schneller (faster)\nklein (small) becomes kleiner (smaller)\n\nMany short adjectives add an umlaut:\ngroß becomes größer\nalt becomes älter\nkalt becomes kälter\nwarm becomes wärmer\n\nIrregular forms (memorize these):\ngut becomes besser\nviel becomes mehr\ngern becomes lieber\nhoch becomes höher\n\nUse 'als' for 'than':\nHildi ist ordentlicher als Mia.",deepDive:"The comparative form works like English '-er than' but is more consistent. Almost every German adjective uses the -er ending, whereas English switches between '-er' and 'more' depending on syllable count.\n\nComparatives can also be used as adjectives before nouns. Then they take normal adjective endings too:\nein größerer Mülleimer (a bigger trash can)\neine bessere Idee (a better idea)\n\nThe umlaut rule applies to most one-syllable adjectives with a, o, or u. But not all: toll stays toller, bunt stays bunter."},
{type:"tip",title:"als vs wie in Comparisons",text:"These two words cause the most confusion:\n\nals = than (used in COMPARATIVE: -er + als)\nwie = as (used in EQUALITY: so + adj + wie)\n\nDas Auto ist schneller ALS das Fahrrad. (faster than)\nDas Taxi ist so teuer WIE das Uber. (as expensive as)\n\nNever mix them: 'schneller wie' is a common spoken error but wrong in standard German.",deepDive:{title:"When do native speakers mix als and wie?",text:"In informal spoken German, especially in the South, you often hear 'schneller wie' instead of 'schneller als.' This is dialectal and marked wrong in exams.\n\nThe equality construction with so...wie is essential for Goethe exams:\nso gut wie (as good as)\ngenauso schnell wie (just as fast as)\nnicht so teuer wie (not as expensive as)"}},
{type:"mc",q:"Mia ist schnell. Hildi ist ... als Mia.",opts:["schneller","schnell","am schnellsten","mehr schnell"],ans:"schneller",hint:"Add the comparative ending to the adjective"},
{type:"fb",s:"Diese Wohnung ist {1} als meine alte Wohnung.",a:"größer",opts:["größer","groß","am größten","mehr groß"],hint:"The comparative of groß, with umlaut.",sSrc:"This apartment is bigger than my old apartment."},
{type:"mc",q:"Aufräumen ist gut, aber putzen ist ...",opts:["besser","guter","mehr gut","am besten"],ans:"besser",hint:"The irregular comparative of 'gut'"},
{type:"drag_fill",s:"Stell den Müll {1} die Tonne. Der Müll steht jetzt {2} der Tonne.",blanks:{"1":"in","2":"in"},pool:["in","auf","an","neben","unter"],hint:"Same preposition, but the case changes: direction first, then location.",sSrc:"Put the rubbish in the bin. The rubbish is now in the bin."},
{type:"mc",q:"Die Heizung läuft. Mach bitte das Fenster ...",opts:["zu","auf","an","ab"],ans:"zu",hint:"The opposite of aufmachen"},
{type:"match",pairs:[{trg:"der Haushalt",src:"the household"},{trg:"die Heizung",src:"the heating"},{trg:"die Reinigung",src:"the cleaning"},{trg:"die Wäsche",src:"the laundry"},{trg:"aufräumen",src:"to tidy up"},{trg:"putzen",src:"to clean"}]},
{type:"match",pairs:[{trg:"aufmachen",src:"to open"},{trg:"zumachen",src:"to close"},{trg:"hängen",src:"to hang"},{trg:"stören",src:"to disturb"},{trg:"der Haushalt",src:"the household"},{trg:"die Wäsche",src:"the laundry"}]},
{type:"drag_fill",s:"Hildi {1} die Küche, und ich {2} das Wohnzimmer {3}.",blanks:{"1":"putzt","2":"räume","3":"auf"},pool:["putzt","räume","auf","mache","zu"],hint:"Two different cleaning verbs: scrubbing vs. tidying. One is separable.",sSrc:"Hildi cleans the kitchen, and I tidy the living room up."},
{type:"fb",s:"Mia sagt: 'Störe ich?' Hildi antwortet: 'Nein, du {1} nicht.'",a:"störst",opts:["störst","störe","stört","gestört"],hint:"Second person singular present of stören.",sSrc:"Mia says: 'Am I disturbing?' Hildi answers: 'No, you are not disturbing.'"}
]}
,

// U8 L4: Besser als vorher (Grammar lesson)
// Grammar: #18 Superlative, #8 Nebensatz weil, #11 Subordinate word order
// Reinforces: #7 Wechselpräp, #17 Comparative from L3
// 8 new adjectives + 3 grammar tip cards + verb_table + 6+ combo quizzes
{id:"deu_r8l4",title:"Besser als vorher",icon:"\uD83D\uDCD0",xp:20,board:true,steps:[
{type:"intro",title:"Besser als vorher",desc:"Hildi's recycling lecture continues. Today she explains WHY things matter, compares everything to everything, and declares the best and worst habits. Time to learn superlatives, weil-clauses, and subordinate word order.",goals:["Form superlatives (am besten, der beste)","Build weil-clauses with verb-final word order","Combine comparatives and superlatives in real sentences"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-hildi-kitchen",trg:"Hildi steht in der Küche. Auf dem Tisch liegt eine Liste: 'Regeln für den Müll.' Verumius liest die erste Regel und schluckt.",src:"Hildi stands in the kitchen. On the table lies a list: 'Rules for the rubbish.' Verumius reads the first rule and gulps."},
{type:"story",speaker:"hildi",mood:"passionate",trg:"Recycling ist wichtiger als du denkst, Verumius. Und frisches Essen ist am besten, weil es weniger Verpackung hat.",src:"Recycling is more important than you think, Verumius. And fresh food is the best, because it has less packaging."},
{type:"teach",trg:"hart",src:"hard",note:"Comparative: härter. Superlative: am härtesten.",example:"A: Ist Glas hart?\nB: Ja, Glas ist härter als Plastik.",exampleSrc:"A: Is glass hard?\nB: Yes, glass is harder than plastic.",funFact:"'Hart' and English 'hard' are the same word. Both come from Proto-Germanic 'harduz.' Over 1,000 years apart and still twins."},
{type:"teach",trg:"schwierig",src:"difficult",note:"No umlaut in comparative: schwieriger, am schwierigsten.",example:"A: Ist Mülltrennung schwierig?\nB: Am Anfang ist es schwierig, aber dann wird es leichter.",exampleSrc:"A: Is waste separation difficult?\nB: At the beginning it is difficult, but then it gets easier.",funFact:"Germans rarely say 'schwer' for tasks. 'Schwierig' is for mental difficulty. 'Schwer' is for physical weight. A box is schwer. A grammar rule is schwierig."},
{type:"teach",trg:"stark",src:"strong",note:"Comparative: stärker. Superlative: am stärksten. Umlaut!",example:"A: Ist der Müllgeruch stark?\nB: Ja, heute ist er stärker als gestern.",exampleSrc:"A: Is the rubbish smell strong?\nB: Yes, today it is stronger than yesterday.",funFact:"'Stark' also means 'great/awesome' in slang. 'Das war echt stark!' = That was really awesome! Like English 'strong move.'"},
{type:"teach",trg:"weich",src:"soft",note:"Comparative: weicher. Superlative: am weichsten.",example:"A: Ist das Brot noch weich?\nB: Nein, es ist hart. Wir brauchen frisches.",exampleSrc:"A: Is the bread still soft?\nB: No, it is hard. We need fresh bread.",funFact:"'Weich' comes from the same root as English 'weak.' The original meaning was 'yielding.' Over time English shifted to 'lacking strength' while German kept 'soft to the touch.'"},
{type:"mc",q:"Hildi says the bread is not 'weich' anymore. What does she mean?",opts:["It is not soft anymore","It is not warm anymore","It is not sweet anymore","It is not fresh anymore"],ans:"It is not soft anymore",hint:"This adjective describes texture, not temperature or taste."},
{type:"teach",trg:"scharf",src:"sharp / spicy",note:"Two meanings! Comparative: schärfer. Umlaut in comparative.",example:"A: Ist die Soße scharf?\nB: Ja, sie ist schärfer als gestern.",exampleSrc:"A: Is the sauce spicy?\nB: Yes, it is spicier than yesterday.",funFact:"A knife is 'scharf' (sharp). Chili is 'scharf' (spicy). A photo is 'scharf' (in focus). And a person can be 'scharf' (attractive). One word, four jobs."},
{type:"teach",trg:"frisch",src:"fresh",note:"Comparative: frischer. Superlative: am frischesten.",example:"A: Kaufst du frisches Gemüse?\nB: Ja, frisches Gemüse ist am besten.",exampleSrc:"A: Do you buy fresh vegetables?\nB: Yes, fresh vegetables are the best.",funFact:"'Frisch' and English 'fresh' are the same word. German kept the original spelling. English added an 'e' and softened the 'sch' to 'sh.'"},
{type:"teach",trg:"süß",src:"sweet",note:"Comparative: süßer. Superlative: am süßesten.",example:"A: Ist der Kuchen süß?\nB: Ja, er ist süßer als die Schokolade!",exampleSrc:"A: Is the cake sweet?\nB: Yes, it is sweeter than the chocolate!",funFact:"Germans call cute things 'süß' too. A baby is süß. A puppy is süß. Even a good idea can be 'süß.' Exactly like English 'sweet!'"},
{type:"teach",trg:"sauer",src:"sour",note:"Comparative: saurer. Superlative: am sauersten.",example:"A: Ist die Zitrone sauer?\nB: Ja, sie ist am sauersten von allen Früchten.",exampleSrc:"A: Is the lemon sour?\nB: Yes, it is the sourest of all fruits.",funFact:"'Sauer' also means 'angry' in German. 'Er ist sauer auf mich' = He is angry at me. And 'Sauerbraten' is a famous pot roast marinated in vinegar. Sour meat!"},
{type:"mc",q:"Which word describes both a knife and a chili pepper?",opts:["hart","scharf","stark","frisch"],ans:"scharf",hint:"Think of the word that means both 'sharp' and 'spicy.'"},
{type:"tip",title:"Superlative: am ...sten",text:"To say something is THE MOST or THE BEST:\n\nam + STEM + sten\n\nschnell: am schnellsten (the fastest)\nhart: am härtesten (the hardest)\nfrisch: am frischesten (the freshest)\n\nWith articles (before a noun):\nder/die/das + STEM + ste\n\nder schnellste Zug (the fastest train)\ndie frischeste Orange (the freshest orange)\n\nIrregulars you must memorize:\ngut: am besten (the best)\nviel: am meisten (the most)\ngern: am liebsten (most gladly)",deepDive:"When the stem ends in -t, -d, -s, -ß, -z, add an extra -e- before -sten for pronunciation:\nhärt-esten, süß-esten, frisch-esten.\n\nWith articles, the adjective takes declension endings:\nder beste Müll (nom masc)\ndie beste Idee (nom fem)\ndas beste Essen (nom neut)\nden besten Kuchen (acc masc)"},
{type:"verb_table",title:"Irregular Comparatives and Superlatives",groups:[{label:"Must-know irregulars",rows:[{pronoun:"gut",form:"besser",src:"am besten"},{pronoun:"viel",form:"mehr",src:"am meisten"},{pronoun:"gern",form:"lieber",src:"am liebsten"},{pronoun:"hoch",form:"höher",src:"am höchsten"},{pronoun:"nah",form:"näher",src:"am nächsten"},{pronoun:"groß",form:"größer",src:"am größten"}]},{label:"Umlaut comparatives (a/o/u get ä/ö/ü)",rows:[{pronoun:"alt",form:"älter",src:"am ältesten"},{pronoun:"stark",form:"stärker",src:"am stärksten"},{pronoun:"hart",form:"härter",src:"am härtesten"},{pronoun:"scharf",form:"schärfer",src:"am schärfsten"},{pronoun:"kalt",form:"kälter",src:"am kältesten"},{pronoun:"warm",form:"wärmer",src:"am wärmsten"}]}],note:"Many one-syllable adjectives with a/o/u take umlaut in comparative AND superlative. The irregulars (gut/viel/gern) must simply be memorized."},
{type:"mc",q:"What is the superlative of 'gut'?",opts:["am gusten","am bessten","am besten","am gutsten"],ans:"am besten",hint:"This is completely irregular. Think of English 'good, better, best.'"},
{type:"fb",s:"Frisches Gemüse ist {1} als Dosengemüse.",a:["besser"],opts:["besser","bester","am besten","gut"],hint:"You need the comparative form here because 'als' follows.",sSrc:"Fresh vegetables are better than tinned vegetables."},
{type:"fb",s:"Die Zitrone ist {1} von allen Früchten.",a:["am sauersten"],opts:["am sauersten","saurer","sauer","am saueren"],hint:"You need the superlative form with 'am ... sten.'",sSrc:"The lemon is the sourest of all fruits."},
{type:"tip",title:"weil: Because + Verb to the End",text:"In German, 'weil' (because) sends the verb to the END of the clause.\n\nMain clause: Das Essen ist frisch.\nWith weil: ..., weil das Essen frisch ist.\n\nThe verb 'ist' jumps to the end!\n\nMore examples:\nIch trenne den Müll, weil es wichtig ist.\nHildi ist sauer, weil Verumius falsch sortiert.\nDas Brot ist hart, weil es alt ist.",deepDive:"What happens with separable verbs?\nThe prefix stays attached in weil-clauses:\n\nMain: Verumius räumt auf.\nWith weil: ..., weil Verumius aufräumt.\n\nThe separable verb reunites at the end! This is true for ALL subordinate clauses (weil, dass, wenn, ob)."},
{type:"mc",q:"'Ich kaufe frisches Brot, weil ...' Which ending is correct?",opts:["weil das alte Brot ist hart","weil das alte Brot hart ist","weil hart ist das alte Brot","weil ist das alte Brot hart"],ans:"weil das alte Brot hart ist",hint:"After 'weil,' the conjugated verb moves to the very end."},
{type:"fb",s:"Hildi ist sauer, weil Verumius den Müll falsch {1}.",a:["sortiert"],opts:["sortiert","sortieren","sortiert hat","hat sortiert"],hint:"The verb goes to the end of the weil-clause in present tense.",sSrc:"Hildi is annoyed because Verumius sorts the rubbish incorrectly."},
{type:"tip",title:"Subordinate Clause Word Order",text:"After conjunctions like weil, dass, wenn, ob:\n\nConjunction + Subject + ... + VERB (at the end)\n\nNormal: Plastik gehört nicht in den Biomüll.\nSubordinate: ..., weil Plastik nicht in den Biomüll gehört.\n\nNormal: Er räumt die Küche auf.\nSubordinate: ..., weil er die Küche aufräumt.\n\nThe verb always sits at the very end. Separable prefixes rejoin their verb.",deepDive:"When the subordinate clause comes FIRST, the main clause verb comes immediately after:\n\nWeil es regnet, bleibe ich zu Hause.\n(Because it is raining, I stay at home.)\n\nThe pattern: Subordinate clause (verb-final), VERB (main clause), rest.\nThis is called 'Verb-Zweit' (verb-second): the main verb is always in position 2."},
{type:"drag_fill",s:"Hildi sagt, dass frisches Gemüse {1} als {2} ist.",blanks:{"1":"besser","2":"Dosengemüse"},pool:["besser","Dosengemüse","ist","gut","als"],hint:"After 'dass,' build the comparison and put the verb at the end.",sSrc:"Hildi says that fresh vegetables are better than tinned vegetables."},
{type:"mc",q:"'Weil Plastik nicht in den Biomüll gehört, ...' What is happening with 'gehört' here?",opts:["It is at the start of the clause","It is in the normal second position","It is at the very end of the weil-clause","It has been removed"],ans:"It is at the very end of the weil-clause",hint:"In subordinate clauses, the verb always moves to one specific position."},
{type:"fb",s:"Das ist der {1} Müll in der ganzen Stadt.",a:["schlimmste"],opts:["schlimmste","schlimmer","am schlimmsten","schlimm"],hint:"Before a noun with 'der,' you need the superlative adjective with an -ste ending.",sSrc:"That is the worst rubbish in the whole city."},
{type:"mc",q:"Verumius asks: 'Warum trennst du den Müll?' Hildi answers: 'Weil es ...'",opts:["Weil es ist wichtig für die Natur","Weil es wichtig für die Natur ist","Weil wichtig es für die Natur ist","Weil für die Natur es wichtig ist"],ans:"Weil es wichtig für die Natur ist",hint:"After weil, subject first, then everything else, verb at the very end."},
{type:"drag_fill",s:"Mülltrennung ist am {1}, weil frische Luft am {2} ist.",blanks:{"1":"wichtigsten","2":"besten"},pool:["wichtigsten","besten","wichtiger","besser","wichtig","gut"],hint:"Waste separation is the MOST IMPORTANT. Fresh air is the BEST. Two different superlatives.",sSrc:"Waste separation is the most important, because fresh air is the best."},
{type:"mc",q:"Which sentence correctly combines a comparative with a weil-clause?",opts:["Frisches Brot ist besser, weil es weicher ist.","Frisches Brot ist besser, weil es ist weicher.","Frisches Brot besser ist, weil es weicher ist.","Frisches Brot ist besser, weil weicher es ist."],ans:"Frisches Brot ist besser, weil es weicher ist.",hint:"Main clause has normal word order. The weil-clause puts the verb at the end."},
{type:"fb",s:"Die Soße ist heute {1} als gestern.",a:["schärfer"],opts:["schärfer","scharf","am schärfsten","scharfer"],hint:"You need the comparative with umlaut because 'als' follows.",sSrc:"The sauce is spicier today than yesterday."},
{type:"mc",q:"Hildi says: 'Glas gehört in den Glascontainer, weil ...' How does this clause end?",opts:["...weil man es recyceln kann.","...weil man kann es recyceln.","...weil kann man es recyceln.","...weil es recyceln man kann."],ans:"...weil man es recyceln kann.",hint:"In the weil-clause, the modal verb goes to the very end, after the infinitive."},
{type:"match",pairs:[{trg:"am besten",src:"the best"},{trg:"am härtesten",src:"the hardest"},{trg:"am süßesten",src:"the sweetest"},{trg:"am schärfsten",src:"the sharpest/spiciest"},{trg:"am stärksten",src:"the strongest"},{trg:"am sauersten",src:"the sourest"}]},
{type:"drag_fill",s:"Verumius stellt die Flasche {1} den Glascontainer, weil Glas {2} als Plastik {3}.",blanks:{"1":"in","2":"besser","3":"ist"},pool:["in","auf","besser","gut","ist","hat"],hint:"Direction into a container (Wechselpräp with accusative), then comparative, then verb-final in the weil-clause.",sSrc:"Verumius puts the bottle in the glass container because glass is better than plastic."}
]}
,

// U8 L5: Abendbrot - Vocab + review
{id:"deu_r8l5",title:"Abendbrot",icon:"\uD83E\uDDC0",xp:15,board:true,steps:[
{type:"intro",title:"Abendbrot",desc:"Hildi invites Verumius over for Abendbrot. He expects a hot dinner. What he gets is... very German.",goals:["Learn 12 food and drink words with articles","Discover the Abendbrot tradition","Review Wechselpräpositionen, weil-clauses, and comparatives"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-hildi-kitchen",trg:"Abend bei Hildi. Verumius hat Hunger. Den ganzen Tag hat er nur einen Kaffee getrunken. Jetzt riecht es nach... nichts. Kein Braten, keine Soße. Nur ein Holzbrett auf dem Tisch.",src:"Evening at Hildi's. Verumius is hungry. All day he only had a coffee. Now it smells like... nothing. No roast, no sauce. Just a wooden board on the table."},
{type:"teach",trg:"das Abendbrot",src:"cold evening meal (lit. evening bread)",note:"Neuter. Compound: Abend (evening) + Brot (bread). The traditional German cold supper.",example:"A: Was gibt es zum Abendbrot?\nB: Brot, Käse und Wurst.",exampleSrc:"A: What's for Abendbrot?\nB: Bread, cheese, and cold cuts.",funFact:"Most cultures eat their main hot meal in the evening. Germany is the opposite: the hot meal is lunch (Mittagessen), and dinner is just bread and cold cuts. This tradition dates back to farming life, when workers needed energy at midday."},
{type:"story",speaker:"Hildi",trg:"So! Abendbrot ist fertig. Setz dich!",src:"So! Abendbrot is ready. Sit down!"},
{type:"story",speaker:"Verumius",trg:"Das ist... Brot? Und Käse? Wo ist das warme Essen?",src:"That's... bread? And cheese? Where is the hot food?"},
{type:"story",speaker:"Hildi",trg:"Warmes Essen? Zum Abendbrot? Du bist lustig, Verumius. In Deutschland essen wir abends kalt. Brot, Käse, Wurst. Fertig.",src:"Hot food? For Abendbrot? You're funny, Verumius. In Germany we eat cold in the evening. Bread, cheese, sausage. Done."},
{type:"teach",trg:"der Käse",src:"the cheese",note:"Masculine. No plural form commonly used.",example:"A: Magst du Käse?\nB: Ja, ich liebe Käse! Besonders Gouda.",exampleSrc:"A: Do you like cheese?\nB: Yes, I love cheese! Especially Gouda.",funFact:"Germany produces over 1,500 varieties of cheese. But at Abendbrot, you'll mostly see sliced Gouda, Emmentaler, and Butterkäse on the board."},
{type:"teach",trg:"die Wurst",src:"the sausage",note:"Feminine. Plural: die Würste.",example:"A: Welche Wurst möchtest du?\nB: Die Salami, bitte.",exampleSrc:"A: Which sausage would you like?\nB: The salami, please.",funFact:"Germany has over 1,500 types of Wurst. The saying 'Das ist mir Wurst' (That is sausage to me) means 'I don't care.' Sausage is so common it became a synonym for indifference."},
{type:"teach",trg:"die Bohne",src:"the bean",note:"Feminine. Plural: die Bohnen.",example:"A: Was kochst du?\nB: Ich koche eine Bohnensuppe.",exampleSrc:"A: What are you cooking?\nB: I'm cooking a bean soup.",funFact:"'Bohnenkaffee' (bean coffee) was how Germans distinguished real coffee from the grain substitutes used during wartime. If someone offers you Bohnenkaffee, it means the real stuff."},
{type:"teach",trg:"die Nudel",src:"the noodle",note:"Feminine. Plural: die Nudeln. Used for all pasta.",example:"A: Was gibt es zum Mittagessen?\nB: Nudeln mit Tomatensoße!",exampleSrc:"A: What's for lunch?\nB: Noodles with tomato sauce!",funFact:"Spätzle, Maultaschen, Schupfnudeln: southern Germany has its own noodle tradition older than Italian pasta in Germany. Schwaben (Swabians) take their Nudeln very seriously."},
{type:"teach",trg:"die Orange",src:"the orange",note:"Feminine. Plural: die Orangen. Pronounced with French stress: oh-RAHN-zhuh.",example:"A: Möchtest du eine Orange?\nB: Ja, gerne! Orangen sind gesund.",exampleSrc:"A: Would you like an orange?\nB: Yes, please! Oranges are healthy.",funFact:"In northern Germany you might hear 'Apfelsine' instead of 'Orange.' It means 'apple from China' (Apfel + Sine/China). Two words for the same fruit, split by geography."},
{type:"teach",trg:"die Pizza",src:"the pizza",note:"Feminine. Plural: die Pizzen (or Pizzas).",example:"A: Lass uns Pizza bestellen!\nB: Gute Idee! Ich nehme eine Margherita.",exampleSrc:"A: Let's order pizza!\nB: Good idea! I'll have a Margherita.",funFact:"Germany eats more frozen pizza per capita than any other European country. The brand Dr. Oetker sells over 350 million frozen pizzas per year in Germany alone."},
{type:"mc",q:"Which article goes with 'Käse'?",opts:["der","die","das","ein"],ans:"der",hint:"This dairy product is masculine in German."},
{type:"fb",s:"Ich esse {1} Wurst zum Abendbrot.",a:["die"],opts:["die","der","das","den"],hint:"Wurst is feminine. What is the feminine accusative article.",sSrc:"I eat the sausage for Abendbrot."},
{type:"teach",trg:"das Mineralwasser",src:"the mineral water",note:"Neuter. Compound: Mineral + Wasser.",example:"A: Was trinkst du?\nB: Ein Mineralwasser, bitte.",exampleSrc:"A: What are you drinking?\nB: A mineral water, please.",funFact:"Germans drink more sparkling water than almost anyone. If you order 'Wasser' in a restaurant, you'll get sparkling (mit Kohlensäure). Want still? Say 'stilles Wasser.'"},
{type:"teach",trg:"das Mittagessen",src:"the lunch",note:"Neuter. Compound: Mittag (midday) + Essen (food).",example:"A: Was hast du zum Mittagessen gegessen?\nB: Ich hatte Nudeln mit Gemüse.",exampleSrc:"A: What did you eat for lunch?\nB: I had noodles with vegetables.",funFact:"Mittagessen is the main hot meal in Germany, traditionally eaten between 12:00 and 13:00. That is why Abendbrot (evening bread) is cold. The hot meal already happened at midday."},
{type:"teach",trg:"die Portion",src:"the portion",note:"Feminine. Plural: die Portionen.",example:"A: Die Portionen hier sind riesig!\nB: Ja, das ist typisch deutsch.",exampleSrc:"A: The portions here are huge!\nB: Yes, that's typically German.",funFact:"German restaurant portions tend to be generous. Asking for a 'kleine Portion' (small portion) is perfectly acceptable and common, especially for Kinder (children)."},
{type:"teach",trg:"der Zucker",src:"the sugar",note:"Masculine. No common plural.",example:"A: Nimmst du Zucker in den Kaffee?\nB: Nein, ohne Zucker bitte.",exampleSrc:"A: Do you take sugar in your coffee?\nB: No, without sugar please.",funFact:"The word 'Zucker' traveled from Sanskrit (sharkara) through Arabic (sukkar) to German. The same root gave English 'sugar', French 'sucre', and Spanish 'azucar.'"},
{type:"teach",trg:"die Suppe",src:"the soup",note:"Feminine. Plural: die Suppen.",example:"A: Im Winter esse ich gern Suppe.\nB: Ich auch! Kartoffelsuppe ist mein Favorit.",exampleSrc:"A: In winter I like eating soup.\nB: Me too! Potato soup is my favorite.",funFact:"Eintopf (one-pot) is Germany's comfort soup: a thick stew of meat, potatoes, and vegetables. During both World Wars, the government promoted 'Eintopfsonntag' (one-pot Sunday) to save resources."},
{type:"teach",trg:"das Eis",src:"the ice cream",note:"Neuter. Also means 'ice.' Context tells you which.",example:"A: Möchtest du ein Eis?\nB: Ja, Schokolade bitte!",exampleSrc:"A: Would you like an ice cream?\nB: Yes, chocolate please!",funFact:"German Eisdielen (ice cream parlors) are often run by Italian families who came to Germany in the 1920s. The tradition is so strong that 'Italian ice cream' is considered a German cultural staple."},
{type:"tip",title:"Abendbrot: The Cold Supper",text:"Germans traditionally eat their warm meal at midday (Mittagessen).\n\nAbendbrot (evening bread) is a cold meal:\n\n\u2022 Bread (often dark rye or sourdough)\n\u2022 Sliced cheese and cold cuts\n\u2022 Maybe pickles, tomatoes, or radishes\n\u2022 Butter and mustard\n\nIt is simple, practical, and very German.\nVisitors expecting a hot dinner are often surprised."},
{type:"mc",q:"Hildi sagt: 'In Deutschland essen wir abends kalt.' Was bedeutet das?",opts:["Germans eat cold food in the evening","Germans eat outside in the evening","Germans skip dinner","Germans eat early in the morning"],ans:"Germans eat cold food in the evening",hint:"Translate the two key words: 'kalt' and 'abends' to understand the custom."},
{type:"fb",s:"Nimmst du {1} in den Kaffee?",a:["Zucker"],opts:["Zucker","Käse","Wurst","Nudel"],hint:"Which of these is a sweet white powder.",sSrc:"Do you take sugar in your coffee?"},
{type:"mc",q:"Verumius legt die Wurst auf das Brett. What does 'auf das Brett' tell us?",opts:["The sausage is already on the board","The sausage is moving onto the board","The sausage is under the board","The sausage is next to the board"],ans:"The sausage is moving onto the board",hint:"'Auf das' (accusative) signals movement to a new position."},
{type:"fb",s:"Der Käse liegt {1} dem Tisch.",a:["auf"],opts:["auf","in","über","unter"],hint:"The cheese is resting on a flat surface. Which Wechselpräposition.",sSrc:"The cheese is lying on the table."},
{type:"mc",q:"Verumius sagt: 'Ich esse Suppe, weil ich Hunger habe.' Where is the verb in the weil-clause?",opts:["Second position","Right after weil","At the very end","Before the subject"],ans:"At the very end",hint:"Weil is a subordinating conjunction. It sends the verb somewhere special."},
{type:"drag_fill",s:"Ich trinke Mineralwasser, {1} es {2} als Cola {3}.",blanks:{"1":"weil","2":"gesünder","3":"ist"},pool:["weil","gesünder","ist","denn","gut","hat"],hint:"A weil-clause needs verb-final. The comparative of 'gesund' is irregular.",sSrc:"I drink mineral water because it is healthier than cola."},
{type:"mc",q:"'Die Pizza ist größer als die Portion Nudeln.' What does 'größer als' express?",opts:["The pizza is the same size","The pizza is smaller","The pizza is larger","The pizza is cheaper"],ans:"The pizza is larger",hint:"'Größer' is the comparative form of 'groß' (big)."},
{type:"fb",s:"Abendbrot ist {1} als Mittagessen.",a:["einfacher"],opts:["einfacher","einfach","am einfachsten","einfache"],hint:"You need the comparative form to compare two meals.",sSrc:"Abendbrot is simpler than lunch."},
{type:"teach",trg:"backen",src:"to bake",note:"Irregular: ich backe, du bäckst/backst, er bäckt/backt. Past: gebacken.",example:"A: Was bäckst du da?\nB: Einen Apfelkuchen für die Nachbarn.\nA: Das riecht wunderbar!\nB: Danke, das Rezept ist von meiner Oma.",exampleSrc:"A: What are you baking?\nB: An apple cake for the neighbors.\nA: That smells wonderful!\nB: Thanks, the recipe is from my grandma.",funFact:"German Brotkultur (bread culture) is UNESCO-listed. Over 3,200 registered bread varieties. Every village has a Bäckerei (bakery). Backen is one of the first verbs German children learn."},
{type:"teach",trg:"braten",src:"to fry / to roast",note:"Irregular: ich brate, du brätst, er brät. Past: gebraten.",example:"A: Wie bereitest du das Schnitzel zu?\nB: Ich brate es in der Pfanne.\nA: Mit viel Butter?\nB: Natürlich! So macht man es in Deutschland.",exampleSrc:"A: How do you prepare the schnitzel?\nB: I fry it in the pan.\nA: With lots of butter?\nB: Of course! That is how you do it in Germany.",funFact:"A Braten (roast) is the centerpiece of a German Sunday dinner. Schweinebraten, Rinderbraten, and Gänsebraten are classics."},
{type:"teach",trg:"schneiden",src:"to cut",note:"Irregular: ich schneide, du schneidest. Past: geschnitten. Strong verb!",example:"A: Kannst du das Brot schneiden?\nB: Ja, wo ist das Messer?\nA: In der Schublade links.\nB: Danke. Wie dick soll ich schneiden?",exampleSrc:"A: Can you cut the bread?\nB: Yes, where is the knife?\nA: In the left drawer.\nB: Thanks. How thick should I cut?",funFact:"Der Schneider means tailor (one who cuts fabric). Many German family names come from trades: Schneider, Bäcker, Fischer."},
{type:"match",pairs:[{trg:"der Käse",src:"the cheese"},{trg:"die Wurst",src:"the sausage"},{trg:"die Bohne",src:"the bean"},{trg:"die Nudel",src:"the noodle"},{trg:"das Mineralwasser",src:"the mineral water"},{trg:"das Eis",src:"the ice cream"},{trg:"die Suppe",src:"the soup"},{trg:"der Zucker",src:"the sugar"}]},
{type:"mc",q:"Verumius stellt das Mineralwasser neben den Käse. Why is it 'neben den Käse' and not 'neben dem Käse'?",opts:["Because Käse is masculine","Because the water is already there","Because it describes movement to a new spot","Because neben always takes accusative"],ans:"Because it describes movement to a new spot",hint:"Wechselpräpositionen use accusative for direction and dative for location."},
{type:"fb",s:"Die Suppe steht {1} dem Herd.",a:["auf"],opts:["auf","in","an","neben"],hint:"The soup is sitting on a flat cooking surface.",sSrc:"The soup is standing on the stove."}
]}
,

// U8 L6: Kommst du mit? (Story climax, Mia introduction in stairwell)
{id:"deu_r8l6",title:"Kommst du mit?",icon:"\uD83C\uDFC3\u200D\u2640\uFE0F",xp:20,board:true,steps:[
{type:"intro",title:"Kommst du mit?",desc:"In the stairwell, Verumius meets Mia for the first time. She is athletic, direct, and already uses du. Will he survive her invitation?",goals:["Learn vocabulary for food, home, and daily life","Review Wechselpräpositionen, weil, comparatives, and superlatives","Combine multiple grammar constructs in one sentence"]},
{type:"story",speaker:"narrator",mood:"neutral",art:"de-altbau-stairwell",trg:"Im Treppenhaus. Verumius kommt von Hildis Wohnung. Er ist noch satt vom Abendbrot. Die Haustür unten geht auf. Schnelle Schritte auf der Treppe. Eine junge Frau mit Lauftasche und Pferdeschwanz steht plötzlich vor ihm.",src:"In the stairwell. Verumius is coming from Hildi's apartment. He is still full from dinner. The front door opens below. Quick steps on the stairs. A young woman with a running bag and ponytail suddenly stands in front of him."},
{type:"story",speaker:"Mia",trg:"Hey! Du bist der Neue, oder? Ich bin Mia. Lukas hat mir von dir erzählt. Ich wohne im dritten Stock.",src:"Hey! You're the new guy, right? I'm Mia. Lukas told me about you. I live on the third floor."},
{type:"story",speaker:"Verumius",trg:"Oh, hallo! Ich bin Verumius. Freut mich. Lukas hat auch von dir erzählt.",src:"Oh, hello! I'm Verumius. Nice to meet you. Lukas also told me about you."},
{type:"story",speaker:"Mia",trg:"Hör mal. Ich organisiere einen Lauftreff im Park. Jeden Samstag um acht. Kommst du mit?",src:"Listen. I organize a running group in the park. Every Saturday at eight. Are you coming?"},
{type:"teach",trg:"der Hamburger",src:"the hamburger",note:"Masculine noun. Plural: die Hamburger. The same word in German!",example:"A: Ich hätte gern einen Hamburger, bitte.\nB: Mit Käse oder ohne?",exampleSrc:"A: I'd like a hamburger, please.\nB: With cheese or without?",funFact:"Germans call it 'der Hamburger' because it comes from Hamburg, where the original Frikadelle (meat patty) was invented. Hamburger in Hamburg actually refers to a person FROM Hamburg."},
{type:"teach",trg:"die Süßigkeit",src:"the sweet / candy",note:"Feminine noun. Plural: die Süßigkeiten. From 'süß' (sweet) + '-igkeit' (noun suffix).",example:"A: Willst du eine Süßigkeit?\nB: Nein danke, ich esse keine Süßigkeiten mehr.",exampleSrc:"A: Do you want a sweet?\nB: No thanks, I don't eat sweets anymore.",funFact:"The suffix '-igkeit' turns adjectives into nouns: süß becomes Süßigkeit, schwierig becomes Schwierigkeit. German word building at its finest."},
{type:"teach",trg:"das Handtuch",src:"the towel",note:"Neuter noun. Plural: die Handtücher. Compound: Hand (hand) + Tuch (cloth).",example:"A: Wo hängt das Handtuch?\nB: Das Handtuch hängt an der Tür.",exampleSrc:"A: Where is the towel hanging?\nB: The towel is hanging on the door.",funFact:"Hand + Tuch = hand cloth. Germans also have Badetuch (bath towel), Geschirrtuch (dish towel), and Staubtuch (dust cloth). Always a Tuch for the job!"},
{type:"teach",trg:"die Seife",src:"the soap",note:"Feminine noun. Plural: die Seifen.",example:"A: Hast du Seife im Badezimmer?\nB: Ja, die Seife liegt neben dem Waschbecken.",exampleSrc:"A: Do you have soap in the bathroom?\nB: Yes, the soap is next to the sink.",funFact:"The word 'Seife' comes from the same ancient root as English 'soap.' Germanic tribes taught the Romans about soap. Pliny the Elder wrote about it!"},
{type:"teach",trg:"streiten",src:"to argue / to quarrel",note:"Irregular: ich streite, du streitest, er streitet. Past: gestritten.",example:"A: Warum streiten die Nachbarn?\nB: Weil der Müll im Treppenhaus steht.",exampleSrc:"A: Why are the neighbors arguing?\nB: Because the trash is in the stairwell.",funFact:"'Sich streiten' (reflexive) means to argue with each other. 'Darüber lässt sich streiten' is a common idiom meaning 'that is debatable.'"},
{type:"teach",trg:"renovieren",src:"to renovate",note:"Regular: ich renoviere, du renovierst. Past: renoviert (no ge- prefix, because of the -ieren ending).",example:"A: Was macht der Nachbar im Erdgeschoss?\nB: Er renoviert seine Wohnung.",exampleSrc:"A: What is the neighbor doing on the ground floor?\nB: He is renovating his apartment.",funFact:"Verbs ending in '-ieren' (renovieren, telefonieren, organisieren) never get the 'ge-' prefix in past tense. 'Renoviert,' not 'gerenoviert.' These are all borrowed from French or Latin."},
{type:"teach",trg:"einziehen",src:"to move in",note:"Separable verb: ich ziehe ein, du ziehst ein. Past: eingezogen (sein).",example:"A: Wann bist du eingezogen?\nB: Ich bin letzte Woche eingezogen.",exampleSrc:"A: When did you move in?\nB: I moved in last week.",funFact:"Ein + ziehen = to pull in. Ausziehen = to move out (to pull out). Also: ausziehen = to undress. Context matters. 'Ich ziehe aus' at a party means something very different than at a Wohnungsbesichtigung."},
{type:"mc",q:"Mia sagt: 'Ich lege das Handtuch auf den Stuhl.' Where is the towel going?",opts:["onto the chair","under the chair","behind the chair","next to the chair"],ans:"onto the chair",hint:"'Auf den Stuhl' uses accusative, showing direction of movement."},
{type:"fb",s:"Die Seife liegt neben {1} Waschbecken.",a:["dem"],opts:["dem","den","das","der"],hint:"Location (no movement) after 'neben' requires dative. Waschbecken is neuter.",sSrc:"The soap is lying next to the sink."},
{type:"mc",q:"Die Nachbarn sind laut und böse. Was machen sie?",opts:["streiten","stören","streichen","stellen"],ans:"streiten",hint:"When two people disagree loudly and with anger."},
{type:"fb",s:"Er hat seine Wohnung {1}.",a:["renoviert"],opts:["renoviert","gerenoviert","renovieren","renovierte"],hint:"Verbs ending in -ieren form past tense without ge-. Think of the rule.",sSrc:"He renovated his apartment."},
{type:"drag_fill",s:"Mia legt die Lauftasche {1} den Boden und hängt das Handtuch {2} die Tür.",blanks:{"1":"auf","2":"an"},pool:["auf","an","in","unter","neben","vor"],hint:"Both show direction (accusative). The bag goes onto the floor, the towel goes onto the door.",sSrc:"Mia puts the running bag on the floor and hangs the towel on the door."},
{type:"mc",q:"'Ich bin letzte Woche eingezogen.' Why does this use 'bin' instead of 'habe'?",opts:["Movement verb, so uses sein","It is a reflexive verb here","The subject ich requires sein","Past time phrases force sein"],ans:"Movement verb, so uses sein",hint:"Moving in is a change of location. Think about which helper verb location-change verbs need."},
{type:"fb",s:"Süßigkeiten sind süßer {1} Obst.",a:["als"],opts:["als","wie","von","mit"],hint:"Which word means 'than' when comparing two things in German.",sSrc:"Sweets are sweeter than fruit."},
{type:"drag_fill",s:"Das Handtuch hängt {1} der Tür, weil Mia es {2} die Tür gehängt hat.",blanks:{"1":"an","2":"an"},pool:["an","auf","in","an","unter","neben"],hint:"First blank: location (dative, it is hanging THERE). Second blank: direction (accusative, she PUT it there). Same preposition, different case!",sSrc:"The towel is hanging on the door because Mia hung it on the door."},
{type:"mc",q:"Verumius findet Hildis Abendbrot besser als Pizza, weil es frischer ist. Which two grammar patterns are combined here?",opts:["Comparative + weil-clause","Superlative + dass-clause","Comparative + wenn-clause","Superlative + weil-clause"],ans:"Comparative + weil-clause",hint:"'Besser als' compares two things. 'Weil' explains the reason with verb at the end."},
{type:"fb",s:"Mia ist die {1} Läuferin im Lauftreff.",a:["schnellste"],opts:["schnellste","schneller","schnellere","am schnellsten"],hint:"After a definite article (die), superlatives use the '-ste' ending, not 'am ...sten.'",sSrc:"Mia is the fastest runner in the running group."},
{type:"drag_fill",s:"Mia stellt die Schuhe {1} die Tür, weil es {2} der Wohnung sauberer ist {3} im Treppenhaus.",blanks:{"1":"vor","2":"in","3":"als"},pool:["vor","in","als","an","auf","wie"],hint:"Shoes go in front of the door (direction). Cleaner inside (location) the apartment than in the stairwell (comparison).",sSrc:"Mia puts the shoes in front of the door because it is cleaner in the apartment than in the stairwell."},
{type:"mc",q:"'Im dritten Stock wohnt die netteste Nachbarin.' What grammar is used here?",opts:["Superlative with adjective ending","Comparative with als","Wechselpräposition with dative","Subordinate clause with weil"],ans:"Superlative with adjective ending",hint:"'Die netteste' shows the highest degree of 'nett' with a grammatical suffix after the article."},
{type:"fb",s:"Verumius zieht {1} die Wohnung im zweiten Stock ein.",a:["in"],opts:["in","an","auf","vor"],hint:"Which Wechselpräposition means 'into' when moving into a place.",sSrc:"Verumius moves into the apartment on the second floor."},
{type:"drag_fill",s:"Mia sagt, dass der Lauftreff {1} wichtigsten Termin der Woche ist, weil Laufen {2} als Fernsehen ist.",blanks:{"1":"am","2":"besser"},pool:["am","besser","als","der","im","gut"],hint:"First blank: superlative form uses 'am ...sten.' Second blank: an irregular form meaning 'more good' for the comparison.",sSrc:"Mia says that the running group is the most important appointment of the week because running is better than watching TV."},
{type:"mc",q:"'Weil Mia jeden Samstag im Park läuft, ist sie stärker als Verumius.' Why is 'läuft' at the end of the weil-clause?",opts:["In weil-clauses, the verb moves to the final position","Läuft is always last in German","Mia is the subject so the verb follows","Im Park requires the verb at the end"],ans:"In weil-clauses, the verb moves to the final position",hint:"Remember the subordinate clause word order rule from earlier this unit."},
{type:"match",pairs:[{trg:"der Hamburger",src:"the hamburger"},{trg:"die Süßigkeit",src:"the sweet/candy"},{trg:"das Handtuch",src:"the towel"},{trg:"die Seife",src:"the soap"},{trg:"streiten",src:"to argue"},{trg:"renovieren",src:"to renovate"},{trg:"einziehen",src:"to move in"}]}
]}
,

{id:"deu_r8l7",title:"Müllprüfung",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Müllprüfung",desc:"Alles aus Unit 8 auf dem Prüfstand. Keine neuen Wörter, nur dein Wissen.",goals:["Wechselpräpositionen anwenden","weil-Sätze bilden","Komparativ und Superlativ verwenden","Wortschatz aus L1-L6 beherrschen"]},
{type:"mc",q:"Ich stelle den Topf ___ den Herd.",opts:["auf","im","am","ans"],ans:"auf",hint:"Wohin? Akkusativ mit Richtung nach oben."},
{type:"fb",s:"Die Gabel liegt {1} dem Teller.",a:"auf",opts:["auf","in","an","unter"],hint:"The fork is resting on top of something. Which two-way preposition describes this position.",sSrc:"The fork is lying on the plate."},
{type:"mc",q:"Welches Wort bedeutet das Gegenteil von 'sauber'?",opts:["schmutzig","schädlich","scharf","schwierig"],ans:"schmutzig",hint:"Denk an dreckige Kleidung nach der Gartenarbeit."},
{type:"fb",s:"Er hängt das Handtuch {1} die Tür.",a:"an",opts:["an","auf","in","neben"],hint:"Wohin? Akkusativ, das Handtuch kommt zur Tür.",sSrc:"He hangs the towel on the door."},
{type:"mc",q:"Warum putzt Hildi die Küche? Weil die Küche ___ ist.",opts:["schmutzig","sauber","frisch","nützlich"],ans:"schmutzig",hint:"Putzen macht man, wenn etwas nicht sauber ist."},
{type:"drag_fill",s:"Ich räume auf, weil der {1} so {2} ist.",blanks:{1:"Keller",2:"schmutzig"},pool:["Keller","schmutzig","Stockwerk","sauber","frisch"],hint:"weil schickt das Verb ans Ende. Was ist unten und dreckig.",sSrc:"I tidy up because the basement is so dirty."},
{type:"mc",q:"Pizza ist ___ als Suppe. (lecker)",opts:["leckerer","am leckersten","lecker","das leckerste"],ans:"leckerer",hint:"Vergleich mit 'als' braucht die Komparativform."},
{type:"fb",s:"Das Messer ist {1} als die Gabel. (scharf)",a:"schärfer",opts:["schärfer","am schärfsten","scharf","scharfer"],hint:"Komparativ von scharf: Umlaut nicht vergessen.",sSrc:"The knife is sharper than the fork."},
{type:"match",pairs:[{trg:"die Bohne",src:"bean"},{trg:"der Zucker",src:"sugar"},{trg:"die Wurst",src:"sausage"},{trg:"das Eis",src:"ice cream"},{trg:"die Nudel",src:"noodle"}]},
{type:"mc",q:"Welches Essen ist am süßesten?",opts:["Eis","Käse","Wurst","Suppe"],ans:"Eis",hint:"Superlativ: welches ist wirklich am süßesten?"},
{type:"drag_fill",s:"Sie stellt die {1} in den {2}, weil sie {3} kochen will.",blanks:{1:"Nudeln",2:"Topf",3:"Mittagessen"},pool:["Nudeln","Topf","Mittagessen","Teller","Gabel","Suppe"],hint:"Pasta (plural) goes into a round cooking vessel. The midday meal needs preparing.",sSrc:"She puts the noodles in the pot because she wants to cook lunch."},
{type:"fb",s:"Das Erdgeschoss ist {1} als das dritte Stockwerk. (niedrig)",a:"niedriger",opts:["niedriger","am niedrigsten","niedrig","niedrigere"],hint:"Komparativ: Erdgeschoss liegt tiefer als Stockwerk 3.",sSrc:"The ground floor is lower than the third story."},
{type:"mc",q:"Er macht das Fenster zu, weil es draußen kalt ___.",opts:["ist","sein","hat","wird"],ans:"ist",hint:"weil-Satz: das konjugierte Verb steht ganz am Ende."},
{type:"drag_fill",s:"Die {1} ist nützlich, weil sie die {2} sauber {3}.",blanks:{1:"Seife",2:"Hände",3:"macht"},pool:["Seife","Hände","macht","Lampe","Wäsche","stört"],hint:"Was reinigt? Nebensatzstellung: Verb am Ende.",sSrc:"The soap is useful because it makes the hands clean."},
{type:"mc",q:"Mineralwasser ist ___ als Orangensaft. (gesund)",opts:["gesünder","am gesündesten","gesund","gesunder"],ans:"gesünder",hint:"Vergleich mit 'als': Komparativform mit Umlaut."},
{type:"fb",s:"Die Nachbarin legt die Seife {1} das Waschbecken.",a:"neben",opts:["neben","zwischen","\u00fcber","hinter"],hint:"Wohin? Die Seife kommt zur Seite des Waschbeckens, Akkusativ.",sSrc:"The neighbor puts the soap next to the sink."},
{type:"match",pairs:[{trg:"aufräumen",src:"to tidy up"},{trg:"putzen",src:"to clean"},{trg:"aufmachen",src:"to open"},{trg:"zumachen",src:"to close"},{trg:"stören",src:"to disturb"}]},
{type:"mc",q:"Welcher Satz hat die richtige Wortstellung?",opts:["Ich putze, weil die Küche schmutzig ist.","Ich putze, weil die Küche ist schmutzig.","Ich putze, weil ist die Küche schmutzig.","Ich putze, weil schmutzig die Küche ist."],ans:"Ich putze, weil die Küche schmutzig ist.",hint:"Nach weil geht das konjugierte Verb ans Satzende."},
{type:"drag_fill",s:"Der {1} streitet mit der {2}, weil die Musik zu {3} ist.",blanks:{1:"Nachbar",2:"Nachbarin",3:"laut"},pool:["Nachbar","Nachbarin","laut","leise","Pflanze","Lampe"],hint:"Wer streitet mit wem? Warum? Nebensatz: Verb am Ende.",sSrc:"The neighbor argues with the female neighbor because the music is too loud."},
{type:"fb",s:"Die Reinigung ist am {1}. (schwierig)",a:"schwierigsten",opts:["schwierigsten","schwieriger","schwierig","schwierigste"],hint:"Superlativ mit 'am': am ...sten.",sSrc:"Cleaning is the most difficult."},
{type:"mc",q:"Er stellt die Lampe ___ den Stuhl.",opts:["neben","im","am","beim"],ans:"neben",hint:"Wohin? Akkusativ: die Lampe bewegt sich zum Stuhl."},
{type:"drag_fill",s:"Die {1} im Keller ist {2} als die im {3}.",blanks:{1:"Heizung",2:"stärker",3:"Erdgeschoss"},pool:["Heizung","stärker","Erdgeschoss","Wäsche","schwieriger","Stockwerk"],hint:"Was heizt? Komparativ von stark. Welches Geschoss.",sSrc:"The heating in the basement is stronger than the one on the ground floor."},
{type:"mc",q:"Ich renoviere die Wohnung, weil wir bald ___.",opts:["einziehen","einziehe","ziehen ein","ein ziehen"],ans:"einziehen",hint:"Nach weil bleibt das trennbare Verb zusammen am Ende."},
{type:"match",pairs:[{trg:"schädlich",src:"harmful"},{trg:"nützlich",src:"useful"},{trg:"frisch",src:"fresh"},{trg:"sauer",src:"sour"},{trg:"weich",src:"soft"}]},
{type:"drag_fill",s:"Eine {1} Portion Käse ist {2} als eine große Portion {3}.",blanks:{1:"kleine",2:"gesünder",3:"Süßigkeit"},pool:["kleine","gesünder","Süßigkeit","große","schärfer","Hamburger"],hint:"Komparativ: gesund mit Umlaut. Was ist ungesund und süß.",sSrc:"A small portion of cheese is healthier than a large portion of sweets."}
]}
,

// U8 L8: Neue Nachbarn - Story resolution + remaining vocab
{id:"deu_r8l8",title:"Neue Nachbarn",icon:"\uD83C\uDFE0",xp:15,board:true,steps:[
{type:"intro",title:"Neue Nachbarn",desc:"Verumius finally knows his neighbors, can separate trash like a pro, and Hildi is impressed. Time to settle into the building and learn the last words you need for daily life in Germany.",goals:["Learn vocabulary for places, devices, and animals","Use spatial adverbs: drinnen, nebenan, rein, raus","Master useful expressions: auf jeden Fall, daf\u00fcr, dagegen"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-building-courtyard",trg:"Freitagabend. Verumius steht im Hof und liest die Recycling-Regeln auf seinem Zettel. Hildi kommt mit einer Tasse Kaffee vorbei.",src:"Friday evening. Verumius stands in the courtyard and reads the recycling rules on his sheet. Hildi comes by with a cup of coffee."},
{type:"story",speaker:"hildi",trg:"Na, Verumius? Du sortierst jetzt besser als die meisten Deutschen! Ich bin stolz auf dich. Mia hat \u00fcbrigens gefragt, ob du zum Lauftreff kommst.",src:"Well, Verumius? You sort better than most Germans now! I am proud of you. Mia asked, by the way, whether you are coming to the running club."},
{type:"story",speaker:"verumius",trg:"Auf jeden Fall! Ich kenne jetzt die Nachbarn, die M\u00fclltonne und den Supermarkt. Ich glaube, ich wohne gern hier.",src:"Absolutely! I now know the neighbors, the trash bins, and the supermarket. I think I like living here."},
{type:"teach",trg:"die Vermieterin",src:"the landlady",note:"Feminine. Der Vermieter = landlord. From 'vermieten' (to rent out).",example:"A: Wer ist deine Vermieterin?\nB: Frau Klein. Sie wohnt nebenan.",exampleSrc:"A: Who is your landlady?\nB: Mrs. Klein. She lives next door.",funFact:"German landlords have a reputation for strict house rules. The 'Hausordnung' (house rules) can regulate quiet hours, stairwell cleaning schedules, and even how you hang laundry."},
{type:"teach",trg:"das Wohnzimmer",src:"the living room",note:"Neuter. Compound: Wohn (living) + Zimmer (room).",example:"A: Wo ist der Fernseher?\nB: Im Wohnzimmer, neben dem Sofa.",exampleSrc:"A: Where is the TV?\nB: In the living room, next to the sofa.",funFact:"German has a room for everything: Wohnzimmer (living), Schlafzimmer (sleeping), Esszimmer (eating), Arbeitszimmer (working), Badezimmer (bathing). The system is beautifully logical."},
{type:"teach",trg:"die Garage",src:"the garage",note:"Feminine. Borrowed from French. Plural: die Garagen.",example:"A: Wo ist dein Auto?\nB: In der Garage.",exampleSrc:"A: Where is your car?\nB: In the garage.",funFact:"Many Germans pronounce this the French way: ga-RAH-zhuh. Others say ga-RAH-guh. Both are correct, but the French pronunciation sounds fancier."},
{type:"mc",q:"Verumius asks 'Wo ist das Sofa?' Hildi says 'Im Wohnzimmer.' What is a Wohnzimmer?",opts:["A bedroom","A bathroom","A living room","A kitchen"],ans:"A living room",hint:"'Wohnen' means to live or to dwell in German."},
{type:"teach",trg:"die Baustelle",src:"the construction site",note:"Feminine. Compound: Bau (construction) + Stelle (place/site).",example:"A: Warum ist die Stra\u00dfe gesperrt?\nB: Es gibt eine Baustelle nebenan.",exampleSrc:"A: Why is the street blocked?\nB: There is a construction site next door.",funFact:"Germany is famous for its Baustellen. The Berlin airport BER took 14 years to build. Germans joke that Baustellen are permanent landmarks."},
{type:"teach",trg:"die Cafeteria",src:"the cafeteria",note:"Feminine. Same word in many languages. Plural: die Cafeterien.",example:"A: Wo essen die Studenten?\nB: In der Cafeteria. Das Essen ist g\u00fcnstig.",exampleSrc:"A: Where do the students eat?\nB: In the cafeteria. The food is affordable.",funFact:"German universities have a 'Mensa' (from Latin for table), which is the student cafeteria. A 'Cafeteria' usually refers to one in an office or hospital."},
{type:"teach",trg:"das Ger\u00e4t",src:"the device / appliance",note:"Neuter. Plural: die Ger\u00e4te. From 'Rat' (advice, counsel).",example:"A: Was ist das f\u00fcr ein Ger\u00e4t?\nB: Das ist ein Staubsauger.",exampleSrc:"A: What kind of device is that?\nB: That is a vacuum cleaner.",funFact:"'Ger\u00e4t' originally meant 'equipment' or 'tool.' Today it covers everything from kitchen appliances (Haushaltsger\u00e4te) to smartphones (mobile Ger\u00e4te). Turnger\u00e4t means gymnastics apparatus!"},
{type:"fb",s:"Hildi hat ein neues {1} f\u00fcr die K\u00fcche gekauft.",a:["Ger\u00e4t"],opts:["Ger\u00e4t","Gericht","Garage","Garten"],hint:"Which neuter noun means a device or appliance.",sSrc:"Hildi bought a new device for the kitchen."},
{type:"teach",trg:"das Gericht",src:"the dish / the court",note:"Neuter. Two meanings: a meal dish, or a court of law.",example:"A: Was ist dein Lieblingsgericht?\nB: Schnitzel mit Kartoffelsalat!",exampleSrc:"A: What is your favorite dish?\nB: Schnitzel with potato salad!",funFact:"Same word, two meanings. 'Das Gericht' can be dinner (Hauptgericht = main course) or the law court (Amtsgericht = local court). Context always makes it clear."},
{type:"teach",trg:"die Schere",src:"the scissors",note:"Feminine. Always singular in German, unlike English.",example:"A: Hast du eine Schere?\nB: Ja, sie liegt in der Schublade.",exampleSrc:"A: Do you have scissors?\nB: Yes, they are in the drawer.",funFact:"In German, 'die Schere' is singular. You cut with ONE Schere, not 'a pair of scissors.' English treats scissors as plural, German treats them as one tool."},
{type:"teach",trg:"das Schwein",src:"the pig",note:"Neuter. Plural: die Schweine. Also means 'luck' in slang!",example:"A: Was ist das auf dem Bauernhof?\nB: Das ist ein Schwein.",exampleSrc:"A: What is that on the farm?\nB: That is a pig.",funFact:"'Schwein haben' (to have pig) means 'to be lucky' in German! At New Year, Germans give each other marzipan pigs (Glücksschweine) for good luck. Pigs = prosperity in German culture."},
{type:"teach",trg:"das Glück",src:"luck / happiness",note:"Neuter. No plural. Glück haben = to be lucky. Glücklich = happy.",example:"A: Ich habe die Prüfung bestanden!\nB: Herzlichen Glückwunsch! Du hattest Glück.\nA: Nein, ich habe viel gelernt!\nB: Na gut, dann hast du es verdient.",exampleSrc:"A: I passed the exam!\nB: Congratulations! You were lucky.\nA: No, I studied a lot!\nB: Alright, then you earned it.",funFact:"German distinguishes Glück (luck/happiness) from Pech (bad luck). 'Glück im Unglück' means luck in misfortune, finding a silver lining. New Year symbols: four-leaf clover, chimney sweeps, horseshoes, and marzipan pigs."},
{type:"teach",trg:"das Rind",src:"the beef / cattle",note:"Neuter. Rindfleisch = beef (the meat). Plural: die Rinder.",example:"A: Was möchtest du essen?\nB: Ich nehme das Rind mit Gemüse.",exampleSrc:"A: What would you like to eat?\nB: I'll have the beef with vegetables.",funFact:"Germans distinguish carefully: das Rind (the animal/cattle), das Rindfleisch (beef as meat), die Kuh (cow specifically). Rinderbraten (roast beef) is a classic Sunday dish."},
{type:"mc",q:"Verumius sees a 'Glücksschwein' at New Year. What animal is it?",opts:["A cat","A pig","A cow","A horse"],ans:"A pig",hint:"This neuter noun also has a slang meaning related to luck."},
{type:"tip",title:"Deutsche Nachbarschaft",text:"In Germany, knowing your neighbors matters more than you think.\n\n\u2022 Gr\u00fc\u00dfen ist Pflicht: Always greet neighbors in the stairwell. Not greeting is considered rude.\n\u2022 Hausordnung: Most buildings have written house rules on quiet hours, cleaning schedules, and trash sorting.\n\u2022 Kehrwoche: In S\u00fcddeutschland, tenants take turns sweeping the stairwell and sidewalk. Skipping your turn is a social crime.\n\u2022 Nachbarschaftshilfe: Neighbors help each other with packages, watering plants, and lending tools.\n\u2022 Lauftreff/Stammtisch: Community running groups and regular pub meetups build real friendships.",deepDive:"The concept of 'Nachbarschaft' goes beyond proximity. In smaller cities, neighbors exchange house keys, watch each other's children, and celebrate together. The 'Nachbarschaftsfest' (neighborhood party) is a tradition where the whole street sets up tables outside and shares food. Moving into a new building? Introduce yourself with a small gift or a note in the mailbox. First impressions matter."},
{type:"teach",trg:"drinnen",src:"inside",note:"Opposite of 'drau\u00dfen' (outside). Refers to being indoors.",example:"A: Wo sind die Kinder?\nB: Sie spielen drinnen. Es regnet.",exampleSrc:"A: Where are the children?\nB: They are playing inside. It is raining.",funFact:"'Drinnen' vs 'drin': both mean inside, but 'drin' is more casual. 'Was ist da drin?' (What's in there?) vs 'Drinnen ist es warm' (Inside it is warm)."},
{type:"teach",trg:"nebenan",src:"next door",note:"Adverb. 'Der Nachbar nebenan' = the neighbor next door.",example:"A: Wo wohnt Frau Klein?\nB: Sie wohnt nebenan.",exampleSrc:"A: Where does Mrs. Klein live?\nB: She lives next door.",funFact:"'Nebenan' comes from 'neben' (next to) + 'an' (at). Germans love stacking prepositions to create precise spatial adverbs: nebenan, nebendran, nebenher."},
{type:"teach",trg:"rein",src:"in (colloquial for hinein)",note:"Short for 'herein/hinein.' Very common in spoken German.",example:"A: Komm rein! Es ist kalt drau\u00dfen.\nB: Danke! Hier ist es gem\u00fctlich.",exampleSrc:"A: Come in! It is cold outside.\nB: Thanks! It is cozy in here.",funFact:"'Rein' is the casual version of 'hinein' (into). Similarly, 'raus' = 'hinaus' (out of), 'r\u00fcber' = 'hin\u00fcber' (over). Spoken German loves these short forms."},
{type:"teach",trg:"raus",src:"out (colloquial for hinaus)",note:"Short for 'heraus/hinaus.' 'Geh raus!' = Go outside!",example:"A: Das Wetter ist sch\u00f6n!\nB: Dann lass uns rausgehen!",exampleSrc:"A: The weather is nice!\nB: Then let us go outside!",funFact:"'Raus' appears in many expressions: 'rausfinden' (to find out), 'rauskommen' (to come out), 'rauswerfen' (to throw out/fire someone). The prefix completely changes the verb's meaning."},
{type:"fb",s:"Komm {1}! Wir essen gleich.",a:["rein"],opts:["rein","raus","nebenan","drinnen"],hint:"Which colloquial adverb means 'in' when inviting someone inside.",sSrc:"Come in! We are eating soon."},
{type:"teach",trg:"gegen\u00fcber",src:"opposite / across from",note:"Preposition + adverb. Takes dative: gegen\u00fcber dem Haus.",example:"A: Wo ist die Apotheke?\nB: Gegen\u00fcber dem Supermarkt.",exampleSrc:"A: Where is the pharmacy?\nB: Opposite the supermarket.",funFact:"'Gegen\u00fcber' can also be a noun: 'mein Gegen\u00fcber' means 'the person opposite me.' At dinner, your Gegen\u00fcber is whoever sits across from you."},
{type:"teach",trg:"daf\u00fcr",src:"for it / in favor of it",note:"Da + f\u00fcr. Replaces 'f\u00fcr + noun' when the noun is already known.",example:"A: Bist du daf\u00fcr?\nB: Ja, ich bin daf\u00fcr!",exampleSrc:"A: Are you in favor of it?\nB: Yes, I am for it!",funFact:"German 'da-words' replace prepositional phrases: daf\u00fcr (for it), damit (with it), dar\u00fcber (about it), daran (on it). They avoid repeating the noun. Very efficient!"},
{type:"teach",trg:"dagegen",src:"against it / opposed to it",note:"Da + gegen. Opposite of 'daf\u00fcr.'",example:"A: Alle wollen ein Nachbarschaftsfest. Bist du dagegen?\nB: Nein, ich bin daf\u00fcr!",exampleSrc:"A: Everyone wants a neighborhood party. Are you against it?\nB: No, I am for it!",funFact:"In German parliament, votes are counted as 'daf\u00fcr' (in favor), 'dagegen' (against), and 'Enthaltung' (abstention). You hear these words in every political debate."},
{type:"mc",q:"Hildi asks 'Bist du daf\u00fcr oder dagegen?' What is she asking?",opts:["Are you inside or outside?","Are you coming or staying?","Are you for it or against it?","Are you hungry or full?"],ans:"Are you for it or against it?",hint:"These two da-words express opposite opinions about something."},
{type:"teach",trg:"auf jeden Fall",src:"in any case / absolutely",note:"Strong agreement. 'Auf jeden Fall komme ich!' = I am definitely coming!",example:"A: Kommst du zum Lauftreff?\nB: Auf jeden Fall!",exampleSrc:"A: Are you coming to the running club?\nB: Absolutely!",funFact:"The opposite is 'auf keinen Fall' (no way / under no circumstances). 'Jeden' = every, 'keinen' = no. Same structure, opposite meaning."},
{type:"teach",trg:"auf keinen Fall",src:"no way / under no circumstances",note:"Strong disagreement. 'Auf keinen Fall!' = Absolutely not!",example:"A: Soll ich den Biomüll in den Restm\u00fcll werfen?\nB: Auf keinen Fall! Hildi sieht alles.",exampleSrc:"A: Should I throw the organic waste in the general trash?\nB: No way! Hildi sees everything.",funFact:"Germans use this phrase with conviction. It leaves zero room for doubt. If Hildi says 'auf keinen Fall,' you do NOT put plastic in the Biotonne."},
{type:"fb",s:"Kommst du morgen? {1}!",a:["Auf jeden Fall"],opts:["Auf jeden Fall","Auf keinen Fall","Dagegen","Nebenan"],hint:"Which expression means 'absolutely' or 'definitely'.",sSrc:"Are you coming tomorrow? Absolutely!"},
{type:"drag_fill",s:"Die Apotheke ist {1} dem Supermarkt. Frau Klein wohnt {2}.",blanks:{"1":"gegen\u00fcber","2":"nebenan"},pool:["gegen\u00fcber","nebenan","drinnen","raus","dagegen"],hint:"One means 'opposite/across from,' the other means 'next door.'",sSrc:"The pharmacy is opposite the supermarket. Mrs. Klein lives next door."},
{type:"mc",q:"Verumius says 'Die Kinder spielen drinnen.' Where are the children?",opts:["Outside in the garden","Inside the building","Next door","At the construction site"],ans:"Inside the building",hint:"This adverb is the opposite of 'drau\u00dfen' (outside)."},
{type:"mc",q:"Which word means 'the construction site'?",opts:["die Baustelle","die Cafeteria","die Garage","die Vermieterin"],ans:"die Baustelle",hint:"Compound word: Bau (building/construction) + Stelle (place)."},
{type:"fb",s:"Zum Neujahr verschenkt man Marzipanschweine. Schwein haben bedeutet '{1} haben.'",a:["Gl\u00fcck"],opts:["Gl\u00fcck","Geld","Essen","Angst"],hint:"The opposite of Pech. Something positive that happens by chance.",sSrc:"At New Year, people give marzipan pigs. Having pig means having 'luck'."},
{type:"teach",trg:"leer",src:"empty",note:"Adjective. Opposite: voll (full). Die Flasche ist leer.",example:"A: Ist noch Milch da?\nB: Nein, die Flasche ist leer.\nA: Schon wieder? Wer trinkt so viel Milch?\nB: Verumius. Er macht jeden Morgen Müsli.",exampleSrc:"A: Is there still milk?\nB: No, the bottle is empty.\nA: Again? Who drinks so much milk?\nB: Verumius. He makes muesli every morning.",funFact:"Leergut means empty containers eligible for the Pfand (deposit) return. Supermarkets have Leergutautomaten where you feed in bottles and cans for money back."},
{type:"teach",trg:"notwendig",src:"necessary",note:"Adjective. Stronger than nötig. Es ist notwendig = It is necessary.",example:"A: Ist eine Krankenversicherung notwendig?\nB: Ja, in Deutschland ist sie Pflicht.\nA: Auch für Studenten?\nB: Ja, für alle. Ohne geht es nicht.",exampleSrc:"A: Is health insurance necessary?\nB: Yes, in Germany it is mandatory.\nA: Even for students?\nB: Yes, for everyone. You cannot do without it.",funFact:"Notwendig literally means 'turning away need' (Not = need, wenden = to turn). German loves building words that explain their own meaning."},
{type:"teach",trg:"praktisch",src:"practical",note:"Adjective. Also used as an adverb meaning 'practically' or 'virtually.'",example:"A: Die Wohnung hat einen Balkon.\nB: Oh, das ist sehr praktisch!\nA: Ja, ich trockne dort meine Wäsche.\nB: Praktisch! Kein Trockner nötig.",exampleSrc:"A: The apartment has a balcony.\nB: Oh, that is very practical!\nA: Yes, I dry my laundry there.\nB: Practical! No dryer needed.",funFact:"Germans highly value being practical. A practical gift is better than an expensive one. Practical shoes beat fashionable ones. Functionality is a cultural value."},
{type:"teach",trg:"bauen",src:"to build",note:"Regular: ich baue, du baust, er baut. Past: gebaut.",example:"A: Was bauen sie nebenan?\nB: Eine neue Schule.\nA: Wie lange dauert das?\nB: Mindestens zwei Jahre. Das ist eine große Baustelle.",exampleSrc:"A: What are they building next door?\nB: A new school.\nA: How long will that take?\nB: At least two years. That is a big construction site.",funFact:"Berlin's BER airport took 14 years to build. The Cologne Cathedral took 632 years (started 1248, finished 1880). Germans joke that building is a test of patience."},
{type:"teach",trg:"herstellen",src:"to produce / to manufacture",note:"Separable: ich stelle her. Past: hergestellt. Used for factory production.",example:"A: Wo wird dieses Auto hergestellt?\nB: In Wolfsburg, bei Volkswagen.\nA: Made in Germany!\nB: Genau. Deutsche Qualität.",exampleSrc:"A: Where is this car manufactured?\nB: In Wolfsburg, at Volkswagen.\nA: Made in Germany!\nB: Exactly. German quality.",funFact:"'Made in Germany' was originally a British warning label in 1887 to mark inferior German imports. Germans turned it into a badge of quality worldwide."},
{type:"match",pairs:[{trg:"die Vermieterin",src:"the landlady"},{trg:"das Wohnzimmer",src:"the living room"},{trg:"die Baustelle",src:"the construction site"},{trg:"nebenan",src:"next door"},{trg:"dafür",src:"for it"},{trg:"auf jeden Fall",src:"absolutely"},{trg:"die Schere",src:"the scissors"},{trg:"das Gerät",src:"the device"}]}
]}
]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 9: Freizeit und Vereine
// Story: Lauftreff, Vereinskultur, Satzung comedy, Yilmaz's text
// CEFR: A2.2 - dass/ob clauses, reflexive verbs/pronouns, coord conjunctions
// ═══════════════════════════════════════════════════════════════
{n:9,lang:"de",srcLang:"en",track:"v2",title:"Freizeit und Vereine",sub:"Running club, Vereinskultur, hobbies, and German social life",icon:"🏃",level:"A2.2",color:"#7B5EE8",lessons:[
// ─── L1: Der Lauftreff ───
{id:"deu_r9l1",title:"Der Lauftreff",icon:"🏃",xp:15,board:true,steps:[
{type:"intro",title:"Der Lauftreff",desc:"Mia drags Verumius to her running club in Volkspark Friedrichshain. It's 6:30 AM, the autumn air bites, and Verumius is already regretting this.",goals:["Learn 12 sports and leisure words","Discover German Vereinskultur","Survive your first Lauftreff"]},
{type:"story",speaker:"narrator",mood:"tired",art:"de-volkspark-dawn",trg:"Volkspark Friedrichshain. 6:30 Uhr. Die Bäume sind orange und rot. Kalte Luft, Atem wie kleine Wolken. Mia steht am Eingang und dehnt sich. Verumius steht daneben und gähnt.",src:"Volkspark Friedrichshain. 6:30 AM. The trees are orange and red. Cold air, breath like little clouds. Mia stands at the entrance stretching. Verumius stands next to her and yawns."},
{type:"story",speaker:"Mia",trg:"Guten Morgen! Bist du bereit? Wir treffen uns hier jeden Samstag. Das ist unser Lauftreff!",src:"Good morning! Are you ready? We meet here every Saturday. This is our running club!"},
{type:"story",speaker:"Verumius",trg:"Jeden Samstag? Um halb sieben? Ihr seid alle verrückt.",src:"Every Saturday? At half past six? You're all crazy."},
{type:"teach",trg:"der Ball",src:"the ball",note:"Masculine noun. Plural: die Bälle.",example:"A: Hast du einen Ball?\nB: Ja, der Ball ist im Auto.\nA: Dann hol ihn schnell!",exampleSrc:"A: Do you have a ball?\nB: Yes, the ball is in the car.\nA: Then go get it quickly!",funFact:"'Ball' is identical in English and German. It comes from Old High German 'bal.' Germans host over 400 'Bälle' (formal dance balls) each year, most famously the Vienna Opera Ball."},
{type:"teach",trg:"der Fan",src:"the fan (supporter)",note:"Masculine noun. Plural: die Fans. Borrowed from English.",example:"A: Bist du ein Fan von Bayern München?\nB: Nein! Ich bin ein Fan von Dortmund!\nA: Oh, dann können wir nicht Freunde sein.",exampleSrc:"A: Are you a fan of Bayern Munich?\nB: No! I'm a fan of Dortmund!\nA: Oh, then we can't be friends.",funFact:"Germany's Bundesliga has the highest average stadium attendance in the world. Borussia Dortmund's 'Gelbe Wand' (Yellow Wall) holds 25,000 standing fans in one section alone."},
{type:"teach",trg:"die Mannschaft",src:"the team",note:"Feminine noun. Plural: die Mannschaften.",example:"A: Welche Mannschaft spielt heute?\nB: Die Mannschaft aus Berlin spielt gegen Hamburg.\nA: Das wird ein gutes Spiel!",exampleSrc:"A: Which team is playing today?\nB: The team from Berlin is playing against Hamburg.\nA: That will be a good game!",funFact:"The German national football team is simply called 'die Mannschaft' (the team). The word comes from 'Mann' (man) + '-schaft' (collective suffix), like English '-ship' in 'fellowship.'"},
{type:"teach",trg:"der Sportplatz",src:"the sports field",note:"Masculine compound noun: Sport + Platz (place).",example:"A: Wo ist der Sportplatz?\nB: Der Sportplatz ist hinter der Schule.\nA: Danke! Wir trainieren dort um vier.",exampleSrc:"A: Where is the sports field?\nB: The sports field is behind the school.\nA: Thanks! We train there at four.",funFact:"Every German neighborhood has a Sportplatz. There are over 90,000 sports facilities in Germany. Even tiny villages have their own football field with a clubhouse."},
{type:"mc",q:"Mia says 'Die Mannschaft trainiert auf dem Sportplatz.' Where does the team train?",opts:["At the train station","On the sports field","In the swimming pool","At the supermarket"],ans:"On the sports field",hint:"'Sportplatz' is a compound of Sport and a word meaning 'place.'"},
{type:"fb",s:"Bist du ein {1} von Dortmund?",a:["Fan"],opts:["Fan","Ball","Spiel","Mannschaft"],hint:"Which borrowed English word means a supporter of a team?",sSrc:"Are you a fan of Dortmund?"},
{type:"teach",trg:"das Training",src:"the training / practice",note:"Neuter noun. No common plural form in everyday use.",example:"A: Wann ist das Training?\nB: Das Training ist um sechs Uhr.\nA: So früh? Das ist hart!",exampleSrc:"A: When is the training?\nB: The training is at six o'clock.\nA: So early? That's tough!",funFact:"Germans take training schedules seriously. Club training sessions run year-round, rain or shine. The phrase 'Übung macht den Meister' (practice makes the master) is a national motto."},
{type:"teach",trg:"das Spiel",src:"the game / match",note:"Neuter noun. Plural: die Spiele.",example:"A: Wie war das Spiel?\nB: Das Spiel war fantastisch! 3:1 für uns.\nA: Toll! Wer hat die Tore geschossen?",exampleSrc:"A: How was the game?\nB: The game was fantastic! 3-1 for us.\nA: Great! Who scored the goals?",funFact:"'Spiel' gives us 'Spielplatz' (playground), 'Spielzeug' (toy, literally play-stuff), and the verb 'spielen.' Steven Spielberg's surname literally means 'play mountain.'"},
{type:"teach",trg:"der Spaziergang",src:"the walk / stroll",note:"Masculine compound: spazieren (to stroll) + Gang (way/path).",example:"A: Machen wir einen Spaziergang?\nB: Ja, gerne! Im Park?\nA: Perfekt. Die Sonne scheint.",exampleSrc:"A: Shall we go for a walk?\nB: Yes, I'd love to! In the park?\nA: Perfect. The sun is shining.",funFact:"The Sunday 'Spaziergang' is a sacred German tradition. After lunch, families walk through parks or forests. It is considered healthy, social, and deeply German. Some call it 'Verdauungsspaziergang' (digestion walk)."},
{type:"mc",q:"Verumius says 'Machen wir einen Spaziergang im Park?' What is he suggesting?",opts:["Let's eat in the park","Let's play a game in the park","Let's go for a walk in the park","Let's train in the park"],ans:"Let's go for a walk in the park",hint:"A 'Spaziergang' is a relaxed, leisurely outdoor activity."},
{type:"story",speaker:"narrator",mood:"struggling",art:"de-volkspark-running",trg:"Die Gruppe läuft los. Mia ist vorne, schnell und leicht. Verumius ist hinten. Seine Beine sind schwer. Sein Atem ist laut. Ein älterer Mann überholt ihn. Eine Frau mit Kinderwagen überholt ihn.",src:"The group starts running. Mia is at the front, fast and light. Verumius is at the back. His legs are heavy. His breathing is loud. An older man passes him. A woman with a stroller passes him."},
{type:"teach",trg:"joggen",src:"to jog",note:"Borrowed from English. Regular: ich jogge, du joggst.",example:"A: Gehst du gerne joggen?\nB: Ja, ich jogge jeden Morgen im Park.\nA: Alleine oder mit Freunden?",exampleSrc:"A: Do you like jogging?\nB: Yes, I jog every morning in the park.\nA: Alone or with friends?",funFact:"Germans borrowed 'joggen' in the 1970s running boom. They even created 'der Jogger' and 'die Joggerin.' English sports words flood German: 'der Sprint,' 'das Workout,' 'das Stretching.'"},
{type:"teach",trg:"trainieren",src:"to train / to work out",note:"Regular: ich trainiere, du trainierst, er trainiert.",example:"A: Wie oft trainierst du?\nB: Ich trainiere dreimal pro Woche.\nA: Das ist beeindruckend!",exampleSrc:"A: How often do you train?\nB: I train three times per week.\nA: That's impressive!",funFact:"From Latin 'trahere' (to pull/drag), through French 'trainer.' The same root gave English 'train' (the vehicle literally pulls carriages). In German, 'trainieren' is ONLY for exercise, never for vehicles."},
{type:"teach",trg:"spazieren",src:"to walk / to stroll",note:"Regular: ich spaziere, du spazierst. Often used with 'gehen.'",example:"A: Was machst du am Sonntag?\nB: Ich gehe spazieren. Kommst du mit?\nA: Klar! Wohin gehen wir?",exampleSrc:"A: What are you doing on Sunday?\nB: I'm going for a walk. Do you want to come?\nA: Sure! Where are we going?",funFact:"'Spazieren' comes from Italian 'spaziare' (to wander). It arrived in German during the Renaissance when Italian culture was fashionable. A walk borrowed from Italy!"},
{type:"fb",s:"Ich {1} jeden Morgen im Park.",a:["jogge"],opts:["jogge","spaziere","trainiere","spiele"],hint:"Which verb specifically means running at a moderate pace?",sSrc:"I jog every morning in the park."},
{type:"teach",trg:"aktiv",src:"active",note:"Same spelling as English. Used with sein: 'Ich bin aktiv.'",example:"A: Bist du sportlich?\nB: Ja, ich bin sehr aktiv. Ich jogge und schwimme.\nA: Respekt!",exampleSrc:"A: Are you sporty?\nB: Yes, I'm very active. I jog and swim.\nA: Respect!",funFact:"Germany ranks among the most physically active countries in Europe. Over 27 million Germans are members of a sports club. That is one in three people!"},
{type:"teach",trg:"sportlich",src:"sporty / athletic",note:"From 'Sport' + '-lich' (similar to English '-ly'). Used for people AND things.",example:"A: Mia ist wirklich sportlich!\nB: Ja, sie trainiert jeden Tag.\nA: Ich bin leider nicht so sportlich.",exampleSrc:"A: Mia is really sporty!\nB: Yes, she trains every day.\nA: Unfortunately I'm not that sporty.",funFact:"The suffix '-lich' turns nouns into adjectives: Sport to sportlich, Freund to freundlich, Herz to herzlich. Once you know this trick, you can decode hundreds of German adjectives."},
{type:"mc",q:"Verumius says 'Mia ist sportlich, ich bin es nicht.' What does 'sportlich' mean?",opts:["Tired","Sporty","Hungry","Late"],ans:"Sporty",hint:"This adjective is built from a word you already know plus '-lich.'"},
{type:"tip",title:"Vereinskultur: The Heart of German Community",text:"Germany has over 600,000 registered Vereine (clubs).\n\nFootball clubs, hiking clubs, running clubs, singing clubs, rabbit-breeding clubs.\n\n'Sich treffen' (to meet up) and 'sich anmelden' (to register) are key verbs for club life. You will learn these soon!\n\nJoining a Verein is how Germans build community. Mia's Lauftreff is a perfect example: same people, same time, same park, every week.",deepDive:"The first German Verein was founded in 1791. Today, about 44% of all Germans belong to at least one club. The concept is so central to German identity that 'Vereinsmeier' (someone obsessed with club rules) is a well-known word. Many clubs have a 'Stammtisch' (regulars' table) at a local pub where members meet after activities."},
{type:"mc",q:"How many registered Vereine (clubs) does Germany have?",opts:["About 6,000","About 60,000","About 600,000","About 6,000,000"],ans:"About 600,000",hint:"Think about the tip card. It is a six-figure number."},
{type:"fb",s:"Mia ist sehr {1}. Sie trainiert jeden Tag.",a:["sportlich"],opts:["sportlich","aktiv","müde","hungrig"],hint:"Which adjective describes someone who is athletic?",sSrc:"Mia is very sporty. She trains every day."},
{type:"match",pairs:[{trg:"der Ball",src:"the ball"},{trg:"die Mannschaft",src:"the team"},{trg:"das Spiel",src:"the game"},{trg:"joggen",src:"to jog"},{trg:"trainieren",src:"to train"},{trg:"spazieren",src:"to stroll"},{trg:"aktiv",src:"active"},{trg:"sportlich",src:"sporty"}]},
{type:"story",speaker:"Mia",trg:"Nicht schlecht für dein erstes Mal! Nächste Woche wird es einfacher. Das Training macht dich fit!",src:"Not bad for your first time! Next week it will be easier. The training will get you fit!"},
{type:"story",speaker:"Verumius",trg:"Nächste Woche? Ich kann meine Beine nicht mehr fühlen!",src:"Next week? I can't feel my legs anymore!"},
{type:"mc",q:"'Das Training macht dich fit.' What does 'das Training' mean?",opts:["The game","The walk","The training","The team"],ans:"The training",hint:"This neuter noun describes the activity of practicing a sport."},
{type:"drag_fill",s:"Mia ist {1} und {2}. Sie geht jeden Samstag zum {3}.",blanks:{"1":"aktiv","2":"sportlich","3":"Lauftreff"},pool:["aktiv","sportlich","Lauftreff","müde","Spiel"],hint:"Describe Mia's character and her Saturday activity.",sSrc:"Mia is active and sporty. She goes every Saturday to the Lauftreff."}
]}
,

{id:"deu_r9l2",title:"Was machst du gern?",icon:"🎨",xp:15,board:true,steps:[
{type:"intro",title:"Was machst du gern?",desc:"Lerne Wörter für Hobbys, Kunst und Kultur.",goals:["14 neue Wörter für Freizeit und Kultur","Über Hobbys und Interessen sprechen","Kulturelle Orte und Aktivitäten beschreiben"]},
{type:"teach",trg:"die Musik",src:"music",note:"Feminine. Die Musik spielt eine große Rolle in Deutschland.",funFact:"Deutschland hat über 130 professionelle Orchester. Mehr als jedes andere Land der Welt.",example:"A: Hörst du gern Musik?\nB: Ja, ich höre jeden Tag Musik.",exampleSrc:"A: Do you like listening to music?\nB: Yes, I listen to music every day."},
{type:"teach",trg:"das Instrument",src:"instrument",note:"Neuter. Plural: die Instrumente.",funFact:"Etwa 18% der Deutschen spielen ein Instrument. Klavier und Gitarre sind am beliebtesten.",example:"A: Spielst du ein Instrument?\nB: Ja, ich spiele seit drei Jahren.",exampleSrc:"A: Do you play an instrument?\nB: Yes, I have been playing for three years."},
{type:"teach",trg:"die Gitarre",src:"guitar",note:"Feminine. Plural: die Gitarren.",funFact:"Die klassische Gitarre kam im 19. Jahrhundert nach Deutschland und wurde schnell populär in Wandervogel-Gruppen.",example:"A: Kannst du Gitarre spielen?\nB: Ein bisschen. Ich lerne noch.",exampleSrc:"A: Can you play guitar?\nB: A little. I am still learning."},
{type:"teach",trg:"das Klavier",src:"piano",note:"Neuter. Plural: die Klaviere. Das Wort kommt vom lateinischen clavis (Taste).",funFact:"Beethoven, Bach, Brahms. Deutschland hat mehr berühmte Klavierkomponisten als fast jedes andere Land.",example:"A: Mein Sohn spielt Klavier.\nB: Toll! Seit wann?\nA: Seit September.",exampleSrc:"A: My son plays piano.\nB: Great! Since when?\nA: Since September."},
{type:"mc",q:"Wie sagt man 'guitar' auf Deutsch?",opts:["die Gitarre","das Klavier","die Musik","das Instrument"],ans:"die Gitarre",hint:"Ein Saiteninstrument mit sechs Saiten."},
{type:"teach",trg:"die Kunst",src:"art",note:"Feminine. Kein Plural in dieser Bedeutung.",funFact:"Die documenta in Kassel ist eine der wichtigsten Kunstausstellungen der Welt. Sie findet alle fünf Jahre statt.",example:"A: Interessierst du dich für Kunst?\nB: Ja, besonders für moderne Kunst.",exampleSrc:"A: Are you interested in art?\nB: Yes, especially modern art."},
{type:"teach",trg:"die Kultur",src:"culture",note:"Feminine. Kulturell ist das Adjektiv.",funFact:"In vielen deutschen Städten gibt es eine Kulturkarte. Damit bekommt man Rabatt für Museen, Theater und Konzerte.",example:"A: Die Kultur hier ist sehr interessant.\nB: Ja, es gibt so viel zu sehen!",exampleSrc:"A: The culture here is very interesting.\nB: Yes, there is so much to see!"},
{type:"teach",trg:"das Museum",src:"museum",note:"Neuter. Plural: die Museen (nicht Museums!).",funFact:"Berlin hat die Museumsinsel mit fünf Museen. Sie gehört zum UNESCO-Weltkulturerbe.",example:"A: Warst du schon im Museum?\nB: Ja, das Pergamonmuseum ist fantastisch.",exampleSrc:"A: Have you been to the museum?\nB: Yes, the Pergamon Museum is fantastic."},
{type:"teach",trg:"die Ausstellung",src:"exhibition",note:"Feminine. Plural: die Ausstellungen. Aus + Stellung = etwas wird ausgestellt.",funFact:"Viele deutsche Museen haben am ersten Sonntag im Monat freien Eintritt.",example:"A: Gehst du in die Ausstellung?\nB: Ja, sie ist nur noch bis Freitag.",exampleSrc:"A: Are you going to the exhibition?\nB: Yes, it is only open until Friday."},
{type:"fb",s:"Ich möchte ins {1} gehen. Die Ausstellung über Picasso beginnt heute.",a:["Museum"],opts:["Museum","Theater","Konzert","Bibliothek"],hint:"Ein Ort, wo man Ausstellungen besucht.",sSrc:"I would like to go to the museum. The Picasso exhibition starts today."},
{type:"teach",trg:"das Theater",src:"theater",note:"Neuter. Plural: die Theater. Ins Theater gehen = to go to the theater.",funFact:"Deutschland hat über 800 Theater. Pro Kopf mehr als jedes andere Land.",example:"A: Gehen wir am Samstag ins Theater?\nB: Gute Idee! Was wird gespielt?",exampleSrc:"A: Shall we go to the theater on Saturday?\nB: Good idea! What is playing?"},
{type:"teach",trg:"das Konzert",src:"concert",note:"Neuter. Plural: die Konzerte. Ins Konzert gehen.",funFact:"Die Elbphilharmonie in Hamburg hat eine der besten Akustiken der Welt. Karten sind oft Monate im Voraus ausverkauft.",example:"A: Das Konzert war wunderbar!\nB: Ja, die Musik war so schön.",exampleSrc:"A: The concert was wonderful!\nB: Yes, the music was so beautiful."},
{type:"teach",trg:"die Bibliothek",src:"library",note:"Feminine. Plural: die Bibliotheken. Nicht verwechseln mit Buchhandlung (bookshop).",funFact:"Die Deutsche Nationalbibliothek in Leipzig und Frankfurt sammelt jedes Buch, das auf Deutsch erscheint.",example:"A: Wo ist die Bibliothek?\nB: Gleich neben dem Museum.",exampleSrc:"A: Where is the library?\nB: Right next to the museum."},
{type:"mc",q:"Wo kann man Bücher lesen und ausleihen?",opts:["in der Bibliothek","im großen Museum","im alten Rathaus","im neuen Zentrum"],ans:"in der Bibliothek",hint:"Dieser Ort ist voll mit Büchern und Regalen."},
{type:"teach",trg:"malen",src:"to paint",note:"Regular: ich male, du malst, er malt.",funFact:"Gerhard Richter ist einer der teuersten lebenden Maler der Welt. Er kommt aus Dresden.",example:"A: Was machst du am Wochenende?\nB: Ich male ein Bild für meine Mutter.",exampleSrc:"A: What are you doing on the weekend?\nB: I am painting a picture for my mother."},
{type:"teach",trg:"zeichnen",src:"to draw",note:"Regular: ich zeichne, du zeichnest, er zeichnet. Mit Bleistift oder Kohle.",funFact:"Albrecht Dürer aus Nürnberg war einer der größten Zeichner aller Zeiten. Sein Hase ist weltberühmt.",example:"A: Kannst du gut zeichnen?\nB: Es geht. Ich zeichne gern Tiere.",exampleSrc:"A: Can you draw well?\nB: So-so. I like drawing animals."},
{type:"teach",trg:"basteln",src:"to do crafts",note:"Regular: ich bastle, du bastelst. Basteln = mit den Händen etwas kreativ machen.",funFact:"Basteln ist in Deutschland ein echtes Hobby. Es gibt ganze Bastelgeschäfte nur für Materialien.",example:"A: Die Kinder basteln Laternen für Sankt Martin.\nB: Oh, wie schön! Aus Papier?",exampleSrc:"A: The children are making lanterns for St. Martin's Day.\nB: Oh, how nice! Out of paper?"},
{type:"tip",title:"Musikvereine und Kulturvereine",text:"In Deutschland gibt es tausende Vereine für Musik und Kultur.\n\n- Musikverein: Man spielt zusammen in einem Orchester oder einer Band.\n- Kulturverein: Man organisiert Ausstellungen, Lesungen oder Theaterabende.\n- Volkshochschule (VHS): Hier kann man malen, zeichnen oder basteln lernen.\n\nEin Verein kostet oft nur 5 bis 15 Euro im Monat. Fast jedes Dorf hat einen Musikverein!",deepDive:"Das deutsche Vereinswesen hat Tradition seit dem 19. Jahrhundert. Heute gibt es etwa 600.000 eingetragene Vereine (e.V.) in Deutschland. Viele Kinder lernen ihr erstes Instrument im Musikverein."},
{type:"mc",q:"Lena spielt gern Klavier und Gitarre. Was spielt sie?",opts:["Instrumente","Ausstellungen","Theater","Kultur"],ans:"Instrumente",hint:"Ein Wort für Dinge, die Musik machen."},
{type:"fb",s:"Am Samstag gehen wir ins {1}. Wir sehen ein Stück von Schiller.",a:["Theater"],opts:["Theater","Museum","Konzert","Bibliothek"],hint:"Ein Ort, wo Schauspieler auf der Bühne stehen.",sSrc:"On Saturday we are going to the theater. We are seeing a play by Schiller."},
{type:"drag_fill",s:"Mein Bruder {1} gern und meine Schwester {2} gern. Beide lieben {3}.",blanks:{"1":"malt","2":"zeichnet","3":"Kunst"},pool:["malt","zeichnet","Kunst","bastelt","Musik","Kultur"],hint:"Er benutzt Farben, sie benutzt Bleistift, beide lieben es.",sSrc:"My brother paints and my sister draws. Both love art."},
{type:"match",pairs:[{trg:"die Ausstellung",src:"exhibition"},{trg:"das Konzert",src:"concert"},{trg:"die Bibliothek",src:"library"},{trg:"basteln",src:"to do crafts"},{trg:"zeichnen",src:"to draw"},{trg:"die Gitarre",src:"guitar"}]},
{type:"mc",q:"Was macht man in einer Bibliothek?",opts:["Bücher lesen und ausleihen","Konzerte besuchen","Bilder malen","Instrumente spielen"],ans:"Bücher lesen und ausleihen",hint:"Denk an Regale, Stille und einen Ausweis zum Mitnehmen."},
{type:"fb",s:"Ich gehe heute Abend ins {1}. Die Band spielt meine Lieblingsmusik!",a:["Konzert"],opts:["Konzert","Museum","Theater","Bibliothek"],hint:"Ein Ereignis, wo eine Band live Musik spielt.",sSrc:"I am going to the concert tonight. The band is playing my favorite music!"}
]},

// ─── L3: Die Vereinssitzung ───
{id:"deu_r9l3",title:"Die Vereinssitzung",icon:"📋",xp:15,board:true,steps:[
{type:"intro",title:"Die Vereinssitzung",desc:"Verumius attends his first Verein meeting. Folding chairs, a whiteboard, and a binder labeled SATZUNG. Mia runs a surprisingly formal meeting for a running club.",goals:["Learn reflexive verbs with accusative pronouns","Understand dass-clauses with verb-final word order","Talk about events, fun, and participation"]},
{type:"story",speaker:"narrator",mood:"curious",art:"de-verein-meeting",trg:"Dienstagabend. Ein Kirchenkeller mit Klappstühlen und einer alten Tafel. Mia steht vorne mit einem dicken Ordner. Auf dem Ordner steht: SATZUNG.",src:"Tuesday evening. A church basement with folding chairs and an old whiteboard. Mia stands at the front with a thick binder. On the binder it says: CONSTITUTION."},
{type:"story",speaker:"verumius",mood:"shocked",trg:"Ein Laufverein hat eine Satzung?! In Italien treffen wir uns einfach im Park und laufen los.",src:"A running club has a constitution?! In Italy we just meet in the park and start running."},
{type:"story",speaker:"mia",mood:"cheerful",trg:"Willkommen zur Vereinssitzung! Ich freue mich, dass so viele da sind. Wir haben heute viel zu besprechen.",src:"Welcome to the club meeting! I am happy that so many people are here. We have a lot to discuss today."},
{type:"teach",trg:"das Interesse",src:"the interest",note:"Neuter noun. Plural: die Interessen. 'Interesse an + Dativ.'",example:"A: Hast du Interesse an dem Laufverein?\nB: Ja, ich habe großes Interesse!",exampleSrc:"A: Are you interested in the running club?\nB: Yes, I have great interest!",funFact:"Borrowed directly from Latin 'interesse' (to be between). German, French, English, and Italian all use the same word. A true European traveler."},
{type:"teach",trg:"die Lust",src:"the desire / mood (to do something)",note:"Feminine noun. 'Hast du Lust?' = Do you feel like it?",example:"A: Hast du Lust auf ein Bier nach dem Training?\nB: Ja, ich habe total Lust!",exampleSrc:"A: Do you feel like a beer after training?\nB: Yes, I totally feel like it!",funFact:"'Hast du Lust?' is how Germans casually invite people to do things. It is warmer than 'Möchtest du?' and more natural in everyday speech. You will hear it constantly."},
{type:"teach",trg:"der Spaß",src:"the fun",note:"Masculine noun. 'Das macht Spaß!' = That is fun!",example:"A: Macht Laufen Spaß?\nB: Ja, das macht total Spaß!",exampleSrc:"A: Is running fun?\nB: Yes, it is totally fun!",funFact:"Both 'Spaß machen' (to make fun) and 'Spaß haben' (to have fun) are common in German. 'Das macht Spaß!' focuses on the activity creating fun. 'Ich habe Spaß!' focuses on your experience. You will hear both all the time."},
{type:"teach",trg:"das Fest",src:"the celebration / festival",note:"Neuter noun. Plural: die Feste. Think: Oktoberfest!",example:"A: Wann ist das Sommerfest?\nB: Das Fest ist im Juli.",exampleSrc:"A: When is the summer festival?\nB: The festival is in July.",funFact:"'Fest' gives us Oktoberfest, Weinfest, Schützenfest, Volksfest. Germany has over 10,000 festivals per year. If there is a reason to celebrate, there is a Fest for it."},
{type:"teach",trg:"die Feier",src:"the party / celebration",note:"Feminine noun. Plural: die Feiern. More personal than Fest.",example:"A: Kommst du zur Feier am Samstag?\nB: Ja, ich komme gerne zur Feier!",exampleSrc:"A: Are you coming to the party on Saturday?\nB: Yes, I'd love to come to the party!",funFact:"'Feier' is for personal celebrations (birthdays, weddings). 'Fest' is for public ones (festivals, fairs). A birthday is a Feier, not a Fest. Oktoberfest is a Fest, not a Feier."},
{type:"teach",trg:"die Veranstaltung",src:"the event / organized occasion",note:"Feminine noun. Plural: die Veranstaltungen. Formal word.",example:"A: Welche Veranstaltungen gibt es im Mai?\nB: Es gibt drei Veranstaltungen im Mai.",exampleSrc:"A: Which events are there in May?\nB: There are three events in May.",funFact:"16 letters! One of those long German words that sounds scary but breaks down simply: ver + an + stalt + ung. 'Anstalt' means institution, 'ver-' makes it into an action. An organized occasion."},
{type:"mc",q:"Mia says 'Hast du Lust auf eine Feier?' What is she asking?",opts:["Do you have time for a party?","Do you feel like a party?","Do you need a party?","Do you know about a party?"],ans:"Do you feel like a party?",hint:"'Lust haben auf' expresses wanting or feeling like doing something."},
{type:"fb",s:"Das Training macht {1}!",a:["Spaß"],opts:["Spaß","Lust","Fest","Interesse"],hint:"Which masculine noun means 'fun' and pairs with 'machen'?",sSrc:"Training is fun!"},
{type:"teach",trg:"der Wettbewerb",src:"the competition",note:"Masculine noun. Plural: die Wettbewerbe. Compound: Wette + Bewerb.",example:"A: Gibt es einen Wettbewerb im Oktober?\nB: Ja, der Wettbewerb ist am 15. Oktober.",exampleSrc:"A: Is there a competition in October?\nB: Yes, the competition is on October 15th.",funFact:"'Wette' means bet, 'Bewerb' comes from 'bewerben' (to apply/compete). A competition is literally a 'bet-application.' Germans once settled disputes by betting on athletic contests."},
{type:"teach",trg:"sich freuen",src:"to be happy / to look forward to",note:"Reflexive verb. 'Ich freue mich.' 'sich freuen auf' = look forward to.",example:"A: Ich freue mich auf das Fest!\nB: Ich freue mich auch!",exampleSrc:"A: I'm looking forward to the festival!\nB: I'm looking forward to it too!",funFact:"'Sich freuen' needs a reflexive pronoun. Without it, 'freuen' alone sounds wrong. The 'sich' is like saying 'to glad oneself.' German emotions often work this way: you do the feeling TO yourself."},
{type:"tip",title:"auf vs über with sich freuen",text:"The preposition changes the TIME direction:\n\nsich freuen AUF = looking FORWARD to something (future)\nIch freue mich auf die Ferien.\n\nsich freuen ÜBER = being happy ABOUT something (past or current)\nIch freue mich über das Ergebnis.\n\nauf = arrow pointing to the future. über = reflecting on what happened.",deepDive:{title:"darauf and darüber",text:"When a preposition refers to a thing (not a person), German uses da-compounds:\nFreust du dich auf den Urlaub? Ja, ich freue mich darauf.\nda + auf = darauf. da + über = darüber. You will study these fully in B1."}},
{type:"teach",trg:"sich treffen",src:"to meet up",note:"Reflexive + irregular: ich treffe mich, du triffst dich, er trifft sich.",example:"A: Wann treffen wir uns?\nB: Wir treffen uns um 18 Uhr.",exampleSrc:"A: When do we meet up?\nB: We meet up at 6 PM.",funFact:"'Treffen' alone means 'to hit' (a target). Add 'sich' and it becomes 'to meet.' The reflexive changes the entire meaning. You are not hitting anyone, you are meeting each other!"},
{type:"tip",title:"Reflexive Verbs: The 'sich' System",text:"Some German verbs need a reflexive pronoun. The pronoun refers back to the subject.\n\nKey pattern: subject + reflexive pronoun + verb\n\nIch freue mich. (I am happy.)\nDu freust dich. (You are happy.)\nWir treffen uns. (We meet up.)\n\nThe reflexive pronoun changes with the subject. Next, you will see the full table.",deepDive:{title:"Accusative vs dative reflexive pronouns",text:"German has TWO sets of reflexive pronouns. The accusative set (mich, dich, sich, uns, euch, sich) is used when the reflexive pronoun is the DIRECT OBJECT of the verb.\n\nThe dative set (mir, dir, sich, uns, euch, sich) is used when the verb already has a direct object and the reflexive is the INDIRECT object.\n\nExample: Ich wasche mir die Hände. (I wash my hands, literally: I wash for-myself the hands.)\n\nNotice that uns, euch, and sich are the same in both sets. Only ich and du differ: mich/mir and dich/dir."}},
{type:"verb_table",title:"Accusative Reflexive Pronouns",groups:[{label:"Subject + reflexive pronoun",rows:[{pronoun:"ich",form:"mich",src:"myself"},{pronoun:"du",form:"dich",src:"yourself"},{pronoun:"er/sie/es",form:"sich",src:"himself/herself/itself"},{pronoun:"wir",form:"uns",src:"ourselves"},{pronoun:"ihr",form:"euch",src:"yourselves"},{pronoun:"sie/Sie",form:"sich",src:"themselves/yourself (formal)"}]},{label:"sich freuen (to be happy)",rows:[{pronoun:"ich",form:"freue mich",src:"I am happy"},{pronoun:"du",form:"freust dich",src:"you are happy"},{pronoun:"er/sie/es",form:"freut sich",src:"he/she/it is happy"},{pronoun:"wir",form:"freuen uns",src:"we are happy"},{pronoun:"ihr",form:"freut euch",src:"you all are happy"},{pronoun:"sie/Sie",form:"freuen sich",src:"they are / you (formal) are happy"}]}],note:"The reflexive pronoun sits right after the conjugated verb. In questions: 'Freust du dich?' Common reflexive verbs: sich freuen, sich treffen, sich anmelden, sich fühlen."},
{type:"mc",q:"'Ich freue mich auf das Fest.' What does 'mich' do in this sentence?",opts:["It means 'me' as a direct object","It is a reflexive pronoun referring back to 'ich'","It means 'my' as a possessive","It replaces a noun that was mentioned before"],ans:"It is a reflexive pronoun referring back to 'ich'",hint:"The verb 'sich freuen' always needs a word that refers back to the subject."},
{type:"fb",s:"Wir treffen {1} um 18 Uhr im Park.",a:["uns"],opts:["uns","sich","mich","euch"],hint:"Which reflexive pronoun matches the subject 'wir'?",sSrc:"We meet up at 6 PM in the park."},
{type:"mc",q:"'Er freut sich auf den Wettbewerb.' Which reflexive pronoun is correct for 'er'?",opts:["mich","dich","sich","uns"],ans:"sich",hint:"Third person (er, sie, es) always uses the same reflexive pronoun."},
{type:"fb",s:"Freust du {1} auf die Feier?",a:["dich"],opts:["dich","mich","sich","uns"],hint:"Which reflexive pronoun matches the subject 'du'?",sSrc:"Are you looking forward to the party?"},
{type:"teach",trg:"teilnehmen",src:"to participate / to take part",note:"Separable: ich nehme teil. 'An + Dativ' follows: 'am Wettbewerb teilnehmen.'",example:"A: Nimmst du am Wettbewerb teil?\nB: Ja, ich nehme teil!",exampleSrc:"A: Are you participating in the competition?\nB: Yes, I'm participating!",funFact:"'Teil' (part) + 'nehmen' (to take). Literally 'to take part.' English and German use the exact same logic here, word for word. Separable verbs split apart in main clauses: 'Ich nehme teil.'"},
{type:"teach",trg:"stattfinden",src:"to take place / to happen",note:"Separable: es findet statt. 'Das Fest findet am Samstag statt.'",example:"A: Wann findet das Fest statt?\nB: Es findet am Samstag statt.",exampleSrc:"A: When does the festival take place?\nB: It takes place on Saturday.",funFact:"'Statt' (place/instead) + 'finden' (to find). An event 'finds its place.' This verb is almost always used with events and is very common in formal announcements and newspapers."},
{type:"teach",trg:"organisieren",src:"to organize",note:"Regular verb: ich organisiere, du organisierst, er organisiert.",example:"A: Wer organisiert das Sommerfest?\nB: Mia organisiert alles!",exampleSrc:"A: Who is organizing the summer festival?\nB: Mia organizes everything!",funFact:"Borrowed from French 'organiser.' German happily borrows words from French for anything cultural, administrative, or fashionable. Organisieren, reservieren, telefonieren: the -ieren ending is always French-origin."},
{type:"story",speaker:"mia",mood:"formal",trg:"Punkt eins: Ich glaube, dass wir ein Sommerfest organisieren sollten. Wer nimmt teil?",src:"Point one: I believe that we should organize a summer festival. Who is participating?"},
{type:"tip",title:"dass-Clauses: Verb Goes to the End",text:"After 'dass' (that), the conjugated verb moves to the END of the clause.\n\nMain clause: Ich glaube + dass-clause: dass wir ein Fest organisieren.\n\nIch glaube, dass wir ein Fest organisieren.\nEr sagt, dass das Fest am Samstag stattfindet.\nWir wissen, dass Mia alles organisiert.\n\nCommon starters: glauben (believe), sagen (say), wissen (know), denken (think), hoffen (hope).\n\nThe comma before 'dass' is mandatory in German.",deepDive:{title:"The four verb-final triggers",text:"'dass' is not the only conjunction that sends the verb to the end. Four key conjunctions follow the same rule:\n\nweil = because (reason)\ndass = that (thought/report)\nwenn = if/when (condition/habit)\nob = whether (indirect question)\n\nAll follow the same pattern: conjunction + subject + ... + VERB at the end.\n\nOther subordinating conjunctions you will meet later (obwohl, als, bevor, nachdem, seitdem, damit) all follow this same verb-final rule. Learning it now builds the habit for all subordinate clauses."}},
{type:"mc",q:"'Ich glaube, dass das Fest am Samstag stattfindet.' Where is the verb in the dass-clause?",opts:["Right after the word dass","In the second position","At the end of the clause","Before the comma itself"],ans:"At the end of the clause",hint:"In dass-clauses, the conjugated verb always travels to one specific position."},
{type:"fb",s:"Er sagt, dass er sich auf die Veranstaltung {1}.",a:["freut"],opts:["freut","freuen","freue","freust"],hint:"The verb must agree with 'er' and must go at the end of the dass-clause.",sSrc:"He says that he is happy about the event."},
{type:"mc",q:"Which sentence correctly uses a dass-clause?",opts:["Ich denke, dass Mia das Fest organisiert.","Ich denke, dass organisiert Mia das Fest.","Ich denke, Mia dass das Fest organisiert.","Ich denke dass, Mia das Fest organisiert."],ans:"Ich denke, dass Mia das Fest organisiert.",hint:"After 'dass,' the verb must go to the very end. Check each option for verb position."},
{type:"drag_fill",s:"Wir wissen, {1} die Feier am Samstag {2}.",blanks:{"1":"dass","2":"stattfindet"},pool:["dass","stattfindet","findet","weil","statt"],hint:"The first blank needs the conjunction. The second needs the separable verb reunited at the end.",sSrc:"We know that the party takes place on Saturday."},
{type:"mc",q:"Mia says 'Ich hoffe, dass alle teilnehmen.' What does she hope?",opts:["That everyone organizes something","That everyone participates","That everyone leaves early","That everyone pays a fee"],ans:"That everyone participates",hint:"'Teilnehmen' means to take part in something."},
{type:"fb",s:"Hast du {1} auf den Wettbewerb?",a:["Lust"],opts:["Lust","Spaß","Fest","Interesse"],hint:"Which feminine noun means 'desire/mood' and pairs with 'haben auf'?",sSrc:"Do you feel like it for the competition?"},
{type:"drag_fill",s:"Ich {1} mich, dass du am Wettbewerb {2}.",blanks:{"1":"freue","2":"teilnimmst"},pool:["freue","teilnimmst","nimmst","freuen","teil"],hint:"The main clause needs the reflexive verb for 'ich.' The dass-clause needs the verb for 'du' at the end.",sSrc:"I am happy that you are participating in the competition."},
{type:"match",pairs:[{trg:"sich freuen",src:"to be happy"},{trg:"sich treffen",src:"to meet up"},{trg:"teilnehmen",src:"to participate"},{trg:"stattfinden",src:"to take place"},{trg:"organisieren",src:"to organize"},{trg:"die Veranstaltung",src:"the event"}]},
{type:"story",speaker:"verumius",mood:"amused",trg:"Okay, ich glaube, dass deutsche Vereine ernster sind als italienische. Aber ich freue mich, dass ich dabei bin!",src:"Okay, I believe that German clubs are more serious than Italian ones. But I'm happy that I'm part of it!"}
]}
,

{id:"deu_r9l4",title:"Ob oder dass?",icon:"📐",xp:20,board:true,steps:[
{type:"intro",title:"Ob oder dass?",desc:"Two powerful conjunctions unlock indirect speech: dass (that) introduces facts, ob (whether) introduces yes/no questions. Plus reflexive pronouns get their own dative forms, and you meet the ADUSO gang: five conjunctions that keep word order normal.",goals:["Reflexive pronouns: accusative vs dative","ob: indirect yes/no questions with verb-final","Coordinating conjunctions: und/oder/aber/denn/sondern (ADUSO)"]},
{type:"teach",trg:"sich verabreden",src:"to make a date / to arrange to meet",note:"Reflexive + separable. Ich verabrede mich mit Freunden.",example:"A: Verabredest du dich heute Abend?\nB: Ja, ich verabrede mich mit Lukas.",exampleSrc:"A: Are you meeting up tonight?\nB: Yes, I'm meeting up with Lukas.",funFact:"From 'Abrede' (agreement). Germans don't 'make plans,' they 'agree themselves.' The reflexive pronoun is essential: without 'sich,' it sounds like a legal contract."},
{type:"teach",trg:"sich unterhalten",src:"to chat / to converse",note:"Reflexive. Irregular: du unterhältst dich, er unterhält sich.",example:"A: Worüber unterhaltet ihr euch?\nB: Wir unterhalten uns über den Film.",exampleSrc:"A: What are you chatting about?\nB: We're chatting about the film.",funFact:"Literally 'to hold oneself under.' Also means 'to entertain.' 'Die Unterhaltung' = conversation OR entertainment. German efficiency: one word, two meanings."},
{type:"teach",trg:"diskutieren",src:"to discuss",note:"Regular, not reflexive. Diskutieren über + accusative.",example:"A: Wir diskutieren über das Spiel.\nB: Wer hat gewonnen?",exampleSrc:"A: We're discussing the game.\nB: Who won?",funFact:"Borrowed from Latin 'discutere' (to shake apart). Germans kept the Latin structure but gave it German endings. Easy cognate from English 'discuss.'"},
{type:"teach",trg:"vergessen",src:"to forget",note:"Irregular: du vergisst, er vergisst. Stem change e to i.",example:"A: Vergiss den Schlüssel nicht!\nB: Ich vergesse ihn nie!",exampleSrc:"A: Don't forget the key!\nB: I never forget it!",funFact:"The 'ver-' prefix often means 'wrongly' or 'away': verlaufen (get lost), versprechen (misspeak/promise). Vergessen = to 'get' something wrong in your memory."},
{type:"teach",trg:"verlieren",src:"to lose",note:"Irregular past, but regular present: ich verliere, du verlierst.",example:"A: Ich verliere immer meinen Schlüssel.\nB: Kauf dir eine Schlüsselbox!",exampleSrc:"A: I always lose my key.\nB: Buy yourself a key box!",funFact:"'Ver-' again! 'Verlieren' literally suggests something going astray. The opposite 'gewinnen' (to win) has no 'ver-' because winning is the normal state. Very German."},
{type:"teach",trg:"sich verlieben",src:"to fall in love",note:"Reflexive: ich verliebe mich in + accusative.",example:"A: Hast du dich schon mal verliebt?\nB: Ja, in meinen Hund!",exampleSrc:"A: Have you ever fallen in love?\nB: Yes, with my dog!",funFact:"Liebe = love. Sich verlieben = to love-ify yourself. The 'ver-' here means 'into a state.' You don't just love, you enter the STATE of loving. Very philosophical."},
{type:"teach",trg:"träumen",src:"to dream",note:"Regular: ich träume, du träumst. Träumen von + dative.",example:"A: Wovon träumst du?\nB: Ich träume von einer Reise nach Japan.",exampleSrc:"A: What do you dream about?\nB: I dream about a trip to Japan.",funFact:"'Der Traum' (the dream) shares a root with English 'dream.' In German you dream OF something (von), not ABOUT something. Preposition difference!"},
{type:"teach",trg:"sich ärgern",src:"to get annoyed / to be upset",note:"Reflexive: ich ärgere mich über + accusative (about).",example:"A: Warum ärgerst du dich?\nB: Ich ärgere mich über den Regen.",exampleSrc:"A: Why are you annoyed?\nB: I'm annoyed about the rain.",funFact:"'Ärger' = annoyance/trouble. Without 'sich,' ärgern means to annoy SOMEONE ELSE: 'Du ärgerst mich!' = You're annoying me! The reflexive flips the direction."},
{type:"tip",title:"Reflexive Pronouns: Accusative vs Dative",text:"Most reflexive verbs use ACCUSATIVE reflexive pronouns:\nich: mich, du: dich, er/sie/es: sich\nwir: uns, ihr: euch, sie/Sie: sich\n\nBut when there is ALSO a direct object, the reflexive switches to DATIVE:\nich: mir, du: dir, er/sie/es: sich\nwir: uns, ihr: euch, sie/Sie: sich\n\nCompare:\nIch wasche mich. (I wash myself. No other object.)\nIch wasche mir die Hände. (I wash my hands. Hände = acc object, so mir = dat.)\n\nOnly ich and du change: mich/mir, dich/dir. All others stay the same.",deepDive:{title:"When Does the Switch Happen?",text:"The rule is simple: a sentence can only have ONE accusative object. If the verb already has a direct object (die Hände, die Haare, die Zähne), the reflexive pronoun must step down to dative. This mostly matters with body parts and clothing:\nIch putze mir die Zähne. (I brush my teeth.)\nIch ziehe mir die Jacke an. (I put on my jacket.)\nIch kämme mir die Haare. (I comb my hair.)"}},
{type:"tip",title:"Separable Reflexive Verbs",text:"Some reflexive verbs are ALSO separable. The prefix splits off and goes to the end:\n\nsich anziehen: Ich ziehe mich an. (prefix 'an' at end)\nsich ausziehen: Ich ziehe mich aus. (prefix 'aus' at end)\nsich umziehen: Ich ziehe mich um. (prefix 'um' at end)\n\nThe reflexive pronoun stays right after the main verb.",deepDive:{title:"Separable reflexive verbs in Perfekt",text:"In Perfekt, separable reflexive verbs combine the ge- prefix:\nsich anziehen: Ich habe mich angezogen.\nsich ausziehen: Ich habe mich ausgezogen.\nge- goes between prefix and stem: an+ge+zogen = angezogen."}},
{type:"verb_table",title:"Dative Pronouns: Full Paradigm",label:"Personal pronouns across three cases",groups:[{label:"Singular",rows:[{pronoun:"1st sing.",form:"ich / mich / mir",src:"I / me (acc) / me (dat)"},{pronoun:"2nd sing. (informal)",form:"du / dich / dir",src:"you / you (acc) / you (dat)"},{pronoun:"3rd masc.",form:"er / ihn / ihm",src:"he / him (acc) / him (dat)"},{pronoun:"3rd fem.",form:"sie / sie / ihr",src:"she / her (acc) / her (dat)"},{pronoun:"3rd neut.",form:"es / es / ihm",src:"it / it (acc) / it (dat)"}]},{label:"Plural",rows:[{pronoun:"1st pl.",form:"wir / uns / uns",src:"we / us (acc) / us (dat)"},{pronoun:"2nd pl. (informal)",form:"ihr / euch / euch",src:"you all / you (acc) / you (dat)"},{pronoun:"3rd pl. / formal",form:"sie/Sie / sie/Sie / ihnen/Ihnen",src:"they/you / them/you (acc) / them/you (dat)"}]}],note:"Formal Sie (dative) = Ihnen (capital I).\nuns and euch are the same for accusative and dative.\nOnly ich and du change between acc and dat: mich/mir, dich/dir.",deepDive:{title:"A shortcut: uns and euch do double duty",text:"Uns is both accusative and dative for wir (we).\nEuch is both accusative and dative for ihr (you all).\n\nEr sieht uns. (He sees us, accusative)\nEr hilft uns. (He helps us, dative)\n\nSame form, context makes the case clear."}},
{type:"mc",q:"'Ich wasche ___ die Hände.' Which reflexive pronoun fits?",opts:["mir","mich","sich","dir"],ans:"mir",hint:"The hands are the accusative object. The reflexive must be dative."},
{type:"fb",s:"Ärgerst du {1} über das Wetter?",a:["dich"],opts:["dich","dir","mich","sich"],hint:"No other object here. The reflexive is accusative for du.",sSrc:"Are you annoyed about the weather?"},
{type:"teach",trg:"ob",src:"whether / if",note:"Subordinating conjunction. Sends the verb to the END.\nob + subject + ... + verb (last).",example:"A: Weißt du, ob er morgen kommt?\nB: Nein, ich bin mir nicht sicher.",exampleSrc:"A: Do you know whether he's coming tomorrow?\nB: No, I'm not sure.",funFact:"'Ob' turns a yes/no question into an indirect one. 'Kommt er?' becomes 'Ich frage mich, ob er kommt.' Same question, but embedded. The verb jumps to the end, just like with dass and weil."},
{type:"tip",title:"ob: Indirect Yes/No Questions",text:"'Ob' means 'whether' and turns a yes/no question into an indirect one.\nThe verb goes to the END after ob.\n\nDirect: Kommt er morgen?\nIndirect: Ich weiß nicht, ob er morgen kommt.\n\nCommon triggers for ob:\nfragen (to ask), wissen (to know), sicher sein (to be sure)\n\nCompare with dass (that), which states FACTS:\nIch weiß, dass er morgen kommt. (I know THAT he comes.)\nIch weiß nicht, ob er morgen kommt. (I don't know WHETHER he comes.)\n\ndass = certainty. ob = uncertainty.",deepDive:{title:"Dass vs Ob: The Quick Test",text:"Ask yourself: 'Can I answer this with yes or no?'\nIf YES: use ob.\nIch frage, ob du kommst. (Will you come? Yes/no.)\nIf NO: use dass.\nIch weiß, dass du kommst. (You're coming. Fact.)\n\nBoth send the verb to the end. The difference is certainty vs uncertainty."}},
{type:"mc",q:"'Ich frage mich, ___ er heute kommt.' Which conjunction fits?",opts:["ob","dass","weil","denn"],ans:"ob",hint:"He might come, he might not. You are uncertain."},
{type:"fb",s:"Weißt du, {1} das Kino heute offen ist?",a:["ob"],opts:["ob","dass","weil","und"],hint:"You genuinely don't know. Yes or no question hidden inside.",sSrc:"Do you know whether the cinema is open today?"},
{type:"tip",title:"Coordinating Conjunctions: ADUSO",text:"Five conjunctions that keep NORMAL word order (verb stays in position 2):\n\nA: aber (but)\nD: denn (because, in main clauses)\nU: und (and)\nS: sondern (but rather, after a negative)\nO: oder (or)\n\nThese connect two main clauses. The verb does NOT move.\nIch spiele Tennis, und er spielt Fußball.\nSie kommt nicht, sondern sie bleibt zu Hause.\n\nContrast with dass/ob/weil: those are SUBORDINATING and push the verb to the end.",deepDive:{title:"Aber vs Sondern",text:"Both mean 'but,' with different uses:\n\nAber = general contrast:\nIch bin müde, aber ich gehe ins Kino.\n\nSondern = correction after a negative:\nIch trinke nicht Kaffee, sondern Tee.\n(Not coffee, but RATHER tea.)\n\nSondern always follows 'nicht' or 'kein.' If there is no negation, use aber."}},
{type:"mc",q:"'Er kommt nicht aus Berlin, ___ aus Hamburg.' Which word corrects the false statement?",opts:["sondern","aber","denn","oder"],ans:"sondern",hint:"After 'nicht,' this conjunction replaces a wrong idea with the correct one."},
{type:"fb",s:"Ich möchte mitkommen, {1} ich habe keine Zeit.",a:["aber"],opts:["aber","sondern","denn","ob"],hint:"A general contrast. No negation before this conjunction.",sSrc:"I would like to come along, but I have no time."},
{type:"mc",q:"'Ich weiß, dass er sich verliebt hat.' What does 'dass' introduce here?",opts:["A fact he knows","A yes/no question","A reason","A time clause"],ans:"A fact he knows",hint:"There is certainty here. Dass introduces certainties, ob introduces doubt."},
{type:"drag_fill",s:"Ich frage mich, {1} sie {2} heute {3}.",blanks:{"1":"ob","2":"sich","3":"verabredet"},pool:["ob","sich","verabredet","dass","mich","verliebt"],hint:"Uncertain question: WHETHER she arranges to meet today. Verb to end.",sSrc:"I wonder whether she is meeting up today."},
{type:"mc",q:"'Ich putze mir die Zähne.' Why is it 'mir' and not 'mich'?",opts:["Zähne takes the accusative","Putzen always needs dative","Mir sounds more polite here","There is no real reason"],ans:"Zähne takes the accusative",hint:"A sentence can only have one direct object. The body part fills that role."},
{type:"fb",s:"Wir unterhalten {1} über den neuen Film.",a:["uns"],opts:["uns","euch","sich","mich"],hint:"Wir = we. The reflexive pronoun for wir is the same in acc and dat.",sSrc:"We are chatting about the new film."},
{type:"drag_fill",s:"Er fragt sie, {1} er weiß nicht, {2} sie ihn {3}.",blanks:{"1":"denn","2":"ob","3":"liebt"},pool:["denn","ob","liebt","dass","verliebt","aber"],hint:"He asks her BECAUSE (denn, V2 order) he doesn't know WHETHER she loves him.",sSrc:"He asks her because he does not know whether she loves him."},
{type:"mc",q:"Which conjunction keeps normal V2 word order?",opts:["und","dass","ob","weil"],ans:"und",hint:"ADUSO conjunctions: aber, denn, und, sondern, oder. All keep V2."},
{type:"fb",s:"Ich vergesse nie, {1} du mir geholfen hast.",a:["dass"],opts:["dass","ob","denn","und"],hint:"You know for certain she helped. This is a stated fact.",sSrc:"I never forget that you helped me."},
{type:"drag_fill",s:"Sie {1} sich, {2} sie morgen frei {3}.",blanks:{"1":"fragt","2":"ob","3":"hat"},pool:["fragt","ob","hat","weiß","dass","ist"],hint:"She asks herself WHETHER she has tomorrow off. Verb to end after ob.",sSrc:"She asks herself whether she has tomorrow off."},
{type:"mc",q:"'Ich ärgere mich, denn er vergisst alles.' What does 'denn' mean here?",opts:["because (reason)","but (contrast)","whether (doubt)","that (fact)"],ans:"because (reason)",hint:"Denn explains the cause while keeping main clause word order."},
{type:"match",pairs:[{trg:"sich verabreden",src:"to arrange to meet"},{trg:"sich unterhalten",src:"to chat"},{trg:"vergessen",src:"to forget"},{trg:"sich verlieben",src:"to fall in love"},{trg:"ob",src:"whether"},{trg:"sondern",src:"but rather"}]}
]}
,

{id:"deu_r9l5",title:"Digital und analog",icon:"📱",xp:15,board:true,steps:[
{type:"intro",title:"Digital und analog",desc:"Verumius discovers German media culture: from blogs and podcasts to paper magazines and comic books. The old and the new, side by side.",goals:["Learn 14 words for media and digital life","Review reflexive verbs with sich","Practice dass and ob subordinate clauses"]},
{type:"teach",trg:"der Blog",src:"the blog",note:"Masculine noun. Plural: die Blogs. Borrowed from English.",example:"A: Liest du einen Blog über Kochen?\nB: Ja, ich lese jeden Tag einen neuen Blog.",exampleSrc:"A: Do you read a blog about cooking?\nB: Yes, I read a new blog every day.",funFact:"Germans adopted 'Blog' directly from English but gave it a masculine article. Some Germans say 'das Blog' (neuter), which causes fierce grammar debates online."},
{type:"teach",trg:"das E-Book",src:"the e-book",note:"Neuter noun. Plural: die E-Books. Pronounced like English.",example:"A: Liest du lieber E-Books oder Bücher?\nB: Ich lese lieber E-Books, weil sie leichter sind.",exampleSrc:"A: Do you prefer reading e-books or books?\nB: I prefer e-books because they are lighter.",funFact:"Germany has a fixed book price law (Buchpreisbildung). Every bookstore must sell the same book at the same price. E-Books are included since 2016."},
{type:"teach",trg:"der Comic",src:"the comic",note:"Masculine noun. Plural: die Comics.",example:"A: Hast du als Kind Comics gelesen?\nB: Ja, ich habe viele Comics gesammelt.",exampleSrc:"A: Did you read comics as a child?\nB: Yes, I collected many comics.",funFact:"Germany's most famous comic is 'Werner,' about a plumber and his motorcycle. Asterix is also hugely popular in German translation, with brilliant wordplay."},
{type:"teach",trg:"die Sendung",src:"the TV show / broadcast",note:"Feminine noun. Plural: die Sendungen. From 'senden' (to send/broadcast).",example:"A: Welche Sendung schaust du heute Abend?\nB: Ich schaue eine Sendung über Natur.",exampleSrc:"A: Which show are you watching tonight?\nB: I'm watching a show about nature.",funFact:"'Sendung mit der Maus' is Germany's most beloved children's show, running since 1971. The orange mouse explains how things work. Even adults watch it."},
{type:"teach",trg:"die Zeitschrift",src:"the magazine",note:"Feminine noun. Plural: die Zeitschriften. Compound: Zeit (time) + Schrift (writing).",example:"A: Kaufst du noch Zeitschriften?\nB: Nein, ich lese alles online.",exampleSrc:"A: Do you still buy magazines?\nB: No, I read everything online.",funFact:"Zeit + Schrift = time-writing. A magazine captures a moment in time. Der Spiegel and Stern are Germany's most famous magazines, read in every doctor's waiting room."},
{type:"teach",trg:"das Programm",src:"the program / schedule",note:"Neuter noun. Plural: die Programme. Also means TV schedule.",example:"A: Was kommt heute im Programm?\nB: Um acht kommt eine neue Sendung.",exampleSrc:"A: What is on the schedule today?\nB: At eight there is a new show.",funFact:"Germans still say 'Was kommt im Programm?' when asking what is on TV. The word covers software, TV listings, theater schedules, and political platforms."},
{type:"mc",q:"Verumius fragt: 'Was kommt heute im Programm?' What is he asking about?",opts:["What is on TV tonight","What software to install","What is for dinner","When the train leaves"],ans:"What is on TV tonight",hint:"'Programm' here refers to the broadcast schedule."},
{type:"fb",s:"Ich lese eine {1} über Reisen.",a:["Zeitschrift"],opts:["Zeitschrift","Sendung","Blog","Programm"],hint:"Which feminine noun means a printed magazine you can hold?",sSrc:"I read a magazine about travel."},
{type:"teach",trg:"das Radio",src:"the radio",note:"Neuter noun. Plural: die Radios.",example:"A: Hörst du Radio im Auto?\nB: Ja, ich höre immer Radio beim Fahren.",exampleSrc:"A: Do you listen to the radio in the car?\nB: Yes, I always listen to the radio while driving.",funFact:"German public radio is funded by the Rundfunkbeitrag, a monthly fee every household pays (about 18 euros). Germans debate this fee as passionately as the weather."},
{type:"teach",trg:"der Tipp",src:"the tip / piece of advice",note:"Masculine noun. Plural: die Tipps. Borrowed from English.",example:"A: Hast du einen Tipp für mich?\nB: Ja, informiere dich vorher im Internet.",exampleSrc:"A: Do you have a tip for me?\nB: Yes, inform yourself beforehand on the internet.",funFact:"Germans spell it with double 'p' unlike English 'tip.' The word entered German in the 19th century from English horse racing jargon."},
{type:"teach",trg:"das Heft",src:"the notebook / issue (of a magazine)",note:"Neuter noun. Plural: die Hefte. Two meanings depending on context.",example:"A: Hast du das neue Heft gekauft?\nB: Nein, ich kaufe keine Hefte mehr.",exampleSrc:"A: Did you buy the new issue?\nB: No, I don't buy issues anymore.",funFact:"Every German schoolchild has a Heft for each subject: Matheheft, Deutschheft, Englischheft. The word originally meant a handle (what you 'hold'), then shifted to a bound booklet."},
{type:"mc",q:"'Das Heft' can mean two things. Which pair is correct?",opts:["Notebook and issue","Book and a letter","Blog and an email","Radio and a show"],ans:"Notebook and issue",hint:"Think about what you write in at school and what you buy at a newsstand."},
{type:"teach",trg:"fotografieren",src:"to photograph",note:"Regular: ich fotografiere, du fotografierst. Past: fotografiert (no ge- prefix).",example:"A: Fotografierst du gern?\nB: Ja, ich fotografiere am liebsten Landschaften.",exampleSrc:"A: Do you like photographing?\nB: Yes, I like photographing landscapes the most.",funFact:"Like all -ieren verbs (studieren, telefonieren, informieren), fotografieren skips the ge- prefix in past tense: 'Ich habe fotografiert,' never 'gefotografiert.'"},
{type:"teach",trg:"chatten",src:"to chat (online)",note:"Regular: ich chatte, du chattest. Past: gechattet.",example:"A: Mit wem chattest du?\nB: Ich chatte mit meiner Schwester.",exampleSrc:"A: Who are you chatting with?\nB: I'm chatting with my sister.",funFact:"Unlike -ieren verbs, 'chatten' DOES get the ge- prefix: gechattet. Why? Because it was borrowed recently and conjugated like a regular German verb, not through French/Latin."},
{type:"teach",trg:"surfen",src:"to surf (the internet)",note:"Regular: ich surfe, du surfst. 'Im Internet surfen' = to browse the web.",example:"A: Was machst du gerade?\nB: Ich surfe im Internet.",exampleSrc:"A: What are you doing right now?\nB: I'm surfing the internet.",funFact:"Germans say 'im Internet surfen' like riding waves of information. The verb keeps its English pronunciation but gets German endings: surfe, surfst, surft."},
{type:"teach",trg:"sammeln",src:"to collect",note:"Regular: ich sammle, du sammelst. Past: gesammelt.",example:"A: Was sammelst du?\nB: Ich sammle alte Comics und Briefmarken.",exampleSrc:"A: What do you collect?\nB: I collect old comics and stamps.",funFact:"Germans are serious collectors. Briefmarkensammler (stamp collectors), Münzsammler (coin collectors), and Bierdeckelsammler (beer coaster collectors) all have dedicated clubs and meetups."},
{type:"teach",trg:"informieren",src:"to inform",note:"Regular: ich informiere. Reflexive: sich informieren = to find out, to inform oneself.",example:"A: Wo informierst du dich über Nachrichten?\nB: Ich informiere mich online.",exampleSrc:"A: Where do you get your news?\nB: I inform myself online.",funFact:"'Sich informieren' is reflexive: you inform YOURSELF. Germans love reflexive verbs for actions you do for your own benefit: sich erinnern, sich freuen, sich informieren."},
{type:"mc",q:"'Ich informiere mich im Internet.' Why is 'mich' in this sentence?",opts:["Because informieren is used reflexively here","Because the internet requires accusative","Because ich always needs mich","Because it is a question"],ans:"Because informieren is used reflexively here",hint:"The action of informing loops back to the subject. Think: I inform MYSELF."},
{type:"fb",s:"Er {1} sich über das Programm.",a:["informiert"],opts:["informiert","informieren","informiere","informierst"],hint:"Third person singular: er + verb. Which ending fits?",sSrc:"He informs himself about the program."},
{type:"mc",q:"Mia sagt, dass sie jeden Tag einen Blog ___.",opts:["liest","lesen","lese","lest"],ans:"liest",hint:"In a dass-clause the verb goes to the end. Mia is 'sie,' so the verb needs the third person form."},
{type:"fb",s:"Ich weiß nicht, ob er gern {1}.",a:["chattet"],opts:["chattet","chatten","chatte","chattest"],hint:"After 'ob' the verb moves to the end. The subject is 'er.'",sSrc:"I don't know if he likes to chat."},
{type:"drag_fill",s:"Sie fragt, ob Verumius {1} gern {2} und ob er Zeitschriften {3}.",blanks:{"1":"sich","2":"informiert","3":"sammelt"},pool:["sich","informiert","sammelt","mich","surft","chatten"],hint:"First clause: reflexive 'sich informieren' with verb at end. Second clause: 'sammeln' with er-form at end.",sSrc:"She asks whether Verumius likes to inform himself and whether he collects magazines."},
{type:"mc",q:"How do you form the Partizip II of verbs ending in -ieren?",opts:["No ge- prefix: just stem + t","Normal ge- prefix: ge + stem + t","Double ge-: gege + stem + t","No change at all"],ans:"No ge- prefix: just stem + t",hint:"Think about studieren, telefonieren, informieren. They all follow the same pattern."},
{type:"fb",s:"Er sagt, dass er alte Comics {1}.",a:["sammelt"],opts:["sammelt","sammeln","sammle","gesammelt"],hint:"In a dass-clause the conjugated verb goes to the end. Subject is 'er.'",sSrc:"He says that he collects old comics."},
{type:"mc",q:"Verumius surft im Internet. Er findet einen Blog. Was macht er?",opts:["He browses online and finds a blog","He goes surfing at the beach","He collects magazines","He listens to the radio"],ans:"He browses online and finds a blog",hint:"'Im Internet surfen' means browsing, not ocean waves."},
{type:"drag_fill",s:"Lukas erzählt, dass er {1} für Sendungen über Natur {2} und dass er Tipps im {3} gehört hat.",blanks:{"1":"sich","2":"interessiert","3":"Radio"},pool:["sich","interessiert","Radio","mich","informiert","Blog"],hint:"Reflexive 'sich interessieren' in the first dass-clause. He heard tips on which device?",sSrc:"Lukas tells us that he is interested in shows about nature and that he heard tips on the radio."},
{type:"match",pairs:[{trg:"der Blog",src:"the blog"},{trg:"die Sendung",src:"the TV show"},{trg:"das Radio",src:"the radio"},{trg:"fotografieren",src:"to photograph"},{trg:"chatten",src:"to chat online"},{trg:"sammeln",src:"to collect"},{trg:"die Zeitschrift",src:"the magazine"}]},
{type:"teach",trg:"der Fotoapparat",src:"the camera (old style)",note:"Masculine compound: Foto + Apparat. Plural: die Fotoapparate.",example:"A: Hast du deinen Fotoapparat dabei?\nB: Nein, ich fotografiere nur mit dem Handy.\nA: Mein Opa hat noch einen alten Fotoapparat.",exampleSrc:"A: Do you have your camera with you?\nB: No, I only take photos with my phone.\nA: My grandpa still has an old camera.",funFact:"Before digital cameras, every German family had a Fotoapparat for vacations. Leica, a German brand, invented the 35mm camera in 1925."},
{type:"teach",trg:"die Kamera",src:"the camera",note:"Feminine. Plural: die Kameras. Modern, general word for camera.",example:"A: Welche Kamera benutzt du?\nB: Eine kleine Digitalkamera.\nA: Die Fotos sind wirklich gut!",exampleSrc:"A: Which camera do you use?\nB: A small digital camera.\nA: The photos are really good!",funFact:"Germany's camera industry shaped photography worldwide. Zeiss lenses, Leica cameras, and Rollei twin-lens reflexes were all born in Germany."},
{type:"teach",trg:"online",src:"online",note:"Adverb and adjective. Pronounced like English. Online sein = to be online.",example:"A: Bist du gerade online?\nB: Ja, ich surfe im Internet.\nA: Schick mir den Link!",exampleSrc:"A: Are you online right now?\nB: Yes, I'm surfing the internet.\nA: Send me the link!",funFact:"Germans adopted 'online' wholesale from English. The phrase 'online gehen' (to go online) is used by all generations."},
{type:"teach",trg:"das Buch",src:"the book",note:"Neuter. Plural: die Bücher (with Umlaut!).",example:"A: Was liest du gerade?\nB: Ein Buch über deutsche Geschichte.\nA: Klingt interessant! Leihst du es mir?",exampleSrc:"A: What are you reading?\nB: A book about German history.\nA: Sounds interesting! Will you lend it to me?",funFact:"Germany publishes about 70,000 new books per year, making it the third largest book market in the world after the US and China."},
{type:"teach",trg:"ausleihen",src:"to borrow / to lend out",note:"Separable: ich leihe aus. Perfekt: hat ausgeliehen. In der Bibliothek Bücher ausleihen.",example:"A: Kann ich das Buch ausleihen?\nB: Ja, du kannst es zwei Wochen behalten.\nA: Danke! Ich bringe es pünktlich zurück.",exampleSrc:"A: Can I borrow the book?\nB: Yes, you can keep it for two weeks.\nA: Thanks! I'll bring it back on time.",funFact:"German libraries are very popular. Over 200 million items are borrowed per year. Many now also lend e-books, video games, and even kitchen appliances."}
]}
,

// U9 L6: Nach dem Lauf - Story climax (post-run park scene)
{id:"deu_r9l6",title:"Nach dem Lauf",icon:"☕",xp:20,board:true,steps:[
{type:"intro",title:"Nach dem Lauf",desc:"The run is over. Verumius stretches in the park while Lukas arrives with coffees on his cargo bike. A text from Dr. Yilmaz reminds everyone why community matters.",goals:["Learn animal and leisure vocabulary","Review reflexive verbs, dass, ob, and conjunctions","Combine multiple grammar patterns in real conversation"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-park-stretching",trg:"Sonntagmorgen im Park. Verumius dehnt sich auf einer Bank. Die Luft riecht nach Gras und Kaffee. Ein Vogel singt in der Eiche über ihm.",src:"Sunday morning in the park. Verumius stretches on a bench. The air smells of grass and coffee. A bird sings in the oak above him."},
{type:"story",speaker:"verumius",trg:"Ich fühle mich großartig! Aber meine Beine tun weh. Ich muss mich mehr dehnen.",src:"I feel great! But my legs hurt. I need to stretch more."},
{type:"story",speaker:"lukas",trg:"Hey, Verumius! Ich habe Kaffee mitgebracht. Setz dich hin und trink! Ich glaube, dass du den verdient hast.",src:"Hey, Verumius! I brought coffee. Sit down and drink! I think that you earned it."},
{type:"teach",trg:"die Katze",src:"the cat",note:"Feminine. Plural: die Katzen.",example:"A: Hast du ein Haustier?\nB: Ja, ich habe eine Katze. Sie heißt Mimi.",exampleSrc:"A: Do you have a pet?\nB: Yes, I have a cat. Her name is Mimi.",funFact:"Germany has about 15 million pet cats, making them the most popular pet. The idiom 'die Katze im Sack kaufen' (to buy the cat in the bag) means to buy something sight unseen."},
{type:"teach",trg:"der Vogel",src:"the bird",note:"Masculine. Plural: die Vögel (with Umlaut!).",example:"A: Hörst du den Vogel?\nB: Ja, er singt wunderschön!",exampleSrc:"A: Do you hear the bird?\nB: Yes, it sings beautifully!",funFact:"'Einen Vogel haben' (to have a bird) means to be crazy in German. People tap their forehead to show someone 'hat einen Vogel.' Careful with this gesture!"},
{type:"teach",trg:"das Pferd",src:"the horse",note:"Neuter. Plural: die Pferde.",example:"A: Warst du schon mal auf einem Pferd?\nB: Nein, aber ich möchte es versuchen.",exampleSrc:"A: Have you ever been on a horse?\nB: No, but I would like to try.",funFact:"German has a great expression: 'Das beste Pferd im Stall' (the best horse in the stable) means the top performer. Germany's equestrian tradition runs deep."},
{type:"teach",trg:"das Tier",src:"the animal",note:"Neuter. Plural: die Tiere. From Old High German 'tior.'",example:"A: Was ist dein Lieblingstier?\nB: Ich mag Hunde, aber auch Katzen.",exampleSrc:"A: What is your favorite animal?\nB: I like dogs, but also cats.",funFact:"The German word 'Tierarzt' (animal doctor) is wonderfully literal. 'Tierschutz' (animal protection) is taken very seriously in Germany, with animal welfare written into the constitution since 2002."},
{type:"mc",q:"Lukas fragt: 'Hast du ein Haustier?' Verumius sagt: 'Ja, eine Katze.' Was ist eine Katze?",opts:["a dog","a bird","a cat","a horse"],ans:"a cat",hint:"This feminine noun names a popular pet that purrs."},
{type:"fb",s:"Im Park singt ein {1} im Baum.",a:"Vogel",opts:["Vogel","Pferd","Katze","Tier"],hint:"Which masculine animal is known for singing from branches?",sSrc:"In the park a bird sings in the tree."},
{type:"teach",trg:"der Park",src:"the park",note:"Masculine. Plural: die Parks. Borrowed from English/French.",example:"A: Wo treffen wir uns?\nB: Im Park, neben der großen Eiche.",exampleSrc:"A: Where do we meet?\nB: In the park, next to the big oak.",funFact:"Berlin alone has over 2,500 public parks. The Tiergarten (animal garden) in Berlin was originally a royal hunting ground. Now it is the city's green lung."},
{type:"teach",trg:"die Tour",src:"the tour",note:"Feminine. Plural: die Touren. Also means 'a trip' or 'a route.'",example:"A: Machen wir am Samstag eine Radtour?\nB: Gute Idee! Ich freue mich darauf.",exampleSrc:"A: Shall we do a bike tour on Saturday?\nB: Good idea! I look forward to it.",funFact:"'Radtour' (bike tour), 'Wandertour' (hiking tour), 'Stadttour' (city tour). Germans love compound nouns, and they love organized outings even more."},
{type:"teach",trg:"der Workshop",src:"the workshop",note:"Masculine. Plural: die Workshops. Anglicism used in German.",example:"A: Ich besuche einen Workshop über Fotografie.\nB: Das klingt interessant!",exampleSrc:"A: I am attending a workshop on photography.\nB: That sounds interesting!",funFact:"Germans borrow many English words but pronounce them differently. 'Workshop' becomes 'VORK-shop' with a German W. The original German word is 'Werkstatt,' but Workshop sounds trendier."},
{type:"teach",trg:"der Zirkus",src:"the circus",note:"Masculine. Plural: die Zirkusse.",example:"A: Warst du schon im Zirkus?\nB: Ja, als Kind. Ich fand die Tiere toll.",exampleSrc:"A: Have you been to the circus?\nB: Yes, as a child. I loved the animals.",funFact:"The famous Circus Roncalli in Germany stopped using real animals in 2018 and replaced them with holograms. Technology meets tradition!"},
{type:"teach",trg:"der Zoo",src:"the zoo",note:"Masculine. Short for 'der Zoologische Garten.'",example:"A: Gehen wir morgen in den Zoo?\nB: Ja, ich möchte die Elefanten sehen.",exampleSrc:"A: Shall we go to the zoo tomorrow?\nB: Yes, I want to see the elephants.",funFact:"The Berlin Zoo, opened in 1844, is the oldest zoo in Germany and one of the most species-rich in the world, with over 20,000 animals."},
{type:"teach",trg:"der Krimi",src:"the crime novel / thriller",note:"Masculine. Short for 'der Kriminalroman.' Plural: die Krimis.",example:"A: Was liest du gerade?\nB: Einen Krimi von Sebastian Fitzek. Sehr spannend!",exampleSrc:"A: What are you reading right now?\nB: A thriller by Sebastian Fitzek. Very exciting!",funFact:"Germans love their Krimis. The TV show 'Tatort' (crime scene) has been running since 1970 and is a Sunday night ritual. Bars even host Tatort viewing parties."},
{type:"story",speaker:"verumius",trg:"Lukas, ich habe eine Nachricht von Dr. Yilmaz bekommen. Sie schreibt, dass Gemeinschaft das Wichtigste ist. Ob wir nächste Woche zusammen eine Tour machen?",src:"Lukas, I got a message from Dr. Yilmaz. She writes that community is the most important thing. Whether we should do a tour together next week?"},
{type:"story",speaker:"lukas",trg:"Natürlich! Und ich bringe Kaffee mit, denn ohne Kaffee läuft bei mir nichts.",src:"Of course! And I will bring coffee, because without coffee nothing works for me."},
{type:"mc",q:"Verumius sagt, dass Dr. Yilmaz über Gemeinschaft schreibt. Welcher Nebensatz ist richtig?",opts:["Sie schreibt, dass Gemeinschaft wichtig ist.","Sie schreibt, dass ist Gemeinschaft wichtig.","Sie schreibt, dass wichtig Gemeinschaft ist.","Sie schreibt, ist dass Gemeinschaft wichtig."],ans:"Sie schreibt, dass Gemeinschaft wichtig ist.",hint:"In a dass clause, the conjugated verb moves to the very end."},
{type:"fb",s:"Ich frage mich, {1} der Zoo am Sonntag offen ist.",a:"ob",opts:["ob","dass","weil","denn"],hint:"Which conjunction introduces an indirect yes/no question?",sSrc:"I wonder whether the zoo is open on Sunday."},
{type:"drag_fill",s:"Lukas sagt, {1} er {2} auf die Tour {3}.",blanks:{1:"dass",2:"sich",3:"freut"},pool:["dass","sich","freut","ob","mich","lacht"],hint:"'Sich freuen' is reflexive. In a dass clause, the verb goes to the end.",sSrc:"Lukas says that he is looking forward to the tour."},
{type:"mc",q:"'Ich interessiere mich für Krimis, und Lukas interessiert sich für Sport.' What connects these two clauses?",opts:["und","aber","denn","oder"],ans:"und",hint:"Both facts are true and simply added together without contrast."},
{type:"fb",s:"Die Katze schläft, {1} sie müde ist.",a:"weil",opts:["weil","und","oder","denn"],hint:"This subordinating conjunction means 'because' and sends the verb to the end.",sSrc:"The cat is sleeping because it is tired."},
{type:"drag_fill",s:"Er fragt, {1} sie {2} für Pferde {3}.",blanks:{1:"ob",2:"sich",3:"interessiert"},pool:["ob","sich","interessiert","dass","mich","fragt"],hint:"Indirect yes/no question with a reflexive verb. Verb goes last.",sSrc:"He asks whether she is interested in horses."},
{type:"mc",q:"Welcher Satz kombiniert 'sich fühlen' und 'denn' korrekt?",opts:["Ich fühle mich gut, denn ich habe Sport gemacht.","Ich mich fühle gut, denn ich habe Sport gemacht.","Ich fühle mich gut, denn ich Sport gemacht habe.","Ich fühle gut mich, denn ich habe Sport gemacht."],ans:"Ich fühle mich gut, denn ich habe Sport gemacht.",hint:"'Denn' is a coordinating conjunction, so the word order after it stays normal (verb second)."},
{type:"fb",s:"Sie ärgert {1} über den Lärm im Park.",a:"sich",opts:["sich","mich","dich","uns"],hint:"Third person reflexive pronoun for 'she' in a reflexive verb.",sSrc:"She is annoyed about the noise in the park."},
{type:"mc",q:"'Verumius weiß nicht, ob er morgen eine Radtour macht oder ob er in den Zoo geht.' How many ob clauses are in this sentence?",opts:["One","Two","Three","None"],ans:"Two",hint:"Count the word 'ob.' Each one opens a new indirect question."},
{type:"drag_fill",s:"Er {1} sich, {2} der Krimi spannend ist, {3} er ihn lesen will.",blanks:{1:"fragt",2:"ob",3:"denn"},pool:["fragt","ob","denn","dass","freut","weil"],hint:"He asks himself (reflexive), whether... because... Two different conjunctions needed.",sSrc:"He asks himself whether the thriller is exciting, because he wants to read it."},
{type:"match",pairs:[{trg:"die Katze",src:"the cat"},{trg:"der Vogel",src:"the bird"},{trg:"das Pferd",src:"the horse"},{trg:"das Tier",src:"the animal"},{trg:"der Park",src:"the park"},{trg:"der Krimi",src:"the thriller"}]},
{type:"teach",trg:"die Gemeinschaft",src:"the community",note:"Feminine. From gemein (common) + -schaft (collective suffix). Plural: die Gemeinschaften.",example:"A: Die Gemeinschaft im Verein ist toll.\nB: Ja, alle helfen sich gegenseitig.\nA: Das ist das Beste am Vereinsleben.",exampleSrc:"A: The community in the club is great.\nB: Yes, everyone helps each other.\nA: That's the best thing about club life.",funFact:"Gemeinschaft vs. Gesellschaft is a famous sociological contrast coined by Ferdinand Tonnies in 1887. Gemeinschaft is warm personal bonds, Gesellschaft is formal society."},
{type:"teach",trg:"interessieren (sich)",src:"to be interested (in)",note:"Reflexive: sich interessieren für + accusative. Ich interessiere mich für Musik.",example:"A: Wofür interessierst du dich?\nB: Ich interessiere mich für Fotografie.\nA: Dann musst du die Ausstellung sehen!",exampleSrc:"A: What are you interested in?\nB: I'm interested in photography.\nA: Then you have to see the exhibition!",funFact:"Like many German reflexive verbs, the meaning changes with 'sich.' Without it, 'interessieren' means to interest someone else: Das interessiert mich (That interests me)."},
{type:"teach",trg:"leihen",src:"to lend / to borrow",note:"Irregular: ich leihe, du leihst. Past: geliehen. Not separable (unlike ausleihen).",example:"A: Kannst du mir zehn Euro leihen?\nB: Klar, hier bitte.\nA: Danke! Ich gebe es dir morgen zurück.",exampleSrc:"A: Can you lend me ten euros?\nB: Sure, here you go.\nA: Thanks! I'll give it back tomorrow.",funFact:"Leihen is the base verb. Add prefixes for nuance: ausleihen (borrow from a library), verleihen (to award/bestow), entleihen (formal borrowing)."},
{type:"teach",trg:"komisch",src:"funny / weird",note:"Adjective. Can mean 'funny' (humor) or 'strange' (suspicious). Context decides.",example:"A: Der Film war sehr komisch.\nB: Lustig komisch oder seltsam komisch?\nA: Beides!",exampleSrc:"A: The film was very funny/weird.\nB: Funny-funny or strange-funny?\nA: Both!",funFact:"Komisch comes from Greek 'komikos' (of comedy). In German it drifted to also mean 'strange.' If someone says 'Das ist komisch,' check their face to know which meaning."},
{type:"teach",trg:"sympathisch",src:"likeable / nice (personality)",note:"Adjective. Er ist sehr sympathisch = He is very likeable. Not 'sympathetic' (=mitfühlend)!",example:"A: Wie findest du den neuen Trainer?\nB: Er ist sehr sympathisch!\nA: Ja, er lacht viel.",exampleSrc:"A: What do you think of the new trainer?\nB: He is very likeable!\nA: Yes, he laughs a lot.",funFact:"False friend alert! German 'sympathisch' means likeable, not sympathetic. If you want to say sympathetic, use 'mitfühlend' or 'verständnisvoll.'"}
]},

{id:"deu_r9l7",title:"Vereinsprüfung",icon:"✅",xp:25,board:true,steps:[
{type:"mc",q:"Ich freue mich, ___ das Konzert heute Abend stattfindet.",opts:["dass","ob","weil","denn"],ans:"dass",hint:"You know for certain it's happening."},
{type:"mc",q:"Er fragt sich, ___ das Training heute ausfällt.",opts:["ob","dass","weil","aber"],ans:"ob",hint:"He's uncertain and wants to find out."},
{type:"fb",s:"Sie {1} sich jeden Samstag im Park zum Joggen.",a:"treffen",opts:["treffen","freuen","ärgern","unterhalten"],hint:"They come together at a location.",sSrc:"They meet up every Saturday in the park for jogging."},
{type:"mc",q:"Wir ___ uns über die Ausstellung im Museum.",opts:["unterhalten","verlieren","vergessen","trainieren"],ans:"unterhalten",hint:"Think about having a conversation."},
{type:"fb",s:"Er hat Lust, Gitarre zu spielen, {1} er hat kein Instrument.",a:"aber",opts:["aber","dass","ob","denn"],hint:"A contrast between wanting and not having.",sSrc:"He feels like playing guitar, but he has no instrument."},
{type:"drag_fill",s:"Ich weiß, {1} sie {2} für Kunst interessiert.",blanks:{"1":"dass","2":"sich"},pool:["dass","ob","sich","mich","denn"],hint:"She has interest in art. Which conjunction for a known fact?",sSrc:"I know that she is interested in art."},
{type:"mc",q:"___ du dich für den Wettbewerb anmelden möchtest, musst du morgen kommen.",opts:["Ob","Dass","Falls","Denn"],ans:"Falls",hint:"This is a conditional: if you want to sign up..."},
{type:"match",pairs:[{trg:"sich freuen",src:"to be happy/excited"},{trg:"sich treffen",src:"to meet up"},{trg:"sich ärgern",src:"to be annoyed"},{trg:"sich verlieben",src:"to fall in love"},{trg:"sich verabreden",src:"to make plans to meet"}]},
{type:"fb",s:"Hast du {1}, das Heft mitzubringen?",a:"vergessen",opts:["vergessen","verloren","geträumt","organisiert"],hint:"You were supposed to bring it but didn't remember.",sSrc:"Did you forget to bring the notebook?"},
{type:"mc",q:"Sie träumt davon, in einem Zirkus zu arbeiten, ___ sie liebt Tiere.",opts:["denn","dass","ob","sich"],ans:"denn",hint:"This gives the reason. A coordinating conjunction."},
{type:"drag_fill",s:"Er fragt, {1} wir {2} am Samstag im Theater treffen.",blanks:{"1":"ob","2":"uns"},pool:["ob","dass","uns","sich","euch"],hint:"He's unsure about the plan. Which pronoun for 'wir'?",sSrc:"He asks whether we meet up at the theater on Saturday."},
{type:"fb",s:"Die Veranstaltung {1} nächsten Freitag im Museum statt.",a:"findet",opts:["findet","nimmt","macht","gibt"],hint:"A separable verb meaning 'to take place'.",sSrc:"The event takes place next Friday at the museum."},
{type:"mc",q:"Ich interessiere ___ für Musik und Kultur.",opts:["mich","sich","dich","uns"],ans:"mich",hint:"The reflexive pronoun must match 'ich'."},
{type:"mc",q:"Er sagt, dass er gern Comics ___ und im Internet surft.",opts:["sammelt","sammeln","gesammelt","sammelst"],ans:"sammelt",hint:"After 'dass', the verb goes to the end, conjugated."},
{type:"drag_fill",s:"Wir nehmen an der Tour teil {1} fotografieren die Vögel im Park, {2} das Wetter ist schön.",blanks:{"1":"und","2":"denn"},pool:["und","aber","denn","dass","ob"],hint:"Two coordinating conjunctions (ADUSO): one connects actions, one gives a reason. Denn keeps normal V2 word order.",sSrc:"We do the tour and photograph the birds in the park, because the weather is nice."},
{type:"fb",s:"Sie ärgert {1} über die Sendung im Radio.",a:"sich",opts:["sich","mich","dich","euch"],hint:"The reflexive pronoun matches 'sie' (she).",sSrc:"She is annoyed about the show on the radio."},
{type:"mc",q:"Weißt du, ___ der Workshop morgen stattfindet ___ am Wochenende?",opts:["ob ... oder","dass ... und","ob ... denn","dass ... aber"],ans:"ob ... oder",hint:"Asking between two possibilities you're unsure about."},
{type:"match",pairs:[{trg:"das Konzert",src:"the concert"},{trg:"die Zeitschrift",src:"the magazine"},{trg:"der Wettbewerb",src:"the competition"},{trg:"die Bibliothek",src:"the library"},{trg:"die Mannschaft",src:"the team"}]},
{type:"drag_fill",s:"Sie informiert {1}, {2} der Krimi heute Abend im Programm ist.",blanks:{"1":"sich","2":"ob"},pool:["sich","mich","ob","dass","denn"],hint:"She checks for herself whether something is on tonight.",sSrc:"She checks whether the thriller is on tonight."},
{type:"fb",s:"Ich weiß, {1} er jeden Tag auf dem Sportplatz trainiert.",a:"dass",opts:["dass","ob","denn","aber"],hint:"You're stating a fact you're certain about.",sSrc:"I know that he trains on the sports field every day."},
{type:"mc",q:"Er bastelt gern, ___ er malt nicht so oft.",opts:["aber","denn","dass","ob"],ans:"aber",hint:"A contrast between two hobbies."},
{type:"drag_fill",s:"Wir verabreden {1} für die Feier {2} treffen {3} vor dem Zoo.",blanks:{"1":"uns","2":"und","3":"uns"},pool:["uns","sich","und","aber","euch"],hint:"'Wir' reflexive appears twice: making plans AND meeting up.",sSrc:"We arrange to meet for the party and meet up in front of the zoo."},
{type:"mc",q:"Er hat viel Spaß, ___ er aktiv und sportlich ist.",opts:["denn","aber","ob","dass"],ans:"denn",hint:"Gives the reason why he has fun."},
{type:"fb",s:"Sie zeichnet gern Katzen {1} Pferde.",a:"und",opts:["und","aber","dass","ob"],hint:"Connecting two things she likes to draw.",sSrc:"She likes drawing cats and horses."},
{type:"drag_fill",s:"Ich glaube, {1} sie {2} auf das Fest freut, {3} sie hat schon ein Kleid gekauft.",blanks:{"1":"dass","2":"sich","3":"denn"},pool:["dass","ob","sich","mich","denn","aber"],hint:"A known belief, a reflexive verb, and a reason.",sSrc:"I believe that she is excited about the festival, because she has already bought a dress."}
]},

{id:"deu_r9l8",title:"Der Mitgliedsausweis",icon:"🎫",xp:15,board:true,steps:[
{type:"intro",title:"Der Mitgliedsausweis",desc:"Verumius pins his Lauftreff membership card to the corkboard. His German life is growing. Time to learn the rest of the Freizeit vocabulary.",goals:["Sports and entertainment vocabulary","Personality adjectives","Everyday verbs for social life"]},
{type:"story",speaker:"narrator",mood:"proud",art:"de-corkboard",trg:"Verumius hängt den Mitgliedsausweis an die Pinnwand. Neben dem Mietvertrag, der Anmeldung und der Krankenkassenkarte. Vier Dokumente. Vier Schritte in Deutschland. Er lächelt.",src:"Verumius pins the membership card to the corkboard. Next to the lease, the registration, and the health insurance card. Four documents. Four steps in Germany. He smiles."},
{type:"teach",trg:"das Tennis",src:"tennis",note:"Neuter. Tennis spielen = to play tennis.",example:"A: Spielst du Tennis?\nB: Ja, jeden Samstag im Verein.\nA: Toll! Ich möchte auch anfangen.",exampleSrc:"A: Do you play tennis?\nB: Yes, every Saturday at the club.\nA: Great! I want to start too.",funFact:"Boris Becker won Wimbledon at 17. Germany went tennis-crazy in the 1980s. Every town built courts."},
{type:"teach",trg:"der Basketball",src:"basketball",note:"Masculine. Basketball spielen.",example:"A: Wer spielt heute Basketball?\nB: Die Mannschaft aus Hamburg.\nA: Ich bin Fan!",exampleSrc:"A: Who is playing basketball today?\nB: The team from Hamburg.\nA: I am a fan!",funFact:"Dirk Nowitzki made basketball huge in Germany. The BBL (Basketball Bundesliga) now has 18 teams."},
{type:"teach",trg:"der Volleyball",src:"volleyball",note:"Masculine. Beach-Volleyball is also popular in Germany.",example:"A: Wollen wir Volleyball spielen?\nB: Gern! Am Strand oder in der Halle?",exampleSrc:"A: Do you want to play volleyball?\nB: Sure! At the beach or in the hall?",funFact:"Germany's beach volleyball duo won Olympic gold in 2012 in London. Beach volleyball is huge at German lakes."},
{type:"mc",q:"Which sport uses a net and you hit the ball over it with your hands?",opts:["Volleyball","Basketball","Tennis","Fußball"],ans:"Volleyball",hint:"Teams of six stand on either side of a net."},
{type:"teach",trg:"das Rad",src:"wheel / bicycle",note:"Neuter. Rad fahren = to cycle. Plural: Räder.",example:"A: Fährst du mit dem Rad zur Arbeit?\nB: Ja, jeden Tag. Es ist gesünder.",exampleSrc:"A: Do you cycle to work?\nB: Yes, every day. It is healthier.",funFact:"Germans cycle about 1,000 km per person per year. Many cities have more bike paths than car lanes."},
{type:"teach",trg:"reiten",src:"to ride (horse)",note:"Irregular: ich reite, du reitest. Past: geritten (with sein!).",example:"A: Kannst du reiten?\nB: Ein bisschen. Als Kind habe ich geritten.",exampleSrc:"A: Can you ride?\nB: A little. I rode as a child.",funFact:"Germany is one of Europe's top equestrian nations. The German Riding Federation has over 660,000 members."},
{type:"teach",trg:"singen",src:"to sing",note:"Irregular: ich singe, du singst. Past: gesungen.",example:"A: Singst du gern?\nB: Ja, ich bin im Chor!\nA: Wirklich? Das ist toll!",exampleSrc:"A: Do you like singing?\nB: Yes, I am in a choir!\nA: Really? That is great!",funFact:"Germany has more amateur choirs than any country in Europe. About 3 million Germans sing in a choir."},
{type:"fb",s:"Mia {1} jeden Morgen im Park.",a:["joggt"],opts:["joggt","singt","reitet","malt"],hint:"What does Mia do at the Lauftreff? Running activity.",sSrc:"Mia jogs every morning in the park."},
{type:"teach",trg:"unternehmen",src:"to undertake / to do (an activity)",note:"Irregular: ich unternehme, du unternimmst. Separable: NOT (inseparable un-).",example:"A: Was wollen wir heute unternehmen?\nB: Wir könnten ins Museum gehen.",exampleSrc:"A: What shall we do today?\nB: We could go to the museum.",funFact:"Despite looking like a separable verb, unternehmen is inseparable. The 'unter' is a prefix, not a particle."},
{type:"teach",trg:"ausgehen",src:"to go out",note:"Separable: ich gehe aus, du gehst aus. Past: ausgegangen (sein).",example:"A: Gehst du heute Abend aus?\nB: Ja, wir gehen in die Disco.",exampleSrc:"A: Are you going out tonight?\nB: Yes, we are going to the disco.",funFact:"Germans go out later than many Europeans. Dinner at 8, clubs after midnight. Berlin clubs famously open at 1 AM."},
{type:"teach",trg:"probieren",src:"to try / to taste",note:"Regular: ich probiere, du probierst. Probieren geht über Studieren!",example:"A: Möchtest du den Kuchen probieren?\nB: Ja, gern! Er sieht lecker aus.",exampleSrc:"A: Would you like to try the cake?\nB: Yes, please! It looks delicious.",funFact:"The German proverb 'Probieren geht über Studieren' means 'trying beats studying.' Learning by doing!"},
{type:"mc",q:"'Was wollen wir heute unternehmen?' means:",opts:["What shall we do today?","What are you studying?","Where are you going?","Who is coming along?"],ans:"What shall we do today?",hint:"Planning an activity together. What should we DO?"},
{type:"teach",trg:"tauschen",src:"to swap / to exchange",note:"Regular: ich tausche. Tauschbörse = swap market.",example:"A: Wollen wir die Plätze tauschen?\nB: Ja, klar! Ich sitze gern am Fenster.",exampleSrc:"A: Do you want to swap seats?\nB: Yes, sure! I like sitting by the window.",funFact:"Germany has a strong Tauschkultur. Swap parties for clothes, books, and toys are common, especially in Berlin."},
{type:"teach",trg:"teilen",src:"to share / to divide",note:"Regular: ich teile. Teilen ist leben! (Sharing is living.)",example:"A: Sollen wir die Pizza teilen?\nB: Gute Idee! Eine ganze Pizza ist zu viel.",exampleSrc:"A: Should we share the pizza?\nB: Good idea! A whole pizza is too much.",funFact:"In German restaurants, 'getrennt' means separate bills and 'zusammen' means one bill. Germans often split."},
{type:"teach",trg:"schimpfen",src:"to scold / to complain",note:"Regular: ich schimpfe. Schimpfwort = swear word.",example:"A: Warum schimpft Hildi?\nB: Weil jemand den Müll falsch sortiert hat!",exampleSrc:"A: Why is Hildi scolding?\nB: Because someone sorted the trash wrong!",funFact:"Germans are known for Beschwerdekultur (complaint culture). If the rules are broken, someone WILL say something."},
{type:"fb",s:"Sollen wir die Rechnung {1}?",a:["teilen"],opts:["teilen","tauschen","schimpfen","probieren"],hint:"To split the bill between two people.",sSrc:"Should we split the bill?"},
{type:"teach",trg:"fantastisch",src:"fantastic",note:"Same in English! Easily recognizable.",example:"A: Wie war das Konzert?\nB: Fantastisch! Die Band war super.",exampleSrc:"A: How was the concert?\nB: Fantastic! The band was great.",funFact:"Many German adjectives for positive emotions are borrowed from French or Latin: fantastisch, romantisch, sympathisch."},
{type:"teach",trg:"langweilig",src:"boring",note:"Lang (long) + weilig (time-related). Literally: making time feel long.",example:"A: Wie findest du den Film?\nB: Langweilig. Lass uns gehen.",exampleSrc:"A: How do you find the movie?\nB: Boring. Let us leave.",funFact:"The word structure tells you the meaning: lang (long) + Weile (while). Something that makes time stretch."},
{type:"teach",trg:"nett",src:"nice / kind",note:"Common everyday compliment. 'Das ist nett von dir.'",example:"A: Dein Nachbar ist sehr nett.\nB: Ja, er hilft mir oft mit dem Müll.",exampleSrc:"A: Your neighbor is very nice.\nB: Yes, he often helps me with the trash.",funFact:"In German culture, 'nett' can also be faint praise. 'Nett ist die kleine Schwester von...' means nett is the lesser version of truly good."},
{type:"teach",trg:"toll",src:"great / awesome",note:"Very common positive adjective. Informal but widely used.",example:"A: Ich habe den Job bekommen!\nB: Toll! Herzlichen Glückwunsch!",exampleSrc:"A: I got the job!\nB: Great! Congratulations!",funFact:"'Toll' originally meant 'crazy/mad' in Old German. Over centuries it shifted to mean 'amazing.' Similar to English 'terrific.'"},
{type:"teach",trg:"witzig",src:"witty / funny",note:"From Witz (joke). Ein witziger Mensch = a funny person.",example:"A: Der Film war sehr witzig.\nB: Ja, ich habe so viel gelacht!",exampleSrc:"A: The movie was very funny.\nB: Yes, I laughed so much!",funFact:"German humor exists! Loriot, a legendary German comedian, proved that dry observational humor is universal."},
{type:"mc",q:"The opposite of 'langweilig' (boring) would be:",opts:["spannend","nett","toll","witzig"],ans:"spannend",hint:"Something that keeps you on the edge of your seat. Exciting."},
{type:"teach",trg:"spannend",src:"exciting / thrilling",note:"From spannen (to stretch/tighten). Like a taut bowstring.",example:"A: Das Buch ist sehr spannend!\nB: Wirklich? Worum geht es?",exampleSrc:"A: The book is very exciting!\nB: Really? What is it about?",funFact:"Spannend comes from the same root as English 'suspense.' A Spannungsroman is a thriller novel."},
{type:"teach",trg:"beliebt",src:"popular / well-liked",note:"From belieben (to please). Ein beliebtes Restaurant.",example:"A: Diese Sendung ist sehr beliebt.\nB: Ja, alle schauen sie!",exampleSrc:"A: This show is very popular.\nB: Yes, everyone watches it!",funFact:"Beliebt is a participial adjective. 'Es beliebt mir' (it pleases me) is the archaic origin."},
{type:"teach",trg:"berühmt",src:"famous",note:"From Ruhm (fame). Ein berühmter Musiker.",example:"A: Kennst du diesen berühmten Musiker?\nB: Ja, er ist überall bekannt!",exampleSrc:"A: Do you know this famous musician?\nB: Yes, he is known everywhere!",funFact:"Be-rühm-t: the prefix be- + Ruhm (glory) + -t ending. 'Touched by glory.' German word building at its finest."},
{type:"teach",trg:"besonders",src:"especially / particularly",note:"Adverb. Besonders gut = especially good.",example:"A: Was gefällt dir an Berlin?\nB: Besonders die Kultur und die Musik.",exampleSrc:"A: What do you like about Berlin?\nB: Especially the culture and the music.",funFact:"Besonders comes from 'besonder' (special/separate). Something that stands apart from the rest."},
{type:"teach",trg:"meistens",src:"mostly / usually",note:"Adverb. Meistens + verb = what you usually do.",example:"A: Was machst du am Wochenende?\nB: Meistens gehe ich spazieren.",exampleSrc:"A: What do you do on weekends?\nB: I usually go for a walk.",funFact:"Meistens comes from 'meist' (most). The -ens ending turns it into 'for the most part.'"},
{type:"drag_fill",s:"Der Film war {1} und {2}. Ich habe so viel gelacht!",blanks:{"1":"witzig","2":"toll"},pool:["witzig","toll","langweilig","schlimm","nett","traurig"],hint:"A funny and great movie. Two positive adjectives.",sSrc:"The film was funny and great. I laughed so much!"},
{type:"match",pairs:[{trg:"fantastisch",src:"fantastic"},{trg:"langweilig",src:"boring"},{trg:"spannend",src:"exciting"},{trg:"beliebt",src:"popular"},{trg:"berühmt",src:"famous"},{trg:"witzig",src:"funny"},{trg:"nett",src:"nice"},{trg:"toll",src:"great"}]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-corkboard",trg:"Lukas schreibt in den Gruppenchat: 'Wer will nächste Woche mit dem ICE nach München fahren? Ich habe günstige Tickets gefunden!' Verumius hat noch nie allein den ICE genommen. Aber jetzt hat er einen Mitgliedsausweis. Er kann alles.",src:"Lukas writes in the group chat: 'Who wants to take the ICE to Munich next week? I found cheap tickets!' Verumius has never taken the ICE alone. But now he has a membership card. He can do anything."},
{type:"mc",q:"What is Lukas proposing in the group chat?",opts:["A train trip to Munich","A running competition","A museum visit","A concert in Berlin"],ans:"A train trip to Munich",hint:"He found cheap ICE tickets. Where does he want to go?"},
{type:"teach",trg:"die Band",src:"the band (music group)",note:"Feminine. Plural: die Bands. Borrowed from English.",example:"A: Welche Band spielte auf dem Festival?\nB: Eine Indie-Band aus Berlin.\nA: Waren sie gut?",exampleSrc:"A: Which band played at the festival?\nB: An indie band from Berlin.\nA: Were they good?",funFact:"Germany has a huge live music scene. Rock am Ring, Wacken Open Air, and Splash! are among Europe's biggest festivals."},
{type:"teach",trg:"die Disco",src:"the disco / nightclub",note:"Feminine. Also: die Disko. Plural: die Discos.",example:"A: Gehen wir heute Abend in die Disco?\nB: Ja, die Musik dort ist super!\nA: Um wie viel Uhr?",exampleSrc:"A: Shall we go to the club tonight?\nB: Yes, the music there is great!\nA: What time?",funFact:"Germans still say 'Disco' for nightclub, though younger people also say 'Club.' Berlin is considered the techno capital of the world."},
{type:"teach",trg:"das Festival",src:"the festival",note:"Neuter. Plural: die Festivals. From English.",example:"A: Warst du schon auf einem Festival?\nB: Ja, letztes Jahr auf dem Wacken Open Air.\nA: Drei Tage Musik und Camping!",exampleSrc:"A: Have you been to a festival?\nB: Yes, last year at Wacken Open Air.\nA: Three days of music and camping!",funFact:"Wacken Open Air is the world's largest heavy metal festival, held in a tiny village with just 2,000 residents but 85,000 visitors."},
{type:"teach",trg:"der Klub",src:"the club",note:"Masculine. Plural: die Klubs. Also spelled Club.",example:"A: Bist du Mitglied in einem Klub?\nB: Ja, in einem Leseclub.\nA: Was lest ihr gerade?",exampleSrc:"A: Are you a member of a club?\nB: Yes, in a book club.\nA: What are you reading now?",funFact:"The Berghain in Berlin is often called the world's most exclusive nightclub. The doormen decide who enters based on criteria nobody fully understands."},
{type:"teach",trg:"das Plakat",src:"the poster (public)",note:"Neuter. Plural: die Plakate. For advertising posters, event announcements.",example:"A: Hast du das Plakat für das Konzert gesehen?\nB: Ja, es hängt am Bahnhof.\nA: Die Farben sind toll!",exampleSrc:"A: Have you seen the poster for the concert?\nB: Yes, it hangs at the train station.\nA: The colors are great!",funFact:"Germany has Litfaßsäulen (advertising columns) on streets since 1855, invented by Ernst Litfaß to reduce wild poster chaos."},
{type:"teach",trg:"das Poster",src:"the poster (decorative)",note:"Neuter. Plural: die Poster. Borrowed from English. More personal than Plakat.",example:"A: Ich habe ein neues Poster für mein Zimmer.\nB: Was ist darauf?\nA: Ein Foto von den Alpen.",exampleSrc:"A: I have a new poster for my room.\nB: What's on it?\nA: A photo of the Alps.",funFact:"Plakat is for public/commercial posters. Poster is for decorative ones at home. Germans keep both words with different meanings."},
{type:"teach",trg:"das Quiz",src:"the quiz",note:"Neuter. Plural: die Quiz or Quizze. Borrowed from English.",example:"A: Machen wir ein Quiz über Deutschland?\nB: Gute Idee! Wer weiß mehr?\nA: Ich bin bereit!",exampleSrc:"A: Shall we do a quiz about Germany?\nB: Good idea! Who knows more?\nA: I'm ready!",funFact:"'Wer wird Millionär?' (Who Wants to Be a Millionaire?) has been running since 1999 with host Günther Jauch."},
{type:"teach",trg:"das Rätsel",src:"the puzzle / riddle",note:"Neuter. Plural: die Rätsel. Ein Kreuzworträtsel = crossword puzzle.",example:"A: Ich liebe Rätsel!\nB: Dann mach das Kreuzworträtsel in der Zeitung.\nA: Gute Idee!",exampleSrc:"A: I love puzzles!\nB: Then do the crossword in the newspaper.\nA: Good idea!",funFact:"The Brothers Grimm filled their fairy tales with riddles. Rumpelstiltskin is basically one giant name-guessing puzzle."},
{type:"teach",trg:"das Team",src:"the team",note:"Neuter. Plural: die Teams. Synonym: die Mannschaft (more traditional).",example:"A: Unser Team hat gewonnen!\nB: Fantastisch! Wie war das Spiel?\nA: Drei zu eins!",exampleSrc:"A: Our team won!\nB: Fantastic! How was the game?\nA: Three to one!",funFact:"Germans use both 'Team' (modern, borrowed) and 'Mannschaft' (traditional). In business, Team is preferred. In football, Mannschaft rules."},
{type:"teach",trg:"vereinbaren",src:"to arrange / to agree upon",note:"Inseparable: ich vereinbare. Perfekt: hat vereinbart.",example:"A: Wollen wir einen Termin vereinbaren?\nB: Ja, passt dir Dienstag?\nA: Perfekt, Dienstag um zehn.",exampleSrc:"A: Shall we arrange an appointment?\nB: Yes, does Tuesday work for you?\nA: Perfect, Tuesday at ten.",funFact:"From Verein (club). Vereinbaren means to come to an agreement. Very German: even scheduling is an act of unification."},
{type:"teach",trg:"auspacken",src:"to unpack",note:"Separable: ich packe aus. Opposite of einpacken.",example:"A: Hast du den Koffer schon ausgepackt?\nB: Nein, ich bin zu müde.\nA: Das mache ich morgen.",exampleSrc:"A: Have you unpacked the suitcase yet?\nB: No, I'm too tired.\nA: I'll do it tomorrow.",funFact:"In colloquial German, 'auspacken' also means to reveal secrets. A witness who 'auspackt' is spilling everything."},
{type:"teach",trg:"austauschen",src:"to exchange / to swap",note:"Separable: ich tausche aus. Emphasizes mutual exchange.",example:"A: Wollen wir Telefonnummern austauschen?\nB: Ja, gerne! Hier ist meine.\nA: Danke! Ich schreibe dir.",exampleSrc:"A: Shall we exchange phone numbers?\nB: Yes, gladly! Here is mine.\nA: Thanks! I'll text you.",funFact:"Schüleraustausch (student exchange) is very popular. About 20,000 German students go abroad each year."},
{type:"teach",trg:"romantisch",src:"romantic",note:"Adjective. Same root as English. Ein romantischer Abend.",example:"A: Der Film war sehr romantisch.\nB: Ja, aber auch ein bisschen kitschig.\nA: Das ist doch das Beste daran!",exampleSrc:"A: The film was very romantic.\nB: Yes, but also a bit cheesy.\nA: That's the best part!",funFact:"The Rhine Valley inspired the German Romantic movement in the 19th century. Romantisch comes from this era."}
]}
]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 10: Deutsche Bahn
// Story: 47 min delay, seat conflict, sprint for Anschluss, Bordbistro
// CEFR: A2.2 - Perfekt sein, Partizip II, wenn-clause, subordinate word order
// ═══════════════════════════════════════════════════════════════
{n:10,lang:"de",srcLang:"en",track:"v2",title:"Deutsche Bahn",sub:"Train delays, seat conflicts, sprinting for connections",icon:"🚂",level:"A2.2",color:"#7B5EE8",lessons:[
{id:"deu_r10l1",title:"47 Minuten Verspätung",icon:"🚂",xp:15,board:true,steps:[
{type:"intro",title:"47 Minuten Verspätung",desc:"Berlin Hauptbahnhof. Der ICE hat 47 Minuten Verspätung. Die Anzeigetafel leuchtet rot. Erfahrene Reisende trinken Kaffee. Verumius starrt auf die Tafel.",goals:["Learn 10 travel and transport words","Understand train delay culture in Germany","See your first Perfekt sentences with sein"]},
{type:"teach",trg:"der Fahrplan",src:"the timetable",note:"der Fahrplan (masculine). Literally: drive-plan.\nCompound: fahren (to drive) + Plan (plan).",example:"A: Hast du den Fahrplan gesehen?\nB: Ja, der Zug kommt um 14:30.\nA: Dann haben wir noch Zeit.\nB: Lass uns einen Kaffee trinken.",exampleSrc:"A: Have you seen the timetable?\nB: Yes, the train comes at 14:30.\nA: Then we still have time.\nB: Let's grab a coffee.",funFact:"Deutsche Bahn prints pocket timetables (Taschenfahrplan) that some collectors treasure. The tradition goes back to the 1800s."},
{type:"teach",trg:"die Verspätung",src:"the delay",note:"die Verspätung (feminine). From: spät (late).\nverspäten = to be late, die Verspätung = the delay.",example:"A: Der ICE hat 47 Minuten Verspätung.\nB: Schon wieder?\nA: Ja, das ist leider normal.\nB: Dann verpasse ich meinen Anschluss.",exampleSrc:"A: The ICE has a 47-minute delay.\nB: Again?\nA: Yes, unfortunately that's normal.\nB: Then I'll miss my connection.",funFact:"In 2024, only about 64% of Deutsche Bahn long-distance trains arrived on time. Germans joke that delays are the only reliable thing about DB."},
{type:"teach",trg:"der Verkehr",src:"the traffic",note:"der Verkehr (masculine). Used for all traffic:\nStraßenverkehr (road), Zugverkehr (rail), Flugverkehr (air).",example:"A: Wie ist der Verkehr heute?\nB: Auf der Autobahn ist Stau.\nA: Dann nehme ich den Zug.\nB: Gute Idee, der fährt bald.",exampleSrc:"A: How is the traffic today?\nB: There's a traffic jam on the highway.\nA: Then I'll take the train.\nB: Good idea, it leaves soon.",funFact:"Germany's Autobahn has sections with no speed limit, yet traffic jams (Stau) cause roughly 450,000 hours of delays per year."},
{type:"teach",trg:"das Verkehrsmittel",src:"the means of transport",note:"das Verkehrsmittel (neuter). Compound:\nVerkehr (traffic) + Mittel (means/tool).\nPlural: die Verkehrsmittel.",example:"A: Welches Verkehrsmittel nimmst du?\nB: Ich fahre mit dem Zug.\nA: Ich nehme lieber das Fahrrad.\nB: Bei Regen? Du bist mutig!",exampleSrc:"A: Which means of transport do you take?\nB: I go by train.\nA: I prefer the bicycle.\nB: In rain? You're brave!",funFact:"Germans use over 30 billion trips per year on public transport. The Deutschlandticket (49-euro ticket) made buses and trains across the country accessible with one pass."},
{type:"teach",trg:"der Weg",src:"the way / path",note:"der Weg (masculine). Both literal path and figurative way.\nauf dem Weg = on the way.\nPlural: die Wege.",example:"A: Kennst du den Weg zum Bahnhof?\nB: Ja, immer geradeaus und dann links.\nA: Ist es weit?\nB: Nein, nur zehn Minuten zu Fuß.",exampleSrc:"A: Do you know the way to the station?\nB: Yes, straight ahead and then left.\nA: Is it far?\nB: No, only ten minutes on foot.",funFact:"The word Weg appears in hundreds of German compounds: Gehweg (sidewalk), Radweg (bike path), Umweg (detour), Ausweg (way out)."},
{type:"teach",trg:"die Nähe",src:"the vicinity / nearness",note:"die Nähe (feminine). From: nah (near/close).\nin der Nähe von = in the vicinity of, near.",example:"A: Gibt es ein Hotel in der Nähe?\nB: Ja, direkt am Bahnhof.\nA: Ist es teuer?\nB: Nein, es ist ganz günstig.",exampleSrc:"A: Is there a hotel nearby?\nB: Yes, right at the train station.\nA: Is it expensive?\nB: No, it's quite affordable.",funFact:"In der Nähe is one of the most useful travel phrases in German. You can combine it with von + dative to say near anything: in der Nähe vom Flughafen."},
{type:"tip",title:"Deutsche Bahn Kultur",text:"\"Wenige Minuten\" on the display board?\nThat means 5 to 60 minutes. Nobody knows.\n\nKey vocabulary for the Anzeigetafel:\n. pünktlich = on time\n. ca. 15 Min. später = approx. 15 min late\n. Zug fällt aus = train cancelled\n\nAnschluss = connecting train. Missing yours because of a delay? Deutsche Bahn must rebook you for free.\n\nThe Bordbistro sells coffee and pretzels on ICE trains. Many travelers treat delays as bonus reading time."},
{type:"mc",q:"Verumius steht am Hauptbahnhof. Der ICE hat 47 Minuten ___.",opts:["Verspätung","Verkehr","Fahrplan","Nähe"],ans:"Verspätung",hint:"Think about what happens when a train is late."},
{type:"fb",s:"Kennst du den {1} zum Bahnhof?",a:"Weg",opts:["Weg","Verkehr","Flug","Nähe"],hint:"Which word means way or path?",sSrc:"Do you know the way to the train station?"},
{type:"teach",trg:"der Flug",src:"the flight",note:"der Flug (masculine). From: fliegen (to fly).\nder Flughafen = the airport (flight harbor).\nPlural: die Flüge (note the umlaut).",example:"A: Wann geht dein Flug?\nB: Um halb acht morgen früh.\nA: Das ist aber früh!\nB: Ja, ich muss um fünf aufstehen.",exampleSrc:"A: When does your flight leave?\nB: At half past seven tomorrow morning.\nA: That's really early!\nB: Yes, I have to get up at five.",funFact:"Frankfurt Airport (Flughafen Frankfurt) is the busiest in Germany and the fourth busiest in Europe, handling over 59 million passengers a year."},
{type:"teach",trg:"buchen",src:"to book / to reserve",note:"buchen (regular verb). ich buche, du buchst, er bucht.\neine Reise buchen = to book a trip.\nein Hotel buchen = to book a hotel.",example:"A: Hast du das Hotel schon gebucht?\nB: Nein, ich mache das heute Abend.\nA: Buch lieber jetzt, es wird teurer!\nB: Okay, ich buche sofort online.",exampleSrc:"A: Have you already booked the hotel?\nB: No, I'll do it tonight.\nA: Better book now, it gets more expensive!\nB: Okay, I'll book online right away.",funFact:"The DB Navigator app lets you book train tickets, check live delays, and find your platform. Over 20 million Germans use it regularly."},
{type:"teach",trg:"umsteigen",src:"to transfer / to change (trains)",note:"umsteigen (separable verb). ich steige um.\nPerfekt: Ich bin umgestiegen (uses sein!).\num = around/change + steigen = to climb.",example:"A: Muss ich in Hannover umsteigen?\nB: Ja, auf Gleis 7.\nA: Wie viel Zeit habe ich?\nB: Nur acht Minuten. Beeil dich!",exampleSrc:"A: Do I have to transfer in Hannover?\nB: Yes, at platform 7.\nA: How much time do I have?\nB: Only eight minutes. Hurry!",funFact:"Umsteigen is a separable verb: the um splits off. Ich steige in Hamburg um. But in subordinate clauses it stays together: weil ich in Hamburg umsteige."},
{type:"teach",trg:"verpassen",src:"to miss (a train, bus, flight)",note:"verpassen (inseparable verb). ich verpasse.\nver- does NOT separate. ich verpasse den Zug.\nAlso used for missing events or deadlines.",example:"A: Ich habe den Zug verpasst!\nB: Wann fährt der nächste?\nA: In 45 Minuten.\nB: Dann hol dir einen Kaffee am Kiosk.",exampleSrc:"A: I missed the train!\nB: When does the next one leave?\nA: In 45 minutes.\nB: Then grab a coffee at the kiosk.",funFact:"Verpassen is inseparable (the ver- stays attached), while umsteigen is separable (the um detaches). Learning which prefixes separate is a key German skill."},
{type:"mc",q:"Verumius will nach München fliegen. Er braucht einen ___.",opts:["Flug","Weg","Fahrplan","Verkehr"],ans:"Flug",hint:"What do you need when you want to fly somewhere?"},
{type:"fb",s:"Ich muss in Hannover {1}.",a:"umsteigen",opts:["umsteigen","verpassen","buchen","fahren"],hint:"Which verb means to change trains?",sSrc:"I have to transfer in Hannover."},
{type:"mc",q:"Verumius hat den ICE verpasst. Was bedeutet verpassen?",opts:["to miss","to book","to transfer","to arrive"],ans:"to miss",hint:"The train left without him."},
{type:"tip",title:"Perfekt mit sein: Bewegung!",text:"Most German verbs form Perfekt with haben.\nBut verbs of MOVEMENT use sein:\n\nIch bin nach München gefahren.\n(I drove/went to Munich.)\n\nEr ist umgestiegen.\n(He transferred.)\n\nWir sind angekommen.\n(We arrived.)\n\nKey idea: if you physically move from A to B, use sein.\nYou will practice this more in the coming lessons.",deepDive:{title:"Which verbs take sein?",text:"Two main groups take sein:\n1. Motion verbs that describe moving from A to B: gehen, fahren, fliegen, laufen, reisen, schwimmen, klettern.\n2. Change-of-state verbs: werden (become), einschlafen (fall asleep), aufwachen (wake up), sterben (die).\n\nPlus the verb bleiben (to stay) as a special case.\n\nAll other verbs use haben. When in doubt, ask: does this verb describe moving somewhere or changing state? If yes, use sein."}},
{type:"mc",q:"Ich ___ nach Berlin gefahren. (Perfekt with movement verb)",opts:["bin","habe","ist","hat"],ans:"bin",hint:"Movement verbs use a form of sein, not haben."},
{type:"fb",s:"Gibt es ein Hotel in der {1}?",a:"Nähe",opts:["Nähe","Weg","Verspätung","Verkehr"],hint:"Which word means vicinity or nearness?",sSrc:"Is there a hotel in the vicinity?"},
{type:"mc",q:"Verumius will ein Ticket kaufen. Er muss das Ticket online ___.",opts:["buchen","umsteigen","verpassen","fahren"],ans:"buchen",hint:"Which verb means to book or reserve?"},
{type:"match",pairs:[{trg:"der Fahrplan",src:"the timetable"},{trg:"die Verspätung",src:"the delay"},{trg:"umsteigen",src:"to transfer"},{trg:"verpassen",src:"to miss"},{trg:"die Nähe",src:"the vicinity"}]},
{type:"mc",q:"Der ___ auf der Autobahn ist heute sehr schlecht.",opts:["Verkehr","Fahrplan","Flug","Weg"],ans:"Verkehr",hint:"Which word describes cars, buses, and trucks on the road?"},
{type:"fb",s:"Welches {1} nimmst du? Den Zug oder das Flugzeug?",a:"Verkehrsmittel",opts:["Verkehrsmittel","Verkehr","Fahrplan","Weg"],hint:"Which compound word means means of transport?",sSrc:"Which means of transport do you take? The train or the airplane?"}
]}
,

{id:"deu_r10l2",title:"Unterwegs",icon:"🗺️",xp:15,board:true,steps:[
{type:"intro",title:"Unterwegs",desc:"Lerne wichtige Orte und Landschaften auf Deutsch kennen.",goals:["12 Orte und Landschaftswörter lernen","Artikel (der/die/das) mit neuen Nomen üben","Über deutsche Geografie sprechen"]},
{type:"teach",trg:"die Ampel",src:"traffic light",gender:"f",article:"die",note:"Feminine. Plural: die Ampeln.",funFact:"Deutsche Ampelmännchen sind Kultsymbole. Das Ost-Ampelmännchen mit Hut ist weltberühmt.",example:"A: Ist die Ampel grün?\nB: Nein, sie ist noch rot. Wir müssen warten.",exampleSrc:"A: Is the traffic light green?\nB: No, it's still red. We have to wait."},
{type:"teach",trg:"der Berg",src:"mountain",gender:"m",article:"der",note:"Masculine. Plural: die Berge.",funFact:"Die Zugspitze ist mit 2.962 Metern der höchste Berg Deutschlands.",example:"A: Siehst du den Berg dort?\nB: Ja, er ist sehr hoch. Können wir wandern gehen?",exampleSrc:"A: Do you see the mountain there?\nB: Yes, it's very high. Can we go hiking?"},
{type:"teach",trg:"die Brücke",src:"bridge",gender:"f",article:"die",note:"Feminine. Plural: die Brücken.",funFact:"Die Basteibrücke in Sachsen ist eine der meistfotografierten Brücken Europas.",example:"A: Gehen wir über die Brücke?\nB: Ja, auf der anderen Seite ist der Markt.",exampleSrc:"A: Shall we walk over the bridge?\nB: Yes, on the other side is the market."},
{type:"teach",trg:"der Fluss",src:"river",gender:"m",article:"der",note:"Masculine. Plural: die Flüsse. Beachte den Umlaut!",funFact:"Der Rhein ist 1.230 km lang und fließt durch sechs Länder.",example:"A: Welcher Fluss ist das?\nB: Das ist die Spree. Sie fließt durch Berlin.",exampleSrc:"A: Which river is that?\nB: That's the Spree. It flows through Berlin."},
{type:"teach",trg:"die Insel",src:"island",gender:"f",article:"die",note:"Feminine. Plural: die Inseln.",funFact:"Rügen ist die größte deutsche Insel mit berühmten weißen Kreidefelsen.",example:"A: Warst du schon mal auf einer Insel?\nB: Ja, ich war letzten Sommer auf Sylt.",exampleSrc:"A: Have you ever been to an island?\nB: Yes, I was on Sylt last summer."},
{type:"teach",trg:"die Landschaft",src:"landscape",gender:"f",article:"die",note:"Feminine. Plural: die Landschaften.",funFact:"Deutschland hat alles: Alpen im Süden, Nordsee im Norden, Wälder in der Mitte.",example:"A: Wie ist die Landschaft in Bayern?\nB: Sehr schön! Berge, Seen und grüne Wiesen.",exampleSrc:"A: What's the landscape like in Bavaria?\nB: Very beautiful! Mountains, lakes, and green meadows."},
{type:"teach",trg:"das Flugzeug",src:"the airplane",note:"Neuter noun. Plural: die Flugzeuge.\nCompound: Flug (flight) + Zeug (stuff/thing).",example:"A: Nimmst du den Zug oder das Flugzeug?\nB: Das Flugzeug. Es ist schneller.\nA: Aber der Zug ist umweltfreundlicher.\nB: Stimmt. Nächstes Mal nehme ich den Zug.",exampleSrc:"A: Are you taking the train or the plane?\nB: The plane. It is faster.\nA: But the train is more environmentally friendly.\nB: True. Next time I will take the train.",funFact:"'Flugzeug' literally means 'flying thing.' German compounds are wonderfully literal: Feuerzeug (fire-thing = lighter), Fahrzeug (driving-thing = vehicle), Werkzeug (work-thing = tool). The suffix '-zeug' is one of German's most productive."},
{type:"teach",trg:"der Norden",src:"the north",note:"Masculine noun. No common plural.\nAdjective: nördlich (northern).",example:"A: Wo liegt Hamburg?\nB: Hamburg liegt im Norden von Deutschland.\nA: Und München?\nB: München liegt im Süden.",exampleSrc:"A: Where is Hamburg?\nB: Hamburg is in the north of Germany.\nA: And Munich?\nB: Munich is in the south.",funFact:"Norddeutschland (Northern Germany) has a completely different culture from the south. The north is flatter, cooler, and more reserved. People say 'Moin' instead of 'Hallo.' The food is heavier on fish and potatoes."},
{type:"teach",trg:"der Süden",src:"the south",note:"Masculine noun. No common plural.\nAdjective: südlich (southern).",example:"A: Im Süden gibt es Berge.\nB: Ja, die Alpen sind wunderschön!\nA: Ich möchte im Süden wandern gehen.",exampleSrc:"A: In the south there are mountains.\nB: Yes, the Alps are beautiful!\nA: I would like to go hiking in the south.",funFact:"Southern Germany (Bayern and Baden-Württemberg) is economically the strongest region. The cultural divide between north and south is real: different dialects, different food, different beer. Northerners drink Pils, southerners drink Weizen."},
{type:"teach",trg:"das Fundbüro",src:"the lost and found office",note:"Neuter noun. Compound: Fund (find) + Büro (office).\nEvery train station and airport has one.",example:"A: Ich habe meinen Koffer verloren!\nB: Geh zum Fundbüro am Hauptbahnhof.\nA: Wo ist das Fundbüro?\nB: Im Erdgeschoss, neben dem Ausgang.",exampleSrc:"A: I lost my suitcase!\nB: Go to the lost and found office at the main station.\nA: Where is the lost and found?\nB: On the ground floor, next to the exit.",funFact:"German Fundbüros are remarkably efficient. The Deutsche Bahn central lost-and-found service handles over 250,000 items per year. You can search for lost items online at fundservice.bahn.de."},
{type:"teach",trg:"die Rolltreppe",src:"the escalator",note:"Feminine noun. Compound: Roll (roll) + Treppe (stairs).\nLiterally: rolling stairs.",example:"A: Wo ist die Rolltreppe?\nB: Dort drüben, neben dem Aufzug.\nA: Danke! Ich muss schnell zum Gleis 14.\nB: Dann lauf auf der Rolltreppe!",exampleSrc:"A: Where is the escalator?\nB: Over there, next to the elevator.\nA: Thanks! I need to get to platform 14 quickly.\nB: Then run on the escalator!",funFact:"On German escalators, stand on the RIGHT and walk on the LEFT. Breaking this rule in a busy train station will earn you angry looks and muttered 'Entschuldigung!' from rushing commuters."},
{type:"mc",q:"Wie sagt man 'traffic light' auf Deutsch?",opts:["die Ampel","der Berg","die Brücke","der Fluss"],ans:"die Ampel",hint:"Denk an die roten, gelben und grünen Lichter."},
{type:"teach",trg:"der Markt",src:"market",gender:"m",article:"der",note:"Masculine. Plural: die Märkte. Beachte den Umlaut!",funFact:"Deutsche Weihnachtsmärkte sind weltweit bekannt. Der Nürnberger Christkindlesmarkt ist über 400 Jahre alt.",example:"A: Gehen wir heute auf den Markt?\nB: Gute Idee! Ich brauche frisches Obst.",exampleSrc:"A: Shall we go to the market today?\nB: Good idea! I need fresh fruit."},
{type:"teach",trg:"das Rathaus",src:"town hall",gender:"n",article:"das",note:"Neuter. Plural: die Rathäuser. Rat (council) + Haus (house).",funFact:"Das Hamburger Rathaus hat 647 Zimmer, mehr als der Buckingham Palace.",example:"A: Wo ist das Rathaus?\nB: Direkt am Marktplatz, das große Gebäude.",exampleSrc:"A: Where is the town hall?\nB: Right at the market square, the big building."},
{type:"teach",trg:"die Kirche",src:"church",gender:"f",article:"die",note:"Feminine. Plural: die Kirchen.",funFact:"Der Kölner Dom brauchte über 600 Jahre bis zur Fertigstellung.",example:"A: Ist die Kirche alt?\nB: Ja, sie ist aus dem 14. Jahrhundert.",exampleSrc:"A: Is the church old?\nB: Yes, it's from the 14th century."},
{type:"teach",trg:"das Zentrum",src:"center",gender:"n",article:"das",note:"Neuter. Auch: die Mitte, die Innenstadt (city center).",funFact:"Viele deutsche Innenstädte haben Fußgängerzonen ohne Autos.",example:"A: Wie komme ich ins Zentrum?\nB: Nimm die U-Bahn bis Hauptbahnhof.",exampleSrc:"A: How do I get to the center?\nB: Take the subway to the main station."},
{type:"teach",trg:"der Strand",src:"beach",gender:"m",article:"der",note:"Masculine. Plural: die Strände. Beachte den Umlaut!",funFact:"Deutsche Nordseestrände haben Strandkörbe: überdachte Sitze gegen den Wind.",example:"A: Gibt es hier einen Strand?\nB: Ja, der Strand ist nur zehn Minuten zu Fuß.",exampleSrc:"A: Is there a beach here?\nB: Yes, the beach is only ten minutes on foot."},
{type:"teach",trg:"der Wald",src:"forest",gender:"m",article:"der",note:"Masculine. Plural: die Wälder. Beachte den Umlaut!",funFact:"Ein Drittel Deutschlands ist Wald. Der Schwarzwald inspirierte viele Märchen der Brüder Grimm.",example:"A: Gehen wir im Wald spazieren?\nB: Ja, die Luft dort ist wunderbar frisch.",exampleSrc:"A: Shall we go for a walk in the forest?\nB: Yes, the air there is wonderfully fresh."},
{type:"mc",q:"Welchen Artikel hat das Wort für 'town hall'?",opts:["das","der","die","den"],ans:"das",hint:"Es ist ein zusammengesetztes Wort mit Haus. Haus ist sächlich."},
{type:"fb",s:"Wir gehen über die {1} zum Markt.",a:"Brücke",opts:["Brücke","Berg","Strand","Wald"],hint:"Man geht darüber, um einen Fluss zu überqueren.",sSrc:"We walk over the bridge to the market."},
{type:"mc",q:"Der Rhein, die Donau und die Elbe sind deutsche ...",opts:["Flüsse","Berge","Inseln","Wälder"],ans:"Flüsse",hint:"Wasser fließt durch diese Landschaftsform."},
{type:"fb",s:"Im Dezember besuchen viele Menschen den Weihnachts{1}.",a:"markt",opts:["markt","berg","wald","strand"],hint:"Dort kann man Geschenke und Glühwein kaufen.",sSrc:"In December many people visit the Christmas market."},
{type:"tip",title:"Deutsche Geografie: 16 Bundesländer",text:"Deutschland hat 16 Bundesländer mit sehr unterschiedlichen Landschaften:\n\n- Norden: Nordsee, Ostsee, flaches Land, Inseln (Sylt, Rügen)\n- Mitte: Wälder (Schwarzwald, Thüringer Wald), Flüsse (Rhein, Elbe)\n- Süden: Alpen, Seen (Bodensee, Chiemsee), Berge\n- Osten: Seenplatte, historische Städte\n- Westen: Industriegebiete, Weinregionen am Rhein",deepDive:"Die 16 Bundesländer sind: Baden-Württemberg, Bayern, Berlin, Brandenburg, Bremen, Hamburg, Hessen, Mecklenburg-Vorpommern, Niedersachsen, Nordrhein-Westfalen, Rheinland-Pfalz, Saarland, Sachsen, Sachsen-Anhalt, Schleswig-Holstein und Thüringen. Jedes hat eine eigene Hauptstadt und Kultur."},
{type:"mc",q:"Welches Wort passt? 'Die Zugspitze ist der höchste ... Deutschlands.'",opts:["Berg","Fluss","Strand","Wald"],ans:"Berg",hint:"Die Zugspitze ist fast 3.000 Meter hoch."},
{type:"match",pairs:[{trg:"die Ampel",src:"traffic light"},{trg:"der Fluss",src:"river"},{trg:"die Insel",src:"island"},{trg:"der Wald",src:"forest"},{trg:"die Kirche",src:"church"},{trg:"das Zentrum",src:"center"}]},
{type:"fb",s:"Rügen ist die größte deutsche {1}.",a:"Insel",opts:["Insel","Brücke","Ampel","Kirche"],hint:"Ein Stück Land, umgeben von Wasser.",sSrc:"Rügen is the largest German island."},
{type:"mc",q:"Wo kann man im Sommer in der Sonne liegen?",opts:["am Strand","im Rathaus","an der Ampel","auf der Brücke"],ans:"am Strand",hint:"Sand, Wasser und Sonnenschirme sind dort."},
{type:"drag_fill",s:"Die {1} in Deutschland ist sehr vielfältig: {2} im Süden, {3} in der Mitte und {4} im Norden.",blanks:{"1":"Landschaft","2":"Berge","3":"Wälder","4":"Strände"},pool:["Landschaft","Berge","Wälder","Strände","Kirchen","Ampeln"],hint:"Denk an die Geografie: Alpen, Schwarzwald, Nordsee.",sSrc:"The landscape in Germany is very diverse: mountains in the south, forests in the middle and beaches in the north."},
{type:"mc",q:"Was ist das Hamburger Rathaus?",opts:["Ein Gebäude für den Stadtrat","Ein Berg in Hamburg","Ein Fluss in Hamburg","Ein Markt in Hamburg"],ans:"Ein Gebäude für den Stadtrat",hint:"Rat bedeutet council, Haus bedeutet house."}
]}
,

{id:"deu_r10l3",title:"Mein Platz!",icon:"💺",xp:15,board:true,steps:[
{type:"intro",title:"Mein Platz!",desc:"Verumius findet seinen reservierten Platz im ICE besetzt. Zeit für eine höfliche Konfrontation.",goals:["Perfekt mit sein lernen","Partizip II bilden","Reisevokabeln üben"]},
{type:"teach",trg:"der Rucksack",src:"backpack",phonetic:"ROOK-zahk",example:"A: Ist das dein Rucksack auf dem Sitz?\nB: Oh, Entschuldigung! Ich nehme ihn weg.",exampleSrc:"A: Is that your backpack on the seat?\nB: Oh, sorry! I'll take it away.",note:"der Rucksack: literally 'back sack'. From Rücken (back) + Sack (sack).",funFact:"The word Rucksack was borrowed into English directly from German. Soldiers brought it back from WWI."},
{type:"teach",trg:"reservieren",src:"to reserve",phonetic:"reh-zer-VEER-en",example:"A: Haben Sie einen Platz reserviert?\nB: Ja, ich habe Platz 47 reserviert.",exampleSrc:"A: Did you reserve a seat?\nB: Yes, I reserved seat 47.",note:"Inseparable verb: no ge- in Partizip II. Reserviert, not gereserviert.",funFact:"Deutsche Bahn lets you reserve specific seats for just 4.50 EUR. Window or aisle, quiet zone or family area."},
{type:"teach",trg:"das Schiff",src:"ship",phonetic:"SHIF",example:"A: Bist du mit dem Schiff gefahren?\nB: Nein, ich bin mit dem Zug gefahren.",exampleSrc:"A: Did you travel by ship?\nB: No, I traveled by train.",note:"das Schiff, Plural: die Schiffe. Neuter noun.",funFact:"Germany has over 7,300 km of inland waterways. River cruises on the Rhine are world famous."},
{type:"teach",trg:"der Stadtplan",src:"city map",phonetic:"SHTAT-plahn",example:"A: Hast du einen Stadtplan?\nB: Nein, ich benutze mein Handy.",exampleSrc:"A: Do you have a city map?\nB: No, I use my phone.",note:"Compound: Stadt (city) + Plan (plan/map).",funFact:"Before smartphones, every German train station had a big Stadtplan on the wall outside. Some still do."},
{type:"teach",trg:"der Tourist / die Touristin",src:"tourist (m/f)",phonetic:"too-RIST / too-RIS-tin",example:"A: Bist du ein Tourist?\nB: Ja, ich bin zum ersten Mal in Deutschland.",exampleSrc:"A: Are you a tourist?\nB: Yes, it's my first time in Germany.",note:"der Tourist (male), die Touristin (female). Plural: die Touristen / die Touristinnen.",funFact:"Germany is the 7th most visited country in the world with over 30 million international visitors per year."},
{type:"teach",trg:"der Reifen",src:"tire",phonetic:"RYE-fen",example:"A: Der Reifen ist kaputt!\nB: Wir brauchen einen neuen Reifen.",exampleSrc:"A: The tire is broken!\nB: We need a new tire.",note:"der Reifen: also means 'hoop'. Don't confuse with reifen (to ripen).",funFact:"Germany has no general speed limit on many Autobahn sections. Good tires are essential."},
{type:"teach",trg:"der Motor",src:"motor, engine",phonetic:"MOH-tor",example:"A: Der Motor macht ein komisches Geräusch.\nB: Wir sollten zur Werkstatt fahren.",exampleSrc:"A: The engine is making a strange noise.\nB: We should drive to the workshop.",note:"der Motor, Plural: die Motoren. Stress on first syllable in German.",funFact:"Germany is home to BMW, Mercedes, Audi, Porsche, and VW. The car engine is practically a national symbol."},
{type:"teach",trg:"der Motorroller",src:"scooter",phonetic:"MOH-tor-rol-er",example:"A: Fährst du mit dem Motorroller zur Arbeit?\nB: Ja, das ist schneller als der Bus.",exampleSrc:"A: Do you ride the scooter to work?\nB: Yes, it's faster than the bus.",note:"Compound: Motor + Roller (roller). Also called just Roller.",funFact:"In German cities, e-scooters (E-Roller) are everywhere. You need to be at least 14 to ride one."},
{type:"tip",title:"Perfekt mit sein: Bewegung und Veränderung",text:"Most verbs use haben for Perfekt.\nBut verbs of MOTION or CHANGE OF STATE use sein:\n\nIch bin gefahren. (I drove/traveled)\nEr ist gegangen. (He went/walked)\nSie ist gekommen. (She came)\nWir sind angekommen. (We arrived)\n\nThink: if the subject MOVES somewhere or CHANGES state, use sein.\nStay, happen, be = also sein: Ich bin geblieben, es ist passiert.",deepDive:"The sein verbs are a closed group. The most common ones:\n\nMotion: gehen, kommen, fahren, fliegen, laufen, reisen, schwimmen\nArrival/departure: ankommen, abfahren, einsteigen, aussteigen\nChange of state: werden (become), sterben (die), einschlafen (fall asleep), aufwachen (wake up)\nExceptions: sein (to be) and bleiben (to stay) also use sein.\n\nIch bin gewesen. (I was/have been)\nEr ist geblieben. (He stayed)"},
{type:"verb_table",title:"Perfekt mit sein",label:"sein + Partizip II",groups:[{header:"Bewegungsverben (motion verbs)",rows:[{pronoun:"ich",form:"bin gefahren",src:"drove/traveled"},{pronoun:"du",form:"bist gegangen",src:"went/walked"},{pronoun:"er/sie/es",form:"ist gekommen",src:"came"},{pronoun:"wir",form:"sind angekommen",src:"arrived"},{pronoun:"ihr",form:"seid geflogen",src:"flew"},{pronoun:"sie/Sie",form:"sind gelaufen",src:"ran/walked"}]}],note:"All these verbs describe movement from A to B. That's why they use sein."},
{type:"verb_table",title:"Perfekt with sein: Full Conjugation",label:"Ich bin gegangen (I went)",groups:[{label:"Singular",rows:[{pronoun:"ich",form:"bin gegangen",src:"I went"},{pronoun:"du",form:"bist gegangen",src:"you went"},{pronoun:"er/sie/es",form:"ist gegangen",src:"he/she/it went"}]},{label:"Plural",rows:[{pronoun:"wir",form:"sind gegangen",src:"we went"},{pronoun:"ihr",form:"seid gegangen",src:"you all went"},{pronoun:"sie/Sie",form:"sind gegangen",src:"they / you (formal) went"}]}],note:"Only the sein helper conjugates. Gegangen never changes.",deepDive:{title:"Position of Partizip II",text:"In a main clause, the Partizip II goes to the END of the sentence:\nIch bin gestern nach Berlin gefahren.\n\nThe TMP rule (time, manner, place) still applies to the middle. The Partizip II is always last."}},
{type:"verb_table",title:"Bewegungsverben: Partizip II",label:"Movement verbs + sein",groups:[{label:"Regular (-t ending)",rows:[{pronoun:"reisen",form:"ist gereist",src:"traveled"},{pronoun:"wandern",form:"ist gewandert",src:"hiked"},{pronoun:"klettern",form:"ist geklettert",src:"climbed"}]},{label:"Irregular (-en ending)",rows:[{pronoun:"laufen",form:"ist gelaufen",src:"ran"},{pronoun:"schwimmen",form:"ist geschwommen",src:"swam"},{pronoun:"springen",form:"ist gesprungen",src:"jumped"},{pronoun:"rennen",form:"ist gerannt",src:"sprinted"}]}],note:"When you see -en in Partizip II, the verb is usually irregular.",deepDive:{title:"laufen vs rennen",text:"Both describe movement on foot:\nlaufen = general running or walking\nrennen = sprinting, urgent or fast running\n\nIn Southern Germany, laufen often means 'to walk.' In the North, laufen means 'to run.'"}},
{type:"verb_table",title:"Zustandsverben: Partizip II",label:"Change-of-state verbs + sein",groups:[{label:"Separable prefix verbs",rows:[{pronoun:"einschlafen",form:"ist eingeschlafen",src:"fell asleep"},{pronoun:"aufwachen",form:"ist aufgewacht",src:"woke up"}]},{label:"Irregular core verbs",rows:[{pronoun:"werden",form:"ist geworden",src:"became"},{pronoun:"sterben",form:"ist gestorben",src:"died"},{pronoun:"bleiben",form:"ist geblieben",src:"stayed"}]},{label:"Regular loanword",rows:[{pronoun:"passieren",form:"ist passiert",src:"happened"}]}],note:"Separable verbs insert ge- between prefix and stem.",deepDive:{title:"Separable prefix + ge- rule",text:"einschlafen becomes eingeschlafen: ein + ge + schlafen.\naufwachen becomes aufgewacht: auf + ge + wacht.\n\nThe ge- always goes BETWEEN the prefix and the stem."}},
{type:"verb_table",title:"Complete Partizip II Reference",label:"Key forms to memorize",groups:[{label:"sein group (motion)",rows:[{pronoun:"gehen",form:"ist gegangen",src:"went"},{pronoun:"kommen",form:"ist gekommen",src:"came"},{pronoun:"fahren",form:"ist gefahren",src:"drove/traveled"},{pronoun:"fliegen",form:"ist geflogen",src:"flew"},{pronoun:"laufen",form:"ist gelaufen",src:"ran"},{pronoun:"schwimmen",form:"ist geschwommen",src:"swam"}]},{label:"sein group (state change)",rows:[{pronoun:"werden",form:"ist geworden",src:"became"},{pronoun:"bleiben",form:"ist geblieben",src:"stayed"},{pronoun:"einschlafen",form:"ist eingeschlafen",src:"fell asleep"},{pronoun:"aufwachen",form:"ist aufgewacht",src:"woke up"}]},{label:"haben group (activities)",rows:[{pronoun:"essen",form:"hat gegessen",src:"ate"},{pronoun:"lesen",form:"hat gelesen",src:"read"},{pronoun:"schreiben",form:"hat geschrieben",src:"wrote"},{pronoun:"kaufen",form:"hat gekauft",src:"bought"},{pronoun:"besuchen",form:"hat besucht",src:"visited"}]}],note:"These are the highest-frequency verbs in German.\nMotion and state-change = sein. Everything else = haben."},
{type:"tip",title:"Partizip II: So bildest du es",text:"Regular verbs: ge + Stamm + t\nmachen -> gemacht, kaufen -> gekauft\n\nIrregular verbs: ge + Stamm + en (often with vowel change)\nfahren -> gefahren, gehen -> gegangen\n\nSeparable verbs: Präfix + ge + Stamm + t/en\nankommen -> angekommen, einkaufen -> eingekauft\n\nInseparable verbs (be-, er-, ver-, ent-, ge-, zer-): NO ge-\nreservieren -> reserviert, besuchen -> besucht",deepDive:"The inseparable prefixes are: be-, emp-, ent-, er-, ge-, miss-, ver-, zer-.\nAlso: verbs ending in -ieren never get ge-: telefonieren -> telefoniert, reservieren -> reserviert.\n\nSeparable prefix verbs split the ge- inside:\nein|kaufen -> ein-ge-kauft\nan|kommen -> an-ge-kommen\nab|fahren -> ab-ge-fahren\n\nIrregular Partizip II forms must be memorized. Common ones:\ngehen -> gegangen, kommen -> gekommen, fahren -> gefahren, fliegen -> geflogen, nehmen -> genommen, essen -> gegessen, trinken -> getrunken, schreiben -> geschrieben, lesen -> gelesen."},
{type:"verb_table",title:"Regular Partizip II Patterns",groups:[{label:"Regular -t",rows:[{pronoun:"machen",form:"gemacht",src:"made/done"},{pronoun:"kochen",form:"gekocht",src:"cooked"},{pronoun:"spielen",form:"gespielt",src:"played"},{pronoun:"lernen",form:"gelernt",src:"learned"}]},{label:"Stem ends in -t or -d (add -et)",rows:[{pronoun:"arbeiten",form:"gearbeitet",src:"worked"},{pronoun:"warten",form:"gewartet",src:"waited"},{pronoun:"reden",form:"geredet",src:"talked"}]}],note:"The -et ending is added when the stem ends in -t or -d. This makes the Partizip II easier to pronounce."},
{type:"verb_table",title:"Separable Verbs: Partizip II",groups:[{label:"Separable Partizip II (PREFIX + ge + STEM + t/en)",rows:[{pronoun:"einkaufen",form:"eingekauft",src:"shopped"},{pronoun:"aufräumen",form:"aufgeräumt",src:"tidied up"},{pronoun:"anfangen",form:"angefangen",src:"started"},{pronoun:"mitbringen",form:"mitgebracht",src:"brought along"},{pronoun:"aufstehen",form:"aufgestanden",src:"got up"},{pronoun:"anrufen",form:"angerufen",src:"called (phone)"}]}],note:"ge- goes BETWEEN prefix and stem. Strong separable verbs (like anfangen) use -en ending."},
{type:"mc",q:"Verumius sagt: 'Ich ___ mit dem ICE gefahren.' Welches Hilfsverb passt?",opts:["bin","habe","ist","hat"],ans:"bin",hint:"Fahren is a motion verb. First person singular of sein?"},
{type:"mc",q:"Welcher Satz ist richtig?",opts:["Sie ist nach Berlin geflogen.","Sie hat nach Berlin geflogen.","Sie ist nach Berlin gefliegen.","Sie hat nach Berlin gefliegen."],ans:"Sie ist nach Berlin geflogen.",hint:"Fliegen uses sein for Perfekt. The Partizip II is unregelmäßig."},
{type:"fb",s:"Der Zug {1} um 10 Uhr angekommen.",a:"ist",opts:["ist","hat","bin","sind"],hint:"Ankommen is arrival. Third person singular of sein.",sSrc:"The train has arrived at 10 o'clock."},
{type:"fb",s:"Wir {1} gestern nach Hamburg gefahren.",a:"sind",opts:["sind","haben","ist","bin"],hint:"Wir uses the plural form of sein in Perfekt.",sSrc:"We traveled to Hamburg yesterday."},
{type:"mc",q:"Was ist das Partizip II von 'reservieren'?",opts:["reserviert","gereserviert","reservieren","gereservieren"],ans:"reserviert",hint:"Verbs ending in -ieren are inseparable. No ge- prefix needed."},
{type:"fb",s:"Er hat einen Platz {1}.",a:"reserviert",opts:["reserviert","gereserviert","reservieren","reserve"],hint:"Inseparable verb: no ge- prefix. Past participle ends in -t.",sSrc:"He has reserved a seat."},
{type:"mc",q:"'ankommen' -> Partizip II?",opts:["angekommen","geankommen","ankommen","angekommt"],ans:"angekommen",hint:"Separable verb: the ge- goes between prefix and stem."},
{type:"drag_fill",s:"Verumius {1} zum Platz {2} und hat seinen Rucksack {3}.",blanks:{1:"ist",2:"gegangen",3:"genommen"},pool:["ist","hat","gegangen","genommen","gefahren","gemacht"],hint:"Walking to a seat uses sein. Taking a backpack uses haben.",sSrc:"Verumius went to the seat and has taken his backpack."},
{type:"mc",q:"Ein Mann sitzt auf Platz 47. Verumius sagt: 'Entschuldigung, ich habe diesen Platz ___.' Was fehlt?",opts:["reserviert","gereserviert","reservieren","reserve"],ans:"reserviert",hint:"Reservieren keeps no ge- prefix. Think about the -ieren rule."},
{type:"fb",s:"Die Touristin {1} mit dem Schiff nach Norwegen gefahren.",a:"ist",opts:["ist","hat","bin","sind"],hint:"Fahren means motion from A to B. She is one person.",sSrc:"The tourist traveled by ship to Norway."},
{type:"drag_fill",s:"Verumius {1} mit dem ICE {2} und {3} in Frankfurt {4}.",blanks:{1:"ist",2:"gefahren",3:"ist",4:"angekommen"},pool:["ist","ist","hat","hat","gefahren","angekommen","gefahrt","ankommt"],hint:"Both fahren and ankommen are motion verbs. Both need sein.",sSrc:"Verumius traveled by ICE and arrived in Frankfurt."},
{type:"match",pairs:[{trg:"gefahren",src:"driven/traveled"},{trg:"gegangen",src:"went/walked"},{trg:"angekommen",src:"arrived"},{trg:"geflogen",src:"flew"},{trg:"reserviert",src:"reserved"}]},
{type:"mc",q:"Verumius zeigt seine Reservierung. Der Mann sagt: 'Oh! Ich ___ im falschen Wagen gesessen.' Welches Hilfsverb?",opts:["habe","bin","ist","hat"],ans:"habe",hint:"Sitzen is NOT motion. You stay in one place. Think about haben."},
{type:"fb",s:"Mein Motorroller {1} letzte Woche kaputt gegangen.",a:"ist",opts:["ist","hat","bin","sind"],hint:"Kaputt gehen means to break. It is a change of state.",sSrc:"My scooter broke down last week."}
]},

{id:"deu_r10l4",title:"Wenn der Zug Verspätung hat",icon:"📐",xp:20,board:true,steps:[
{type:"intro",title:"Wenn der Zug Verspätung hat",desc:"Nebensätze mit wenn, Wortstellung in Nebensätzen und Reisevokabular.",goals:["wenn + verb-final word order","Subordinate clause consolidation (weil/dass/wenn/ob)","Präteritum modals in travel context","8 new travel words"]},
{type:"teach",trg:"packen",src:"to pack",phonetic:"PAH-ken",example:"A: Hast du schon gepackt?\nB: Nein, ich packe immer am letzten Tag.",exampleSrc:"A: Have you packed already?\nB: No, I always pack on the last day.",note:"Regular verb. Also used figuratively: Das packe ich! (I can handle it!)",funFact:"Germans are famous for packing efficiently. There is even a verb 'zusammenpacken' for packing things together."},
{type:"teach",trg:"einpacken",src:"to pack (in), to wrap up",phonetic:"AIN-pah-ken",example:"A: Soll ich die Geschenke einpacken?\nB: Ja, bitte pack sie in Papier ein.",exampleSrc:"A: Should I wrap the gifts?\nB: Yes, please wrap them in paper.",note:"Separable verb: ein|packen. Ich packe den Koffer ein.",funFact:"At German stores, cashiers rarely bag your items. You einpacken your own groceries."},
{type:"teach",trg:"parken",src:"to park",phonetic:"PAR-ken",example:"A: Wo hast du geparkt?\nB: Ich habe direkt am Bahnhof geparkt.",exampleSrc:"A: Where did you park?\nB: I parked right at the train station.",note:"Regular verb. Partizip II: geparkt. Uses haben.",funFact:"Parking at German train stations can cost 5 to 15 Euro per day. Many commuters use Park-and-Ride lots instead."},
{type:"teach",trg:"verreisen",src:"to go on a trip, to travel away",phonetic:"fair-RYE-zen",example:"A: Verreist ihr diesen Sommer?\nB: Ja, wir sind letztes Jahr nach Italien verreist.",exampleSrc:"A: Are you going on a trip this summer?\nB: Yes, we traveled to Italy last year.",note:"Inseparable prefix ver-. Uses sein in Perfekt: Ich bin verreist.",funFact:"Germans have on average 30 vacation days per year. Verreisen is practically a national hobby."},
{type:"teach",trg:"ziehen",src:"to pull, to move (residence)",phonetic:"TSEE-en",example:"A: Zieh bitte die Tür zu!\nB: Okay, ich ziehe sie zu.",exampleSrc:"A: Please pull the door shut!\nB: Okay, I am pulling it shut.",note:"Irregular: ziehen, zog, gezogen. With sein when meaning 'to move': Ich bin nach Berlin gezogen.",funFact:"Ziehen has over 20 compound forms in German, from anziehen (to dress) to umziehen (to move house)."},
{type:"teach",trg:"liefern",src:"to deliver",phonetic:"LEE-fern",example:"A: Wann wird das Paket geliefert?\nB: Der Bote liefert es morgen.",exampleSrc:"A: When will the package be delivered?\nB: The courier delivers it tomorrow.",note:"Regular verb. Die Lieferung = the delivery.",funFact:"Deutsche Post delivers around 1.6 billion parcels per year in Germany alone."},
{type:"teach",trg:"direkt",src:"direct, directly",phonetic:"dee-REKT",example:"A: Gibt es einen direkten Zug nach Hamburg?\nB: Ja, der ICE fährt direkt ohne Umsteigen.",exampleSrc:"A: Is there a direct train to Hamburg?\nB: Yes, the ICE goes directly without changing.",note:"Adjective and adverb. Direkt am Bahnhof = right at the station.",funFact:"A direkter Zug means no transfers. Germans strongly prefer these, because Umsteigen (changing trains) risks missing connections."},
{type:"teach",trg:"offen",src:"open, honest",phonetic:"OH-fen",example:"A: Ist das Fenster offen?\nB: Ja, ich habe es offen gelassen.",exampleSrc:"A: Is the window open?\nB: Yes, I left it open.",note:"Adjective. Not the same as öffnen (to open, verb). Die Tür ist offen = The door is open.",funFact:"Offene Türen (open doors) is a common metaphor in German. Tag der offenen Tür is an open house event at schools and businesses."},
{type:"tip",title:"Nebensatz mit wenn",text:"wenn (if/when) sends the conjugated verb to the END of the clause.\n\nMain clause: Der Zug hat Verspätung.\nNebensatz: Wenn der Zug Verspätung hat, ...\n\nNotice: hat moves to the end after wenn.\n\nWenn can mean 'if' (conditional) or 'when/whenever' (temporal):\n. Wenn es regnet, bleibe ich zu Hause. (If/When it rains...)\n. Wenn ich nach Berlin fahre, nehme ich den ICE. (When I go to Berlin...)\n\nThe main clause after a wenn-clause starts with the verb (verb-second rule):\nWenn ich packe, vergesse ich immer etwas.",deepDive:"The conjugated verb always goes to the final position in a wenn-clause. If the sentence starts with the wenn-clause, the main clause begins with the verb: Wenn ..., VERB subject ... This is called 'inversion' and happens after all subordinate clauses."},
{type:"tip",title:"Why war/hatte even in speech?",text:"Most Präteritum forms sound stiff in conversation.\nBut war and hatte are the EXCEPTIONS:\n\n'Ich war müde.' sounds natural.\n'Ich bin müde gewesen.' sounds awkward.\n\n'Er hatte Hunger.' sounds natural.\n'Er hat Hunger gehabt.' sounds clumsy.\n\nRule: always use war/hatte in speech AND writing.",deepDive:{title:"The three Präteritum survivors",text:"In spoken German, only three verb groups consistently use Präteritum:\n1. sein: war/warst/war/waren\n2. haben: hatte/hattest/hatte/hatten\n3. Modal verbs: konnte/musste/wollte/durfte/sollte\n\nEverything else uses Perfekt in speech."}},
{type:"tip",title:"Nebensatz-Wortstellung: weil, dass, wenn, ob",text:"Four conjunctions you know all share the same rule: the verb goes to the END.\n\n. weil (because): Ich bin müde, weil ich früh aufgestanden bin.\n. dass (that): Ich weiß, dass der Zug um 9 fährt.\n. wenn (if/when): Wenn du kommst, bringe ich Kaffee mit.\n. ob (whether): Ich frage, ob der Zug pünktlich ist.\n\nAll four: conjunction + subject + ... + VERB (at the end).\nWith Perfekt, the helping verb goes last: ... weil ich den Zug verpasst habe.",deepDive:"These are called subordinating conjunctions (Subjunktionen). They create dependent clauses that cannot stand alone. The verb-final rule applies to ALL subordinating conjunctions in German, not just these four."},
{type:"mc",q:"Which word order is correct after 'wenn'?",opts:["Wenn ich den Koffer packe, ...","Wenn ich packe den Koffer, ...","Wenn packe ich den Koffer, ...","Wenn den Koffer ich packe, ..."],ans:"Wenn ich den Koffer packe, ...",hint:"The verb moves to the final position in the clause."},
{type:"fb",s:"Wenn der Zug Verspätung {1}, verpasse ich den Anschluss.",a:"hat",opts:["hat","haben","habe","ist"],hint:"The subject is 'der Zug', so which form fits?",sSrc:"If the train has a delay, I will miss the connection."},
{type:"mc",q:"'Wenn ich nach München verreist bin, habe ich immer den ICE genommen.' What does 'wenn' mean here?",opts:["Whenever (temporal, repeated action)","If (conditional, hypothetical)","Because (causal)","That (declarative)"],ans:"Whenever (temporal, repeated action)",hint:"The sentence describes something that happened multiple times."},
{type:"fb",s:"Ich frage, ob der Zug pünktlich {1}.",a:"ist",opts:["ist","sein","bist","hat"],hint:"The subject is 'der Zug', third person singular.",sSrc:"I ask whether the train is on time."},
{type:"drag_fill",s:"Wenn ich früh {1}, {2} ich alles in den Koffer {3}.",blanks:{"1":"aufstehe","2":"packe","3":"ein"},pool:["aufstehe","packe","ein","stehe","packen","aus"],hint:"First blank: getting up early (separable verb). Main clause: a separable verb that means putting things into something.",sSrc:"When I get up early, I pack everything into the suitcase."},
{type:"mc",q:"Wir konnten nicht verreisen, ... der Zug Verspätung hatte.",opts:["weil","wenn","und","aber"],ans:"weil",hint:"This gives a reason for not traveling."},
{type:"fb",s:"Er {1} gestern nicht parken, weil der Parkplatz voll war.",a:"konnte",opts:["konnte","kann","konnten","gekonnt"],hint:"Präteritum modal, third person singular, past tense.",sSrc:"He could not park yesterday because the parking lot was full."},
{type:"drag_fill",s:"Wenn ich nach Berlin {1}, {2} ich immer direkt am Bahnhof.",blanks:{"1":"fahre","2":"parke"},pool:["fahre","parke","fährt","parken"],hint:"Wenn-clause: verb final. Main clause: verb second after comma.",sSrc:"When I drive to Berlin, I always park right at the train station."},
{type:"mc",q:"Sie wollte den Koffer einpacken, aber sie ... keine Zeit.",opts:["hatte","hat","haben","hatten"],ans:"hatte",hint:"Präteritum of haben, third person singular."},
{type:"fb",s:"Wenn das Paket {1} wird, bin ich nicht zu Hause.",a:"geliefert",opts:["geliefert","liefern","liefert","geliefern"],hint:"Partizip II of a regular verb in a passive construction.",sSrc:"When the package is delivered, I will not be at home."},
{type:"match",pairs:[{trg:"Wenn es regnet, ...",src:"verb-final: regnet at end"},{trg:"..., weil er müde war.",src:"verb-final: war at end"},{trg:"Ich weiß, dass er kommt.",src:"verb-final: kommt at end"},{trg:"Ich frage, ob sie parkt.",src:"verb-final: parkt at end"}]},
{type:"mc",q:"Wenn ich letztes Jahr verreist ..., habe ich den Koffer immer selbst gepackt.",opts:["bin","habe","war","hatte"],ans:"bin",hint:"Verreisen uses sein in Perfekt, not haben."},
{type:"drag_fill",s:"Ich musste den Koffer {1}, weil ich morgen {2}.",blanks:{"1":"packen","2":"verreise"},pool:["packen","verreise","gepackt","verreist","packe","reise"],hint:"After a modal verb, use the infinitive. Weil-clause: verb final.",sSrc:"I had to pack the suitcase because I am traveling tomorrow."},
{type:"fb",s:"Wenn der Zug direkt {1}, muss man nicht umsteigen.",a:"fährt",opts:["fährt","fahren","gefahren","fuhr"],hint:"Present tense, third person singular of fahren.",sSrc:"If the train goes directly, one does not have to transfer."},
{type:"mc",q:"Wir sind nach Hamburg gezogen, weil mein Vater dort eine Stelle ... .",opts:["hatte","hat","haben","gehabt"],ans:"hatte",hint:"Präteritum of haben. The reason is in the past."},
{type:"drag_fill",s:"Wenn ich {1} habe, {2} ich immer die Tür {3}.",blanks:{"1":"gepackt","2":"ziehe","3":"zu"},pool:["gepackt","ziehe","zu","packe","gezogen","auf"],hint:"Perfekt in wenn-clause (habe at end). Main clause: a separable verb meaning to close by pulling.",sSrc:"When I have packed, I always pull the door shut."},
{type:"mc",q:"Which sentence has correct word order?",opts:["Ich weiß, dass er den Koffer gepackt hat.","Ich weiß, dass er hat den Koffer gepackt.","Ich weiß, dass er gepackt den Koffer hat.","Ich weiß, dass gepackt er den Koffer hat."],ans:"Ich weiß, dass er den Koffer gepackt hat.",hint:"In Perfekt inside a dass-clause, the helping verb goes last."},
{type:"fb",s:"Wenn die Tür {1} ist, kommt kalte Luft herein.",a:"offen",opts:["offen","öffnen","geöffnet","offene"],hint:"An adjective describing the state of the door.",sSrc:"If the door is open, cold air comes in."},
{type:"mc",q:"Er konnte nicht einpacken, weil der Koffer zu klein ... .",opts:["war","ist","sein","gewesen"],ans:"war",hint:"Präteritum of sein. The sentence is about a past situation."},
{type:"drag_fill",s:"Wenn ich {1} bin, {2} ich immer viel {3}.",blanks:{"1":"verreist","2":"habe","3":"erlebt"},pool:["verreist","habe","erlebt","verreise","bin","erleben"],hint:"Wenn-clause uses Perfekt with sein (verreisen). Main clause also Perfekt with haben (erleben).",sSrc:"When I have traveled, I have always experienced a lot."}
]},

{id:"deu_r10l5",title:"Hin und her",icon:"↔️",xp:15,board:true,steps:[
{type:"intro",title:"Hin und her",desc:"Wohin geht die Reise? Lerne Richtungswörter mit hin, her und zurück.",goals:["Directional words with hin/her/zurück","Review Perfekt with sein","Combine with wenn-clauses"]},
{type:"teach",trg:"zurückfahren",src:"to drive back",phonetic:"tsoo-RÜCK-fah-ren",example:"A: Wann fährst du zurück?\nB: Ich fahre morgen Abend zurück.",exampleSrc:"A: When are you driving back?\nB: I'm driving back tomorrow evening.",note:"Separable: fährt ... zurück. Perfekt: ist zurückgefahren (sein, because movement).",funFact:"Germans say 'Ich fahre zurück' even for train travel. Fahren covers all vehicle transport."},
{type:"teach",trg:"zurückgeben",src:"to give back",phonetic:"tsoo-RÜCK-gay-ben",example:"A: Kannst du mir das Buch zurückgeben?\nB: Ja, ich gebe es dir morgen zurück.",exampleSrc:"A: Can you give the book back to me?\nB: Yes, I'll give it back to you tomorrow.",note:"Separable: gibt ... zurück. Perfekt: hat zurückgegeben (haben, no movement).",funFact:"At German libraries you 'geben zurück' your books. Late fees are called Mahngebühren."},
{type:"teach",trg:"zurückgehen",src:"to go back",phonetic:"tsoo-RÜCK-gay-en",example:"A: Gehen wir zurück zum Bahnhof?\nB: Ja, wir müssen zurückgehen.",exampleSrc:"A: Shall we go back to the station?\nB: Yes, we have to go back.",note:"Separable: geht ... zurück. Perfekt: ist zurückgegangen (sein).",funFact:"Zurückgehen also means 'to decrease.' Prices can zurückgehen too."},
{type:"teach",trg:"zurückkommen",src:"to come back",phonetic:"tsoo-RÜCK-koh-men",example:"A: Wann kommst du zurück?\nB: Ich komme in einer Stunde zurück.",exampleSrc:"A: When are you coming back?\nB: I'm coming back in an hour.",note:"Separable: kommt ... zurück. Perfekt: ist zurückgekommen (sein).",funFact:"Komm zurück! is what you shout when someone leaves and you want them back."},
{type:"teach",trg:"zurücklaufen",src:"to run back",phonetic:"tsoo-RÜCK-lau-fen",example:"A: Der Zug fährt gleich!\nB: Dann müssen wir zurücklaufen!",exampleSrc:"A: The train is leaving soon!\nB: Then we have to run back!",note:"Separable: läuft ... zurück. Perfekt: ist zurückgelaufen (sein).",funFact:"Laufen means both 'to walk' and 'to run' in German. Context decides the speed."},
{type:"teach",trg:"hin",src:"away from speaker",phonetic:"hin",example:"A: Wo gehst du hin?\nB: Ich gehe zum Bahnhof hin.",exampleSrc:"A: Where are you going (to)?\nB: I'm going to the station.",note:"Hin shows movement AWAY from the speaker. Often at the end: Wo gehst du hin?",funFact:"Wohin (where to) is literally wo + hin. Germans split it in speech: Wo gehst du hin?"},
{type:"teach",trg:"her",src:"toward speaker",phonetic:"hehr",example:"A: Komm mal her!\nB: Ich komme schon her.",exampleSrc:"A: Come here!\nB: I'm already coming.",note:"Her shows movement TOWARD the speaker. Opposite of hin.",funFact:"Woher (where from) is wo + her. Germans ask 'Wo kommst du her?' to learn your origin."},
{type:"tip",title:"Das Hin-und-her-System",text:"German has a directional pair system:\n\n. hin = away from speaker (Wo gehst du hin?)\n. her = toward speaker (Komm her!)\n\nThey attach to verbs as prefixes:\n. hingehen = to go there\n. herkommen = to come here\n. hinfahren = to drive there\n. herfahren = to drive here\n\nWith zurück, the movement reverses:\n. zurückfahren = to drive back\n. zurückgehen = to go back",deepDive:"Hin and her also combine with prepositions: hinaus (out, away), herein (in, toward), hinauf (up, away), herunter (down, toward). In casual speech, many Germans shorten these: raus, rein, rauf, runter."},
{type:"teach",trg:"drüben",src:"over there",phonetic:"DRÜ-ben",example:"A: Wo ist der Kiosk?\nB: Der Kiosk ist drüben, auf der anderen Seite.",exampleSrc:"A: Where is the kiosk?\nB: The kiosk is over there, on the other side.",note:"Points to the other side of something (street, room, border).",funFact:"During the Cold War, drüben meant 'the other Germany.' West Germans said die drüben for East Germans and vice versa."},
{type:"teach",trg:"unterwegs",src:"on the way",phonetic:"un-ter-VEGS",example:"A: Wo bist du?\nB: Ich bin unterwegs zum Hauptbahnhof.",exampleSrc:"A: Where are you?\nB: I'm on the way to the main station.",note:"Used with sein: Ich bin unterwegs. No separable parts.",funFact:"Unterwegs sein is the German version of 'I'm on my way.' You'll hear it in every phone call about delays."},
{type:"teach",trg:"vorbei",src:"past/over",phonetic:"for-BYE",example:"A: Ist der Zug schon vorbei?\nB: Ja, er ist vor fünf Minuten vorbeigefahren.",exampleSrc:"A: Has the train already passed?\nB: Yes, it drove past five minutes ago.",note:"Two meanings: (1) physically past (vorbeifahren), (2) finished/over (Die Party ist vorbei).",funFact:"Vorbei ist vorbei is a common German saying meaning 'what's done is done.'"},
{type:"teach",trg:"vorher",src:"before (temporal)",phonetic:"FOR-hehr",example:"A: Hast du vorher gefrühstückt?\nB: Nein, ich hatte vorher keine Zeit.",exampleSrc:"A: Did you eat breakfast before?\nB: No, I didn't have time before.",note:"Temporal only. For 'in front of' use vor.",funFact:"Germans love temporal precision. Vorher, nachher, davor, danach: four ways to say before and after."},
{type:"teach",trg:"vorwärts",src:"forward",phonetic:"FOR-verts",example:"A: Gehen wir vorwärts oder rückwärts?\nB: Immer vorwärts!",exampleSrc:"A: Are we going forward or backward?\nB: Always forward!",note:"Opposite: rückwärts (backward). Used for physical and abstract progress.",funFact:"Vorwärts was the name of the German Social Democrats' newspaper since 1876."},
{type:"teach",trg:"weg",src:"away/gone",phonetic:"vek",example:"A: Wo ist mein Koffer?\nB: Er ist weg! Jemand hat ihn genommen!",exampleSrc:"A: Where is my suitcase?\nB: It's gone! Someone took it!",note:"Short and blunt. Weg! alone means 'Go away!' As a noun, der Weg means 'the path.'",funFact:"Geh weg! (Go away!) is one of the first phrases German children learn to yell at siblings."},
{type:"mc",q:"'Hin' zeigt Bewegung ...",opts:["vom Sprecher weg","zum Sprecher","nach oben","nach unten"],ans:"vom Sprecher weg",hint:"Think about the direction: toward or away?"},
{type:"fb",s:"Wann kommst du {1}?",a:"zurück",opts:["zurück","weg","hin","vorbei"],hint:"You want to know when someone returns.",sSrc:"When are you coming back?"},
{type:"mc",q:"Welches Wort bedeutet 'on the way'?",opts:["unterwegs","vorwärts","drüben","vorher"],ans:"unterwegs",hint:"You're not there yet, but you're traveling."},
{type:"fb",s:"Der Zug ist schon {1}. Wir haben ihn verpasst.",a:"vorbei",opts:["vorbei","weg","hin","unterwegs"],hint:"The train already passed. It's over.",sSrc:"The train is already past. We missed it."},
{type:"mc",q:"'Ich bin gestern zurückgefahren.' Welches Hilfsverb braucht zurückfahren im Perfekt?",opts:["sein","haben","werden","können"],ans:"sein",hint:"Driving back involves a change of location."},
{type:"fb",s:"Wenn du morgen {1}, bringe bitte Brot mit.",a:"zurückkommst",opts:["zurückkommst","zurückgeben","vorwärts","unterwegs"],hint:"Fill in: when you come back tomorrow ...",sSrc:"When you come back tomorrow, please bring bread."},
{type:"drag_fill",s:"Ich bin vorher zum Gleis {1}, aber der Zug war schon {2}.",blanks:{"1":"hingegangen","2":"weg"},pool:["hingegangen","weg","zurück","her","vorbei"],hint:"First blank: went there (away from speaker). Second: gone.",sSrc:"I had previously gone there to the platform, but the train was already gone."},
{type:"mc",q:"Was sagt man, wenn jemand auf der anderen Straßenseite steht?",opts:["Er steht drüben.","Er ist unterwegs.","Er geht vorwärts.","Er kommt her."],ans:"Er steht drüben.",hint:"The person is on the other side, across from you."},
{type:"match",pairs:[{trg:"zurückgeben",src:"to give back"},{trg:"vorher",src:"before (temporal)"},{trg:"vorwärts",src:"forward"},{trg:"weg",src:"away/gone"},{trg:"drüben",src:"over there"}]},
{type:"fb",s:"Komm bitte {1}! Ich brauche deine Hilfe.",a:"her",opts:["her","hin","weg","zurück"],hint:"You want the person to come toward you.",sSrc:"Please come here! I need your help."},
{type:"mc",q:"Wenn ich den Koffer nicht finde, muss ich zum Fundbüro ...",opts:["hingehen","herkommen","zurückgeben","vorbeifahren"],ans:"hingehen",hint:"You need to go there, away from where you are now."},
{type:"drag_fill",s:"Wenn der Zug {1} ist, müssen wir zu Fuß {2}.",blanks:{"1":"vorbei","2":"zurücklaufen"},pool:["vorbei","zurücklaufen","unterwegs","hingehen","vorher"],hint:"First: the train has passed. Second: run back on foot.",sSrc:"If the train is past, we have to run back on foot."}
]},

// ─── L6: Der Anschluss ───
{id:"deu_r10l6",title:"Der Anschluss",icon:"🏃‍♂️",xp:20,board:true,steps:[
{type:"intro",title:"Der Anschluss",desc:"Munich Hauptbahnhof. Verumius has exactly 4 minutes to catch his connection train. Escalators, crowds, the smell of fresh Brezeln. Can he make it?",goals:["Review Perfekt with sein and haben","Combine wenn + subordinate word order","Use Präteritum modals in past narratives","Multi-construct sentences with 2-3 grammar points"]},
{type:"story",speaker:"narrator",mood:"tense",art:"de-munich-hbf",trg:"München Hauptbahnhof. Die Durchsage: 'ICE 517 nach Hamburg fährt in vier Minuten ab, Gleis 14.' Verumius steht auf Gleis 3. Elf Gleise Unterschied. Er rennt.",src:"Munich Central Station. The announcement: 'ICE 517 to Hamburg departs in four minutes, platform 14.' Verumius is on platform 3. Eleven platforms apart. He runs."},
{type:"story",speaker:"narrator",mood:"tense",art:"de-munich-sprint",trg:"Er springt auf die Rolltreppe, drückt sich an einer Frau mit einem Kinderwagen vorbei. 'Entschuldigung!' Der Geruch von frischen Brezeln aus einer Bäckerei. Sein Magen knurrt, aber der Zug wartet nicht.",src:"He jumps on the escalator, squeezes past a woman with a stroller. 'Excuse me!' The smell of fresh pretzels from a bakery. His stomach growls, but the train won't wait."},
{type:"teach",trg:"das Kaufhaus",src:"the department store",note:"Neuter. Compound: Kauf (purchase) + Haus (house).",example:"A: Wo hast du die Jacke gekauft?\nB: Im Kaufhaus am Marienplatz.",exampleSrc:"A: Where did you buy the jacket?\nB: At the department store on Marienplatz.",funFact:"KaDeWe in Berlin (Kaufhaus des Westens) is the largest department store in continental Europe. Six floors, 60,000 square meters, and an entire floor just for food."},
{type:"teach",trg:"das Einkaufszentrum",src:"the shopping center",note:"Neuter. Compound: Einkauf (shopping) + Zentrum (center).",example:"A: Gibt es ein Einkaufszentrum in der Nähe?\nB: Ja, wenn du die Kreuzung überquerst, ist es auf der rechten Seite.",exampleSrc:"A: Is there a shopping center nearby?\nB: Yes, if you cross the intersection, it's on the right side.",funFact:"German compound nouns can get famously long. Einkaufszentrum is 16 letters, but that is short by German standards. The linking 's' in Einkauf-s-zentrum is called a Fugen-s."},
{type:"teach",trg:"die Kreuzung",src:"the intersection",note:"Feminine. From kreuzen (to cross). Plural: die Kreuzungen.",example:"A: An der Kreuzung musste ich warten.\nB: Ja, die Ampel war rot.",exampleSrc:"A: At the intersection I had to wait.\nB: Yes, the traffic light was red.",funFact:"German intersections are strictly regulated. Jaywalking (bei Rot gehen) can earn you a fine of 5 to 10 euros. Germans really do wait for the green light, even at 3 AM with no cars in sight."},
{type:"teach",trg:"der Rundgang",src:"the tour / round",note:"Masculine. Compound: rund (round) + Gang (walk).",example:"A: Wir haben einen Rundgang durch die Altstadt gemacht.\nB: Das klingt toll! Was habt ihr gesehen?",exampleSrc:"A: We did a tour through the old town.\nB: That sounds great! What did you see?",funFact:"A Rundgang is literally a 'round walk,' a circular tour that ends where it started. German city guides love offering Rundgänge through historic neighborhoods."},
{type:"teach",trg:"die Messe",src:"the trade fair",note:"Feminine. Also means 'mass' (church service). Context decides.",example:"A: Bist du zur Messe gefahren?\nB: Ja, ich bin mit dem Zug hingefahren.",exampleSrc:"A: Did you go to the trade fair?\nB: Yes, I went there by train.",funFact:"Germany hosts some of the world's biggest trade fairs. The Hannover Messe attracts over 200,000 visitors. Frankfurt's Buchmesse (book fair) is the world's largest book event."},
{type:"teach",trg:"das Zelt",src:"the tent",note:"Neuter. Plural: die Zelte.",example:"A: Wenn es regnet, gehen wir ins Zelt.\nB: Gute Idee! Es ist warm und trocken.",exampleSrc:"A: If it rains, we'll go into the tent.\nB: Good idea! It's warm and dry.",funFact:"At Oktoberfest, the Bierzelte (beer tents) are massive. The largest, the Hofbräu-Festzelt, seats 10,000 people. They are really more like temporary buildings than tents."},
{type:"teach",trg:"rund",src:"round",note:"Adjective. Also used as 'approximately': rund 100 Leute (around 100 people).",example:"A: Der Tisch ist rund.\nB: Ja, und rund 20 Leute sitzen daran.",exampleSrc:"A: The table is round.\nB: Yes, and around 20 people are sitting at it.",funFact:"'Rund' does double duty in German. Shape: ein runder Tisch (a round table). Approximation: rund 50 Euro (about 50 euros). Both meanings come from the idea of completeness."},
{type:"mc",q:"'Verumius ist durch das Kaufhaus gerannt.' Which auxiliary verb forms the Perfekt here?",opts:["ist (movement verb)","hat (action verb)","war (past tense)","wurde (passive)"],ans:"ist (movement verb)",hint:"Rennen involves a change of location. Motion verbs use sein."},
{type:"fb",s:"An der {1} musste ich fünf Minuten warten.",a:["Kreuzung"],opts:["Kreuzung","Messe","Rolltreppe","Bäckerei"],hint:"Where two streets meet and traffic lights control the flow.",sSrc:"At the intersection I had to wait five minutes."},
{type:"mc",q:"'Wenn der Zug abfährt, muss ich am Gleis sein.' What happens to the verb in the wenn-clause?",opts:["The conjugated verb goes to the end","The verb stays in second position","The verb is dropped","The verb becomes an infinitive"],ans:"The conjugated verb goes to the end",hint:"Subordinate clauses in German send the verb to the final position."},
{type:"drag_fill",s:"Verumius {1} durch das Einkaufszentrum {2}, weil er seinen Anschluss nicht {3} wollte.",blanks:{"1":"ist","2":"gerannt","3":"verpassen"},pool:["ist","gerannt","verpassen","hat","gelaufen","verpasst"],hint:"Rennen uses sein in Perfekt. Wollen + infinitive in the subordinate clause.",sSrc:"Verumius ran through the shopping center because he did not want to miss his connection."},
{type:"fb",s:"Wir haben einen {1} durch die Altstadt gemacht.",a:["Rundgang"],opts:["Rundgang","Kreuzung","Zelt","Kaufhaus"],hint:"A circular walking tour. Compound of rund + Gang.",sSrc:"We did a tour through the old town."},
{type:"mc",q:"'Er konnte den Zug nicht sehen, weil das Kaufhaus im Weg war.' Which grammar points combine here?",opts:["Präteritum modal + weil-clause","Perfekt + wenn-clause here","Imperativ + Partizip II","Futur + Relativsatz combo"],ans:"Präteritum modal + weil-clause",hint:"Konnte is past tense of können. Weil sends the verb to the end."},
{type:"drag_fill",s:"Wenn es {1}, gehen wir ins {2}. Dort {3} wir gestern auch {4}.",blanks:{"1":"regnet","2":"Zelt","3":"sind","4":"gewesen"},pool:["regnet","Zelt","sind","gewesen","hat","geregnet"],hint:"Wenn-clause with present tense. Second sentence: Perfekt of the verb 'to be' in past.",sSrc:"If it rains, we go into the tent. We were also there yesterday."},
{type:"mc",q:"'___ 200 Leute waren auf der Messe.' Which word fits for 'approximately'?",opts:["Rund","Leute","Messe","Waren"],ans:"Rund",hint:"This word also means 'round' as a shape, but here it modifies a number."},
{type:"fb",s:"Er {1} den Zug nehmen, aber er konnte das Gleis nicht finden.",a:["wollte"],opts:["wollte","konnte","musste","durfte"],hint:"He WANTED to take the train. Past tense of wollen.",sSrc:"He wanted to take the train, but he could not find the platform."},
{type:"drag_fill",s:"Wenn Verumius das {1} {2} hat, ist er zum {3} {4}.",blanks:{"1":"Kaufhaus","2":"gesehen","3":"Gleis","4":"gerannt"},pool:["Kaufhaus","gesehen","Gleis","gerannt","Messe","gefahren"],hint:"When he SAW the department store, he RAN to the platform. Wenn + Perfekt, main clause Perfekt with sein.",sSrc:"When Verumius saw the department store, he ran to the platform."},
{type:"story",speaker:"narrator",mood:"triumphant",art:"de-train-doors",trg:"Gleis 14. Die Türen piepen. Verumius springt hinein. Die Türen schließen sich hinter ihm. Er hat es geschafft! Im Bordbistro bestellt er eine Currywurst. Er hat sie verdient.",src:"Platform 14. The doors beep. Verumius jumps in. The doors close behind him. He made it! In the onboard bistro he orders a Currywurst. He's earned it."},
{type:"mc",q:"'Er hat es geschafft, weil er schnell genug gerannt ist.' How many grammar constructs combine here?",opts:["Three: Perfekt haben + weil-clause + Perfekt sein","Two: Perfekt haben + Perfekt sein","One: just Perfekt","Four: Perfekt + weil + modal + sein"],ans:"Three: Perfekt haben + weil-clause + Perfekt sein",hint:"Hat geschafft (Perfekt with haben), weil sends verb to end, gerannt ist (Perfekt with sein)."},
{type:"fb",s:"Wenn ich am Bahnhof {1}, kaufe ich eine Brezel.",a:["ankomme"],opts:["ankomme","ankommen","angekommen","ankam"],hint:"Wenn-clause needs present tense, first person singular. In subordinate clauses, separable verbs reunite at the end.",sSrc:"When I arrive at the station, I buy a pretzel."},
{type:"drag_fill",s:"Gestern {1} ich zur Messe {2}, und danach {3} ich ein Zelt auf dem Marktplatz {4}.",blanks:{"1":"bin","2":"gefahren","3":"habe","4":"gesehen"},pool:["bin","gefahren","habe","gesehen","ist","gekauft"],hint:"Fahren uses sein in Perfekt. Sehen uses haben. Two different auxiliaries in one sentence.",sSrc:"Yesterday I traveled to the trade fair, and afterwards I saw a tent at the market square."},
{type:"match",pairs:[{trg:"das Kaufhaus",src:"department store"},{trg:"das Einkaufszentrum",src:"shopping center"},{trg:"die Kreuzung",src:"intersection"},{trg:"der Rundgang",src:"tour / round"},{trg:"die Messe",src:"trade fair"},{trg:"das Zelt",src:"tent"},{trg:"rund",src:"round / approximately"}]},
{type:"tip",title:"Sprint geschafft!",text:"Verumius made his connection by 12 seconds.\nHe combined everything from Unit 10:\n\n1. Perfekt with sein (ist gerannt, ist gefahren)\n2. Perfekt with haben (hat geschafft, hat gesehen)\n3. Wenn-clauses with verb at the end\n4. Weil-clauses with verb at the end\n5. Präteritum modals (konnte, wollte, musste)\n\nThe Currywurst? Totally earned.",deepDive:{title:"Partizip II patterns",text:"Four patterns to recognize:\n1. Weak regular: ge + stem + t (kaufen: gekauft, machen: gemacht)\n2. Mixed irregular: ge + changed stem + t (rennen: gerannt, bringen: gebracht)\n3. Strong: ge + changed stem + en (fahren: gefahren, fliegen: geflogen)\n4. Separable: prefix + ge + stem + t/en (einchecken: eingecheckt, ankommen: angekommen)\n\nVerbs with inseparable prefixes (be-, ge-, er-, ver-) do NOT add ge-:\nbesuchen: besucht, verstehen: verstanden, erklären: erklärt."}}
]}
,

{id:"deu_r10l7",title:"Fahrkartenkontrolle",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Fahrkartenkontrolle!",desc:"The ticket inspector is here. Time to prove you know your way around Deutsche Bahn, German geography, and travel vocabulary. Everything from Unit 10 is fair game.",goals:["Test all U10 travel and geography vocabulary","Combine Perfekt, wenn-clauses, and subordinate word order","Show you can handle real travel situations"]},
{type:"mc",q:"Verumius ist mit dem Zug nach München gefahren. Which tense is this sentence in?",opts:["Präsens","Perfekt with sein","Perfekt with haben","Präteritum"],ans:"Perfekt with sein",hint:"'Gefahren' is a movement verb. Think about which auxiliary it needs."},
{type:"fb",s:"Wir haben den Flug nach Berlin {1}.",a:["gebucht"],opts:["gebucht","buchen","gebuchen","buchte"],hint:"You need the Partizip II of 'buchen' after 'haben.'",sSrc:"We have booked the flight to Berlin."},
{type:"mc",q:"'Wenn der Zug Verspätung hat, verpasse ich meinen Flug.' What does 'Verspätung' mean?",opts:["ticket","platform","delay","departure"],ans:"delay",hint:"This noun describes when something arrives later than planned."},
{type:"drag_fill",s:"Ich {1} gestern am Markt {2}.",blanks:{"1":"bin","2":"umgestiegen"},pool:["bin","habe","umgestiegen","umsteigen","hat"],hint:"'Umsteigen' is a movement action. Which auxiliary does it take?",sSrc:"I transferred at the market yesterday."},
{type:"fb",s:"Wenn es regnet, nehme ich den {1} statt das Fahrrad.",a:["Bus"],opts:["Bus","Strand","Wald","Berg"],hint:"Which Verkehrsmittel keeps you dry when it rains?",sSrc:"When it rains, I take the bus instead of the bicycle."},
{type:"match",pairs:[{trg:"der Fahrplan",src:"timetable / schedule"},{trg:"die Verspätung",src:"delay"},{trg:"das Verkehrsmittel",src:"means of transport"},{trg:"umsteigen",src:"to change / transfer"},{trg:"verpassen",src:"to miss"},{trg:"buchen",src:"to book"}]},
{type:"mc",q:"'Der Tourist hat seinen Rucksack im Zug vergessen.' What happened?",opts:["The tourist packed his backpack","The tourist bought a new backpack","The tourist forgot his backpack on the train","The tourist found his backpack at the station"],ans:"The tourist forgot his backpack on the train",hint:"'Vergessen' means to forget. Where did it happen?"},
{type:"drag_fill",s:"Wenn ich {1}, muss ich am Rathaus {2}.",blanks:{"1":"verreise","2":"umsteigen"},pool:["verreise","umsteigen","verreisen","umgestiegen","packen"],hint:"Fill in the present tense verb in the wenn-clause and the infinitive after 'muss.'",sSrc:"When I travel, I have to transfer at the town hall."},
{type:"fb",s:"Das Schiff fährt über den {1} zur Insel.",a:["Fluss"],opts:["Fluss","Berg","Wald","Markt"],hint:"Ships travel over water. Which word means 'river'?",sSrc:"The ship travels over the river to the island."},
{type:"mc",q:"'Wir konnten nicht parken, weil der Markt offen war.' Which grammar features appear here?",opts:["Perfekt + wenn-clause","Präteritum + weil-clause","Präsens + dass-clause","Perfekt + ob-clause"],ans:"Präteritum + weil-clause",hint:"Look at 'konnten' and the word order after 'weil.'"},
{type:"drag_fill",s:"Wenn du den {1} liest, findest du den {2} zum Zentrum.",blanks:{"1":"Stadtplan","2":"Weg"},pool:["Stadtplan","Weg","Strand","Flug","Rucksack"],hint:"A map helps you find the route to the city center.",sSrc:"If you read the city map, you will find the way to the center."},
{type:"fb",s:"Er ist gestern mit dem Motorroller zur {1} gefahren.",a:["Brücke"],opts:["Brücke","Verspätung","Ampel","Verkehr"],hint:"This is a structure built over water to cross from one side to the other.",sSrc:"He drove to the bridge by scooter yesterday."},
{type:"mc",q:"Which sentence has correct subordinate word order?",opts:["Wenn ich den Zug verpasse, muss ich warten.","Wenn ich verpasse den Zug, muss ich warten.","Wenn verpasse ich den Zug, muss ich warten.","Wenn ich den Zug verpasse, ich muss warten."],ans:"Wenn ich den Zug verpasse, muss ich warten.",hint:"In a wenn-clause the verb goes to the end. In the main clause after a wenn-clause, the verb comes first."},
{type:"match",pairs:[{trg:"die Brücke",src:"bridge"},{trg:"die Insel",src:"island"},{trg:"die Landschaft",src:"landscape"},{trg:"der Strand",src:"beach"},{trg:"der Wald",src:"forest"},{trg:"der Berg",src:"mountain"}]},
{type:"fb",s:"Die Touristen {1} ihre Koffer schon eingepackt.",a:["haben"],opts:["haben","sind","hat","ist"],hint:"Which auxiliary does a non-motion verb use in the Perfekt?",sSrc:"The tourists have already packed their suitcases."},
{type:"mc",q:"Verumius fragt: 'Ist die Kirche in der Nähe?' What is he asking about?",opts:["Whether the church is nearby","Whether the church is open","When the church was built","How old the church is"],ans:"Whether the church is nearby",hint:"'In der Nähe' describes physical proximity, not time or age."},
{type:"drag_fill",s:"Ich {1} vorher den Reifen {2}, weil er kaputt {3}.",blanks:{"1":"musste","2":"wechseln","3":"war"},pool:["musste","wechseln","war","konnte","gewechselt","ist"],hint:"Präteritum modal + infinitive in the main clause, verb-final in the weil-clause.",sSrc:"I had to change the tire beforehand because it was broken."},
{type:"fb",s:"Wenn du an der Kreuzung rechts gehst, siehst du das {1}.",a:["Kaufhaus"],opts:["Kaufhaus","Reifen","Motor","Zelt"],hint:"This is a large building where you can buy many things.",sSrc:"If you turn right at the intersection, you will see the department store."},
{type:"mc",q:"'Sie sind direkt zum Einkaufszentrum gefahren.' Why is 'sind' used here instead of 'haben'?",opts:["Because 'fahren' is a reflexive verb","Because the subject is plural","Because 'fahren' expresses movement from A to B","Because it is a question"],ans:"Because 'fahren' expresses movement from A to B",hint:"Verbs expressing a change of location take a specific auxiliary in the Perfekt."},
{type:"drag_fill",s:"Wenn wir den {1} {2}, müssen wir den nächsten {3} nehmen.",blanks:{"1":"Zug","2":"verpassen","3":"Flug"},pool:["Zug","verpassen","Flug","Verspätung","gefahren","buchen"],hint:"If we miss the train, we must take the next flight.",sSrc:"If we miss the train, we must take the next flight."},
{type:"mc",q:"'Wir ___ auf der Messe zelten, aber es gab kein Zelt.' Which Präteritum modal expresses a past wish?",opts:["mussten","konnten","wollten","durften"],ans:"wollten",hint:"This modal expresses a desire or intention in the past."},
{type:"fb",s:"Die Fahrt zum Flughafen dauert {1} zwei Stunden.",a:["rund"],opts:["rund","weg","hin","her"],hint:"This word means 'approximately' and sounds like a shape.",sSrc:"The trip to the airport takes approximately two hours."},
{type:"match",pairs:[{trg:"vorwärts",src:"forward"},{trg:"zurückfahren",src:"to drive back"},{trg:"unterwegs",src:"on the way"},{trg:"drüben",src:"over there"},{trg:"vorbei",src:"past / over"},{trg:"hin",src:"there (away from speaker)"}]},
{type:"drag_fill",s:"Wenn das Fenster {1} ist, kommt frische Luft {2}, und wir müssen nicht den {3} einschalten.",blanks:{"1":"offen","2":"herein","3":"Ventilator"},pool:["offen","herein","Ventilator","geschlossen","draußen","Heizung"],hint:"When the window is open (offen), fresh air comes in, so no fan needed.",sSrc:"When the window is open, fresh air comes in, and we do not need to turn on the fan."},
{type:"mc",q:"Verumius hat seinen Stadtplan verloren. Er konnte den Weg zum Rathaus nicht finden. Wenn er vorher reserviert hätte, wäre er nicht unterwegs gewesen. How many U10 vocabulary words appear in this passage?",opts:["Three: Stadtplan, Weg, Rathaus","Five: Stadtplan, Weg, Rathaus, reserviert, unterwegs","Four: Stadtplan, Rathaus, reserviert, unterwegs","Six: Stadtplan, Weg, Rathaus, reserviert, unterwegs, verloren"],ans:"Five: Stadtplan, Weg, Rathaus, reserviert, unterwegs",hint:"Count carefully. Some words look familiar but are not from the U10 vocabulary list."}
]}
,

{id:"deu_r10l8",title:"Im Bordbistro",icon:"\u{1F35B}",xp:15,board:true,steps:[
{type:"intro",title:"Im Bordbistro",desc:"Verumius hat den Anschluss geschafft! Jetzt sitzt er im Bordbistro, isst Currywurst und schaut aus dem Fenster. Bayern ist wundersch\u00f6n.",goals:["Reisevokabular abschlie\u00dfen","Neue Adverbien und Pr\u00e4positionen lernen","\u00dcber Reisepl\u00e4ne sprechen"]},
{type:"teach",trg:"der F\u00fchrerschein",src:"driver's license",phonetic:"FYOO-rer-shyne",example:"A: Hast du einen F\u00fchrerschein?\nB: Ja, aber ich fahre lieber mit dem Zug.\nA: Das verstehe ich. Z\u00fcge sind bequemer.",exampleSrc:"A: Do you have a driver's license?\nB: Yes, but I prefer to travel by train.\nA: I understand that. Trains are more comfortable.",note:"F\u00fchren (to lead) + Schein (certificate). You lead a vehicle.",funFact:"In Germany you can get your F\u00fchrerschein at 18. Driving lessons cost 2,000 to 3,500 euros on average."},
{type:"teach",trg:"die Hauptstadt",src:"capital city",phonetic:"HOWPT-shtat",example:"A: Was ist die Hauptstadt von Bayern?\nB: M\u00fcnchen! Wir fahren gerade dorthin.\nA: Stimmt, ich sehe schon die Berge.",exampleSrc:"A: What is the capital of Bavaria?\nB: Munich! We are heading there right now.\nA: Right, I can already see the mountains.",note:"Haupt (main) + Stadt (city). Simple compound.",funFact:"Berlin became Germany's capital again in 1990 after reunification. Before that, Bonn was the capital of West Germany."},
{type:"teach",trg:"die Jugendherberge",src:"youth hostel",phonetic:"YOO-gent-hair-bair-guh",example:"A: Wo \u00fcbernachtest du in M\u00fcnchen?\nB: In einer Jugendherberge. Das ist g\u00fcnstig.\nA: Gute Idee! Die sind oft sehr sch\u00f6n.",exampleSrc:"A: Where are you staying overnight in Munich?\nB: In a youth hostel. That is affordable.\nA: Good idea! They are often very nice.",note:"Jugend (youth) + Herberge (shelter). Three parts, one word.",funFact:"Germany invented the youth hostel. The first one opened in 1912 in Altena Castle. Today there are over 400 across the country."},
{type:"teach",trg:"das Paket",src:"package",phonetic:"pa-KETT",example:"A: Ich muss ein Paket nach Berlin schicken.\nB: Es gibt einen Paketshop im Bahnhof.\nA: Perfekt, dann gehe ich vor der Abfahrt dorthin.",exampleSrc:"A: I need to send a package to Berlin.\nB: There is a parcel shop in the station.\nA: Perfect, then I will go there before departure.",note:"From French paquet. Plural: Pakete.",funFact:"DHL delivers over 1.8 billion parcels per year in Germany. Germans love online shopping."},
{type:"teach",trg:"der Umzug",src:"move (relocation)",phonetic:"OOM-tsook",example:"A: Wann ist dein Umzug nach M\u00fcnchen?\nB: N\u00e4chsten Monat. Ich brauche noch Kartons.\nA: Ich kann dir helfen!",exampleSrc:"A: When is your move to Munich?\nB: Next month. I still need boxes.\nA: I can help you!",note:"Um (around) + Zug (pull). You pull your things to a new place.",funFact:"In Germany, friends help with Umz\u00fcge and get paid in pizza and beer. It is a tradition."},
{type:"teach",trg:"die Unterkunft",src:"accommodation",phonetic:"OON-ter-koonft",example:"A: Hast du schon eine Unterkunft in M\u00fcnchen?\nB: Noch nicht. Ich suche ein Zimmer.\nA: Schau mal im Internet. Es gibt viele Angebote.",exampleSrc:"A: Do you already have accommodation in Munich?\nB: Not yet. I am looking for a room.\nA: Check online. There are many offers.",note:"Unter (under) + Kunft (from kommen, to come). Where you come to stay.",funFact:"Finding a Wohnung in Munich is notoriously difficult. People bring full application folders to apartment viewings."},
{type:"teach",trg:"fast",src:"almost",phonetic:"fasst",example:"A: Sind wir fast da?\nB: Ja, noch zehn Minuten bis M\u00fcnchen.\nA: Endlich! Die Reise war lang.",exampleSrc:"A: Are we almost there?\nB: Yes, ten more minutes to Munich.\nA: Finally! The trip was long.",note:"Be careful: fast means almost, NOT fast. Schnell means fast.",funFact:"This is a classic false friend for English speakers. Fast alle means almost everyone, not fast everyone."},
{type:"teach",trg:"zuerst",src:"first (of all)",phonetic:"tsoo-AIRST",example:"A: Was machst du zuerst in M\u00fcnchen?\nB: Zuerst gehe ich ins Hotel. Dann esse ich.\nA: Guter Plan!",exampleSrc:"A: What will you do first in Munich?\nB: First I will go to the hotel. Then I will eat.\nA: Good plan!",note:"Zu (to) + erst (first). Literally: to first.",funFact:"Germans love planning their day in order: zuerst, dann, danach, zum Schluss. Structure is everything."},
{type:"teach",trg:"zuletzt",src:"last, finally",phonetic:"tsoo-LETST",example:"A: Und was machst du zuletzt?\nB: Zuletzt besuche ich den Marienplatz.\nA: Das Glockenspiel ist wundersch\u00f6n!",exampleSrc:"A: And what will you do last?\nB: Last I will visit Marienplatz.\nA: The Glockenspiel is wonderful!",note:"Zu (to) + letzt (last). The opposite of zuerst.",funFact:"The Glockenspiel at Marienplatz plays every day at 11:00, 12:00, and 17:00. Tourists gather to watch the mechanical figures dance."},
{type:"teach",trg:"dorthin",src:"to there",phonetic:"DORT-hin",example:"A: Ich m\u00f6chte nach M\u00fcnchen.\nB: Ich fahre auch dorthin!\nA: Super, dann fahren wir zusammen.",exampleSrc:"A: I would like to go to Munich.\nB: I am also going there!\nA: Great, then we will travel together.",note:"Dort (there) + hin (towards). Hin always means motion away from speaker.",funFact:"German is very precise about direction. Dorthin is to there, dorther is from there. English uses just there for both."},
{type:"teach",trg:"wegen",src:"because of",phonetic:"VAY-gen",example:"A: Warum f\u00e4hrst du mit dem Zug?\nB: Wegen der Umwelt. Z\u00fcge sind gr\u00fcner.\nA: Das stimmt. Und es ist auch gem\u00fctlich.",exampleSrc:"A: Why are you traveling by train?\nB: Because of the environment. Trains are greener.\nA: That is true. And it is also comfortable.",note:"Wegen takes the genitive case: wegen des Wetters, wegen der Arbeit.",funFact:"Deutsche Bahn advertises itself as the green alternative. One train trip produces 80% less CO2 than the same trip by car."},
{type:"teach",trg:"hinter",src:"behind",phonetic:"HIN-ter",example:"A: Wo ist das Bordbistro?\nB: Hinter dem Wagen sechs.\nA: Danke! Ich habe Hunger.",exampleSrc:"A: Where is the onboard bistro?\nB: Behind car six.\nA: Thanks! I am hungry.",note:"Hinter + dative (no motion) or accusative (motion). Hinter dem Haus = behind the house.",funFact:"German has nine two-way prepositions that switch between dative and accusative. Hinter is one of them."},
{type:"teach",trg:"pro",src:"per",phonetic:"proh",example:"A: Was kostet die Currywurst?\nB: F\u00fcnf Euro pro St\u00fcck.\nA: Nicht schlecht! Eine bitte.",exampleSrc:"A: How much is the Currywurst?\nB: Five euros per piece.\nA: Not bad! One please.",note:"Same as English per. Used with prices, rates, and quantities.",funFact:"Currywurst im Bordbistro costs about 5 to 7 euros. On the platform it is cheaper, but the view is not as good."},
{type:"teach",trg:"vorn, vorne",src:"in front, at the front",phonetic:"forn, FOR-nuh",example:"A: Wo sitzt du im Zug?\nB: Ganz vorne, im ersten Wagen.\nA: Ich sitze hinten. Wir treffen uns in der Mitte!",exampleSrc:"A: Where are you sitting on the train?\nB: Right at the front, in the first car.\nA: I am sitting at the back. We will meet in the middle!",note:"Vorne is the longer, more common form. Vorn is shorter, same meaning. Opposite: hinten.",funFact:"In German ICE trains, first class is usually vorne. Some passengers pay extra just for the quiet at the front."},
{type:"teach",trg:"austragen",src:"to deliver, to carry out",phonetic:"OWS-trah-gen",example:"A: Mein Bruder tr\u00e4gt Zeitungen aus.\nB: Wirklich? Das ist ein guter Nebenjob.\nA: Ja, er macht das jeden Morgen vor der Schule.",exampleSrc:"A: My brother delivers newspapers.\nB: Really? That is a good side job.\nA: Yes, he does it every morning before school.",note:"Separable verb: aus + tragen. Er tr\u00e4gt Pakete aus. Past: hat ausgetragen.",funFact:"Zeitungsaustragen (newspaper delivery) is the classic first job for German teenagers, just like a paper route in America."},
{type:"tip",title:"Zugkultur: Das Bordbistro",text:"Every ICE has a Bordbistro (onboard bistro car) serving hot meals, snacks, and drinks.\n\nPopular items:\n\u2022 Currywurst mit Pommes (the classic)\n\u2022 Brezel mit Butter\n\u2022 Radler (beer mixed with lemon soda)\n\u2022 Kaffee und Kuchen\n\nThe Bordbistro is a social space. Strangers share tables and chat. It is one of the few places in Germany where talking to strangers is completely normal.",deepDive:"DB also offers an app called Komfort Check-in where you can order food to your seat in first class. The Bordbistro staff are famous for their dry humor. If the train is late, they sometimes announce: Wir bitten um Entschuldigung. Unser Zug hat sich verlaufen. (We apologize. Our train got lost.)"},
{type:"mc",q:"Verumius bestellt eine Currywurst. Was kostet sie pro St\u00fcck?",opts:["F\u00fcnf Euro","Zehn Euro","Drei Euro","Sieben Euro"],ans:"F\u00fcnf Euro",hint:"Think about what the teach card said about Bordbistro prices."},
{type:"fb",s:"Wir sind {1} da. Noch f\u00fcnf Minuten!",a:"fast",opts:["fast","zuerst","zuletzt","dorthin"],hint:"Which word means almost in German?",sSrc:"We are almost there. Just five more minutes!"},
{type:"mc",q:"Was bedeutet 'zuerst'?",opts:["first of all","at the end","almost done","right behind"],ans:"first of all",hint:"It starts with zu and relates to ordering events."},
{type:"fb",s:"{1} gehe ich ins Hotel, dann esse ich.",a:"Zuerst",opts:["Zuerst","Zuletzt","Fast","Wegen"],hint:"Which adverb introduces the first action in a sequence?",sSrc:"First I go to the hotel, then I eat."},
{type:"mc",q:"Wo ist das Bordbistro? Es ist {blank} dem Wagen sechs.",opts:["hinter","vorne","wegen","pro"],ans:"hinter",hint:"The bistro is located at the back of car six."},
{type:"fb",s:"Ich fahre auch nach M\u00fcnchen. Ich fahre {1}.",a:"dorthin",opts:["dorthin","vorne","zuletzt","hinter"],hint:"Which word means to there, showing direction?",sSrc:"I am also going to Munich. I am going there."},
{type:"mc",q:"Was ist eine Jugendherberge?",opts:["A youth hostel","A train station","A restaurant","A school"],ans:"A youth hostel",hint:"Think about the compound: Jugend + Herberge."},
{type:"drag_fill",s:"{1} des Wetters fahre ich mit dem Zug. {2} kaufe ich ein Ticket, {3} steige ich ein.",blanks:{"1":"Wegen","2":"Zuerst","3":"dann"},pool:["Wegen","Zuerst","dann","fast","pro"],hint:"Because of the weather, first I buy a ticket, then I board.",sSrc:"Because of the weather I travel by train. First I buy a ticket, then I board."},
{type:"match",pairs:[{trg:"der F\u00fchrerschein",src:"driver's license"},{trg:"die Hauptstadt",src:"capital city"},{trg:"die Unterkunft",src:"accommodation"},{trg:"das Paket",src:"package"},{trg:"der Umzug",src:"move (relocation)"},{trg:"vorne",src:"at the front"}]},
{type:"teach",trg:"warten",src:"to wait",note:"Regular: ich warte, du wartest. Warten auf + accusative = to wait for.",example:"A: Wie lange wartest du schon?\nB: Schon zwanzig Minuten!\nA: Der Zug hat Versp\u00e4tung. Typisch.",exampleSrc:"A: How long have you been waiting?\nB: Already twenty minutes!\nA: The train is delayed. Typical.",funFact:"Warten has a second meaning: to maintain/service. 'Das Auto warten' means to service the car. Context decides."},
{type:"teach",trg:"der Euro",src:"the euro",note:"Masculine. Plural after numbers: Euro (no change). F\u00fcnf Euro, nicht f\u00fcnf Euros.",example:"A: Was kostet das Ticket?\nB: Neunundvierzig Euro.\nA: Das ist g\u00fcnstig f\u00fcr ganz Deutschland!",exampleSrc:"A: How much does the ticket cost?\nB: Forty-nine euros.\nA: That's cheap for all of Germany!",funFact:"Germany adopted the Euro in 2002, replacing the Deutsche Mark. German Euro coins show the Brandenburg Gate, the German eagle, or an oak leaf."},
{type:"teach",trg:"das Geb\u00e4ude",src:"the building",note:"Neuter. Plural: die Geb\u00e4ude. From bauen (to build).",example:"A: Was ist das gro\u00dfe Geb\u00e4ude dort?\nB: Das ist der Hauptbahnhof.\nA: Er ist wirklich beeindruckend!",exampleSrc:"A: What is that big building there?\nB: That's the main train station.\nA: It's really impressive!",funFact:"Berlin Hauptbahnhof is the largest crossing station in Europe. The glass and steel building has five levels and opened in 2006."},
{type:"teach",trg:"der Stadtrat",src:"the city council",note:"Masculine. Compound: Stadt (city) + Rat (council/advice).",example:"A: Wer entscheidet \u00fcber neue Stra\u00dfen?\nB: Der Stadtrat trifft diese Entscheidungen.\nA: Wie oft trifft sich der Stadtrat?",exampleSrc:"A: Who decides about new streets?\nB: The city council makes those decisions.\nA: How often does the city council meet?",funFact:"Every German city and town has a Stadtrat or Gemeinderat. Members are elected locally. Town hall meetings are open to the public."},
{type:"teach",trg:"dorther",src:"from there",note:"Adverb. Dort (there) + her (toward speaker). Opposite of dorthin.",example:"A: Woher kommt der Zug?\nB: Er kommt dorther, aus Hamburg.\nA: Ah, dann ist er bald hier.",exampleSrc:"A: Where does the train come from?\nB: It comes from there, from Hamburg.\nA: Ah, then it will be here soon.",funFact:"German is very precise about direction. Dorthin = to there (away). Dorther = from there (toward). English uses just 'there' for both."}
]}
]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 11: Auf dem Weihnachtsmarkt
// Story: Gendarmenmarkt magic, Opa Heinrich, Glühwein, snow walk home
// CEFR: A2.3 - Adj declension (nom/acc/dat), possessives, temporal preps, Konj II
// ═══════════════════════════════════════════════════════════════
{n:11,lang:"de",srcLang:"en",track:"v2",title:"Auf dem Weihnachtsmarkt",sub:"Christmas market, Opa Heinrich, Glühwein, adjective declension",icon:"🎄",level:"A2.3",color:"#7B5EE8",lessons:[
{id:"deu_r11l1",title:"Gendarmenmarkt",icon:"🎄",xp:15,board:true,steps:[
{type:"intro",title:"Gendarmenmarkt",desc:"Dusk falls over Berlin's most beautiful Christmas market. Golden lights, wooden stalls, the smell of Glühwein and roasted almonds. Hildi pulls Verumius into the crowd.",goals:["Learn 10 winter and Christmas market words","See adjective endings in real sentences","Discover German Weihnachtsmarkt culture"]},
{type:"teach",trg:"das Weihnachten",src:"Christmas",phonetic:"VYE-nakh-ten",gender:"n",example:"A: Was machst du an Weihnachten?\nB: Ich besuche meine Familie.\nA: Das klingt schön!",exampleSrc:"A: What are you doing at Christmas?\nB: I am visiting my family.\nA: That sounds lovely!",note:"das Weihnachten (neuter). Often used without article: 'an Weihnachten' or 'zu Weihnachten.' Compound: Weih (holy) + Nachten (nights).",funFact:"Germany celebrates on Heiligabend (Christmas Eve, Dec 24), not Dec 25. Gifts are opened in the evening, often after church. The 25th and 26th are quiet family days."},
{type:"teach",trg:"der Schnee",src:"the snow",phonetic:"shnay",gender:"m",example:"A: Schau mal, der Schnee!\nB: Ja, alles ist weiß. Wie im Märchen!",exampleSrc:"A: Look, the snow!\nB: Yes, everything is white. Like in a fairy tale!",note:"der Schnee (masculine, no plural). Related: schneien (to snow), Schneemann (snowman).",funFact:"Germans have a saying: 'Weiße Weihnachten' (white Christmas). Statistically, Berlin gets snow on Christmas Day only about once every 10 years."},
{type:"teach",trg:"schneien",src:"to snow",example:"A: Es schneit! Hast du einen Schirm?\nB: Nein, aber ich habe eine Mütze.",exampleSrc:"A: It's snowing! Do you have an umbrella?\nB: No, but I have a hat.",note:"Impersonal verb: always 'es schneit' (it snows). Past: es hat geschneit.",funFact:"The word 'schneien' comes from Old High German 'snīwan'. In Bavaria, heavy snow is called 'Schneegestöber' (snow flurry)."},
{type:"teach",trg:"die Wolke",src:"the cloud",gender:"f",example:"A: Siehst du die dunklen Wolken?\nB: Ja, es schneit bestimmt bald.",exampleSrc:"A: Do you see the dark clouds?\nB: Yes, it will definitely snow soon.",note:"die Wolke, plural: die Wolken. 'Wolkenkratzer' means skyscraper (cloud scratcher).",funFact:"The German word 'Wolkenkuckucksheim' (cloud cuckoo land) means a fantasy world. It comes from an ancient Greek comedy by Aristophanes."},
{type:"teach",trg:"der Himmel",src:"the sky / heaven",gender:"m",example:"A: Der Himmel ist so schön heute Abend.\nB: Ja, die Sterne leuchten über dem Markt.",exampleSrc:"A: The sky is so beautiful this evening.\nB: Yes, the stars shine above the market.",note:"der Himmel = sky AND heaven. 'Himmelblau' = sky blue. Plural: die Himmel (rare).",funFact:"'Himmel und Hölle' (heaven and hell) is the German name for hopscotch. Kids still play it in schoolyards across Germany."},
{type:"teach",trg:"der Kalender",src:"the calendar",gender:"m",example:"A: Hast du einen Adventskalender?\nB: Ja, mit Schokolade! Heute ist Türchen Nummer zwölf.",exampleSrc:"A: Do you have an Advent calendar?\nB: Yes, with chocolate! Today is door number twelve.",note:"der Kalender, plural: die Kalender. Adventskalender = Advent calendar (24 little doors, one per day until Christmas).",funFact:"The first printed Advent calendar was made in Germany in 1902. Today, Germans spend over 60 million euros on them every year."},
{type:"teach",trg:"die Postkarte",src:"the postcard",gender:"f",example:"A: Ich schreibe eine Postkarte an meine Eltern.\nB: Gute Idee! Der Weihnachtsmarkt ist ein tolles Motiv.",exampleSrc:"A: I'm writing a postcard to my parents.\nB: Good idea! The Christmas market is a great motif.",note:"die Postkarte, plural: die Postkarten. Compound: Post (mail) + Karte (card).",funFact:"Germany's postal service delivers around 200 million Christmas cards every December. The town of 'Himmelpfort' (Heaven's Gate) has a special Santa Claus post office."},
{type:"mc",q:"Hildi says: 'Schau, es ___!' What is happening?",opts:["Es schneit","Es regnet","Es ist warm","Es ist dunkel"],ans:"Es schneit",hint:"Think of what falls from winter clouds"},
{type:"fb",s:"Der {1} ist heute Abend wunderschön.",a:"Himmel",opts:["Himmel","Schnee","Wolke","Kalender"],hint:"Look up above the market stalls",sSrc:"The sky is beautiful tonight."},
{type:"teach",trg:"die Schokolade",src:"the chocolate",gender:"f",example:"A: Möchtest du heiße Schokolade?\nB: Oh ja, bitte! Mit Sahne?",exampleSrc:"A: Would you like hot chocolate?\nB: Oh yes, please! With cream?",note:"die Schokolade (no common plural). Heiße Schokolade = hot chocolate. Short form: Schoki.",funFact:"Germany is the largest chocolate consumer in Europe, averaging 11 kg per person per year. Ritter Sport and Milka are iconic German brands."},
{type:"teach",trg:"die Torte",src:"the cake / tart",gender:"f",example:"A: Diese Torte sieht lecker aus!\nB: Das ist Schwarzwälder Kirschtorte. Sehr berühmt!",exampleSrc:"A: This cake looks delicious!\nB: That is Black Forest cherry cake. Very famous!",note:"die Torte, plural: die Torten. Different from 'der Kuchen' (simpler cake). Torte = layered, fancy.",funFact:"Schwarzwälder Kirschtorte (Black Forest cake) must legally contain Kirschwasser (cherry brandy) to carry the name. It was invented around 1915."},
{type:"teach",trg:"die Rose",src:"the rose",gender:"f",example:"A: Rosen im Winter?\nB: Ja, rote Rosen für den Weihnachtstisch!",exampleSrc:"A: Roses in winter?\nB: Yes, red roses for the Christmas table!",note:"die Rose, plural: die Rosen. Same word as English, from Latin 'rosa'.",funFact:"Germany grows over 80 million roses per year, mostly in greenhouses. The city of Bad Langensalza is called the 'Rosenstadt' (Rose City)."},
{type:"teach",trg:"der Ring",src:"the ring",gender:"m",example:"A: Schau mal, der goldene Ring am Stand!\nB: Sehr schön. Ist das ein Geschenk?",exampleSrc:"A: Look, the golden ring at the stall!\nB: Very nice. Is that a gift?",note:"der Ring, plural: die Ringe. Also means circle or arena (Boxring).",funFact:"The 'Ringstraße' tradition in German cities dates back to medieval times, when ring roads replaced old city walls. Vienna's famous Ringstraße is the most well known."},
{type:"tip",title:"Weihnachtsmarkt: A German Tradition",text:"Christmas markets (Weihnachtsmärkte) open across Germany from late November until Christmas Eve. Every city has its own.\n\nBerlin alone has over 60 markets. The Gendarmenmarkt is considered the most beautiful, framed by two cathedrals and the Konzerthaus.\n\nTypical treats: Glühwein (mulled wine), gebrannte Mandeln (roasted almonds), Lebkuchen (gingerbread), Bratwurst, Stollen (fruit bread).\n\nThe tradition dates back to the 1300s. Dresden's Striezelmarkt (founded 1434) is the oldest.",deepDive:"Markets are called 'Weihnachtsmarkt' or 'Christkindlmarkt' (especially in southern Germany). Each region has specialties: Nuremberg is famous for its tiny Lebkuchen, Aachen for Printen cookies, and Dresden for Christstollen."},
{type:"mc",q:"What is 'die Schokolade'?",opts:["chocolate","calendar","postcard","cake"],ans:"chocolate",hint:"A sweet treat, often served hot in winter"},
{type:"mc",q:"Verumius wants to write home. Which does he need?",opts:["die Postkarte","der Kalender","die Torte","der Ring"],ans:"die Postkarte",hint:"Something you write on and send by mail"},
{type:"fb",s:"Es gibt dunkle {1} am Himmel.",a:"Wolken",opts:["Wolken","Schnee","Ringe","Rosen"],hint:"These float in the sky before snow falls",sSrc:"There are dark clouds in the sky."},
{type:"mc",q:"'Die Torte' is different from 'der Kuchen' because a Torte is...",opts:["layered and fancy","simple and plain","always chocolate","served cold"],ans:"layered and fancy",hint:"Think of a decorated multi-layer dessert"},
{type:"fb",s:"Hildi kauft eine {1} am Weihnachtsmarkt.",a:"Rose",opts:["Rose","Wolke","Schnee","Himmel"],hint:"A beautiful flower, often red",sSrc:"Hildi buys a rose at the Christmas market."},
{type:"mc",q:"Which word means 'ring'?",opts:["der Ring","die Rose","der Schnee","die Torte"],ans:"der Ring",hint:"A small circle you wear on your finger"},
{type:"match",pairs:[{trg:"der Schnee",src:"the snow"},{trg:"die Wolke",src:"the cloud"},{trg:"der Himmel",src:"the sky"},{trg:"die Postkarte",src:"the postcard"},{trg:"die Schokolade",src:"the chocolate"},{trg:"die Rose",src:"the rose"}]},
{type:"tip",title:"Sneak Peek: Adjective Endings",text:"You saw phrases like 'der warme Glühwein', 'die dunklen Wolken', 'der goldene Ring'.\n\nNotice the endings on the adjectives: warm-E, dunkel-N, golden-E.\n\nGerman adjectives change their endings depending on gender, case, and article. This is called adjective declension.\n\nDo not memorize rules yet. Just notice the patterns. You will learn the system step by step in coming lessons.",deepDive:"Adjective declension is one of German's trickiest grammar topics. There are three declension patterns (strong, weak, mixed) depending on what comes before the adjective. For now, just get used to hearing 'der warme', 'die schöne', 'das frische' as natural chunks."},
{type:"mc",q:"Hildi sagt: 'Der Gendarmenmarkt hat den schönsten Weihnachtsmarkt in Berlin.' What does she mean?",opts:["Gendarmenmarkt has the most beautiful Christmas market in Berlin","Gendarmenmarkt has the biggest Christmas market in Berlin","Gendarmenmarkt has the oldest Christmas market in Berlin","Gendarmenmarkt has the cheapest Christmas market in Berlin"],ans:"Gendarmenmarkt has the most beautiful Christmas market in Berlin",hint:"'schön' is an adjective in its highest form (superlative) here."}
]},

{id:"deu_r11l2",title:"Was ziehe ich an?",icon:"🧣",xp:15,board:true,steps:[
{type:"intro",title:"Was ziehe ich an?",desc:"Es ist kalt auf dem Weihnachtsmarkt! Lerne die wichtigsten Kleidungsstücke für den Winter.",goals:["14 Kleidungswörter mit Artikel","Über Kleidung sprechen","Sich für kaltes Wetter anziehen"]},
{type:"teach",trg:"der Mantel",src:"the coat",gender:"m",phonetic:"MAN-tel",example:"A: Es ist so kalt draußen!\nB: Zieh deinen Mantel an!",exampleSrc:"A: It's so cold outside!\nB: Put your coat on!",note:"der Mantel, masculine. Plural: die Mäntel.",funFact:"German Christmas markets run from late November to December 23rd, so a warm Mantel is essential."},
{type:"teach",trg:"die Mütze",src:"the hat/beanie",gender:"f",phonetic:"MÜT-tse",example:"A: Hast du eine Mütze?\nB: Ja, ich trage immer meine rote Mütze.",exampleSrc:"A: Do you have a beanie?\nB: Yes, I always wear my red beanie.",note:"die Mütze, feminine. For formal hats, use der Hut.",funFact:"In Bavaria, the traditional Filzhut (felt hat) is still worn at festivals, but a Mütze keeps your ears warm."},
{type:"teach",trg:"der Stiefel",src:"the boot",gender:"m",phonetic:"SHTEE-fel",example:"A: Welche Schuhe trägst du heute?\nB: Meine schwarzen Stiefel, es schneit!",exampleSrc:"A: Which shoes are you wearing today?\nB: My black boots, it's snowing!",note:"der Stiefel, masculine. Plural: die Stiefel (same form).",funFact:"The word Stiefel also means a large beer glass shaped like a boot, popular at Oktoberfest."},
{type:"teach",trg:"der Pullover",src:"the sweater",gender:"m",phonetic:"pul-OH-ver",example:"A: Der Pullover sieht warm aus.\nB: Ja, er ist aus Wolle.",exampleSrc:"A: That sweater looks warm.\nB: Yes, it's made of wool.",note:"der Pullover, masculine. Often shortened to Pulli in everyday speech.",funFact:"Pullover comes from English 'pull over'. Germans borrowed the word but gave it a masculine article."},
{type:"teach",trg:"die Hose",src:"the pants",gender:"f",phonetic:"HO-ze",example:"A: Die Hose passt dir gut!\nB: Danke, sie ist neu.",exampleSrc:"A: The pants fit you well!\nB: Thanks, they're new.",note:"die Hose, feminine. Always singular in German, unlike English 'pants'.",funFact:"Lederhosen literally means 'leather pants'. die Hose is singular even though pants come in pairs."},
{type:"teach",trg:"das Hemd",src:"the shirt",gender:"n",phonetic:"HEMT",example:"A: Trägst du ein Hemd zur Arbeit?\nB: Ja, ein weißes Hemd.",exampleSrc:"A: Do you wear a shirt to work?\nB: Yes, a white shirt.",note:"das Hemd, neuter. Refers to a button-up shirt specifically.",funFact:"Das Hemd is related to the old German word for 'cover'. A T-Shirt is a separate word in German."},
{type:"teach",trg:"das Kleid",src:"the dress",gender:"n",phonetic:"KLITE",example:"A: Das Kleid ist wunderschön!\nB: Danke, ich trage es gern.",exampleSrc:"A: The dress is beautiful!\nB: Thanks, I like wearing it.",note:"das Kleid, neuter. Plural: die Kleider. Also means 'clothes' in plural.",funFact:"Kleider machen Leute is a famous German proverb: 'Clothes make the person.'"},
{type:"mc",q:"Wie sagt man 'coat' auf Deutsch?",opts:["der Mantel","die Mütze","der Pullover","das Hemd"],ans:"der Mantel",hint:"Think of something long that keeps you warm outside."},
{type:"fb",s:"Im Winter trage ich immer meine {1}.",a:"Mütze",opts:["Mütze","Mantel","Hemd","Kleid"],hint:"It keeps your ears warm on cold days.",sSrc:"In winter I always wear my beanie."},
{type:"teach",trg:"die Bluse",src:"the blouse",gender:"f",phonetic:"BLUE-ze",example:"A: Die Bluse passt gut zum Rock.\nB: Findest du? Ich bin nicht sicher.",exampleSrc:"A: The blouse goes well with the skirt.\nB: You think so? I'm not sure.",note:"die Bluse, feminine. Similar to Hemd but typically for women.",funFact:"German fashion vocabulary often borrows from French. Bluse came via French from medieval Latin."},
{type:"teach",trg:"der Rock",src:"the skirt",gender:"m",phonetic:"ROK",example:"A: Der Rock ist zu kurz für den Winter.\nB: Dann ziehe ich eine Hose an.",exampleSrc:"A: The skirt is too short for winter.\nB: Then I'll put on pants.",note:"der Rock, masculine. Be careful: Rock also means 'rock music' in German.",funFact:"Der Rock is masculine even though it refers to a garment traditionally worn by women. German grammar does not follow logic."},
{type:"teach",trg:"die Jeans",src:"the jeans",gender:"f",phonetic:"JEENS",example:"A: Ich trage am liebsten Jeans.\nB: Ich auch, sie sind so bequem!",exampleSrc:"A: I prefer wearing jeans.\nB: Me too, they're so comfortable!",note:"die Jeans, feminine. Pronounced like in English. Singular in German.",funFact:"Jeans were invented by Levi Strauss, a German immigrant from Bavaria who moved to San Francisco."},
{type:"teach",trg:"der Schirm",src:"the umbrella",gender:"m",phonetic:"SHIRM",example:"A: Hast du einen Schirm dabei?\nB: Nein, aber es regnet!",exampleSrc:"A: Do you have an umbrella with you?\nB: No, but it's raining!",note:"der Schirm, masculine. Short for der Regenschirm (rain umbrella).",funFact:"Schirm literally means 'shield'. A Bildschirm is a 'picture shield', the German word for screen or monitor."},
{type:"teach",trg:"der Anzug",src:"the suit",gender:"m",phonetic:"AN-tsook",example:"A: Wann trägst du einen Anzug?\nB: Nur bei der Arbeit.",exampleSrc:"A: When do you wear a suit?\nB: Only at work.",note:"der Anzug, masculine. Literally 'something you pull on' (anziehen).",funFact:"Anzug comes from anziehen (to put on). German builds many clothing words from the verb 'to dress'."},
{type:"teach",trg:"die Brille",src:"the glasses",gender:"f",phonetic:"BRIL-le",example:"A: Ohne meine Brille sehe ich nichts.\nB: Dann vergiss sie nicht!",exampleSrc:"A: Without my glasses I can't see anything.\nB: Then don't forget them!",note:"die Brille, feminine. Always singular in German, even though you wear two lenses.",funFact:"Brille comes from Beryll, a gemstone once used to make lenses in the Middle Ages."},
{type:"teach",trg:"das T-Shirt",src:"the t-shirt",gender:"n",phonetic:"TEE-shört",example:"A: Im Sommer trage ich nur ein T-Shirt.\nB: Im Winter brauchst du mehr!",exampleSrc:"A: In summer I only wear a t-shirt.\nB: In winter you need more!",note:"das T-Shirt, neuter. Borrowed from English. Always capitalized in German.",funFact:"German capitalizes all nouns, so even borrowed words like T-Shirt get a capital letter and an article."},
{type:"tip",title:"Sich anziehen: Dressing for the Weihnachtsmarkt",text:"Germans layer up for winter markets:\n\n1. das Unterhemd (undershirt)\n2. das Hemd oder der Pullover\n3. der Mantel\n4. die Mütze, der Schal, die Handschuhe\n\nUseful verb: anziehen (to put on)\nIch ziehe meinen Mantel an.\nZieh dich warm an! (Dress warmly!)",deepDive:"anziehen is a separable verb: the an- goes to the end.\n\nIch ziehe einen Pullover an.\nSie zieht ihre Stiefel an.\n\nThe opposite is ausziehen (to take off):\nEr zieht seinen Mantel aus."},
{type:"mc",q:"Welches Wort bedeutet 'glasses'?",opts:["die Brille","die Bluse","die Hose","die Jeans"],ans:"die Brille",hint:"This word comes from a gemstone name."},
{type:"fb",s:"Levi Strauss war Deutscher. Er hat die {1} erfunden.",a:"Jeans",opts:["Jeans","Brille","Mütze","Bluse"],hint:"A famous type of pants from Bavaria.",sSrc:"Levi Strauss was German. He invented jeans."},
{type:"mc",q:"Was trägst du bei Regen?",opts:["einen Schirm","eine Mütze","einen Anzug","ein Kleid"],ans:"einen Schirm",hint:"Think of what keeps you dry when water falls from the sky."},
{type:"fb",s:"Für die Arbeit brauche ich einen {1} und ein Hemd.",a:"Anzug",opts:["Anzug","Rock","Pullover","Stiefel"],hint:"A formal outfit that you 'pull on' (anziehen).",sSrc:"For work I need a suit and a shirt."},
{type:"mc",q:"Was ist 'der Rock' auf Englisch?",opts:["skirt","rock music","coat","dress"],ans:"skirt",hint:"A piece of clothing, not a music genre."},
{type:"drag_fill",s:"Im Winter ziehe ich {1}, {2} und {3} an.",blanks:{"1":"Stiefel","2":"einen Mantel","3":"eine Mütze"},pool:["Stiefel","einen Mantel","eine Mütze","ein T-Shirt","einen Rock"],hint:"Think about what keeps you warm from head to toe.",sSrc:"In winter I put on boots, a coat and a beanie."},
{type:"match",pairs:[{trg:"der Mantel",src:"the coat"},{trg:"die Mütze",src:"the beanie"},{trg:"der Stiefel",src:"the boot"},{trg:"die Hose",src:"the pants"},{trg:"das Kleid",src:"the dress"},{trg:"die Brille",src:"the glasses"}]},
{type:"mc",q:"Welches Kleidungsstück ist immer Neutrum (das)?",opts:["das Hemd und das Kleid","der Mantel und der Rock","die Hose und die Jeans","die Bluse und die Mütze"],ans:"das Hemd und das Kleid",hint:"Look for the neuter articles among the clothing words you learned."},
{type:"fb",s:"Kleider machen {1}.",a:"Leute",opts:["Leute","Kleider","Schuhe","Sachen"],hint:"A famous proverb about how clothes affect perception of people.",sSrc:"Clothes make people."}
]}
,

// Unit 11, Lesson 3: Opa Heinrichs Brötchen
// Story dev + grammar intro: adjective declension (nominative) + temporal prepositions
// 8 vocab teach cards + verb_table + tip + 8 quiz steps = 24 steps total

{id:"deu_r11l3",title:"Opa Heinrichs Brötchen",icon:"🍞",xp:15,board:true,steps:[
{type:"intro",title:"Opa Heinrichs Brötchen",desc:"A man in a wool coat and flat cap appears at the Weihnachtsmarkt. He has bread from this morning and opinions about everything. Meet Opa Heinrich.",goals:["Learn 8 new words for gifts and shopping","Understand adjective endings in nominative case","Use temporal prepositions to talk about time"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-weihnachtsmarkt-opa",trg:"Ein alter Mann kommt langsam durch die Menge. Wollmantel, Schiebermütze, eine Tüte Brötchen unter dem Arm. Er sieht Hildi und winkt. 'Von heute Morgen,' sagt er und hält die Tüte hoch. 'Noch frisch!'",src:"An old man comes slowly through the crowd. Wool coat, flat cap, a bag of bread rolls under his arm. He sees Hildi and waves. 'From this morning,' he says, holding up the bag. 'Still fresh!'"},
{type:"story",speaker:"hildi",trg:"Verumius, das ist mein Opa Heinrich. Opa, das ist Verumius. Er lernt Deutsch.",src:"Verumius, this is my grandpa Heinrich. Grandpa, this is Verumius. He is learning German."},
{type:"story",speaker:"opa",trg:"Ah, der neue Freund! Hier, nimm ein frisches Brötchen. Nach dem Frühstück habe ich noch zehn übrig. Vor einer Stunde waren es zwölf.",src:"Ah, the new friend! Here, take a fresh bread roll. After breakfast I still had ten left. An hour ago there were twelve."},
{type:"teach",trg:"die Kette",src:"the necklace / the chain",note:"Feminine noun. Plural: die Ketten.",example:"A: Die goldene Kette ist schön!\nB: Ja, die ist seit gestern im Angebot.",exampleSrc:"A: The golden necklace is beautiful!\nB: Yes, it has been on sale since yesterday.",funFact:"'Kette' means both 'necklace' and 'chain.' A bicycle chain is also 'eine Kette.' Context tells you if it is jewelry or hardware."},
{type:"teach",trg:"das Parfüm",src:"the perfume",note:"Neuter noun. Plural: die Parfüms. Borrowed from French.",example:"A: Das teure Parfüm riecht toll!\nB: Ich schenke es meiner Mutter nach Weihnachten.",exampleSrc:"A: The expensive perfume smells great!\nB: I'll give it to my mother after Christmas.",funFact:"Germans borrowed 'Parfüm' straight from French 'parfum.' The umlaut ü was added to match German pronunciation. Many luxury words in German are French imports."},
{type:"teach",trg:"die Kosmetik",src:"the cosmetics",note:"Feminine noun. Used as singular for the category.",example:"A: Wo finde ich gute Kosmetik?\nB: Seit letztem Jahr gibt es einen neuen Stand hier.",exampleSrc:"A: Where can I find good cosmetics?\nB: Since last year there has been a new stall here.",funFact:"From Greek 'kosmetikos' meaning 'skilled in decorating.' The same root gives us 'cosmos,' because the Greeks thought the universe was beautifully ordered."},
{type:"teach",trg:"die Mode",src:"the fashion",note:"Feminine noun. From French 'mode.'",example:"A: Ist diese Mode noch modern?\nB: Ja, vor zwei Wochen war sie auf Instagram!",exampleSrc:"A: Is this fashion still modern?\nB: Yes, two weeks ago it was on Instagram!",funFact:"'Mode' and 'modern' share the same Latin root 'modus' (way, style). In German, 'altmodisch' (old-fashioned) literally means 'old-mode-ish.'"},
{type:"mc",q:"Opa Heinrich says 'Von heute Morgen, noch frisch!' What is he talking about?",opts:["His wool coat","His flat cap","His bread rolls","His necklace"],ans:"His bread rolls",hint:"He is carrying a bag of something baked under his arm."},
{type:"teach",trg:"die Ferien",src:"the holidays / the vacation",note:"Always plural in German. No singular form.",example:"A: Was machst du in den Ferien?\nB: Während der Ferien fahre ich nach Spanien.",exampleSrc:"A: What are you doing during the holidays?\nB: During the holidays I'm going to Spain.",funFact:"'Ferien' is always plural. For a single day off, Germans say 'Feiertag' (celebration-day). School holidays are 'Schulferien,' and summer break is 'Sommerferien.'"},
{type:"teach",trg:"der Flohmarkt",src:"the flea market",note:"Masculine noun. Compound: Floh (flea) + Markt (market).",example:"A: Auf dem alten Flohmarkt gibt es schöne Ketten.\nB: Stimmt, seit letztem Monat ist er noch größer.",exampleSrc:"A: At the old flea market there are beautiful necklaces.\nB: True, since last month it is even bigger.",funFact:"'Flohmarkt' is a direct loan-translation from French 'marché aux puces.' The story goes that old clothes sold at these markets often had fleas in them!"},
{type:"teach",trg:"schenken",src:"to give (as a gift)",note:"Regular verb. Different from 'geben' (to give). Schenken = always a gift.",example:"A: Was schenkst du ihr?\nB: Ich schenke ihr eine neue Kette vor ihrem Geburtstag.",exampleSrc:"A: What are you giving her?\nB: I'm giving her a new necklace before her birthday.",funFact:"'Schenken' comes from 'einschenken' (to pour a drink). Originally, offering someone a drink was the act of giving. The meaning broadened to any gift."},
{type:"teach",trg:"wünschen",src:"to wish",note:"Regular verb. 'Ich wünsche dir alles Gute!' = I wish you all the best!",example:"A: Was wünschst du dir zu Weihnachten?\nB: Ich wünsche mir ein gutes Parfüm.",exampleSrc:"A: What do you wish for for Christmas?\nB: I wish for a nice perfume.",funFact:"The reflexive 'sich wünschen' means 'to wish for oneself.' A Wunschzettel is a 'wish-list' that German children write for Weihnachten."},
{type:"teach",trg:"der Schal",src:"the scarf",gender:"m",phonetic:"SHAHL",example:"A: Dein Schal ist wirklich schön!\nB: Danke, ich habe ihn auf dem Weihnachtsmarkt gekauft.\nA: Die Farbe passt perfekt zu deinem Mantel.",exampleSrc:"A: Your scarf is really beautiful!\nB: Thanks, I bought it at the Christmas market.\nA: The color matches your coat perfectly.",note:"der Schal, masculine. Plural: die Schals. A winter essential on the Weihnachtsmarkt.",funFact:"The German word 'Schal' comes from Persian via French. Cashmere scarves from Kashmir were luxury items in 18th century Europe."},
{type:"mc",q:"'Ich schenke dir eine Kette.' What is the speaker doing?",opts:["Buying a necklace for themselves","Giving a necklace as a gift","Borrowing a necklace","Returning a necklace"],ans:"Giving a necklace as a gift",hint:"This verb means presenting something as a gift, permanently."},
{type:"verb_table",title:"Adjective Endings: Nominative Case",groups:[{label:"After der/die/das (definite article): always -e",rows:[{pronoun:"der",form:"-e",src:"der alte Mann (the old man)"},{pronoun:"die",form:"-e",src:"die goldene Kette (the golden necklace)"},{pronoun:"das",form:"-e",src:"das teure Parfüm (the expensive perfume)"},{pronoun:"die (pl.)",form:"-en",src:"die frischen Brötchen (the fresh rolls)"}]},{label:"After ein/eine/ein (indefinite article)",rows:[{pronoun:"ein (masc.)",form:"-er",src:"ein alter Mann (an old man)"},{pronoun:"eine (fem.)",form:"-e",src:"eine goldene Kette (a golden necklace)"},{pronoun:"ein (neut.)",form:"-es",src:"ein teures Parfüm (an expensive perfume)"}]},{label:"No article (strong endings)",rows:[{pronoun:"masc.",form:"-er",src:"frischer Kaffee (fresh coffee)"},{pronoun:"fem.",form:"-e",src:"gute Kosmetik (good cosmetics)"},{pronoun:"neut.",form:"-es",src:"kaltes Wasser (cold water)"},{pronoun:"plural",form:"-e",src:"frische Brötchen (fresh rolls)"}]}],note:"After definite articles, adjectives are 'weak' and almost always end in -e (except plural: -en). After indefinite articles, the adjective shows the gender."},
{type:"tip",title:"Temporal Prepositions: When Did It Happen?",text:"German uses specific prepositions for time expressions:\n\nvor + dative: ago, before\n'Vor einer Stunde' = an hour ago\n'Vor dem Frühstück' = before breakfast\n\nnach + dative: after\n'Nach dem Essen' = after the meal\n'Nach Weihnachten' = after Christmas\n\nwährend + genitive: during\n'Während der Ferien' = during the holidays\n\nbis: until\n'Bis morgen!' = Until tomorrow!\n\nseit + dative: since, for (ongoing)\n'Seit gestern' = since yesterday\n'Seit zwei Wochen' = for two weeks\n\nab + dative: from (a point in time)\n'Ab morgen' = from tomorrow on",deepDive:"'Vor' and 'nach' are the most common pair. Think of them as opposites on a timeline: vor = to the left (earlier), nach = to the right (later). 'Seit' describes something that STARTED in the past and CONTINUES now. 'Bis' marks where something ENDS."},
{type:"mc",q:"Opa Heinrich says 'Vor einer Stunde waren es zwölf.' What does 'vor einer Stunde' mean?",opts:["In one hour","For one hour","An hour ago","Before one hour"],ans:"An hour ago",hint:"'Vor' with a time expression looks backward on the timeline."},
{type:"fb",s:"{1} dem Frühstück habe ich noch zehn übrig.",a:["Nach"],opts:["Nach","Vor","Seit","Bis"],hint:"Which preposition means 'after' with a past event?",sSrc:"After breakfast I have ten left."},
{type:"mc",q:"'Die goldene Kette ist schön.' Why does the adjective end in -e?",opts:["Because 'Kette' is feminine","Because it follows 'die' (definite article)","Because 'golden' always ends in -e","Because the sentence is about beauty"],ans:"Because it follows 'die' (definite article)",hint:"After 'die' in nominative, the suffix on the descriptor is nearly always the same."},
{type:"fb",s:"Ein alt{1} Mann kommt durch die Menge.",a:["er"],opts:["er","e","es","en"],hint:"After 'ein' in nominative, what ending does the adjective need for a masculine noun?",sSrc:"An old man comes through the crowd."},
{type:"drag_fill",s:"Ich wünsche mir {1} Parfüm {2} Weihnachten.",blanks:{"1":"ein gutes","2":"vor"},pool:["ein gutes","eine gute","ein guter","vor","nach","seit"],hint:"A neuter noun after 'ein' needs which ending? And which preposition means 'before'?",sSrc:"I wish for a good perfume before Christmas."},
{type:"mc",q:"'Seit letztem Jahr gibt es einen neuen Stand.' What does 'seit' tell you?",opts:["It happened once last year","It started last year and continues now","It will happen next year","It ended last year"],ans:"It started last year and continues now",hint:"This preposition describes something ongoing from a past starting point."},
{type:"fb",s:"{1} der Ferien fahre ich nach Spanien.",a:["Während"],opts:["Während","Seit","Vor","Ab"],hint:"Which preposition means 'during' and takes the genitive case?",sSrc:"During the holidays I am travelling to Spain."},
{type:"drag_fill",s:"{1} Brötchen sind {2} heute Morgen.",blanks:{"1":"Die frischen","2":"von"},pool:["Die frischen","Das frische","Der frischer","von","vor","nach"],hint:"Definite article + plural adjective ending? And 'from' this morning?",sSrc:"The fresh rolls are from this morning."},
{type:"match",pairs:[{trg:"die Kette",src:"the necklace"},{trg:"schenken",src:"to give (as gift)"},{trg:"wünschen",src:"to wish"},{trg:"die Ferien",src:"the holidays"},{trg:"vor",src:"ago / before"},{trg:"seit",src:"since / for"}]},
{type:"story",speaker:"opa",trg:"Hier, frische Brötchen für alle! Seit fünfzig Jahren kaufe ich beim gleichen Bäcker. Vor dem Krieg war der Laden noch klein. Während der Ferien backt er sogar Stollen!",src:"Here, fresh rolls for everyone! For fifty years I have been buying from the same baker. Before the war the shop was still small. During the holidays he even bakes Stollen!"},
{type:"mc",q:"Opa Heinrich says 'Seit fünfzig Jahren kaufe ich beim gleichen Bäcker.' How long has he been going to the same baker?",opts:["For five years","For fifteen years","For fifty years","Since his birthday"],ans:"For fifty years",hint:"'Fünfzig' is the German word for a number between 49 and 51."}
]},
,

// U11 L4: Der rote Schal - Grammar: Adjective declension (acc/dat), possessives, Konjunktiv II
{id:"deu_r11l4",title:"Der rote Schal",icon:"\uD83D\uDCD0",xp:20,board:true,steps:[
{type:"intro",title:"Der rote Schal",desc:"Verumius spots a beautiful red scarf at the Weihnachtsmarkt. But describing it means mastering adjective endings in accusative and dative. Plus: how to say 'I would like...'",goals:["Decline adjectives in accusative and dative","Use possessive articles across cases","Express wishes with w\u00fcrde + infinitive"]},
{type:"story",speaker:"narrator",mood:"curious",art:"de-xmas-market-scarves",trg:"Am Schalstand. Bunte Schals h\u00e4ngen \u00fcberall. Verumius sieht einen roten Schal und greift danach. Hildi lacht.",src:"At the scarf stand. Colorful scarves hang everywhere. Verumius sees a red scarf and reaches for it. Hildi laughs."},
{type:"story",speaker:"Hildi",trg:"Du willst den roten Schal? Der passt zu deinem blauen Mantel. Aber ich w\u00fcrde den gr\u00fcnen nehmen!",src:"You want the red scarf? It goes with your blue coat. But I would take the green one!"},
{type:"teach",trg:"beschreiben",src:"to describe",note:"Irregular (strong verb): ich beschreibe, du beschreibst, er beschreibt. Past: beschrieb, Partizip II: beschrieben.",example:"A: Kannst du den Schal beschreiben?\nB: Er ist lang, rot und sehr weich.",exampleSrc:"A: Can you describe the scarf?\nB: It is long, red, and very soft.",funFact:"'Beschreiben' literally means 'to write upon.' You 'write upon' something with words to paint a picture. The same 'schreiben' root appears in 'Schreibtisch' (writing desk)."},
{type:"teach",trg:"passen",src:"to fit / to suit",note:"Regular: ich passe, du passt, er passt. Often used with 'zu' (to/with).",example:"A: Passt der Schal zu meinem Mantel?\nB: Ja, die Farben passen perfekt zusammen!",exampleSrc:"A: Does the scarf go with my coat?\nB: Yes, the colors match perfectly!",funFact:"'Das passt!' is how Germans say 'That works!' In restaurants, 'Passt so' after paying means 'keep the change.' One little verb, many daily uses."},
{type:"teach",trg:"tragen",src:"to wear / to carry",note:"Irregular: ich trage, du tr\u00e4gst, er tr\u00e4gt. Stem change a \u2192 \u00e4.",example:"A: Was tr\u00e4gst du heute?\nB: Ich trage einen warmen Pullover.",exampleSrc:"A: What are you wearing today?\nB: I'm wearing a warm sweater.",funFact:"'Tragen' means both 'to wear' and 'to carry.' A 'Gep\u00e4cktr\u00e4ger' is a luggage carrier. Context decides whether clothes or cargo are involved."},
{type:"teach",trg:"vergleichen",src:"to compare",note:"Irregular past, but regular present: ich vergleiche, du vergleichst.",example:"A: Lass uns die zwei Schals vergleichen.\nB: Der rote ist weicher als der blaue.",exampleSrc:"A: Let's compare the two scarves.\nB: The red one is softer than the blue one.",funFact:"'Vergleichen' contains 'gleich' (same/equal). To compare is literally to 'check for sameness.' 'Gleich' also means 'soon' in casual speech: 'Ich komme gleich!'"},
{type:"teach",trg:"wechseln",src:"to change / to exchange",note:"Regular: ich wechsle, du wechselst. Used for money, clothes, or topics.",example:"A: Kann ich den Schal wechseln?\nB: Nat\u00fcrlich, gegen welche Farbe?",exampleSrc:"A: Can I exchange the scarf?\nB: Of course, for which color?",funFact:"A 'Wechselstube' is a currency exchange booth. 'Geld wechseln' = to exchange money. At the Weihnachtsmarkt, you might need to 'wechseln' big bills for small coins."},
{type:"teach",trg:"ansehen",src:"to look at",note:"Separable: ich sehe ... an, du siehst ... an. Stem change e \u2192 ie.",example:"A: Sieh dir den Schal an!\nB: Oh, der ist wirklich sch\u00f6n!",exampleSrc:"A: Look at the scarf!\nB: Oh, it is really beautiful!",funFact:"'Ansehen' is separable: the 'an' jumps to the end of the clause. 'Ich sehe den Schal an.' But in a subordinate clause it reunites: 'weil ich den Schal ansehe.' German word Tetris!"},
{type:"mc",q:"Which verb means 'to wear' or 'to carry' in German?",opts:["tragen","passen","wechseln","beschreiben"],ans:"tragen",hint:"This irregular verb has a stem change from a to \u00e4 in the du/er forms."},
{type:"tip",title:"Adjective Endings: The Big Picture",text:"German adjectives change their ending based on THREE things:\n\n1. Case: nominative, accusative, or dative?\n2. Gender: der, die, or das?\n3. Article type: definite (der/die/das) or indefinite (ein/eine/ein)?\n\nYou already know nominative from L3.\nNow we add accusative (direct object) and dative (indirect object).\n\nGood news: there are PATTERNS that simplify everything.",deepDive:"Why does German do this? Because adjective endings carry grammatical information. In 'Ich sehe den roten Schal,' the '-en' on 'roten' confirms this is accusative masculine. Even if you missed 'den,' the adjective ending tells you the case. It is a backup system built into the language."},
{type:"verb_table",title:"Adjective Declension: Accusative Case",groups:[{label:"With definite article (den/die/das)",rows:[{pronoun:"Masculine",form:"den rot-en Schal",src:"the red scarf (-en)"},{pronoun:"Feminine",form:"die rot-e M\u00fctze",src:"the red hat (-e)"},{pronoun:"Neuter",form:"das rot-e Kleid",src:"the red dress (-e)"}]},{label:"With indefinite article (einen/eine/ein)",rows:[{pronoun:"Masculine",form:"einen rot-en Schal",src:"a red scarf (-en)"},{pronoun:"Feminine",form:"eine rot-e M\u00fctze",src:"a red hat (-e)"},{pronoun:"Neuter",form:"ein rot-es Kleid",src:"a red dress (-es)"}]}],note:"Accusative masculine always gets -en. Feminine stays -e. Neuter: -e with definite, -es with indefinite (because 'ein' has no ending to show gender)."},
{type:"mc",q:"'Ich kaufe _____ warmen Schal.' Which article completes this accusative masculine phrase?",opts:["den","die","das","dem"],ans:"den",hint:"Accusative changes only the masculine article from 'der' to something else."},
{type:"fb",s:"Verumius tr\u00e4gt einen rot{1} Schal.",a:["en"],opts:["en","e","es","em"],hint:"After 'einen' (accusative masc. indefinite), what ending does the adjective take?",sSrc:"Verumius wears a red scarf."},
{type:"mc",q:"'Hildi sieht die sch\u00f6n___ Lampe an.' Which ending fits this accusative feminine phrase?",opts:["-e","-en","-es","-em"],ans:"-e",hint:"Accusative feminine with 'die' keeps the same ending as nominative feminine."},
{type:"fb",s:"Ich m\u00f6chte ein warm{1} Kleid kaufen.",a:["es"],opts:["es","e","en","em"],hint:"Accusative neuter with 'ein' needs an ending that shows neuter gender.",sSrc:"I would like to buy a warm dress."},
{type:"verb_table",title:"Adjective Declension: Dative Case",groups:[{label:"With definite article (dem/der/dem)",rows:[{pronoun:"Masculine",form:"dem rot-en Schal",src:"the red scarf (-en)"},{pronoun:"Feminine",form:"der rot-en M\u00fctze",src:"the red hat (-en)"},{pronoun:"Neuter",form:"dem rot-en Kleid",src:"the red dress (-en)"}]},{label:"With indefinite article (einem/einer/einem)",rows:[{pronoun:"Masculine",form:"einem rot-en Schal",src:"a red scarf (-en)"},{pronoun:"Feminine",form:"einer rot-en M\u00fctze",src:"a red hat (-en)"},{pronoun:"Neuter",form:"einem rot-en Kleid",src:"a red dress (-en)"}]}],note:"Dative is the EASY case for adjectives: EVERY ending is -en. Always. No exceptions. Masculine, feminine, neuter, definite, indefinite: always -en."},
{type:"tip",title:"Dative Shortcut: Always -en!",text:"Dative adjective endings are the simplest in German:\n\ndem kalten Wind = -en\nder warmen Suppe = -en\ndem alten Haus = -en\neinem neuen Freund = -en\n\nAll genders. All article types. Always -en.\nThis is the one case you can learn in five seconds.",deepDive:"Why always -en? In dative, the article itself already shows the gender clearly (dem = masc/neut, der = fem). The adjective does not need to carry extra gender information, so it relaxes to the default -en ending. Less work for the adjective when the article is already doing the job."},
{type:"fb",s:"Ich gebe es dem klein{1} Kind.",a:["en"],opts:["en","e","es","em"],hint:"In dative, adjective endings follow one universal rule for all genders.",sSrc:"I give it to the small child."},
{type:"teach",trg:"die Tasse",src:"the cup",gender:"f",phonetic:"TA-suh",example:"A: Möchtest du eine Tasse Tee?\nB: Ja, gerne! Mit Zucker, bitte.\nA: Hier, eine warme Tasse für dich.",exampleSrc:"A: Would you like a cup of tea?\nB: Yes, please! With sugar.\nA: Here, a warm cup for you.",note:"die Tasse, feminine. Plural: die Tassen. Used for cups with handles, including mugs.",funFact:"Germans drink about 164 litres of coffee per person per year. On the Weihnachtsmarkt, Glühwein comes in collectible Tassen you can keep."},
{type:"mc",q:"'Mit einer warm___ Tasse Tee.' Which ending completes this dative phrase?",opts:["-en","-e","-es","-er"],ans:"-en",hint:"Dative adjectives follow one universal rule regardless of gender or article type."},
{type:"drag_fill",s:"Verumius gibt {1} Frau {2} Schal.",blanks:{"1":"der netten","2":"den roten"},pool:["der netten","den roten","die nette","das rote","dem netten"],hint:"'Der Frau' is dative feminine. 'Den Schal' is accusative masculine. Pick the matching adjective forms.",sSrc:"Verumius gives the nice woman the red scarf."},
{type:"verb_table",title:"Possessive Articles: mein/dein/sein/ihr",groups:[{label:"Nominative",rows:[{pronoun:"Masculine",form:"mein roter Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meine rote M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"mein rotes Kleid",src:"my red dress"}]},{label:"Accusative",rows:[{pronoun:"Masculine",form:"meinen roten Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meine rote M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"mein rotes Kleid",src:"my red dress"}]},{label:"Dative",rows:[{pronoun:"Masculine",form:"meinem roten Schal",src:"my red scarf"},{pronoun:"Feminine",form:"meiner roten M\u00fctze",src:"my red hat"},{pronoun:"Neuter",form:"meinem roten Kleid",src:"my red dress"}]}],note:"Possessives (mein/dein/sein/ihr/unser/euer/ihr) follow the SAME pattern as ein/eine/ein. Just swap 'ein' for 'mein' and adjective endings stay identical."},
{type:"tip",title:"Possessives = ein-Words",text:"Great news: mein, dein, sein, ihr, unser, euer, ihr, and kein all follow the EXACT same pattern as ein/eine/ein.\n\nIf you know 'einen roten Schal,' you know:\nmeinen roten Schal\ndeinen roten Schal\nseinen roten Schal\nihren roten Schal\n\nOne pattern, eight words. Learn it once, use it everywhere.",deepDive:"The possessives are called 'ein-words' because they take the same endings as 'ein.' The definite article words (dieser, jeder, welcher) are called 'der-words' and follow 'der/die/das' endings. Knowing which group a word belongs to tells you all its endings automatically."},
{type:"fb",s:"Hildi tr\u00e4gt {1} neuen Schal.",a:["ihren"],opts:["ihren","ihre","ihr","ihrem"],hint:"Accusative masculine with a possessive follows the same pattern as 'einen.'",sSrc:"Hildi wears her new scarf."},
{type:"mc",q:"'Ich gebe es meinem alten Freund.' What case is 'meinem alten' in?",opts:["Dative","Accusative","Nominative","Genitive"],ans:"Dative",hint:"'Meinem' with -em ending signals the case used for giving things TO someone."},
{type:"tip",title:"Konjunktiv II: Wishes and Polite Requests",text:"To say 'I would...' in German, use:\nw\u00fcrde + infinitive (at the end)\n\nIch w\u00fcrde den Schal kaufen. = I would buy the scarf.\nW\u00fcrdest du mir helfen? = Would you help me?\n\nFour common verbs have their OWN Konjunktiv II forms:\nw\u00e4re (would be), h\u00e4tte (would have),\nk\u00f6nnte (could), m\u00fcsste (would have to).",deepDive:"Konjunktiv II comes from the simple past (Pr\u00e4teritum) form with an umlaut added. 'War' becomes 'w\u00e4re,' 'hatte' becomes 'h\u00e4tte,' 'konnte' becomes 'k\u00f6nnte.' For most verbs, this old form sounds archaic, so modern German uses 'w\u00fcrde + infinitive' instead. But the four common ones (w\u00e4re, h\u00e4tte, k\u00f6nnte, m\u00fcsste) are used daily."},
{type:"verb_table",title:"Konjunktiv II: w\u00fcrde + Infinitive",groups:[{label:"w\u00fcrde (would)",rows:[{pronoun:"ich",form:"w\u00fcrde",src:"I would"},{pronoun:"du",form:"w\u00fcrdest",src:"you would"},{pronoun:"er/sie/es",form:"w\u00fcrde",src:"he/she/it would"},{pronoun:"wir",form:"w\u00fcrden",src:"we would"},{pronoun:"ihr",form:"w\u00fcrdet",src:"you all would"},{pronoun:"sie/Sie",form:"w\u00fcrden",src:"they/you (formal) would"}]},{label:"Common irregular forms",rows:[{pronoun:"sein",form:"w\u00e4re",src:"would be"},{pronoun:"haben",form:"h\u00e4tte",src:"would have"},{pronoun:"k\u00f6nnen",form:"k\u00f6nnte",src:"could"},{pronoun:"m\u00fcssen",form:"m\u00fcsste",src:"would have to"}]}],note:"Use w\u00fcrde + infinitive for most verbs. Use w\u00e4re/h\u00e4tte/k\u00f6nnte/m\u00fcsste directly (no w\u00fcrde needed). 'Ich w\u00fcrde kaufen' but 'Ich h\u00e4tte gern...'"},
{type:"mc",q:"Hildi says 'Ich w\u00fcrde den gr\u00fcnen nehmen!' What does 'w\u00fcrde ... nehmen' mean?",opts:["would take","must take","will take","should take"],ans:"would take",hint:"This construction expresses a hypothetical wish, not certainty or obligation."},
{type:"fb",s:"Ich {1} gern einen Gl\u00fchwein trinken.",a:["w\u00fcrde"],opts:["w\u00fcrde","w\u00e4re","h\u00e4tte","k\u00f6nnte"],hint:"Which word means 'would' and combines with an infinitive at the end?",sSrc:"I would like to drink a mulled wine."},
{type:"mc",q:"'Das w\u00e4re sehr nett!' What does 'w\u00e4re' mean?",opts:["would be","would have","could","would have to"],ans:"would be",hint:"This irregular Konjunktiv II form comes from 'sein' (to be)."},
{type:"drag_fill",s:"Ich {1} gern {2} roten Schal f\u00fcr {3} Freundin kaufen.",blanks:{"1":"w\u00fcrde","2":"den","3":"meine"},pool:["w\u00fcrde","den","meine","w\u00e4re","dem","meiner"],hint:"Express a wish (would), then accusative masc. article, then accusative fem. possessive.",sSrc:"I would like to buy the red scarf for my girlfriend."},
{type:"mc",q:"'Wenn ich reich ___, ___ ich alles kaufen.' Which pair completes this?",opts:["w\u00e4re ... w\u00fcrde","w\u00fcrde ... w\u00e4re","h\u00e4tte ... w\u00e4re","k\u00f6nnte ... h\u00e4tte"],ans:"w\u00e4re ... w\u00fcrde",hint:"First blank needs the Konjunktiv II of 'sein,' second needs 'would' with an infinitive."},
{type:"match",pairs:[{trg:"den roten Schal",src:"the red scarf (acc.)"},{trg:"dem kalten Wind",src:"the cold wind (dat.)"},{trg:"meinen neuen Mantel",src:"my new coat (acc.)"},{trg:"einer warmen Tasse",src:"a warm cup (dat.)"},{trg:"w\u00fcrde kaufen",src:"would buy"},{trg:"w\u00e4re",src:"would be"}]}
]}
,

{id:"deu_r11l5",title:"Wie ist das Wetter?",icon:"🌨️",xp:15,board:true,steps:[
{type:"intro",title:"Wie ist das Wetter?",desc:"Wetter und Adjektive auf dem Weihnachtsmarkt. Beschreibe, was du siehst und fühlst.",goals:["20 Wetter- und Beschreibungswörter lernen","Adjektivendungen in Sätzen üben","Über das Wetter sprechen"]},
{type:"teach",trg:"kalt",src:"cold",phonetic:"kahlt",example:"A: Ist es draußen kalt?\nB: Ja, es ist sehr kalt heute.",exampleSrc:"A: Is it cold outside?\nB: Yes, it is very cold today.",note:"Das klassische Winterwort. Kälte = the cold (noun).",funFact:"Deutsche reden ständig übers Wetter. 'Kalt, oder?' ist ein vollwertiger Gesprächseinstieg."},
{type:"teach",trg:"kühl",src:"cool",phonetic:"küül",example:"A: Wie ist es abends auf dem Markt?\nB: Es wird kühl nach sechs Uhr.",exampleSrc:"A: How is it in the evening at the market?\nB: It gets cool after six o'clock.",note:"Milder als kalt. Frische Luft = cool air.",funFact:"Kühl beschreibt auch Personen: 'Sie war sehr kühl zu mir' bedeutet distanziert."},
{type:"teach",trg:"warm",src:"warm",phonetic:"varm",example:"A: Der Glühwein ist schön warm.\nB: Ja, perfekt für kalte Hände!",exampleSrc:"A: The mulled wine is nicely warm.\nB: Yes, perfect for cold hands!",note:"Cognate mit Englisch. Wärme = warmth.",funFact:"Glühwein auf dem Weihnachtsmarkt wird in Tassen serviert, die man als Souvenir behalten darf."},
{type:"teach",trg:"heiß",src:"hot",phonetic:"haiß",example:"A: Vorsicht, die Suppe ist heiß!\nB: Danke, ich warte kurz.",exampleSrc:"A: Careful, the soup is hot!\nB: Thanks, I'll wait a moment.",note:"Auch für Wetter: Es ist heiß draußen.",funFact:"'Heißhunger' bedeutet plötzlichen, starken Hunger. Wörtlich: heißer Hunger."},
{type:"teach",trg:"nass",src:"wet",phonetic:"nass",example:"A: Meine Schuhe sind ganz nass.\nB: Es hat den ganzen Tag geregnet.",exampleSrc:"A: My shoes are completely wet.\nB: It has rained all day.",note:"Auch: patschnass = soaking wet.",funFact:"Deutsche haben viele Wörter für nass: feucht, klamm, durchnässt, patschnass."},
{type:"teach",trg:"trocken",src:"dry",phonetic:"trokken",example:"A: Bleibt es heute trocken?\nB: Ja, kein Regen bis Freitag.",exampleSrc:"A: Will it stay dry today?\nB: Yes, no rain until Friday.",note:"Gegenteil von nass. Auch für Humor: trockener Witz.",funFact:"'Trockener Humor' ist typisch norddeutsch, besonders in Hamburg."},
{type:"teach",trg:"sonnig",src:"sunny",phonetic:"zonnich",example:"A: Wie wird das Wetter morgen?\nB: Sonnig und warm, sagt die App.",exampleSrc:"A: How will the weather be tomorrow?\nB: Sunny and warm, the app says.",note:"Von die Sonne. Suffix -ig macht Adjektive.",funFact:"Berlin hat im Durchschnitt mehr Sonnenstunden als London, aber weniger als Madrid."},
{type:"teach",trg:"windig",src:"windy",phonetic:"vindich",example:"A: Warum trägst du eine Mütze?\nB: Es ist sehr windig draußen.",exampleSrc:"A: Why are you wearing a hat?\nB: It is very windy outside.",note:"Von der Wind. Gleiche -ig Endung wie sonnig.",funFact:"An der Nordsee ist es fast immer windig. Die Friesen sagen: 'Wind ist hier Luft.'"},
{type:"teach",trg:"der Wind",src:"the wind",gender:"m",phonetic:"VINT",example:"A: Spürst du den kalten Wind?\nB: Ja, er kommt vom Fluss.\nA: Lass uns in die Hütte gehen.",exampleSrc:"A: Do you feel the cold wind?\nB: Yes, it is coming from the river.\nA: Let us go into the hut.",note:"der Wind, masculine. Plural: die Winde. Related adjective: windig (windy).",funFact:"Germany gets strong winds from the North Sea coast. The Beaufort scale is used in German weather reports: Windstarke 8 means gale force."},
{type:"teach",trg:"nebelig",src:"foggy",phonetic:"nebelich",example:"A: Ich sehe die Kirche nicht.\nB: Normal, es ist heute sehr nebelig.",exampleSrc:"A: I can't see the church.\nB: Normal, it is very foggy today.",note:"Von der Nebel (fog). Nebelig = foggy.",funFact:"Novembernebel in deutschen Flusstälern kann tagelang bleiben. Man nennt das Inversionswetterlage."},
{type:"teach",trg:"bewölkt",src:"cloudy",phonetic:"bevölkt",example:"A: Scheint die Sonne?\nB: Nein, es ist leider bewölkt.",exampleSrc:"A: Is the sun shining?\nB: No, it's unfortunately cloudy.",note:"Von die Wolke (cloud). Be- Präfix + -t Endung.",funFact:"Der deutsche Wetterbericht unterscheidet zwischen bewölkt, stark bewölkt und bedeckt."},
{type:"tip",title:"Deutsche und das Wetter",text:"Deutsche reden gern und oft übers Wetter. Es ist ein perfekter Gesprächseinstieg.\n\nTypische Fragen:\n\n'Wie ist das Wetter?' (allgemein)\n'Wie wird es morgen?' (Vorhersage)\n'Schönes Wetter heute, oder?' (Small Talk)\n\nAntworten mit 'Es ist...' + Adjektiv:\nEs ist kalt. Es ist sonnig. Es ist bewölkt.",deepDive:"Das Wort 'Wetter' kommt in vielen Zusammensetzungen vor: Wetterbericht (weather report), Wetterdienst (weather service), Wettervorhersage (forecast), wetterbeständig (weatherproof). Die Frage 'Na, wie ist das Wetter bei euch?' ist ein Standardeinstieg für Telefonate."},
{type:"mc",q:"Verumius sagt: 'Brr! Es ist heute wirklich ___.' Was fehlt?",opts:["kalt","sonnig","trocken","warm"],ans:"kalt",hint:"Brr drückt aus, dass jemandem nicht warm ist."},
{type:"fb",s:"Meine Jacke ist ganz {1} vom Regen.",a:"nass",opts:["nass","trocken","warm","heiß"],hint:"Regen macht Kleidung nicht trocken.",sSrc:"My jacket is completely wet from the rain."},
{type:"teach",trg:"dunkel",src:"dark",phonetic:"dunkel",example:"A: Es wird schon um vier Uhr dunkel.\nB: Ja, typisch für Dezember in Deutschland.",exampleSrc:"A: It already gets dark at four o'clock.\nB: Yes, typical for December in Germany.",note:"Gegenteil: hell (bright). Die Dunkelheit = darkness.",funFact:"Im Dezember wird es in Norddeutschland schon gegen 16 Uhr dunkel."},
{type:"teach",trg:"bunt",src:"colorful",phonetic:"bunt",example:"A: Schau mal, die bunten Lichter!\nB: Der Weihnachtsmarkt sieht toll aus.",exampleSrc:"A: Look, the colorful lights!\nB: The Christmas market looks great.",note:"Bunt = viele Farben zusammen. Kunterbunt = very colorful.",funFact:"'Bunter Abend' ist ein deutscher Ausdruck für einen Abend mit verschiedenem Programm."},
{type:"teach",trg:"dick",src:"thick/fat",phonetic:"dik",example:"A: Ich brauche einen dicken Schal.\nB: Ja, am besten Wolle.",exampleSrc:"A: I need a thick scarf.\nB: Yes, wool is best.",note:"Dick = thick (für Sachen), fat (für Personen). Vorsicht beim Kontext.",funFact:"'Dicke Freunde' bedeutet sehr gute Freunde, nicht dass sie dick sind."},
{type:"teach",trg:"dünn",src:"thin",phonetic:"dünn",example:"A: Die Jacke ist zu dünn für Dezember.\nB: Du brauchst einen Wintermantel.",exampleSrc:"A: The jacket is too thin for December.\nB: You need a winter coat.",note:"Gegenteil von dick. Für Kleidung, Papier, Personen.",funFact:"'Dünnhäutig' (thin-skinned) bedeutet im Deutschen wie im Englischen: empfindlich."},
{type:"teach",trg:"eng",src:"tight/narrow",phonetic:"eng",example:"A: Die Gassen auf dem Markt sind eng.\nB: Ja, aber das macht es gemütlich.",exampleSrc:"A: The lanes at the market are narrow.\nB: Yes, but it makes it cozy.",note:"Eng = räumlich schmal oder Kleidung zu klein.",funFact:"'Enge' Beziehung ist positiv und bedeutet: eine nahe, vertraute Beziehung."},
{type:"teach",trg:"modern",src:"modern",phonetic:"modärn",example:"A: Der neue Weihnachtsmarkt ist sehr modern.\nB: Ich mag die traditionellen Märkte lieber.",exampleSrc:"A: The new Christmas market is very modern.\nB: I prefer the traditional markets.",note:"Cognate. Betont auf der zweiten Silbe: moˈdern.",funFact:"Viele Deutsche bevorzugen 'traditionell' gegenüber 'modern' beim Weihnachtsmarkt."},
{type:"teach",trg:"früh",src:"early",phonetic:"frü",example:"A: Wir müssen früh losgehen.\nB: Warum? Wann öffnet der Markt?\nA: Um elf, aber es wird schnell voll.",exampleSrc:"A: We have to leave early.\nB: Why? When does the market open?\nA: At eleven, but it gets crowded quickly.",note:"Gegenteil: spät (late). Früher = earlier / in the past.",funFact:"'Der frühe Vogel fängt den Wurm' ist das deutsche Äquivalent zu 'the early bird catches the worm.'"},
{type:"teach",trg:"einzeln",src:"individual/single",phonetic:"aintseln",example:"A: Kann ich einzelne Pralinen kaufen?\nB: Ja, fünfzig Cent pro Stück.",exampleSrc:"A: Can I buy individual chocolates?\nB: Yes, fifty cents each.",note:"Auch: ein einzelner Mensch = a single person.",funFact:"'Einzelkind' (only child) ist im Deutschen ein normales Wort, nicht negativ."},
{type:"teach",trg:"fleißig",src:"hardworking",phonetic:"flaißich",example:"A: Die Verkäufer auf dem Markt sind sehr fleißig.\nB: Ja, sie arbeiten von morgens bis abends.",exampleSrc:"A: The vendors at the market are very hardworking.\nB: Yes, they work from morning to evening.",note:"Ein typisch deutsches Kompliment. Fleiß = diligence.",funFact:"'Fleiß' ist eine der klassischen deutschen Tugenden neben Pünktlichkeit und Ordnung."},
{type:"teach",trg:"typisch",src:"typical",phonetic:"tüpisch",example:"A: Glühwein und Lebkuchen auf dem Markt.\nB: Das ist typisch deutsch!",exampleSrc:"A: Mulled wine and gingerbread at the market.\nB: That's typically German!",note:"Cognate. Typisch + für: typisch für Deutschland.",funFact:"'Typisch!' als Ausruf bedeutet oft: Das war zu erwarten. Leicht genervt."},
{type:"teach",trg:"der Enkel",src:"the grandson / grandchild",note:"Masculine noun. Plural: die Enkel.\nFeminine: die Enkelin (granddaughter). Plural: die Enkelinnen.",example:"A: Wie viele Enkel hast du, Heinrich?\nB: Drei Enkel! Hildi, Thomas und die kleine Lena.\nA: Hildi ist deine Enkelin?\nB: Ja, meine älteste Enkelin.",exampleSrc:"A: How many grandchildren do you have, Heinrich?\nB: Three grandchildren! Hildi, Thomas, and little Lena.\nA: Hildi is your granddaughter?\nB: Yes, my oldest granddaughter.",funFact:"In Germany, grandparents often live close to their grandchildren. The word 'Enkel' comes from Old High German 'eninchili' meaning 'little ancestor.' Grandchildren were seen as small versions of their grandparents."},
{type:"teach",trg:"das Feuer",src:"the fire",note:"Neuter noun. Plural: die Feuer.\nRelated: Feuerwehr (fire department), Feuerzeug (lighter).",example:"A: Schau, ein Feuer auf dem Markt!\nB: Das ist eine Feuerschale. Zum Wärmen.\nA: Stell dich ans Feuer, es ist warm.\nB: Gute Idee, meine Hände sind eiskalt.",exampleSrc:"A: Look, a fire at the market!\nB: That is a fire bowl. For warming up.\nA: Stand by the fire, it is warm.\nB: Good idea, my hands are ice cold.",funFact:"At German Christmas markets, Feuerschalen (fire bowls) are gathering spots where strangers warm their hands and chat. The Feuerwehr (fire department) literally means 'fire defense.' Feuerzeug (lighter) means 'fire thing.'"},
{type:"teach",trg:"die Decke",src:"the blanket / ceiling",note:"Feminine noun. Plural: die Decken.\nTwo meanings: (1) blanket/cover, (2) ceiling.",example:"A: Mir ist kalt.\nB: Hier, nimm eine Decke!\nA: Danke, die Decke ist so weich.\nB: Ja, das ist reine Wolle.",exampleSrc:"A: I am cold.\nB: Here, take a blanket!\nA: Thanks, the blanket is so soft.\nB: Yes, that is pure wool.",funFact:"'Decke' means both 'blanket' and 'ceiling.' 'Mir fällt die Decke auf den Kopf' (the ceiling falls on my head) is an idiom meaning 'I am going stir-crazy' from being indoors too long. 'Bettdecke' specifically means the bed blanket."},
{type:"teach",trg:"der Nebel",src:"the fog / mist",note:"Masculine noun. Plural: die Nebel.\nAdjective: nebelig (foggy).",example:"A: Ich sehe den Weihnachtsmarkt nicht.\nB: Der Nebel ist heute sehr dicht.\nA: Kann man bei Nebel laufen?\nB: Ja, aber langsam und vorsichtig.",exampleSrc:"A: I cannot see the Christmas market.\nB: The fog is very dense today.\nA: Can you walk in the fog?\nB: Yes, but slowly and carefully.",funFact:"German November is famous for 'Novembernebel' (November fog). In river valleys like the Rhine, fog can last for days. The word 'Nebel' is related to Latin 'nebula' (cloud). Astronomy borrowed it back as 'nebula.'"},
{type:"teach",trg:"das Weihnachtslied",src:"the Christmas carol",note:"Neuter noun. Compound: Weihnacht (Christmas) + Lied (song).\nPlural: die Weihnachtslieder.",example:"A: Kennst du ein deutsches Weihnachtslied?\nB: Ja! 'Stille Nacht, heilige Nacht.'\nA: Das ist ein typisches deutsches Weihnachtslied?\nB: Es kommt eigentlich aus Österreich!",exampleSrc:"A: Do you know a German Christmas carol?\nB: Yes! 'Silent Night, Holy Night.'\nA: Is that a typical German Christmas carol?\nB: It actually comes from Austria!",funFact:"'Stille Nacht' was first performed in 1818 in a church in Austria. 'O Tannenbaum' (O Christmas Tree) is probably the most famous German Weihnachtslied worldwide. German Weihnachtslieder are often played by live brass bands at Christmas markets."},
{type:"teach",trg:"die Fähigkeit",src:"the ability / skill",note:"Feminine noun. Plural: die Fähigkeiten.\nFrom 'fähig' (capable) + '-keit' (noun suffix).",example:"A: Verumius hat die Fähigkeit, schnell zu lernen.\nB: Ja, sein Deutsch wird jeden Tag besser.\nA: Sprachen lernen ist eine wichtige Fähigkeit.",exampleSrc:"A: Verumius has the ability to learn quickly.\nB: Yes, his German gets better every day.\nA: Learning languages is an important ability.",funFact:"The suffix '-keit' turns adjectives into nouns: fähig to Fähigkeit, möglich to Möglichkeit, freundlich to Freundlichkeit. Once you see this pattern, you unlock hundreds of abstract nouns in German."},
{type:"teach",trg:"trotz",src:"despite / in spite of",note:"Preposition. Takes the GENITIVE case.\ntrotz + genitive: trotz des Regens = despite the rain.",example:"A: Trotz des Schnees gehen wir auf den Markt.\nB: Natürlich! Ein bisschen Schnee stoppt uns nicht.\nA: Trotz der Kälte trinken alle Glühwein draußen.",exampleSrc:"A: Despite the snow, we are going to the market.\nB: Of course! A little snow does not stop us.\nA: Despite the cold, everyone drinks mulled wine outside.",funFact:"'Trotz' takes the genitive, which makes it a favorite word for testing German grammar. 'Trotzdem' (nevertheless) is the adverb form and extremely common in everyday speech. 'Es regnet? Ich gehe trotzdem!' (It is raining? I am going anyway!)"},
{type:"mc",q:"Es regnet seit drei Tagen. Die Straßen sind ___.",opts:["nass","trocken","sonnig","dunkel"],ans:"nass",hint:"Regen bringt Wasser auf die Straßen."},
{type:"fb",s:"Im Dezember wird es in Deutschland sehr {1}.",a:"dunkel",opts:["dunkel","sonnig","heiß","bunt"],hint:"Die Sonne geht früh unter im Winter.",sSrc:"In December it gets very dark in Germany."},
{type:"mc",q:"'Die bunten Lichter auf dem Weihnachtsmarkt.' Was bedeutet 'bunt'?",opts:["colorful","bright","dark","single"],ans:"colorful",hint:"Denk an viele verschiedene Farben zusammen."},
{type:"fb",s:"Der Schal ist zu {1} für den Winter. Ich brauche einen dickeren.",a:"dünn",opts:["dünn","eng","modern","früh"],hint:"Das Gegenteil von dick beschreibt zu wenig Stoff.",sSrc:"The scarf is too thin for winter. I need a thicker one."},
{type:"mc",q:"Verumius fragt: 'Wie ist das Wetter heute?' Hildi antwortet: 'Es ist ___ und kalt.'",opts:["windig","fleißig","einzeln","typisch"],ans:"windig",hint:"Welches Wort beschreibt das Wetter, nicht eine Person?"},
{type:"drag_fill",s:"Es ist {1} und {2} auf dem Weihnachtsmarkt. Ich trinke einen {3} Glühwein.",blanks:{"1":"kalt","2":"dunkel","3":"warmen"},pool:["kalt","dunkel","warmen","sonnig","dicken"],hint:"Winter, Abend, und ein Getränk gegen die Kälte.",sSrc:"It is cold and dark at the Christmas market. I am drinking a warm mulled wine."},
{type:"mc",q:"'Die fleißigen Verkäufer arbeiten den ganzen Tag.' Was ist die Endung von 'fleißig' hier?",opts:["-en (Nom. Plural)","-e (keine Endung)","-es (Nom. Neutrum)","-er (Nom. Maskulin)"],ans:"-en (Nom. Plural)",hint:"Welcher Kasus und Numerus passt zu 'die Verkäufer'?"},
{type:"fb",s:"Das ist {1} für einen deutschen Weihnachtsmarkt: Glühwein, Bratwurst und Lebkuchen.",a:"typisch",opts:["typisch","einzeln","modern","eng"],hint:"Es ist normal und erwartet, also...",sSrc:"That is typical for a German Christmas market: mulled wine, bratwurst and gingerbread."},
{type:"mc",q:"Verumius will um 9 Uhr auf den Markt. Hildi sagt: 'Das ist zu ___! Der Markt öffnet erst um 11.'",opts:["früh","spät","dunkel","kühl"],ans:"früh",hint:"9 Uhr ist vor der Öffnungszeit um 11 Uhr."},
{type:"drag_fill",s:"Im November ist es oft {1} und {2}. Man sieht die Sonne nicht durch den {3} Nebel.",blanks:{"1":"bewölkt","2":"nebelig","3":"dicken"},pool:["bewölkt","nebelig","dicken","sonnig","dünnen"],hint:"Typisches Novemberwetter: grau, feucht, und dichter Dunst.",sSrc:"In November it is often cloudy and foggy. You cannot see the sun through the thick fog."},
{type:"match",pairs:[{trg:"kalt",src:"cold"},{trg:"heiß",src:"hot"},{trg:"nass",src:"wet"},{trg:"trocken",src:"dry"},{trg:"sonnig",src:"sunny"},{trg:"windig",src:"windy"}]},
{type:"fb",s:"Die Gasse zum Weihnachtsmarkt ist sehr {1}. Wir müssen hintereinander gehen.",a:"eng",opts:["eng","dick","bunt","warm"],hint:"Es ist nicht genug Platz nebeneinander.",sSrc:"The alley to the Christmas market is very narrow. We have to walk in single file."},
{type:"mc",q:"Hildi kauft eine Praline. Sie will keine ganze Schachtel, nur eine ___.",opts:["einzelne","dicke","frühe","dunkle"],ans:"einzelne",hint:"Nur ein Stück, nicht die ganze Packung."},
{type:"drag_fill",s:"Der {1} Markt gefällt mir nicht. Ich mag die {2} Weihnachtsmärkte mit {3} Holzbuden.",blanks:{"1":"moderne","2":"traditionellen","3":"bunten"},pool:["moderne","traditionellen","bunten","einzelnen","dunklen"],hint:"Neu vs. alt, und die Hütten haben viele Farben.",sSrc:"The modern market does not appeal to me. I prefer the traditional Christmas markets with colourful wooden stalls."}
]},

{id:"deu_r11l6",title:"Glühwein",icon:"\ud83c\udf77",xp:20,board:true,steps:[
{type:"intro",title:"Glühwein",desc:"Drei Tassen Glühwein, Dampf steigt auf, Lichterketten spiegeln sich im Wein. Heinrich erzählt Geschichten, Hildi verdreht liebevoll die Augen. Verumius ist warm und angekommen.",goals:["8 neue Adjektive und Nomen lernen","Adjektivdeklination in allen drei Fällen üben","Temporale Präpositionen, Possessive und Konjunktiv II wiederholen"]},
{type:"teach",trg:"das Gewitter",src:"thunderstorm",example:"A: Kommt heute Abend ein Gewitter?\nB: Nein, der Himmel ist klar. Perfekt für den Weihnachtsmarkt!",exampleSrc:"A: Is there a thunderstorm coming tonight?\nB: No, the sky is clear. Perfect for the Christmas market!",note:"das Gewitter (neuter). Despite der in some dialects, standard German uses das.",funFact:"German Christmas markets stay open even in light rain. Only a real Gewitter closes the stalls."},
{type:"teach",trg:"tief",src:"deep",example:"A: Der Glühwein hat einen tiefen Geschmack.\nB: Ja, mit Zimt und Nelken. Sehr lecker!",exampleSrc:"A: The mulled wine has a deep flavor.\nB: Yes, with cinnamon and cloves. Very tasty!",note:"tief: deep, low, profound. Opposite of hoch (high).",funFact:"Germans say 'tief in der Nacht' (deep in the night) for the late hours when Christmas markets finally close."},
{type:"teach",trg:"reich",src:"rich",example:"A: Heinrich kennt so viele reiche Geschichten!\nB: Ja, er hat ein reiches Leben geführt.",exampleSrc:"A: Heinrich knows so many rich stories!\nB: Yes, he has led a rich life.",note:"reich: rich (money or experience). Ein reiches Land, eine reiche Geschichte.",funFact:"The word 'Reich' originally just meant 'realm' or 'kingdom.' Frankreich (France) literally means 'realm of the Franks.'"},
{type:"teach",trg:"arm",src:"poor",example:"A: Als Kind war Heinrich arm.\nB: Aber jetzt ist er reich an Freunden.",exampleSrc:"A: As a child, Heinrich was poor.\nB: But now he is rich in friends.",note:"arm: poor. Opposite of reich. Also: der Arm (noun) = the arm (body part).",funFact:"The phrase 'arm aber glücklich' (poor but happy) is a common German saying, especially around Christmas."},
{type:"teach",trg:"bequem",src:"comfortable",example:"A: Ist dein Platz bequem?\nB: Ja, sehr! Und der Glühwein wärmt meine Hände.",exampleSrc:"A: Is your seat comfortable?\nB: Yes, very! And the mulled wine warms my hands.",note:"bequem: comfortable (seats, shoes, life). For temperature comfort, use gemütlich.",funFact:"Germans distinguish bequem (physically comfortable) from gemütlich (cozy atmosphere). A Weihnachtsmarkt is gemütlich, a chair is bequem."},
{type:"teach",trg:"hässlich",src:"ugly",example:"A: Hildi findet Heinrichs Weihnachtspullover hässlich.\nB: Aber Heinrich trägt ihn trotzdem jeden Winter!",exampleSrc:"A: Hildi finds Heinrich's Christmas sweater ugly.\nB: But Heinrich wears it every winter anyway!",note:"hässlich: ugly. Strong word. For 'not pretty,' Germans often soften with nicht so schön.",funFact:"Ugly Christmas sweaters (hässliche Weihnachtspullover) are a growing trend in Germany, borrowed from American culture."},
{type:"teach",trg:"intelligent",src:"intelligent",example:"A: Verumius ist ein intelligenter Kerl.\nB: Stimmt! Er lernt so schnell Deutsch.",exampleSrc:"A: Verumius is an intelligent guy.\nB: True! He learns German so quickly.",note:"intelligent: same as English. Note the ending changes: ein intelligenter Mann, eine intelligente Frau.",funFact:"German borrows 'intelligent' from Latin via French. The native German equivalent is klug, which feels warmer and less academic."},
{type:"teach",trg:"klug",src:"clever, smart",example:"A: Das war eine kluge Entscheidung, hierher zu kommen.\nB: Ja, der Glühwein allein war es wert!",exampleSrc:"A: That was a clever decision to come here.\nB: Yes, the mulled wine alone was worth it!",note:"klug: clever, smart, wise. More everyday than intelligent. Ein kluger Kopf = a smart cookie.",funFact:"The Brothers Grimm used 'klug' constantly in their fairy tales. Das kluge Gretel, Die kluge Else. Cleverness was the ultimate survival trait."},
{type:"tip",title:"Glühwein und Freundschaft",text:"Heinrich hebt seine Tasse: 'Auf uns drei!' Hildi lächelt. Verumius spürt etwas Warmes, und es ist nicht nur der Glühwein. Er hat eine Familie gefunden, auf seine eigene Art.\n\nTonight we review everything from this unit: adjective endings across all three cases, temporal prepositions, possessives, and Konjunktiv II. The Glühwein scene brings it all together."},
{type:"mc",q:"Heinrich erzählt eine ___ Geschichte. (reich, nominative feminine)",opts:["reiche","reicher","reiches","reichen"],ans:"reiche",hint:"Feminine nominative: eine ___e Geschichte."},
{type:"fb",s:"Der Glühwein hat einen {1} Geschmack.",a:"tiefen",opts:["tiefen","tiefer","tiefes","tiefe"],hint:"Accusative masculine: einen ___en.",sSrc:"The mulled wine has a deep taste."},
{type:"mc",q:"Hildi sitzt auf einem ___ Stuhl. (bequem, dative masculine)",opts:["bequemen","bequemer","bequemes","bequem"],ans:"bequemen",hint:"Dative masculine after auf (location): einem ___en."},
{type:"drag_fill",s:"Heinrich war {1} Kind ein {2} Junge, aber er hatte {3} Freunde.",blanks:{"1":"als","2":"armer","3":"kluge"},pool:["als","armer","kluge","reiches","während","hässlicher"],hint:"Temporal prep + nom masc adj + acc plural adj.",sSrc:"Heinrich was as a child a poor boy, but he had clever friends."},
{type:"fb",s:"Wenn ich reich {1}, würde ich jeden Tag Glühwein trinken.",a:"wäre",opts:["wäre","bin","war","sei"],hint:"Konjunktiv II of sein for unreal wishes.",sSrc:"If I were rich, I would drink mulled wine every day."},
{type:"mc",q:"Das ist ___ Pullover! Niemand will ihn tragen. (nominative masculine, ein-word)",opts:["ein hässlicher","einen hässlichen","einem hässlichem","einer hässlicher"],ans:"ein hässlicher",hint:"Nominative masculine with ein: ein ___er."},
{type:"drag_fill",s:"Verumius trinkt {1} Glühwein mit {2} klugen Freunden {3} dem Weihnachtsmarkt.",blanks:{"1":"seinen","2":"seinen","3":"auf"},pool:["seinen","seinen","auf","sein","seine","in"],hint:"Possessive accusative + possessive dative + location preposition.",sSrc:"Verumius drinks his mulled wine with his clever friends at the Christmas market."},
{type:"fb",s:"Wenn das Wetter {1} wäre, könnten wir nicht draußen sitzen.",a:"hässlich",opts:["hässlich","hässliches","hässlichen","hässlicher"],hint:"Predicate adjective after sein: no ending needed.",sSrc:"If the weather were ugly, we would not be able to sit outside."},
{type:"mc",q:"Heinrich hat eine ___ Stimme. Er erzählt gern Geschichten. (tief, accusative feminine)",opts:["tiefe","tiefer","tiefes","tiefen"],ans:"tiefe",hint:"Accusative feminine: eine ___e Stimme."},
{type:"drag_fill",s:"{1} des Gewitters {2} sie gemütlich {3} dem Markt.",blanks:{"1":"Trotz","2":"saßen","3":"auf"},pool:["Trotz","saßen","auf","Wegen","standen","in"],hint:"'Despite' + genitive, then past tense of sitzen + location.",sSrc:"Despite the thunderstorm they sat cosily at the market."},
{type:"fb",s:"Hätte ich {1} intelligenten Freund wie Verumius!",a:"einen",opts:["einen","einem","einer","ein"],hint:"Accusative masculine: hätte ich ___en ___en Freund.",sSrc:"If only I had an intelligent friend like Verumius!"},
{type:"mc",q:"Die drei Freunde sitzen mit ___ warmen Tassen am Tisch. (possessive, dative plural)",opts:["ihren","ihre","ihrer","ihrem"],ans:"ihren",hint:"Dative plural possessive: mit ___en warmen Tassen."},
{type:"match",pairs:[{trg:"tief",src:"deep"},{trg:"reich",src:"rich"},{trg:"arm",src:"poor"},{trg:"bequem",src:"comfortable"},{trg:"hässlich",src:"ugly"},{trg:"klug",src:"clever"}]}
]},

{id:"deu_r11l7",title:"Weihnachtsprüfung",icon:"✅",xp:25,board:true,steps:[
{type:"intro",title:"Weihnachtsprüfung",desc:"Der Glühwein ist leer, die Lichter blinken, und Opa Heinrich wartet auf Antworten. Zeig, was du auf dem Weihnachtsmarkt gelernt hast. Keine neuen Wörter. Nur du und die Grammatik.",goals:["Adjektivdeklination in Nominativ, Akkusativ und Dativ","Possessivartikel in allen Fällen","Temporale Präpositionen korrekt verwenden","Konjunktiv II für Wünsche und Hypothesen"]},
{type:"mc",q:"'Der warme Glühwein schmeckt gut.' Warum endet das Adjektiv auf -e?",opts:["Nach bestimmtem Artikel im Nominativ: immer -e","Das Adjektiv zeigt das Genus mit -e","Warm ist unregelmäßig","Glühwein ist feminin"],ans:"Nach bestimmtem Artikel im Nominativ: immer -e",hint:"Definite articles in nominative make adjective endings predictable."},
{type:"fb",s:"Ein kalt{1} Wind weht über den Markt.",a:"er",opts:["er","e","es","en"],hint:"After 'ein' in nominative, what ending does the adjective need for a masculine noun?",sSrc:"A cold wind blows over the market."},
{type:"mc",q:"Hildi sagt: 'Ich trage meinen dicken Mantel.' Welcher Fall ist 'meinen dicken Mantel'?",opts:["Nominativ","Akkusativ","Dativ","Genitiv"],ans:"Akkusativ",hint:"Tragen takes a direct object. Think about what case marks that."},
{type:"drag_fill",s:"Heinrich schenkt {1} Enkelin {2} goldenen Ring.",blanks:{"1":"seiner","2":"einen"},pool:["seiner","seine","seinem","einen","ein","einem"],hint:"Schenken: dative (to whom?) + accusative (what?). Enkelin is feminine, Ring is masculine.",sSrc:"Heinrich gives his granddaughter a golden ring."},
{type:"fb",s:"Verumius trinkt {1} heißen Glühwein auf dem Markt.",a:"einen",opts:["einen","ein","einem","einer"],hint:"Glühwein is masculine. Direct object means accusative case.",sSrc:"Verumius drinks a hot mulled wine at the market."},
{type:"mc",q:"Welches Wort zeigt den Dativ in: 'Er sitzt mit ___ warmen Pullover am Feuer'?",opts:["einem","einen","ein","einer"],ans:"einem",hint:"'Mit' always governs one specific case. Look at the article form."},
{type:"drag_fill",s:"{1} dem Essen gehen wir {2} den bunten Weihnachtsmarkt.",blanks:{"1":"Nach","2":"auf"},pool:["Nach","Vor","Seit","auf","in","an"],hint:"First eat, then go. Which temporal preposition means 'after'? And which preposition with accusative for destination?",sSrc:"After the meal we go to the colourful Christmas market."},
{type:"fb",s:"{1} drei Wochen ist der Weihnachtsmarkt geöffnet.",a:"Seit",opts:["Seit","Vor","Nach","Bis"],hint:"The market opened three weeks ago and is still open now.",sSrc:"For three weeks the Christmas market has been open."},
{type:"mc",q:"'Wenn ich reich wäre, würde ich jeden Tag Torte essen.' Was drückt dieser Satz aus?",opts:["Einen hypothetischen Wunsch","Eine echte Absicht","Eine Erinnerung","Einen Befehl"],ans:"Einen hypothetischen Wunsch",hint:"The speaker imagines something that is not real. Which grammatical mood fits?"},
{type:"fb",s:"Ich {1} gern eine Reise nach Wien machen.",a:"würde",opts:["würde","werde","wurde","wollte"],hint:"For polite hypothetical wishes, use Konjunktiv II of werden + infinitive.",sSrc:"I would like to take a trip to Vienna."},
{type:"drag_fill",s:"Hildi gibt {1} alten Mann {2} warme Decke {3} dem Fest.",blanks:{"1":"dem","2":"eine","3":"nach"},pool:["dem","den","der","eine","einen","einem","nach","vor","seit"],hint:"Dative recipient (masc.) + accusative object (fem.) + temporal preposition meaning 'after'.",sSrc:"Hildi gives the old man a warm blanket after the celebration."},
{type:"mc",q:"'In meinem bequemen Bett schlafe ich gut.' Welchen Fall regiert 'in' hier?",opts:["Akkusativ","Dativ","Nominativ","Genitiv"],ans:"Dativ",hint:"'In' with location (where something happens) takes a specific case. No movement involved."},
{type:"fb",s:"Die fleißig{1} Verkäufer arbeiten den ganzen Tag.",a:"en",opts:["en","e","er","es"],hint:"Nominative plural after 'die': weak declension applies.",sSrc:"The hardworking vendors work all day."},
{type:"drag_fill",s:"Heinrich erzählt von {1} Kindheit {2} dem Krieg.",blanks:{"1":"seiner","2":"vor"},pool:["seiner","seinem","seine","vor","nach","seit"],hint:"'Von' takes dative. Kindheit is feminine. And which temporal preposition means 'before'?",sSrc:"Heinrich tells of his childhood before the war."},
{type:"mc",q:"'Verumius hätte gern ein warmes Bett.' Was bedeutet 'hätte'?",opts:["would have","has","had","will have"],ans:"would have",hint:"This is an irregular Konjunktiv II form derived from 'haben.'"},
{type:"fb",s:"Mit {1} neuen Mütze sieht Hildi toll aus.",a:"ihrer",opts:["ihrer","ihrem","ihren","ihre"],hint:"'Mit' takes dative. Mütze is feminine. What is the dative feminine possessive for 'her'?",sSrc:"With her new hat Hildi looks great."},
{type:"drag_fill",s:"Verumius {1} gern {2} roten Schal kaufen, aber er {3} nicht genug Geld.",blanks:{"1":"würde","2":"den","3":"hätte"},pool:["würde","wäre","den","dem","einen","hätte","könnte"],hint:"Konjunktiv II wish + accusative masculine definite + irregular Konjunktiv II of haben.",sSrc:"Verumius would like to buy the red scarf, but he did not have enough money."},
{type:"mc",q:"'Während des Gewitters bleiben alle in der warmen Hütte.' Was regiert 'während'?",opts:["Akkusativ","Dativ","Genitiv","Nominativ"],ans:"Genitiv",hint:"This temporal preposition is one of the few that governs a case you rarely see elsewhere."},
{type:"fb",s:"Das ist ein typisch{1} deutsches Weihnachtslied.",a:"es",opts:["es","er","e","en"],hint:"Lied is neuter. After 'ein' in nominative neuter, the adjective shows the gender.",sSrc:"That is a typical German Christmas carol."},
{type:"drag_fill",s:"{1} der Ferien {2} ich gern auf {3} schönen Markt gehen.",blanks:{"1":"Während","2":"würde","3":"den"},pool:["Während","Seit","Vor","würde","werde","wurde","den","dem","der"],hint:"Temporal prep + genitive, Konjunktiv II, accusative masculine (direction).",sSrc:"During the holidays I would like to go to the beautiful market."},
{type:"match",pairs:[{trg:"vor dem Essen",src:"before the meal"},{trg:"nach Weihnachten",src:"after Christmas"},{trg:"seit einer Woche",src:"for a week"},{trg:"während des Fests",src:"during the festival"},{trg:"bis Freitag",src:"until Friday"},{trg:"ab morgen",src:"starting tomorrow"}]},
{type:"mc",q:"'Wenn es nicht so kalt wäre, könnten wir draußen sitzen.' Was drückt 'könnten' aus?",opts:["Eine tatsächliche Fähigkeit","Eine hypothetische Möglichkeit","Eine vergangene Fähigkeit","Einen Zukunftsplan"],ans:"Eine hypothetische Möglichkeit",hint:"The whole sentence describes an unreal condition. The verb form matches."},
{type:"drag_fill",s:"Heinrich schenkt {1} Enkelin {2} bequemen Schal und erzählt von {3} Kindheit.",blanks:{"1":"seiner","2":"einen","3":"seiner"},pool:["seiner","seiner","einen","eine","seinem","ihren"],hint:"Dative fem. possessive (to whom?) + accusative masc. (what?) + dative fem. possessive after 'von.'",sSrc:"Heinrich gives his granddaughter a comfortable scarf and tells of his childhood."},
{type:"fb",s:"Wenn ich Deutsch perfekt sprechen {1}, wäre das wunderbar.",a:"könnte",opts:["könnte","kann","konnte","können"],hint:"Irregular Konjunktiv II of 'können' for a hypothetical ability.",sSrc:"If I could speak German perfectly, that would be wonderful."},
{type:"match",pairs:[{trg:"der rote Schal",src:"the red scarf (nom.)"},{trg:"den roten Schal",src:"the red scarf (acc.)"},{trg:"dem roten Schal",src:"the red scarf (dat.)"},{trg:"ein roter Schal",src:"a red scarf (nom.)"},{trg:"einen roten Schal",src:"a red scarf (acc.)"},{trg:"einem roten Schal",src:"a red scarf (dat.)"}]}
]}
,

{id:"deu_r11l8",title:"Durch den Schnee",icon:"❄️",xp:15,board:true,steps:[
{type:"intro",title:"Durch den Schnee",desc:"Walking home through snowy Berlin after the Weihnachtsmarkt. Heinrich's bread in the bag, warmth in the heart.",goals:["Personality and character adjectives","Time expressions beyond today","Everyday verbs for learning"]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-snowy-street",trg:"Schnee auf den Straßenlaternen. Schnee auf den parkenden Autos. Schnee auf Verumius' Schultern. In der Tasche: Heinrichs Brötchen. Im Herzen: Wärme. Er geht langsam nach Hause.",src:"Snow on the streetlamps. Snow on the parked cars. Snow on Verumius's shoulders. In the bag: Heinrich's bread rolls. In the heart: warmth. He walks slowly home."},
{type:"teach",trg:"egal",src:"doesn't matter / irrelevant",note:"Das ist mir egal = I don't care. Very common.",example:"A: Willst du Tee oder Kaffee?\nB: Das ist mir egal. Beides ist gut.\nA: Dann mache ich Tee.",exampleSrc:"A: Do you want tea or coffee?\nB: I don't care. Both are fine.\nA: Then I'll make tea.",funFact:"From Latin 'aequalis' (equal). If two things are equal, neither matters more."},
{type:"teach",trg:"freiwillig",src:"voluntary",note:"Frei (free) + willig (willing). Freiwillige Feuerwehr = volunteer fire dept.",example:"A: Ist die Teilnahme freiwillig?\nB: Ja, niemand muss kommen.\nA: Gut, dann komme ich gern!",exampleSrc:"A: Is participation voluntary?\nB: Yes, nobody has to come.\nA: Good, then I'll gladly come!",funFact:"Germany has 22,000 volunteer fire departments vs only 100 professional ones."},
{type:"teach",trg:"verschieden",src:"different / various",note:"Verschiedene Leute = various people.",example:"A: Die Glühweinsorten sind ganz verschieden.\nB: Ja, mit Orange, mit Kirsche, klassisch...",exampleSrc:"A: The varieties are quite different.\nB: Yes, with orange, cherry, classic...",funFact:"Literally means 'shifted apart.' Things shifted away from each other are different."},
{type:"mc",q:"'Das ist mir egal' means:",opts:["I don't care","I am sad","I disagree","I am hungry"],ans:"I don't care",hint:"Both options are equal to you. Neither matters more."},
{type:"teach",trg:"blöd",src:"stupid / annoying",note:"Colloquial. 'Das ist blöd' = That's annoying. Milder than dumm.",example:"A: Ich habe meinen Schlüssel vergessen.\nB: Das ist blöd! Hast du einen Ersatzschlüssel?",exampleSrc:"A: I forgot my key.\nB: That's annoying! Do you have a spare?",funFact:"Originally meant 'weak-sighted' in Old German. Now mostly means 'annoying.'"},
{type:"teach",trg:"dumm",src:"dumb / stupid",note:"Stronger than blöd. Dumm wie Brot = dumb as bread.",example:"A: War das eine dumme Idee?\nB: Nein! Manchmal muss man Risiken eingehen.",exampleSrc:"A: Was that a stupid idea?\nB: No! Sometimes you have to take risks.",funFact:"'Dumm wie Brot' exists because bread just sits there doing nothing."},
{type:"teach",trg:"faul",src:"lazy",note:"Also means 'rotten' (fauler Apfel). Context decides.",example:"A: Bist du heute faul?\nB: Ja! Ich bleibe auf dem Sofa.",exampleSrc:"A: Are you lazy today?\nB: Yes! I'm staying on the sofa.",funFact:"Faulenzen on Sundays is protected by Sonntagsruhe law in Germany."},
{type:"teach",trg:"streng",src:"strict",note:"Strenge Regeln = strict rules. Hildi ist streng aber fair.",example:"A: Ist dein Chef streng?\nB: Ja, aber er ist auch fair.",exampleSrc:"A: Is your boss strict?\nB: Yes, but he is also fair.",funFact:"Being streng in Germany is often positive: it means you have standards."},
{type:"fb",s:"Hildi ist {1}, aber sie hat ein großes Herz.",a:["streng"],opts:["streng","faul","dumm","egal"],hint:"She has strict rules, but she cares deeply underneath.",sSrc:"Hildi is strict, but she has a big heart."},
{type:"teach",trg:"deutlich",src:"clear / distinct",note:"Bitte sprechen Sie deutlich = Please speak clearly.",example:"A: Können Sie das deutlicher sagen?\nB: Natürlich. Ich wiederhole langsam.",exampleSrc:"A: Can you say that more clearly?\nB: Of course. I'll repeat slowly.",funFact:"Comes from 'deutsch' via 'diutisc' (of the people). Speaking clearly = speaking for the people."},
{type:"teach",trg:"eigen",src:"own",note:"Mein eigenes Zimmer = my own room.",example:"A: Hast du eine eigene Wohnung?\nB: Nein, nur ein eigenes Zimmer.",exampleSrc:"A: Do you have your own apartment?\nB: No, just my own room.",funFact:"Eigentum, Eigenschaft, eigenartig. 'Eigen' spawns dozens of compound words."},
{type:"mc",q:"'Sprechen Sie deutlich' asks someone to:",opts:["speak clearly","speak quietly","speak German","speak faster"],ans:"speak clearly",hint:"You want to understand every word. Clear and distinct."},
{type:"teach",trg:"damals",src:"back then / at that time",note:"Temporal adverb for the past. Damals war alles anders.",example:"A: Damals gab es kein Internet.\nB: Wirklich? Wie habt ihr kommuniziert?\nA: Mit Briefen!",exampleSrc:"A: Back then there was no internet.\nB: Really? How did you communicate?\nA: With letters!",funFact:"Heinrich says 'damals' constantly. For someone born in the 1930s, it covers a LOT of history."},
{type:"teach",trg:"übermorgen",src:"the day after tomorrow",note:"Über (beyond) + morgen (tomorrow). One word in German!",example:"A: Wann kommt das Paket?\nB: Übermorgen. Am Donnerstag.",exampleSrc:"A: When does the package arrive?\nB: Day after tomorrow. Thursday.",funFact:"German has übermorgen and vorgestern. English needs 3+ words for each."},
{type:"teach",trg:"vorgestern",src:"the day before yesterday",note:"Vor (before) + gestern (yesterday).",example:"A: Wann war das Konzert?\nB: Vorgestern. Am Dienstag.",exampleSrc:"A: When was the concert?\nB: Day before yesterday. Tuesday.",funFact:"Some dialects even have 'vorvorgestern' (3 days ago). Efficient!"},
{type:"teach",trg:"zeigen",src:"to show",note:"Regular: ich zeige, du zeigst. Zeig mal! = Show me!",example:"A: Kann ich dir etwas zeigen?\nB: Ja! Was ist es?\nA: Mein neues Bild!",exampleSrc:"A: Can I show you something?\nB: Yes! What is it?\nA: My new painting!",funFact:"Zeigefinger = index finger (literally: showing finger)."},
{type:"teach",trg:"üben",src:"to practice",note:"Regular: ich übe, du übst. Übung macht den Meister!",example:"A: Übst du jeden Tag Deutsch?\nB: Ja, mindestens eine Stunde.\nA: Übung macht den Meister!",exampleSrc:"A: Do you practice German every day?\nB: Yes, at least one hour.\nA: Practice makes perfect!",funFact:"Every German teacher says 'Übung macht den Meister.' The most-used learning proverb."},
{type:"teach",trg:"die Übung",src:"the exercise / the practice",gender:"f",example:"A: Wie wird man besser?\nB: Nur durch Übung! Übung macht den Meister.\nA: Dann übe ich jeden Tag.",exampleSrc:"A: How do you get better?\nB: Only through practice! Practice makes perfect.\nA: Then I will practice every day.",note:"die Übung, feminine. Plural: die Übungen. From the verb üben (to practice).",funFact:"The proverb 'Übung macht den Meister' (practice makes the master) is used in every German classroom, sports club, and music lesson."},
{type:"fb",s:"{1} macht den Meister!",a:["Übung"],opts:["Übung","Ordnung","Bildung","Erfahrung"],hint:"Practice makes perfect. Which word means 'practice'?",sSrc:"Practice makes perfect!"},
{type:"teach",trg:"aussprechen",src:"to pronounce",note:"Separable: ich spreche aus. Wie spricht man das aus?",example:"A: Wie spricht man 'Eichhörnchen' aus?\nB: Das ist schwer! Aich-hörn-chen.",exampleSrc:"A: How do you pronounce 'Eichhörnchen'?\nB: That's hard! Aich-hörn-chen.",funFact:"'Eichhörnchen' (squirrel) is the word Germans use to test foreigners. Nobody gets it right first time."},
{type:"drag_fill",s:"{1} war alles anders. Aber {2} haben wir Internet und Handys.",blanks:{"1":"Damals","2":"heute"},pool:["Damals","heute","Morgen","Gestern","übermorgen","vorgestern"],hint:"Back then vs now. Past contrasted with present.",sSrc:"Back then everything was different. But today we have the internet and mobile phones."},
{type:"teach",trg:"blond",src:"blond / fair-haired",example:"A: Hildi ist blond, oder?\nB: Ja, sie hat blonde Haare.\nA: Und Verumius?",exampleSrc:"A: Hildi is blond, right?\nB: Yes, she has blond hair.\nA: And Verumius?",note:"blond: same word as English. Endings change: blonder Mann, blonde Frau, blondes Kind.",funFact:"Germany has one of the highest percentages of natural blonds in the world, especially in the north."},
{type:"teach",trg:"einmal",src:"once / one time",example:"A: Warst du schon einmal in Wien?\nB: Ja, einmal. Es war wunderschön.\nA: Ich möchte auch einmal dorthin.",exampleSrc:"A: Have you ever been to Vienna?\nB: Yes, once. It was wonderful.\nA: I would like to go there too.",note:"einmal = once. Zweimal = twice. Dreimal = three times. Also used in 'Es war einmal...' (Once upon a time).",funFact:"Every German fairy tale starts with 'Es war einmal...' (Once upon a time). The Brothers Grimm made this opening famous worldwide."},
{type:"teach",trg:"wurscht",src:"doesn't matter (colloquial)",example:"A: Willst du Pizza oder Pasta?\nB: Das ist mir wurscht!\nA: Na gut, dann Pizza.",exampleSrc:"A: Do you want pizza or pasta?\nB: I don't care!\nA: Alright, pizza then.",note:"Colloquial southern German variant of 'egal.' Very common in Bavaria and Austria. From Wurst (sausage).",funFact:"'Das ist mir Wurst' or 'wurscht' literally means 'that is sausage to me.' Nobody knows exactly why sausage means indifference, but it has been used since the 1800s."},
{type:"match",pairs:[{trg:"egal",src:"doesn't matter"},{trg:"streng",src:"strict"},{trg:"faul",src:"lazy"},{trg:"deutlich",src:"clear"},{trg:"damals",src:"back then"},{trg:"übermorgen",src:"day after tomorrow"},{trg:"üben",src:"to practice"},{trg:"zeigen",src:"to show"}]},
{type:"tip",title:"German Christmas Traditions",text:"Weihnachten starts December 24 (Heiligabend), not December 25.\n\n- Adventskranz: 4 candles, one lit each Sunday before Christmas\n- Adventskalender: 24 doors, one per day in December\n- Nikolaus (Dec 6): shoes by the door, filled with sweets\n- Heiligabend: family dinner, gifts, church\n- Weihnachtsgans: roast goose, the traditional Christmas meal\n- Stille Nacht: world's most famous carol, written in Austria 1818",deepDive:"The Weihnachtsmarkt tradition dates to the 14th century. Dresden's Striezelmarkt (1434) is the oldest. Every city has one. Many Germans visit 5-10 different markets each season."},
{type:"mc",q:"Walking through snow, Verumius feels:",opts:["warm and content, like he belongs","cold and lonely","angry about the weather","worried about tomorrow"],ans:"warm and content, like he belongs",hint:"Heinrich's bread in his bag. Glühwein warmth in his heart."}
]}

]}

,

// ═══════════════════════════════════════════════════════════════
// UNIT 12: Halbjahresbilanz
// Story: Cafe with Yilmaz, document montage, KD's first joke, group chat
// CEFR: A2.3 - Imperative expanded, Konjunktiv II, coord conj, adverbs, A2 capstone
// ═══════════════════════════════════════════════════════════════
{n:12,lang:"de",srcLang:"en",track:"v2",title:"Halbjahresbilanz",sub:"Six months in Germany: reflection, KD's first joke, the decision to stay",icon:"🎉",level:"A2.3",color:"#7B5EE8",lessons:[
// ─── U12 L1: Im Literaturcafé ───
{id:"deu_r12l1",title:"Im Literaturcafé",icon:"☕",xp:15,board:true,steps:[
{type:"intro",title:"Im Literaturcafé",desc:"Six months in Germany. Verumius meets Yilmaz at a Berlin Literaturcafé for coffee and Kuchen. For the first time, they talk not as teacher and student, but as friends.",goals:["Express opinions and thoughts","Talk about experiences and ideas","Use abstract nouns in conversation"]},
{type:"story",speaker:"narrator",mood:"warm",art:"de-literaturcafe",trg:"Ein Literaturcafé in Prenzlauer Berg. Bücherregale an den Wänden, freiliegende Backsteine, warmes Nachmittagslicht. Yilmaz sitzt am Fenster mit einem Milchkaffee. Sie trägt keine Brille heute. Verumius kommt herein und lächelt.",src:"A literary café in Prenzlauer Berg. Bookshelves on the walls, exposed brick, warm afternoon light. Yilmaz sits at the window with a milky coffee. She is not wearing glasses today. Verumius walks in and smiles."},
{type:"story",speaker:"Verumius",trg:"Yilmaz! Schön, dich hier zu sehen. Sechs Monate in Deutschland. Ich kann es kaum glauben.",src:"Yilmaz! Nice to see you here. Six months in Germany. I can barely believe it."},
{type:"story",speaker:"Yilmaz",trg:"Sechs Monate! Und du sprichst schon so gut. Ich habe eine Frage: Was denkst du über deine Zeit hier? Ehrlich.",src:"Six months! And you already speak so well. I have a question: What do you think about your time here? Honestly."},
{type:"teach",trg:"die Meinung",src:"the opinion",note:"Feminine noun. Plural: die Meinungen.",example:"A: Was ist deine Meinung?\nB: Meiner Meinung nach ist Berlin toll.",exampleSrc:"A: What is your opinion?\nB: In my opinion, Berlin is great.",funFact:"'Meiner Meinung nach' (in my opinion) is one of the most used phrases in German debates. Germans love a well-structured opinion. The noun comes from 'meinen' (to think/mean)."},
{type:"teach",trg:"die Idee",src:"the idea",note:"Feminine noun. Plural: die Ideen. From French/Latin.",example:"A: Ich habe eine Idee!\nB: Wirklich? Erzähl mal!",exampleSrc:"A: I have an idea!\nB: Really? Tell me!",funFact:"German borrowed 'Idee' from French, which got it from Latin, which got it from Greek 'idea' (form, pattern). The word traveled 2,500 years through four languages to reach your vocabulary list."},
{type:"teach",trg:"die Geschichte",src:"the story / history",note:"Feminine noun. Plural: die Geschichten. Both meanings common.",example:"A: Kennst du die Geschichte von Berlin?\nB: Ja, es ist eine lange Geschichte!",exampleSrc:"A: Do you know the history of Berlin?\nB: Yes, it's a long story!",funFact:"In German, 'story' and 'history' are the same word. Context decides. 'Eine lustige Geschichte' = a funny story. 'Die deutsche Geschichte' = German history. Every story IS history, in a way."},
{type:"teach",trg:"die Erfahrung",src:"the experience",note:"Feminine noun. Plural: die Erfahrungen. From 'erfahren' (to experience).",example:"A: Hast du Erfahrung mit Kochen?\nB: Ja, ich habe viel Erfahrung.",exampleSrc:"A: Do you have experience with cooking?\nB: Yes, I have a lot of experience.",funFact:"'Erfahrung' comes from 'fahren' (to travel). Originally, experience was what you gained by TRAVELING. You had to leave home to learn something new. The word still carries that spirit."},
{type:"mc",q:"Yilmaz asks 'Was ist deine Meinung?' What does she want to know?",opts:["Your name","Your opinion","Your address","Your age"],ans:"Your opinion",hint:"She is asking what you think about something."},
{type:"fb",s:"Das war eine tolle {1}!",a:["Erfahrung"],opts:["Erfahrung","Meinung","Qualität","Nachricht"],hint:"Which feminine noun means an experience you lived through?",sSrc:"That was a great experience!"},
{type:"teach",trg:"die Situation",src:"the situation",note:"Feminine noun. Plural: die Situationen. Same as English.",example:"A: Wie ist die Situation?\nB: Die Situation ist kompliziert.",exampleSrc:"A: How is the situation?\nB: The situation is complicated.",funFact:"A perfect cognate. Same spelling, same meaning, just different pronunciation. German stresses the last syllable: Si-tu-a-TION. Most Latin-origin words ending in '-tion' work the same in German."},
{type:"teach",trg:"die Qualität",src:"the quality",note:"Feminine noun. Plural: die Qualitäten.",example:"A: Wie ist die Qualität?\nB: Die Qualität ist sehr gut.",exampleSrc:"A: How is the quality?\nB: The quality is very good.",funFact:"Another Latin import. Notice the umlaut: Qualität, not Qualitat. German adds umlauts to borrowed words like a passport stamp. Universität, Nationalität, Realität. The '-tät' ending always means feminine."},
{type:"teach",trg:"die Person",src:"the person",note:"Feminine noun. Plural: die Personen. Always feminine, even for men.",example:"A: Wer ist diese Person?\nB: Das ist eine wichtige Person.",exampleSrc:"A: Who is this person?\nB: That is an important person.",funFact:"Grammatical gender and real gender are different things. 'Die Person' is feminine even when talking about a man. 'Das Mädchen' (the girl) is NEUTER. German grammar follows word endings, not biology."},
{type:"mc",q:"All these nouns share something. Which article do they use: die Meinung, die Idee, die Geschichte, die Erfahrung?",opts:["der (masculine)","die (feminine)","das (neuter)","ein (indefinite)"],ans:"die (feminine)",hint:"Look at the article that appears before each noun."},
{type:"story",speaker:"Verumius",trg:"Ich denke, diese sechs Monate waren die beste Erfahrung meines Lebens. Ich hoffe, dass es so weitergeht.",src:"I think these six months were the best experience of my life. I hope it continues like this."},
{type:"teach",trg:"die Nachricht",src:"the news / message",note:"Feminine noun. Plural: die Nachrichten. TV news: die Nachrichten.",example:"A: Hast du die Nachricht gelesen?\nB: Ja, das sind gute Nachrichten!",exampleSrc:"A: Did you read the message?\nB: Yes, that is good news!",funFact:"'Nachricht' literally means 'something to direct yourself after' (nach + richten). The plural 'Nachrichten' is used for TV news. 'Die Tagesschau' is Germany's most watched Nachrichtensendung (news program)."},
{type:"teach",trg:"das Interview",src:"the interview",note:"Neuter noun. Plural: die Interviews. Borrowed from English.",example:"A: Ich habe morgen ein Interview.\nB: Viel Glück! Du schaffst das.",exampleSrc:"A: I have an interview tomorrow.\nB: Good luck! You can do it.",funFact:"One of many English words in modern German. Germans also use 'der Job,' 'das Meeting,' 'der Computer.' But watch out: 'das Handy' means mobile phone, NOT handy. That is a false friend!"},
{type:"teach",trg:"schön",src:"beautiful / nice",example:"A: Die Stadt ist wirklich schön!\nB: Ja, besonders im Winter.\nA: Schön, dass wir hier sind.",exampleSrc:"A: The city is really beautiful!\nB: Yes, especially in winter.\nA: Nice that we are here.",note:"schön: beautiful, nice, lovely. Also used as a filler: 'Schön!' (Great!). Comparative: schöner, superlative: am schönsten.",funFact:"Germans use 'schön' constantly: schönes Wetter, schöne Grüße, schön gemacht, na schön. It is one of the most versatile adjectives in German."},
{type:"teach",trg:"hoffen",src:"to hope",note:"Regular verb: ich hoffe, du hoffst, er hofft.",example:"A: Ich hoffe, dass alles gut wird.\nB: Ich hoffe es auch!",exampleSrc:"A: I hope everything will be fine.\nB: I hope so too!",funFact:"'Hoffen' and English 'hope' are related through Germanic roots. 'Ich hoffe auf besseres Wetter' (I hope for better weather). Germans hope 'auf' (on/for) things, not just hope them."},
{type:"teach",trg:"denken",src:"to think",note:"Irregular past, but regular present: ich denke, du denkst.",example:"A: Was denkst du?\nB: Ich denke, das ist eine gute Idee.",exampleSrc:"A: What do you think?\nB: I think that is a good idea.",funFact:"'Denken' and English 'think' come from the same root. And remember 'Danke' (thank you)? Same family! Thinking and thanking were once the same concept: keeping something in mind."},
{type:"teach",trg:"meinen",src:"to mean / to think (opinion)",note:"Used for personal opinions: 'Ich meine, dass...'",example:"A: Was meinst du damit?\nB: Ich meine, wir sollten gehen.",exampleSrc:"A: What do you mean by that?\nB: I mean, we should go.",funFact:"'Meinen' and 'die Meinung' are a family. But careful: 'meinen' is softer than 'denken.' 'Ich denke' = I think (after reflection). 'Ich meine' = I reckon/believe (more casual opinion)."},
{type:"mc",q:"Verumius sagt: 'Ich hoffe, dass es so weitergeht.' What does he express?",opts:["A complaint about Germany","A wish that things continue well","A question about the future","A fear of going home"],ans:"A wish that things continue well",hint:"The verb 'hoffen' expresses positive expectation about what comes next."},
{type:"fb",s:"Was {1} du über Berlin?",a:["denkst"],opts:["denkst","hoffst","meinst","sagst"],hint:"Which verb asks what someone thinks after reflection?",sSrc:"What do you think about Berlin?"},
{type:"tip",title:"Literaturcafés: Germany's Living Rooms",text:"Germany has a deep café culture. A Literaturcafé combines coffee with books and often hosts readings.\n\nKey vocabulary:\nder Milchkaffee: milky coffee\nder Kuchen: cake\ndie Lesung: a reading event\ndie Buchhandlung: bookshop\n\nIn German cafés, you can sit for hours with one coffee. Nobody will rush you. It is your living room away from home.",deepDive:{title:"Choosing the right reporting verb",text:"German has a scale of reporting verbs, each with a different level of credibility:\n\nHigh credibility: erklären (declare), berichten (report), betonen (emphasize)\nNeutral: sagen (say)\nPersonal opinion: meinen (think/mean)\nLow credibility: behaupten (claim)\n\nCompare:\nDie Ministerin erklärte, die Reform sei nötig. (sounds official, credible)\nDie Ministerin behauptete, die Reform sei nötig. (sounds like the reporter doubts it)\n\nThis is a powerful tool in German journalism and academic writing."}},
{type:"mc",q:"'Die Qualität ist sehr gut.' What is being described?",opts:["The price","The quality","The quantity","The person"],ans:"The quality",hint:"This feminine cognate looks almost the same in English."},
{type:"fb",s:"Hast du die {1} im Radio gehört?",a:["Nachricht"],opts:["Nachricht","Geschichte","Meinung","Idee"],hint:"Which word means a news item or message you receive?",sSrc:"Did you hear the news item on the radio?"},
{type:"mc",q:"Which sentence correctly uses 'meinen' to express an opinion?",opts:["Ich meine, das Café ist schön.","Ich meine nach Berlin.","Ich meine einen Kaffee.","Ich meine um drei Uhr."],ans:"Ich meine, das Café ist schön.",hint:"This verb introduces a personal opinion or belief."},
{type:"match",pairs:[{trg:"die Meinung",src:"the opinion"},{trg:"die Erfahrung",src:"the experience"},{trg:"die Nachricht",src:"the news/message"},{trg:"hoffen",src:"to hope"},{trg:"denken",src:"to think"},{trg:"meinen",src:"to mean/think (opinion)"}]},
{type:"drag_fill",s:"Ich {1}, dass du eine gute {2} hast. {3} Meinung nach ist das eine tolle {4}.",blanks:{"1":"denke","2":"Idee","3":"Meiner","4":"Erfahrung"},pool:["denke","Idee","Meiner","Erfahrung","hoffe","Geschichte","Seiner","Qualität"],hint:"Build a sentence combining thinking, ideas, opinions, and experiences.",sSrc:"I think that you have a good idea. In my opinion that is a great experience."}
]}
,

{id:"deu_r12l2",title:"Papierkram",icon:"📄",xp:15,board:true,steps:[
{type:"intro",title:"Papierkram",desc:"Work, admin, and tech vocabulary for everyday German life. From job applications to passwords, this is the language of getting things done.",goals:["Learn 16 work/admin/tech nouns","Use time adverbs: schon, noch, erst, gerade","Talk about office life and digital tools"]},
{type:"teach",trg:"die Bewerbung",src:"application (job)",phonetic:"beh-VEHR-boong",example:"A: Hast du die Bewerbung schon geschickt?\nB: Nein, ich schreibe sie heute Abend.",exampleSrc:"A: Have you already sent the application?\nB: No, I'm writing it tonight.",note:"From 'bewerben' (to apply). Always die.",funFact:"Germans often include a professional photo with job applications. It is still common practice."},
{type:"teach",trg:"die Ausbildung",src:"training, apprenticeship",phonetic:"OWS-bil-doong",example:"A: Was macht dein Bruder?\nB: Er macht eine Ausbildung als Koch.",exampleSrc:"A: What does your brother do?\nB: He is doing an apprenticeship as a cook.",note:"Aus (out) + Bildung (education). Always die.",funFact:"Germany's dual Ausbildung system combines school and on-the-job training. Over 300 recognized trades use it."},
{type:"teach",trg:"das Büro",src:"office",phonetic:"bue-ROH",example:"A: Wo arbeitest du?\nB: Ich arbeite in einem Büro in der Stadt.",exampleSrc:"A: Where do you work?\nB: I work in an office in the city.",note:"From French 'bureau'. Always das.",funFact:"Many German offices still close doors between rooms. An open door signals you are available for a chat."},
{type:"teach",trg:"das Gehalt",src:"salary",phonetic:"geh-HALT",example:"A: Bist du zufrieden mit dem Gehalt?\nB: Ja, es ist ganz okay.",exampleSrc:"A: Are you happy with the salary?\nB: Yes, it's quite okay.",note:"Always das. Plural: die Gehälter.",funFact:"In Germany, talking about your salary with colleagues is considered very impolite. Many people never share the number."},
{type:"teach",trg:"der Vertrag",src:"contract",phonetic:"fehr-TRAHK",example:"A: Hast du den Vertrag schon unterschrieben?\nB: Noch nicht, ich lese ihn erst morgen.",exampleSrc:"A: Have you already signed the contract?\nB: Not yet, I'll read it tomorrow first.",note:"Always der. Plural: die Verträge.",funFact:"Germans love contracts. Even a gym membership comes with a detailed Vertrag, often with a long cancellation period."},
{type:"teach",trg:"die Übersetzung",src:"translation",phonetic:"ue-ber-ZET-soong",example:"A: Kannst du die Übersetzung prüfen?\nB: Klar, schick mir die Datei.",exampleSrc:"A: Can you check the translation?\nB: Sure, send me the file.",note:"From 'übersetzen' (to translate). Always die.",funFact:"German compound words are famously hard to translate. Schadenfreude and Wanderlust have been borrowed into English directly."},
{type:"teach",trg:"das Zeugnis",src:"certificate, report card",phonetic:"TSOYG-nis",example:"A: Brauchst du das Zeugnis für die Bewerbung?\nB: Ja, ich muss es kopieren.",exampleSrc:"A: Do you need the certificate for the application?\nB: Yes, I have to copy it.",note:"Always das. Plural: die Zeugnisse.",funFact:"When you leave a German job, you receive a coded Arbeitszeugnis. Phrases like 'stets bemüht' (always tried hard) actually mean poor performance."},
{type:"teach",trg:"der Artikel",src:"article",phonetic:"ar-TEE-kel",example:"A: Hast du den Artikel gelesen?\nB: Welchen Artikel meinst du?",exampleSrc:"A: Have you read the article?\nB: Which article do you mean?",note:"Always der. Also means grammatical article (der/die/das).",funFact:"The word Artikel is used both for newspaper articles and grammar articles. Context always makes the meaning clear."},
{type:"teach",trg:"das Blatt",src:"sheet (of paper), leaf",phonetic:"BLAHT",example:"A: Ich brauche ein Blatt Papier.\nB: Hier, nimm eins von meinem Block.",exampleSrc:"A: I need a sheet of paper.\nB: Here, take one from my notepad.",note:"Always das. Plural: die Blätter. Two meanings: paper and leaf.",funFact:"The expression 'kein Blatt vor den Mund nehmen' means to speak bluntly, literally 'to put no leaf in front of your mouth'."},
{type:"teach",trg:"die Datei",src:"file (digital)",phonetic:"dah-TY",example:"A: Wo ist die Datei?\nB: Ich habe sie dir per Mail geschickt.",exampleSrc:"A: Where is the file?\nB: I sent it to you by email.",note:"Always die. Only for digital files, not paper folders.",funFact:"German IT vocabulary mixes English loans (der Link, das Update) with German creations (die Datei from 'Daten' meaning data)."},
{type:"teach",trg:"die Homepage",src:"homepage",phonetic:"HOHM-paydsh",example:"A: Hast du unsere neue Homepage gesehen?\nB: Ja, sie sieht sehr gut aus!",exampleSrc:"A: Have you seen our new homepage?\nB: Yes, it looks very good!",note:"English loanword. Always die.",funFact:"Germans often say Homepage when they mean the entire website, not just the landing page. Die Webseite is the more precise term."},
{type:"teach",trg:"der Link",src:"link",phonetic:"LINK",example:"A: Kannst du mir den Link schicken?\nB: Klar, ich schicke ihn dir gerade.",exampleSrc:"A: Can you send me the link?\nB: Sure, I'm sending it to you right now.",note:"English loanword. Always der.",funFact:"Despite many English tech loanwords, official German tries to use native terms. Der Verweis exists but der Link won the everyday battle."},
{type:"teach",trg:"die Mail",src:"email",phonetic:"MAYL",example:"A: Hast du meine Mail bekommen?\nB: Ja, ich antworte gleich.",exampleSrc:"A: Did you get my email?\nB: Yes, I'll reply shortly.",note:"Short for die E-Mail. Always die.",funFact:"Germans often write very formal emails, even internally. Starting with 'Sehr geehrte Damen und Herren' (Dear ladies and gentlemen) is standard for unknown recipients."},
{type:"teach",trg:"die Mailbox",src:"mailbox (voicemail)",phonetic:"MAYL-boks",example:"A: Ich habe angerufen, aber nur die Mailbox gehört.\nB: Tut mir leid, mein Mobiltelefon war aus.",exampleSrc:"A: I called but only got the voicemail.\nB: Sorry, my mobile phone was off.",note:"In German, Mailbox usually means voicemail, not a physical letterbox.",funFact:"The physical letterbox is der Briefkasten in German. Die Mailbox almost always means voicemail on the phone."},
{type:"teach",trg:"das Mobiltelefon",src:"mobile phone",phonetic:"mo-BEEL-teh-leh-fohn",example:"A: Wo ist dein Mobiltelefon?\nB: Es liegt noch im Büro.",exampleSrc:"A: Where is your mobile phone?\nB: It's still in the office.",note:"Always das. Everyday speech: das Handy.",funFact:"Germans say 'Handy' for mobile phone, an English-sounding word that English speakers never use. It confuses many visitors."},
{type:"teach",trg:"das Passwort",src:"password",phonetic:"PAHS-vort",example:"A: Ich habe mein Passwort vergessen.\nB: Du kannst es auf der Homepage zurücksetzen.",exampleSrc:"A: I forgot my password.\nB: You can reset it on the homepage.",note:"Always das. Plural: die Passwörter.",funFact:"The German Federal Office for IT Security recommends passwords of at least 8 characters. They publish guidelines every year."},
{type:"tip",title:"Zeitadverbien: schon, noch, erst, gerade",text:"German has four key time adverbs that add precision:\n\n• schon (already): Ich habe schon gegessen.\n• noch (still/yet): Er arbeitet noch.\n• erst (only just/not until): Sie kommt erst um neun.\n• gerade (right now/just): Ich lese gerade die Mail.\n\nThese go after the conjugated verb in main clauses. They change the feel of a sentence completely.",deepDive:"schon vs. erst are a natural pair.\nschon = earlier than expected: 'Du bist schon da!' (You're here already!)\nerst = later than expected: 'Du bist erst da?' (You're only here now?)\n\nnoch vs. schon are another pair.\nnoch nicht = not yet: 'Ich habe noch nicht gegessen.' (I haven't eaten yet.)\nschon = already done: 'Ich habe schon gegessen.' (I've already eaten.)\n\ngerade = happening at this exact moment: 'Was machst du gerade?' (What are you doing right now?)"},
{type:"mc",q:"'Ich habe mein ___ vergessen.' Was fehlt?",opts:["Passwort","Gehalt","Vertrag","Ausbildung"],ans:"Passwort",hint:"You forgot something you need to log in."},
{type:"fb",s:"Die {1} liegt auf deinem Schreibtisch.",a:"Bewerbung",opts:["Bewerbung","Gehalt","Link","Passwort"],hint:"A document you send when applying for a job.",sSrc:"The application is on your desk."},
{type:"mc",q:"Was bedeutet 'die Datei'?",opts:["a digital file","a paper folder","an office desk","a mailbox"],ans:"a digital file",hint:"Think about what you store on a computer."},
{type:"fb",s:"Hast du den Vertrag {1} unterschrieben?",a:"schon",opts:["schon","noch","gerade","erst"],hint:"The speaker expects it might be done already.",sSrc:"Have you already signed the contract?"},
{type:"mc",q:"'Er macht eine Ausbildung als Koch.' Was macht er?",opts:["He is doing an apprenticeship as a cook","He is cooking at the office","He is writing a contract","He is reading an article"],ans:"He is doing an apprenticeship as a cook",hint:"Ausbildung combines learning at school and on the job."},
{type:"fb",s:"Ich lese {1} die Mail von meinem Chef.",a:"gerade",opts:["gerade","schon","erst","noch"],hint:"This adverb means 'right now, at this moment'.",sSrc:"I am currently reading the email from my boss."},
{type:"match",pairs:[{trg:"das Büro",src:"office"},{trg:"das Gehalt",src:"salary"},{trg:"das Zeugnis",src:"certificate"},{trg:"das Blatt",src:"sheet/leaf"},{trg:"die Übersetzung",src:"translation"}]},
{type:"mc",q:"'Die Mailbox' bedeutet auf Deutsch meistens...",opts:["voicemail","physical letterbox","email inbox","homepage"],ans:"voicemail",hint:"Not a box you find on the street. Think phone."},
{type:"fb",s:"Kannst du mir den {1} per Mail schicken?",a:"Link",opts:["Link","Blatt","Büro","Gehalt"],hint:"A clickable address that takes you to a website.",sSrc:"Can you send me the link by email?"},
{type:"drag_fill",s:"Sie kommt {1} um neun, aber er ist {2} da.",blanks:{"1":"erst","2":"schon"},pool:["erst","schon","noch","gerade"],hint:"She arrives later than expected, he arrived earlier than expected.",sSrc:"She is only coming at nine, but he is already there."},
{type:"mc",q:"Welches Wort passt? 'Ich brauche ein ___ Papier.'",opts:["Blatt","Datei","Homepage","Mailbox"],ans:"Blatt",hint:"A physical piece you can write on with a pen."},
{type:"fb",s:"Er arbeitet {1} im Büro. Er kommt um acht nach Hause.",a:"noch",opts:["noch","schon","erst","gerade"],hint:"He is still there and has not left yet.",sSrc:"He is still working in the office. He comes home at eight."},
{type:"mc",q:"Was braucht man für eine Bewerbung in Deutschland oft?",opts:["ein Zeugnis","ein Passwort","eine Homepage","eine Mailbox"],ans:"ein Zeugnis",hint:"An official document proving your qualifications."},
{type:"drag_fill",s:"Ich habe die {1} schon auf die {2} hochgeladen.",blanks:{"1":"Datei","2":"Homepage"},pool:["Datei","Homepage","Mailbox","Vertrag"],hint:"A digital file goes onto a website.",sSrc:"I have already uploaded the file to the website."},
{type:"fb",s:"Das {1} ist zu niedrig, sagt er.",a:"Gehalt",opts:["Gehalt","Büro","Blatt","Zeugnis"],hint:"The amount of money you earn each month at work.",sSrc:"The salary is too low, he says."},
{type:"match",pairs:[{trg:"die Mail",src:"email"},{trg:"der Link",src:"link"},{trg:"die Datei",src:"file (digital)"},{trg:"die Homepage",src:"homepage"},{trg:"das Mobiltelefon",src:"mobile phone"}]},
{type:"teach",trg:"geduldig",src:"patient (adjective)",note:"Geduld (patience) + -ig. Sei geduldig! = Be patient!",example:"A: Wann kommt das Ergebnis?\nB: Nächste Woche. Sei geduldig!\nA: Ich versuche es!",exampleSrc:"A: When does the result come?\nB: Next week. Be patient!\nA: I'm trying!",funFact:"Geduld comes from 'dulden' (to endure). A patient person is one who can endure waiting. The medical 'Patient' shares the same Latin root."}
]},

// U12 L3: Rückblick - Story dev + grammar (conjunctions + adverb categories)
{id:"deu_r12l3",title:"Rückblick",icon:"\uD83D\uDD19",xp:15,board:true,steps:[
{type:"intro",title:"Rückblick",desc:"Verumius spreads his German documents across the kitchen table: Mietvertrag, Krankenversicherung, Steuernummer, Anmeldung, GEZ. Six months in Germany. Time to connect the dots.",goals:["Learn 12 new vocabulary words for daily life","Master coordinating conjunctions (ADUSO)","Categorize adverbs by time, place, and manner"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-kitchen-documents",trg:"Verumius sitzt am Küchentisch. Vor ihm liegen Papiere: der Mietvertrag, die Krankenversicherung, die Steuernummer, die Anmeldung, der GEZ-Brief. Er nimmt einen Stift und macht Notizen.",src:"Verumius sits at the kitchen table. In front of him lie papers: the rental contract, the health insurance, the tax number, the registration, the GEZ letter. He picks up a pen and makes notes."},
{type:"teach",trg:"der Kontakt",src:"the contact",note:"Masculine noun. Plural: die Kontakte. Used for people and connections.",example:"A: Hast du den Kontakt von der Vermieterin?\nB: Ja, ich habe ihre Nummer.",exampleSrc:"A: Do you have the landlady's contact?\nB: Yes, I have her number.",funFact:"Germans distinguish 'Kontakt' (a connection you maintain) from 'Bekanntschaft' (an acquaintance). Having someone's number makes them a Kontakt."},
{type:"teach",trg:"der Mitarbeiter",src:"the colleague / coworker",note:"Masculine. Feminine: die Mitarbeiterin. Literally: with-worker.",example:"A: Wer ist das?\nB: Das ist mein Mitarbeiter aus dem Büro.",exampleSrc:"A: Who is that?\nB: That is my colleague from the office.",funFact:"'Mit' (with) + 'Arbeiter' (worker) = someone who works with you. German builds job titles this way: Mitbewohner (roommate) = with-resident, Mitschüler (classmate) = with-pupil."},
{type:"teach",trg:"der Kredit",src:"the credit / loan",note:"Masculine noun. Plural: die Kredite. From Latin 'creditum.'",example:"A: Brauchst du einen Kredit für die Wohnung?\nB: Nein, ich habe genug gespart.",exampleSrc:"A: Do you need a loan for the apartment?\nB: No, I saved enough.",funFact:"In Germany, paying cash is still very common. Many restaurants and small shops do not accept cards. Germans say 'Nur Bargeld' (cash only) more than you would expect."},
{type:"teach",trg:"die Kenntnis",src:"the knowledge / skill",note:"Feminine noun. Plural: die Kenntnisse. Often used in job ads.",example:"A: Welche Kenntnisse brauchst du für den Job?\nB: Man braucht gute Deutschkenntnisse.",exampleSrc:"A: What skills do you need for the job?\nB: You need good German language skills.",funFact:"Job ads in Germany love the word 'Kenntnisse.' 'Deutschkenntnisse' (German skills), 'EDV-Kenntnisse' (computer skills), 'Fachkenntnisse' (specialist knowledge). Compound it and conquer the job market."},
{type:"mc",q:"What does 'die Kenntnis' mean?",opts:["the contact","the knowledge","the loan","the note"],ans:"the knowledge",hint:"This feminine noun appears constantly in German job advertisements."},
{type:"teach",trg:"die Notiz",src:"the note",note:"Feminine noun. Plural: die Notizen. From Latin 'notitia.'",example:"A: Schreibst du eine Notiz?\nB: Ja, ich schreibe alles auf einen Zettel.",exampleSrc:"A: Are you writing a note?\nB: Yes, I'm writing everything on a slip of paper.",funFact:"Germans are famous for their love of written notes. 'Sich Notizen machen' (to take notes) is practically a national hobby. Meetings without Notizen? Unthinkable."},
{type:"teach",trg:"der Stift",src:"the pen / pencil",note:"Masculine noun. Plural: die Stifte. Covers both pens and pencils.",example:"A: Hast du einen Stift?\nB: Ja, hier ist ein Kugelschreiber.",exampleSrc:"A: Do you have a pen?\nB: Yes, here is a ballpoint pen.",funFact:"'Stift' is the generic word. A 'Kugelschreiber' (ball-writer) is a ballpoint pen, a 'Bleistift' (lead-stick) is a pencil, and a 'Filzstift' (felt-stick) is a marker. Germans name their writing tools precisely."},
{type:"teach",trg:"die Tafel",src:"the board / blackboard",note:"Feminine noun. Plural: die Tafeln. Also means a bar of chocolate!",example:"A: Der Lehrer schreibt an die Tafel.\nB: Ich kann es nicht lesen.",exampleSrc:"A: The teacher writes on the board.\nB: I can't read it.",funFact:"'Eine Tafel Schokolade' means a bar of chocolate. Same word, completely different thing. Context saves you: classroom = board, supermarket = chocolate bar."},
{type:"teach",trg:"der Zettel",src:"the slip of paper / note",note:"Masculine noun. Plural: die Zettel. Smaller than a Notiz.",example:"A: Was steht auf dem Zettel?\nB: Die Telefonnummer vom Vermieter.",exampleSrc:"A: What's on the slip of paper?\nB: The landlord's phone number.",funFact:"Germans leave 'Zettel' everywhere: on doors ('Bitte klingeln'), on shared fridges ('Das ist MEIN Joghurt!'), on car windshields ('Sie parken falsch!'). The Zettel is Germany's passive-aggressive weapon of choice."},
{type:"mc",q:"Verumius picks up 'einen Stift' and writes on 'einen Zettel.' What is he doing?",opts:["Picking up a pen and writing on a slip of paper","Picking up a book and reading a letter","Picking up a board and drawing a picture","Picking up a note and folding it"],ans:"Picking up a pen and writing on a slip of paper",hint:"Think about which items are small enough to hold and write on."},
{type:"teach",trg:"die Zahl",src:"the number",note:"Feminine noun. Plural: die Zahlen. Related to 'zahlen' (to pay).",example:"A: Was ist deine Telefonnummer?\nB: Die Nummer ist 030 555 1234.",exampleSrc:"A: What is your phone number?\nB: The number is 030 555 1234.",funFact:"'Zahl' (number) and 'zahlen' (to pay) share a root. In medieval markets, you literally 'counted out' your coins. Paying was counting."},
{type:"teach",trg:"das Stück",src:"the piece / item",note:"Neuter noun. Plural: die Stücke. Very versatile counter word.",example:"A: Wie viele Stücke Kuchen möchtest du?\nB: Zwei Stück, bitte.",exampleSrc:"A: How many pieces of cake would you like?\nB: Two pieces, please.",funFact:"'Stück' appears in dozens of compounds: Frühstück (breakfast, literally 'early-piece'), Theaterstück (play), Musikstück (musical piece), Meisterstück (masterpiece). The humble 'piece' builds grand things."},
{type:"teach",trg:"reden",src:"to talk / to speak",note:"Regular verb. Similar to 'sprechen' but more casual, conversational.",example:"A: Worüber redet ihr?\nB: Wir reden über die Arbeit.",exampleSrc:"A: What are you talking about?\nB: We are talking about work.",funFact:"'Reden' is chatting. 'Sprechen' is speaking. You 'sprichst' a language, but you 'redest' with your friends. A 'Rede' is a formal speech, ironically from the casual verb."},
{type:"teach",trg:"rechnen",src:"to calculate / to do math",note:"Regular verb. 'Rechnen mit' = to expect, to count on.",example:"A: Kannst du gut rechnen?\nB: Ja, ich rechne gern mit Zahlen.",exampleSrc:"A: Can you calculate well?\nB: Yes, I like working with numbers.",funFact:"'Rechnen mit' has a sneaky second meaning: 'to expect.' 'Ich rechne mit Regen' = I expect rain. You are literally 'calculating' the probability in your head."},
{type:"teach",trg:"die Adresse",src:"the address",note:"Feminine noun. Plural: die Adressen. Borrowed from French.",example:"A: Was ist deine Adresse?\nB: Schillerstraße 12, 10625 Berlin.\nA: Und die E-Mail-Adresse?\nB: verumius@email.de",exampleSrc:"A: What is your address?\nB: Schillerstraße 12, 10625 Berlin.\nA: And the email address?\nB: verumius@email.de",funFact:"German addresses follow a specific format: street name + house number, then postal code + city. The postal code (Postleitzahl) always has 5 digits. Berlin codes start with 1, Munich with 8. You need your Adresse for everything: bank, Anmeldung, insurance, doctors."},
{type:"teach",trg:"das Gymnasium",src:"the grammar school / high school (academic track)",note:"Neuter noun. Plural: die Gymnasien.\nNOT a gym for sports! That is die Turnhalle.",example:"A: Wo hat Mia die Schule besucht?\nB: Auf einem Gymnasium in München.\nA: Was ist ein Gymnasium?\nB: Eine Schule, die zum Abitur führt.",exampleSrc:"A: Where did Mia go to school?\nB: At a Gymnasium in Munich.\nA: What is a Gymnasium?\nB: A school that leads to the Abitur exam.",funFact:"The German school system splits children at age 10 into three tracks: Hauptschule (basic), Realschule (intermediate), and Gymnasium (academic). Only Gymnasium leads to the Abitur, which you need for university. 'Gymnasium' comes from Greek 'gymnasion' (place of exercise), but in German it means brain exercise, not body exercise!"},
{type:"teach",trg:"der Hafen",src:"the harbor / port",note:"Masculine noun. Plural: die Häfen (note the umlaut!).\nHamburg has the biggest Hafen in Germany.",example:"A: Der Hamburger Hafen ist riesig!\nB: Ja, er ist der drittgrößte Hafen in Europa.\nA: Kann man den Hafen besichtigen?\nB: Natürlich! Es gibt sogar Hafenrundfahrten.",exampleSrc:"A: The Hamburg harbor is enormous!\nB: Yes, it is the third largest port in Europe.\nA: Can you visit the harbor?\nB: Of course! There are even harbor tours.",funFact:"The Hamburg Hafen celebrated its birthday every May with the 'Hafengeburtstag,' the world's largest port festival. Over a million visitors watch tall ships, fireworks, and tugboat ballets. 'Flughafen' (airport) is literally 'flight harbor.'"},
{type:"teach",trg:"der Unterricht",src:"the lesson / class / instruction",note:"Masculine noun. No common plural.\nUsed for school lessons and any kind of formal instruction.",example:"A: Wann beginnt der Unterricht?\nB: Um acht Uhr. Sei pünktlich!\nA: Was für Unterricht hast du heute?\nB: Deutsch und Mathematik.",exampleSrc:"A: When does the lesson start?\nB: At eight o'clock. Be on time!\nA: What kind of lessons do you have today?\nB: German and Mathematics.",funFact:"'Unterricht' comes from 'unterrichten' (to instruct, to inform). In German schools, lessons are called 'Stunden' (hours): 'Wir haben heute sechs Stunden Unterricht.' (We have six hours of lessons today.) Each Stunde is 45 minutes, not 60."},
{type:"match",pairs:[{trg:"der Kontakt",src:"contact"},{trg:"der Stift",src:"pen"},{trg:"die Notiz",src:"note"},{trg:"der Zettel",src:"slip of paper"},{trg:"die Zahl",src:"number"},{trg:"reden",src:"to talk"}]},
{type:"story",speaker:"narrator",mood:"thoughtful",art:"de-kitchen-documents-2",trg:"Verumius schaut auf seine Notizen und rechnet. Er hat Kontakte, aber er braucht mehr Kenntnisse. Er hat einen Mietvertrag, aber er braucht auch einen Kredit. Er spricht gut Deutsch, aber er versteht nicht alles.",src:"Verumius looks at his notes and calculates. He has contacts, but he needs more knowledge. He has a rental contract, but he also needs a loan. He speaks good German, but he doesn't understand everything."},
{type:"tip",title:"ADUSO: The 5 Coordinating Conjunctions",text:"German has exactly 5 coordinating conjunctions. They connect two main clauses and do NOT change the word order.\n\nA = aber (but)\nD = denn (because)\nU = und (and)\nS = sondern (but rather, after a negative)\nO = oder (or)\n\nWord order stays the same: Subject + Verb.\n'Ich lerne Deutsch und ich arbeite in Berlin.'\n'Er spricht kein Französisch, sondern er spricht Deutsch.'\n\nThese 5 words NEVER push the verb to the end.",deepDive:"Why does 'denn' not change word order? Because coordinating conjunctions join EQUAL clauses. Neither clause is 'inside' the other. Compare with 'weil' (because, subordinating): 'Ich lerne, weil ich Deutsch brauche.' Here the verb 'brauche' goes to the END. With 'denn': 'Ich lerne, denn ich brauche Deutsch.' Verb stays in position 2. Same meaning, different grammar. You will learn subordinating conjunctions later."},
{type:"mc",q:"Which mnemonic helps you remember the 5 German coordinating conjunctions?",opts:["ADUSO","ABCDE","VOWEL","KRAFT"],ans:"ADUSO",hint:"Each letter stands for one conjunction: A, D, U, S, O."},
{type:"mc",q:"'Ich habe einen Mietvertrag, aber ich brauche einen Kredit.' What does 'aber' mean?",opts:["and","because","but","or"],ans:"but",hint:"This conjunction introduces a contrast between two facts."},
{type:"fb",s:"Er lernt Deutsch, {1} er wohnt in Berlin.",a:["denn"],opts:["denn","aber","sondern","oder"],hint:"He learns German BECAUSE he lives in Berlin. Which ADUSO word fits?",sSrc:"He is learning German because he lives in Berlin."},
{type:"mc",q:"'Sie spricht kein Englisch, sondern sie spricht Spanisch.' When do you use 'sondern'?",opts:["After a positive statement with emphasis","After any question about languages","After a negative statement to correct it","In any position within the sentence"],ans:"After a negative statement to correct it",hint:"The first clause says 'kein Englisch,' negating something before offering the correction."},
{type:"fb",s:"Möchtest du Kaffee {1} Tee?",a:["oder"],opts:["oder","und","aber","denn"],hint:"You are being offered a choice between two drinks.",sSrc:"Would you like coffee or tea?"},
{type:"drag_fill",s:"Verumius hat Kontakte {1} er braucht mehr Kenntnisse. Er redet Deutsch {2} er versteht nicht alles.",blanks:{"1":"und","2":"aber"},pool:["und","aber","denn","oder","sondern"],hint:"First: adding two facts together. Second: introducing a contrast.",sSrc:"Verumius has contacts and he needs more knowledge. He speaks German but he does not understand everything."},
{type:"mc",q:"Which sentence has CORRECT word order after a coordinating conjunction?",opts:["Ich lerne Deutsch und ich gehe zur Schule.","Ich lerne Deutsch und gehe ich zur Schule.","Ich lerne Deutsch und zur Schule ich gehe.","Ich lerne Deutsch und zur Schule gehe ich."],ans:"Ich lerne Deutsch und ich gehe zur Schule.",hint:"After ADUSO conjunctions, the word order stays normal: subject then verb."},
{type:"tip",title:"Adverb Categories: Time, Place, Manner",text:"German adverbs fall into three main categories:\n\nTime (wann?): heute, morgen, gestern, oft, manchmal, immer, nie, bald, schon, noch\nPlace (wo?): hier, dort, oben, unten, draußen, drinnen, links, rechts, überall\nManner (wie?): gut, schlecht, schnell, langsam, gern, leider, vielleicht, besonders\n\nIn a sentence with multiple adverbs, the default order is: Time before Place before Manner.\n'Ich arbeite heute hier gern.' = I like working here today.",deepDive:"The time-place-manner order is a tendency, not an unbreakable rule. German is flexible. But for natural-sounding sentences, TeKaMoLo (Temporal, Kausal, Modal, Lokal) is the standard order that native speakers default to. You can break it for emphasis, but learn the default first."},
{type:"mc",q:"'Verumius schreibt heute hier schnell.' What is the adverb order?",opts:["Manner, Place, Time","Place, Time, Manner","Time, Place, Manner","Time, Manner, Place"],ans:"Time, Place, Manner",hint:"'Heute' tells when, 'hier' tells where, 'schnell' tells how."},
{type:"fb",s:"Ich rechne {1} mit Zahlen.",a:["gern"],opts:["gern","hier","morgen","schnell"],hint:"Which manner adverb means you enjoy doing something?",sSrc:"I like to work with numbers."},
{type:"drag_fill",s:"Er redet {1} viel, {2} er versteht nicht alles, {3} er macht Notizen.",blanks:{"1":"heute","2":"aber","3":"und"},pool:["heute","aber","und","denn","dort"],hint:"A time adverb first, then a contrast conjunction, then an adding conjunction.",sSrc:"He talks today a lot, but he does not understand everything, and he takes notes."},
{type:"mc",q:"'Verumius hat keinen Kredit, sondern er hat Ersparnisse.' Is this correct?",opts:["No, 'aber' fits better after a negative","No, 'denn' is needed for giving a reason","Yes, it corrects the negative 'keinen Kredit' with the real situation","No, 'und' simply adds without correcting"],ans:"Yes, it corrects the negative 'keinen Kredit' with the real situation",hint:"The first clause contains 'keinen' (a negation). Sondern replaces and corrects with the real fact."},
{type:"fb",s:"Ich verstehe die Mitarbeiterin nicht, {1} sie redet schnell.",a:["denn"],opts:["denn","und","oder","sondern"],hint:"The second clause gives the REASON why she is hard to understand.",sSrc:"I do not understand the colleague because she speaks quickly."},
{type:"match",pairs:[{trg:"und",src:"and"},{trg:"oder",src:"or"},{trg:"aber",src:"but"},{trg:"denn",src:"because"},{trg:"sondern",src:"but rather"},{trg:"das Stück",src:"piece"}]}
]}
,

{id:"deu_r12l4",title:"Was wäre wenn?",icon:"📐",xp:20,board:true,steps:[
{type:"intro",title:"Was wäre wenn?",desc:"Verumius and Hildi sit in a café, daydreaming about what they would do if they could. Time to master imperatives with separable and irregular verbs, revisit ob-clauses, and sharpen your Konjunktiv II. Plus: subordinate clause word order under pressure.",goals:["Form imperatives with separable and irregular verbs","Combine ob with new vocabulary","Use Konjunktiv II in wishes and hypotheticals","Master subordinate clause word order with all conjunctions"]},
{type:"story",speaker:"narrator",mood:"reflective",art:"de-cafe-daydream",trg:"Im Café am Gendarmenmarkt. Draußen regnet es. Verumius und Hildi trinken Kaffee und planen das nächste Halbjahr. Aber die Pläne werden schnell zu Träumen.",src:"In the café at Gendarmenmarkt. Outside it is raining. Verumius and Hildi drink coffee and plan the next half-year. But the plans quickly turn to dreams."},
{type:"story",speaker:"Hildi",trg:"Steh auf, Verumius! Hör auf zu träumen! Wir müssen planen, nicht träumen. Oder... was würdest du tun, wenn du alles schaffen könntest?",src:"Get up, Verumius! Stop dreaming! We need to plan, not dream. Or... what would you do if you could accomplish anything?"},
{type:"teach",trg:"lassen",src:"to let / to leave",note:"Irregular: ich lasse, du lässt, er lässt. Stem change a to ä.",example:"A: Lass mich in Ruhe!\nB: Okay, ich lasse dich allein.",exampleSrc:"A: Leave me alone!\nB: Okay, I'll leave you alone.",funFact:"'Lassen' is a chameleon verb. 'Lass uns gehen' = let's go. 'Ich lasse es reparieren' = I'm having it repaired. 'Lass das!' = Stop that! One verb, three completely different uses."},
{type:"teach",trg:"schaffen",src:"to manage / to accomplish",note:"Regular: ich schaffe, du schaffst. 'Das schaffe ich!' = I can do this!",example:"A: Schaffst du die Prüfung?\nB: Ja, ich schaffe das!",exampleSrc:"A: Will you pass the exam?\nB: Yes, I can do it!",funFact:"'Schaffen' has a secret twin: 'schaffen' (regular) means 'to manage.' But 'schaffen' (irregular: schuf, geschaffen) means 'to create.' God 'schuf' the world, but you 'schaffst' your homework."},
{type:"teach",trg:"versuchen",src:"to try / to attempt",note:"Regular: ich versuche, du versuchst. Often with 'zu' + infinitive.",example:"A: Versuch es nochmal!\nB: Okay, ich versuche es.",exampleSrc:"A: Try it again!\nB: Okay, I'll try.",funFact:"'Versuchen' contains 'suchen' (to search). To try something is literally 'to search thoroughly.' A 'Versuchung' is a temptation, something that lures you into searching."},
{type:"teach",trg:"vorbereiten",src:"to prepare",note:"Separable: ich bereite ... vor, du bereitest ... vor.",example:"A: Bereitest du das Essen vor?\nB: Ja, ich bereite alles vor.",exampleSrc:"A: Are you preparing the food?\nB: Yes, I'm preparing everything.",funFact:"'Vor' (before) + 'bereiten' (to make ready). You 'make ready beforehand.' In a subordinate clause, it reunites: 'weil ich alles vorbereite.' Separable verbs play hide-and-seek with their prefix!"},
{type:"teach",trg:"wählen",src:"to choose / to vote",note:"Regular: ich wähle, du wählst. Used for elections and menus.",example:"A: Was wählst du?\nB: Ich wähle den Kaffee mit Milch.",exampleSrc:"A: What are you choosing?\nB: I'm choosing the coffee with milk.",funFact:"'Wählen' means both 'to choose' and 'to vote.' A 'Wahl' is an election. 'Die Qual der Wahl' (the agony of choice) is a beloved German rhyme for when you cannot decide."},
{type:"teach",trg:"prüfen",src:"to test / to examine",note:"Regular: ich prüfe, du prüfst. A 'Prüfung' is an exam.",example:"A: Prüf bitte die Rechnung!\nB: Alles stimmt.",exampleSrc:"A: Please check the bill!\nB: Everything is correct.",funFact:"Every German car gets a 'TÜV-Prüfung' (technical inspection) every two years. Germans love prüfen: testing, checking, verifying. The 'Prüfung' (exam) is sacred in German education."},
{type:"teach",trg:"planen",src:"to plan",note:"Regular: ich plane, du planst. 'Einen Plan machen' = to make a plan.",example:"A: Was planst du für morgen?\nB: Ich plane einen Ausflug nach Potsdam.",exampleSrc:"A: What are you planning for tomorrow?\nB: I'm planning a trip to Potsdam.",funFact:"Germans are famous for planning. 'Planwirtschaft' = planned economy. 'Fahrplan' = train schedule. 'Stadtplan' = city map. If it exists, Germans have a plan for it."},
{type:"teach",trg:"sparen",src:"to save (money)",note:"Regular: ich spare, du sparst. 'Ein Sparkonto' = a savings account.",example:"A: Sparst du für etwas Besonderes?\nB: Ja, ich spare für eine Reise.",exampleSrc:"A: Are you saving for something special?\nB: Yes, I'm saving for a trip.",funFact:"Germany is a nation of savers. The 'Sparbuch' (savings book) was every child's first financial tool. 'Sparschwein' (savings pig) is the word for piggy bank. Pigs are lucky in German culture!"},
{type:"mc",q:"Which verb means 'to try' or 'to attempt'?",opts:["versuchen","vorbereiten","prüfen","wählen"],ans:"versuchen",hint:"This word contains 'suchen' (to search) with a prefix."},
{type:"fb",s:"Ich {1} für eine Reise nach Japan.",a:["spare"],opts:["spare","plane","schaffe","prüfe"],hint:"Which verb means putting money aside for the future?",sSrc:"I am saving for a trip to Japan."},
{type:"tip",title:"Imperative: Separable and Irregular Verbs",text:"Separable verbs split in the imperative. The prefix goes to the end:\n\nvorbereiten: Bereite dich vor! (Prepare yourself!)\naufstehen: Steh auf! (Get up!)\nzumachen: Mach die Tür zu! (Close the door!)\n\nIrregular verbs with e to i stem change keep the change:\n\ngeben: Gib mir das Buch! (not 'Geb')\nnehmen: Nimm Platz! (not 'Nehm')\nlesen: Lies das! (not 'Les')\n\nSein has a special form: Sei ruhig! (Be quiet!)",deepDive:"Why do separable verbs split? The prefix carries meaning (auf = up, vor = before, zu = closed), and in main clauses it jumps to the end for emphasis. The imperative is a main clause, so the same rule applies. In a subordinate clause, the prefix stays attached: 'Ich sage, dass du aufstehen sollst.'"},
{type:"mc",q:"How do you say 'Get up!' using the separable verb 'aufstehen'?",opts:["Steh auf!","Aufsteh!","Stehe auf!","Auf steh!"],ans:"Steh auf!",hint:"The prefix separates and moves to the end of the command."},
{type:"fb",s:"{1} mir bitte das Salz!",a:["Gib"],opts:["Gib","Geb","Gibt","Geben"],hint:"The irregular verb 'geben' changes its stem vowel in the du-imperative.",sSrc:"Give me the salt please!"},
{type:"mc",q:"Which imperative form of 'nehmen' is correct?",opts:["Nimm!","Nehm!","Nimmt!","Nehme!"],ans:"Nimm!",hint:"Like geben to Gib, this verb changes its stem vowel from e to i."},
{type:"mc",q:"How do you say 'Be patient!' using 'sein'?",opts:["Sei geduldig!","Bist geduldig!","Seid geduldig!","Sein geduldig!"],ans:"Sei geduldig!",hint:"The verb 'sein' has a completely unique imperative form for the du-form."},
{type:"tip",title:"ob: Whether or Not",text:"'ob' means 'whether' and sends the verb to the END of its clause:\n\nIch weiß nicht, ob er kommt.\n(I don't know whether he is coming.)\n\nWeißt du, ob das Café offen ist?\n(Do you know whether the café is open?)\n\nob works like weil, dass, wenn: verb LAST.\nDon't confuse ob with wenn (if/when for conditions).",deepDive:"'ob' is used for indirect yes/no questions. Any yes/no question can become an ob-clause: 'Kommt er?' (Is he coming?) becomes 'Ich frage, ob er kommt' (I ask whether he is coming). The original verb-first order flips to verb-last."},
{type:"fb",s:"Ich frage mich, {1} ich das schaffe.",a:["ob"],opts:["ob","wenn","dass","weil"],hint:"Which conjunction means 'whether' and introduces indirect yes/no questions?",sSrc:"I wonder whether I will manage it."},
{type:"mc",q:"'Weißt du, ob Hildi morgen ___?' Which verb form fits the ob-clause?",opts:["kommt","kommen","kommst","komme"],ans:"kommt",hint:"In an ob-clause the verb goes to the end, conjugated for the subject 'Hildi.'"},
{type:"drag_fill",s:"Ich weiß nicht, {1} er das Essen {2}.",blanks:{"1":"ob","2":"vorbereitet"},pool:["ob","vorbereitet","wenn","bereitet vor","dass"],hint:"In the ob-clause, the separable verb stays TOGETHER because the verb goes to the end.",sSrc:"I do not know whether he prepared the food."},
{type:"teach",trg:"hatte",src:"had (simple past of haben)",example:"A: Hattest du gestern frei?\nB: Ja, ich hatte einen freien Tag.\nA: Schön! Was hast du gemacht?",exampleSrc:"A: Did you have a day off yesterday?\nB: Yes, I had a free day.\nA: Nice! What did you do?",note:"Präteritum of haben: ich hatte, du hattest, er hatte, wir hatten. Used in writing and with modal verbs.",funFact:"Germans prefer Perfekt (ich habe gehabt) in speech but Präteritum (ich hatte) in writing. The exception: haben and sein almost always use Präteritum even in speech."},
{type:"teach",trg:"ginge",src:"would go (Konjunktiv II of gehen)",example:"A: Wenn es mir besser ginge, würde ich mitkommen.\nB: Ruh dich aus! Morgen ginge es bestimmt.\nA: Ich hoffe es!",exampleSrc:"A: If I felt better, I would come along.\nB: Rest up! Tomorrow it would surely work.\nA: I hope so!",note:"Konjunktiv II of gehen: ich ginge, du gingest, er ginge. From Präteritum 'ging' + umlaut pattern. Often replaced by 'würde gehen' in speech.",funFact:"'Es ginge' is a polite way to say 'it would work.' At the Amt: 'Ginge es auch morgen?' (Would tomorrow also work?) sounds much softer than 'Geht es morgen?'"},
{type:"tip",title:"Konjunktiv II: Dreaming Big",text:"Review: würde + infinitive for wishes.\n\nWenn ich Zeit hätte, würde ich mehr sparen.\n(If I had time, I would save more.)\n\nWas würdest du tun, wenn du alles schaffen könntest?\n(What would you do if you could accomplish anything?)\n\nKey irregular forms:\nwäre (would be), hätte (would have)\nkönnte (could), müsste (would have to)\nwüsste (would know), dürfte (would be allowed to)",deepDive:"Wenn-clauses with Konjunktiv II always have verb-last order in the wenn-part, and the main clause starts with the conjugated verb: 'Wenn ich reich wäre, würde ich reisen.' This is verb-second in the main clause because 'wenn ich reich wäre' counts as position 1."},
{type:"verb_table",title:"hätte (would have)",label:"Konjunktiv II of haben",groups:[{label:"Full conjugation",rows:[{pronoun:"ich",form:"hätte",src:"I would have"},{pronoun:"du",form:"hättest",src:"you would have"},{pronoun:"er/sie/es",form:"hätte",src:"he/she/it would have"},{pronoun:"wir",form:"hätten",src:"we would have"},{pronoun:"ihr",form:"hättet",src:"you all would have"},{pronoun:"sie/Sie",form:"hätten",src:"they/you (formal) would have"}]}],note:"Never say 'würde haben'. Always use hätte.\nIch hätte gern... = I would like to have..."},
{type:"verb_table",title:"wäre (would be)",label:"Konjunktiv II of sein",groups:[{label:"Full conjugation",rows:[{pronoun:"ich",form:"wäre",src:"I would be"},{pronoun:"du",form:"wär(e)st",src:"you would be"},{pronoun:"er/sie/es",form:"wäre",src:"he/she/it would be"},{pronoun:"wir",form:"wären",src:"we would be"},{pronoun:"ihr",form:"wär(e)t",src:"you all would be"},{pronoun:"sie/Sie",form:"wären",src:"they/you (formal) would be"}]}],note:"Never say 'würde sein'. Always use wäre.\nDas wäre schön! = That would be nice!"},
{type:"verb_table",title:"könnte (could)",label:"Konjunktiv II of können",groups:[{label:"Full conjugation",rows:[{pronoun:"ich",form:"könnte",src:"I could"},{pronoun:"du",form:"könntest",src:"you could"},{pronoun:"er/sie/es",form:"könnte",src:"he/she/it could"},{pronoun:"wir",form:"könnten",src:"we could"},{pronoun:"ihr",form:"könntet",src:"you all could"},{pronoun:"sie/Sie",form:"könnten",src:"they/you (formal) could"}]}],note:"Like können but with umlaut and -te ending.\nUsed for polite requests and hypothetical ability."},
{type:"tip",title:"werden vs. würde",text:"werden = future (WILL happen)\nIch werde morgen kommen. (I will come tomorrow.)\n\nwürde = hypothetical (WOULD happen)\nIch würde gern kommen. (I would like to come.)\n\nSame word order, completely different meaning!\nwerden = real plans\nwürde = wishes, hypotheticals, polite requests",deepDive:{title:"The Satzklammer (sentence bracket)",text:"Both werden and würde create a bracket structure: conjugated form in position 2, infinitive at the end.\n\nIch werde morgen früh aufstehen.\nIch würde gern früh aufstehen.\n\nThis bracket (Satzklammer) is one of the defining features of German sentence structure."}},
{type:"tip",title:"hätte and wäre: No würde Needed",text:"haben and sein have their OWN Konjunktiv II forms.\nNever use würde haben or würde sein.\n\nCorrect: Ich hätte gern ein Bier.\nWrong: Ich würde gern ein Bier haben.\n\nCorrect: Das wäre toll.\nWrong: Das würde toll sein.\n\nThese forms are used constantly in spoken German.",deepDive:{title:"Which verbs have their own Konjunktiv II?",text:"Besides haben (hätte) and sein (wäre), the modal verbs all have their own forms:\nkönnen → könnte, müssen → müsste, dürfen → dürfte, sollen → sollte, wollen → wollte\n\nFor these verbs, NEVER use würde + infinitive. Use the direct form."}},
{type:"tip",title:"kann vs. könnte",text:"kann = can (ability, fact)\nIch kann schwimmen. (I can swim.)\n\nkönnte = could (polite, hypothetical)\nKönnte ich bitte...? (Could I please...?)\n\nUsing kann for requests sounds blunt:\nKann ich Wasser haben? (direct)\nKönnte ich Wasser haben? (polite)\n\nIn formal settings, ALWAYS use könnte.",deepDive:{title:"könnte for unrealized ability",text:"Könnte also expresses unrealized ability:\nIch könnte morgen kommen. (I could come tomorrow, if needed.)\nWir könnten das versuchen. (We could try that.)\n\nThis is different from kann, which states a definite ability."}},
{type:"tip",title:"Politeness Ranking",text:"From least to most polite:\n1. Machen Sie das! (Do that! = command)\n2. Können Sie das machen? (Can you do that? = direct)\n3. Könnten Sie das machen? (Could you do that? = polite)\n4. Würden Sie das bitte machen? (Would you please? = very polite)\n5. Wäre es möglich, das zu machen? (Would it be possible? = most formal)\n\nFor strangers and formal settings, use level 3-5.",deepDive:{title:"Workplace German and register",text:"In German offices, levels 3-4 are standard among colleagues. Level 5 is reserved for emails to management, clients, or official requests.\n\nGerman politeness is encoded in grammar (Konjunktiv II), not just in saying 'bitte.' Mastering these levels is essential for professional German."}},
{type:"mc",q:"'Wenn ich mehr Geld ___, würde ich eine Reise planen.' Which form completes this?",opts:["hätte","habe","hatte","würde haben"],ans:"hätte",hint:"This hypothetical needs the Konjunktiv II form of 'haben.'"},
{type:"fb",s:"Wenn ich du {1}, würde ich es versuchen.",a:["wäre"],opts:["wäre","würde","hätte","könnte"],hint:"Which Konjunktiv II form means 'were' from the verb 'sein'?",sSrc:"If I were you, I would try it."},
{type:"drag_fill",s:"Wenn ich alles {1}, {2} ich zuerst Deutsch {3}.",blanks:{"1":"schaffen könnte","2":"würde","3":"prüfen"},pool:["schaffen könnte","würde","prüfen","schaffen kann","werde","geprüft"],hint:"The wenn-clause needs Konjunktiv II. The main clause needs the subjunctive helper + infinitive.",sSrc:"If I could manage everything, I would first check German."},
{type:"tip",title:"Subordinate Clause Word Order: All Conjunctions",text:"ALL these conjunctions send the verb to the END:\n\nweil (because): Ich spare, weil ich reisen will.\ndass (that): Ich glaube, dass er es schafft.\nob (whether): Ich frage, ob sie kommt.\nwenn (if/when): Wenn ich könnte, würde ich planen.\nobwohl (although): Er plant, obwohl er müde ist.\n\nSeparable verbs REUNITE at the end:\nIch weiß, dass er alles vorbereitet. (not 'bereitet vor').",deepDive:"The verb-last rule in subordinate clauses is one of German's most consistent rules. No matter which subordinating conjunction you use, the conjugated verb goes to the final position. With modals: 'weil ich planen muss' (the modal goes last, the infinitive sits before it). With separable verbs: the prefix reattaches because there is no sentence end to jump to."},
{type:"mc",q:"'Er spart Geld, _____ er eine Reise plant.' Which conjunction means 'because'?",opts:["weil","ob","dass","wenn"],ans:"weil",hint:"This conjunction explains the reason and sends the verb to the end."},
{type:"drag_fill",s:"Ich glaube, {1} sie alles gut {2}, {3} sie sich immer {4}.",blanks:{"1":"dass","2":"schafft","3":"weil","4":"vorbereitet"},pool:["dass","schafft","weil","vorbereitet","ob","bereitet vor"],hint:"Both clauses need verb-last order. The separable verb 'vorbereiten' stays together in a subordinate clause.",sSrc:"I believe that she does everything well because she always prepares herself."},
{type:"fb",s:"Steh {1}! Wir müssen alles vorbereiten.",a:["auf"],opts:["auf","an","vor","zu"],hint:"Complete this separable imperative. The verb means 'to get up.'",sSrc:"Get up! We have to prepare everything."},
{type:"mc",q:"'Wenn ich es versuchen könnte, ___ ich es sofort tun.' What fills the blank?",opts:["würde","wäre","hätte","müsste"],ans:"würde",hint:"The main clause of a wenn-Konjunktiv II needs the general 'would' form with an infinitive."},
{type:"match",pairs:[{trg:"lassen",src:"to let / to leave"},{trg:"schaffen",src:"to manage"},{trg:"versuchen",src:"to try"},{trg:"vorbereiten",src:"to prepare"},{trg:"wählen",src:"to choose / to vote"},{trg:"prüfen",src:"to test"},{trg:"planen",src:"to plan"},{trg:"sparen",src:"to save (money)"}]}
]}
,

{id:"deu_r12l5",title:"Gefühle",icon:"💭",xp:15,board:true,steps:[
{type:"intro",title:"Gefühle",desc:"Träume, Wünsche und alles dazwischen. Lerne 16 wichtige Substantive für Emotionen und abstrakte Begriffe.",goals:["16 neue Substantive lernen","Grammatik aus Lektion 1\u20134 wiederholen","Abstrakte Begriffe im Kontext verwenden"]},
{type:"teach",trg:"der Traum",src:"dream",gender:"m",note:"Plural: die Träume. Umlaut im Plural.",funFact:"Deutsche sagen 'Traumjob' für ihren perfekten Beruf.",example:"A: Hattest du letzte Nacht einen Traum?\nB: Ja, ich habe von meinem Urlaub geträumt.",exampleSrc:"A: Did you have a dream last night?\nB: Yes, I dreamed about my vacation."},
{type:"teach",trg:"der Wunsch",src:"wish",gender:"m",note:"Plural: die Wünsche. Verb: sich etwas wünschen.",funFact:"Zum Geburtstag sagt man 'Herzlichen Glückwunsch!' mit Wunsch drin.",example:"A: Hast du einen Wunsch?\nB: Ja, ich wünsche mir mehr Freizeit.",exampleSrc:"A: Do you have a wish?\nB: Yes, I wish for more free time."},
{type:"teach",trg:"das Ziel",src:"goal",gender:"n",note:"Plural: die Ziele. Auch: destination (Reiseziel).",funFact:"'Zielstrebig' bedeutet determined, wörtlich: striving toward a goal.",example:"A: Was ist dein Ziel für dieses Jahr?\nB: Ich möchte besser Deutsch sprechen.",exampleSrc:"A: What is your goal for this year?\nB: I want to speak better German."},
{type:"teach",trg:"der Unterschied",src:"difference",gender:"m",note:"Plural: die Unterschiede. Adjektiv: unterschiedlich.",funFact:"Unter + schied kommt von 'scheiden' (to separate). Wörtlich: what separates below.",example:"A: Was ist der Unterschied zwischen Traum und Wunsch?\nB: Ein Traum kommt nachts, ein Wunsch kommt vom Herzen.",exampleSrc:"A: What is the difference between dream and wish?\nB: A dream comes at night, a wish comes from the heart."},
{type:"teach",trg:"das Gegenteil",src:"opposite",gender:"n",note:"Plural: die Gegenteile. gegen (against) + Teil (part).",funFact:"Deutsche lieben Gegensatzpaare: heiß/kalt, groß/klein, laut/leise.",example:"A: Was ist das Gegenteil von Stress?\nB: Ich glaube, das Gegenteil ist Ruhe.",exampleSrc:"A: What is the opposite of stress?\nB: I think the opposite is peace."},
{type:"teach",trg:"die Menge",src:"quantity, crowd",gender:"f",note:"Plural: die Mengen. 'Eine Menge Leute' heißt a lot of people.",funFact:"In der Mathematik ist 'die Menge' auch ein set, wie in der Mengenlehre.",example:"A: Wie war das Konzert?\nB: Toll! Es war eine riesige Menge da.",exampleSrc:"A: How was the concert?\nB: Great! There was a huge crowd there."},
{type:"teach",trg:"die Reihe",src:"row, series",gender:"f",note:"Plural: die Reihen. 'Ich bin an der Reihe' heißt it's my turn.",funFact:"'Der Reihe nach' bedeutet one after another, in order.",example:"A: Wer ist jetzt an der Reihe?\nB: Du bist an der Reihe!",exampleSrc:"A: Whose turn is it now?\nB: It's your turn!"},
{type:"teach",trg:"der Rest",src:"rest, remainder",gender:"m",note:"Plural: die Reste. 'Den Rest' kann man auch für Essensreste benutzen.",funFact:"'Gib ihm den Rest!' heißt umgangssprachlich: finish him off!",example:"A: Möchtest du den Rest vom Kuchen?\nB: Nein danke, ich bin satt.",exampleSrc:"A: Would you like the rest of the cake?\nB: No thanks, I'm full."},
{type:"teach",trg:"die Ruhe",src:"peace, quiet",gender:"f",note:"Kein Plural. Adjektiv: ruhig (calm, quiet).",funFact:"'Immer mit der Ruhe!' ist ein beliebter Spruch: take it easy!",example:"A: Ich brauche etwas Ruhe.\nB: Soll ich das Radio ausmachen?",exampleSrc:"A: I need some peace and quiet.\nB: Should I turn off the radio?"},
{type:"teach",trg:"die Sache",src:"thing, matter",gender:"f",note:"Plural: die Sachen. Auch: belongings (Nimm deine Sachen mit!).",funFact:"'Zur Sache kommen' heißt to get to the point.",example:"A: Ich muss dir eine wichtige Sache sagen.\nB: Was für eine Sache denn?",exampleSrc:"A: I need to tell you an important thing.\nB: What kind of thing?"},
{type:"teach",trg:"der Stress",src:"stress",gender:"m",note:"Kein Plural. Verb: stressen. 'Ich bin gestresst.'",funFact:"Das Wort kommt direkt aus dem Englischen und wird genauso benutzt.",example:"A: Du siehst müde aus. Hast du viel Stress?\nB: Ja, die Arbeit stresst mich gerade sehr.",exampleSrc:"A: You look tired. Do you have a lot of stress?\nB: Yes, work is really stressing me out right now."},
{type:"teach",trg:"die Liebe",src:"love",gender:"f",note:"Kein Plural. Adjektiv: lieb. Verb: lieben.",funFact:"'Liebe geht durch den Magen' heißt: the way to someone's heart is through their stomach.",example:"A: Glaubst du an die große Liebe?\nB: Ja, aber man muss Geduld haben.",exampleSrc:"A: Do you believe in true love?\nB: Yes, but you have to be patient."},
{type:"teach",trg:"der Spaß",src:"fun",gender:"m",note:"Plural: die Späße. 'Spaß machen' heißt to be fun.",funFact:"'Spaß beiseite!' heißt joking aside, jetzt wird es ernst.",example:"A: Macht der Kurs dir Spaß?\nB: Ja, Deutsch lernen macht mir großen Spaß!",exampleSrc:"A: Is the course fun for you?\nB: Yes, learning German is a lot of fun for me!"},
{type:"teach",trg:"die Lüge",src:"lie",gender:"f",note:"Plural: die Lügen. Verb: lügen (to lie). Er lügt.",funFact:"'Lügen haben kurze Beine' heißt: lies have short legs, also die Wahrheit kommt raus.",example:"A: War das eine Lüge?\nB: Nein, ich sage dir die Wahrheit!",exampleSrc:"A: Was that a lie?\nB: No, I'm telling you the truth!"},
{type:"teach",trg:"der Titel",src:"title",gender:"m",note:"Plural: die Titel. Auch für Bücher, Lieder und akademische Titel.",funFact:"In Deutschland benutzt man akademische Titel oft: Herr Dr. Müller, Frau Prof. Schmidt.",example:"A: Wie ist der Titel des Buches?\nB: Der Titel ist 'Der kleine Prinz'.",exampleSrc:"A: What is the title of the book?\nB: The title is 'The Little Prince'."},
{type:"teach",trg:"der Vorschlag",src:"suggestion, proposal",gender:"m",note:"Plural: die Vorschläge. Verb: vorschlagen (separable).",funFact:"Vor (before) + Schlag (hit/strike). Wörtlich: a strike put forward.",example:"A: Ich habe einen Vorschlag.\nB: Was schlägst du vor?",exampleSrc:"A: I have a suggestion.\nB: What do you suggest?"},
{type:"mc",q:"Was bedeutet 'der Unterschied'?",opts:["difference","opposite","remainder","quantity"],ans:"difference",hint:"Es beschreibt, was zwei Dinge voneinander trennt."},
{type:"fb",s:"Ich habe einen {1} für das Wochenende.",a:"Vorschlag",opts:["Vorschlag","Unterschied","Gegenteil","Titel"],hint:"Jemand hat eine Idee und schlägt etwas vor.",sSrc:"I have a suggestion for the weekend."},
{type:"mc",q:"'Lügen haben kurze Beine.' Was bedeutet das?",opts:["Die Wahrheit kommt immer raus","Man soll schnell laufen","Lügen machen Spaß","Beine sind wichtig"],ans:"Die Wahrheit kommt immer raus",hint:"Es ist ein Sprichwort über Ehrlichkeit."},
{type:"fb",s:"Wenn ich müde bin, brauche ich {1}.",a:"Ruhe",opts:["Ruhe","Stress","Menge","Reihe"],hint:"Das Gegenteil von Lärm und Hektik.",sSrc:"When I am tired, I need quiet."},
{type:"drag_fill",s:"Ich weiß nicht, ob er seinen {1} erreichen kann, aber sein {2} ist groß.",blanks:{"1":"Traum","2":"Wunsch"},pool:["Traum","Wunsch","Rest","Titel","Spaß"],hint:"Erst kommt etwas, das man nachts hat, dann etwas, das man sich erhofft.",sSrc:"I do not know whether he can reach his dream, but his wish is great."},
{type:"mc",q:"Welcher Satz benutzt 'die Reihe' richtig?",opts:["Du bist an der Reihe.","Die Reihe ist sehr müde.","Ich esse eine Reihe.","Er kauft die Reihe."],ans:"Du bist an der Reihe.",hint:"Dieses Wort wird oft benutzt, wenn man auf etwas wartet."},
{type:"fb",s:"Das {1} von Liebe ist Hass.",a:"Gegenteil",opts:["Gegenteil","Ziel","Rest","Unterschied"],hint:"Das Wort beschreibt die entgegengesetzte Bedeutung.",sSrc:"The opposite of love is hate."},
{type:"mc",q:"'Mein Ziel ist es, Deutsch zu sprechen.' Was ist 'das Ziel'?",opts:["goal","dream","fun","lie"],ans:"goal",hint:"Etwas, das man erreichen möchte."},
{type:"drag_fill",s:"Er hat viel {1} bei der Arbeit, aber am Abend macht ihm Kochen großen {2}.",blanks:{"1":"Stress","2":"Spaß"},pool:["Stress","Spaß","Liebe","Ruhe","Lüge"],hint:"Zuerst etwas Negatives bei der Arbeit, dann etwas Positives am Abend.",sSrc:"He has a lot of stress at work, but in the evening cooking gives him great fun."},
{type:"match",pairs:[{trg:"der Traum",src:"dream"},{trg:"die Ruhe",src:"peace"},{trg:"die Lüge",src:"lie"},{trg:"der Vorschlag",src:"suggestion"},{trg:"die Sache",src:"thing"}]}
]},

// U12 L6: KD lacht. Story climax. Bürgeramt scene. Heavy A2 grammar review.
{id:"deu_r12l6",title:"KD lacht",icon:"\uD83D\uDE10",xp:20,board:true,steps:[
{type:"intro",title:"KD lacht",desc:"Back at the Bürgeramt. This time Verumius has ALL the right documents. KD processes everything smoothly. And then something impossible happens...",goals:["Review all A2 grammar in multi-construct sentences","Learn 10 new vocabulary words","Witness the impossible: KD smiles"]},
{type:"story",speaker:"narrator",mood:"confident",art:"de-buergeramt-desk",trg:"Bürgeramt, Zimmer 4. KD sitzt hinter ihrem Schreibtisch. Verumius legt einen perfekten Stapel Dokumente auf den Tisch. Alles ist da. Alles ist richtig.",src:"Bürgeramt, Room 4. KD sits behind her desk. Verumius places a perfect stack of documents on the table. Everything is there. Everything is correct."},
{type:"story",speaker:"KD",mood:"neutral",trg:"Personalausweis. Meldebescheinigung. Gehaltsnachweis. Krankenversicherung. Alles vollständig. Das ist... ungewöhnlich.",src:"ID card. Registration certificate. Proof of income. Health insurance. Everything complete. That is... unusual."},
{type:"story",speaker:"narrator",mood:"surprised",trg:"KD tippt schnell auf ihrem Laptop. Der Service ist schnell und effizient. Dann schaut sie aus dem Fenster und sagt trocken: 'Bei dem Wetter braucht man keine Erlaubnis zum Weinen. Das macht der Regen schon.' Ihre Lippe zuckt. War das ein Lächeln?",src:"KD types quickly on her laptop. The service is fast and efficient. Then she looks out the window and says dryly: 'With this weather, you don't need permission to cry. The rain does it for you.' Her lip twitches. Was that a smile?"},
{type:"teach",trg:"die Erlaubnis",src:"the permission",note:"Feminine noun. Plural: die Erlaubnisse. From 'erlauben' (to allow).",example:"A: Hast du die Erlaubnis bekommen?\nB: Ja, ich habe die Erlaubnis gestern bekommen.",exampleSrc:"A: Did you get the permission?\nB: Yes, I got the permission yesterday.",funFact:"Germans need an 'Erlaubnis' for surprisingly many things: building a fence, cutting down a tree, even owning certain dog breeds. Bureaucracy is a national sport."},
{type:"teach",trg:"die Ermäßigung",src:"the discount / reduction",note:"Feminine noun. From 'ermäßigen' (to reduce). Common at museums and trains.",example:"A: Gibt es eine Ermäßigung für Studenten?\nB: Ja, Studenten bekommen eine Ermäßigung von 50 Prozent.",exampleSrc:"A: Is there a discount for students?\nB: Yes, students get a 50 percent discount.",funFact:"The 'BahnCard 50' gives 50% Ermäßigung on all Deutsche Bahn trains. Germans plan their train discounts like military operations."},
{type:"teach",trg:"der Bescheid",src:"the notice / notification",note:"Masculine noun. Official communication from authorities. 'Bescheid wissen' = to be informed.",example:"A: Wann kommt der Bescheid vom Amt?\nB: Der Bescheid kommt in zwei Wochen.",exampleSrc:"A: When does the notice from the office come?\nB: The notice comes in two weeks.",funFact:"'Bescheid geben' means to let someone know. 'Ich gebe dir Bescheid' is one of the most useful everyday phrases in German. Literal: 'I give you notice.'"},
{type:"mc",q:"KD says Verumius doesn't need 'Erlaubnis zum Weinen.' What does she mean?",opts:["Permission to cry","Permission to leave","Permission to work","Permission to stay"],ans:"Permission to cry",hint:"'Weinen' is the verb for shedding tears."},
{type:"teach",trg:"das Paar",src:"the pair / couple",note:"Neuter noun. 'Ein Paar Schuhe' = a pair of shoes. 'Ein Paar' (capitalized) = a couple.",example:"A: Sind die beiden ein Paar?\nB: Ja, sie sind seit drei Jahren ein Paar.",exampleSrc:"A: Are those two a couple?\nB: Yes, they have been a couple for three years.",funFact:"Careful with capitalization! 'Ein Paar' (capital P) = a couple/pair. 'Ein paar' (lowercase) = a few/some. 'Ein Paar Schuhe' = one pair of shoes. 'Ein paar Schuhe' = a few shoes."},
{type:"teach",trg:"die Webseite",src:"the website",note:"Feminine noun. Compound: Web + Seite (page). Also 'die Website.'",example:"A: Hast du die Webseite schon besucht?\nB: Ja, ich habe mich auf der Webseite angemeldet.",exampleSrc:"A: Have you visited the website yet?\nB: Yes, I registered on the website.",funFact:"Germans say both 'Webseite' (half-translated: Web + Seite/page) and 'Website' (full English). The government prefers 'Internetseite' or 'Internetauftritt' (internet appearance). Classic."},
{type:"teach",trg:"der Laptop",src:"the laptop",note:"Masculine noun. Borrowed directly from English. Plural: die Laptops.",example:"A: Wo ist dein Laptop?\nB: Mein Laptop steht auf dem Schreibtisch.",exampleSrc:"A: Where is your laptop?\nB: My laptop is on the desk.",funFact:"German assigns gender to borrowed words too. Laptop is 'der' (masculine), E-Mail is 'die' (feminine), and Handy (mobile phone) is 'das' (neuter). No logic. Just feelings."},
{type:"fb",s:"Mein Laptop steht auf {1} Schreibtisch.",a:["dem"],opts:["dem","den","der","das"],hint:"After 'auf' with a static location, which case follows?",sSrc:"My laptop is on the desk."},
{type:"teach",trg:"das Tablet",src:"the tablet",note:"Neuter noun. Borrowed from English. Plural: die Tablets.",example:"A: Ich habe mir ein neues Tablet gekauft.\nB: Auf dem Tablet kann man gut lesen.",exampleSrc:"A: I bought myself a new tablet.\nB: You can read well on the tablet.",funFact:"Some Germans insist on saying 'der Tablet-Computer' for the full compound. Others just say 'das iPad' regardless of brand, like 'Tempo' for tissues."},
{type:"teach",trg:"der Service",src:"the service",note:"Masculine noun. Pronounced with French stress: ser-VEES. Used for customer service.",example:"A: Wie war der Service im Restaurant?\nB: Der Service war sehr gut.",exampleSrc:"A: How was the service in the restaurant?\nB: The service was very good.",funFact:"German has two words: 'der Service' (pronounced French, for customer service) and 'der Dienst' (native German, for public service/duty). KD provides 'Dienst.' Whether it feels like 'Service' depends on her mood."},
{type:"teach",trg:"der Babysitter",src:"the babysitter",note:"Masculine noun. Used for all genders in casual speech. Feminine: die Babysitterin.",example:"A: Wir brauchen einen Babysitter für Samstag.\nB: Ich habe schon einen Babysitter gefunden.",exampleSrc:"A: We need a babysitter for Saturday.\nB: I already found a babysitter.",funFact:"Germans borrow English job titles constantly: Babysitter, Manager, Designer, Influencer. Each gets a German article and a feminine '-in' form. Globalization meets grammar."},
{type:"teach",trg:"die Chefin",src:"the (female) boss",note:"Feminine of 'der Chef.' The '-in' suffix marks feminine job titles.",example:"A: Wer ist deine Chefin?\nB: Meine Chefin heißt Frau Schneider. Sie ist sehr nett.",exampleSrc:"A: Who is your boss?\nB: My boss is called Mrs. Schneider. She is very nice.",funFact:"Germany had a fierce debate about gendering job titles. Traditionally 'der Chef' covered everyone. Now 'die Chefin' is standard for women. Some texts use 'Chef:in' or 'Chef*in' to include everyone. Language evolves!"},
{type:"mc",q:"'Meine Chefin hat mir einen Bescheid geschickt.' Who sent the notice?",opts:["My male boss","My female boss","My colleague","My babysitter"],ans:"My female boss",hint:"The '-in' suffix on 'Chef' tells you the gender."},
{type:"tip",title:"A2 Grammar Power Review",text:"You have learned all of these in A2. Let's combine them!\n\n1. Perfekt: Ich habe/bin + Partizip II\n2. Dative: mit dem/der/den + noun\n3. Wechselpräpositionen: auf den Tisch (wohin?) vs. auf dem Tisch (wo?)\n4. weil/dass/wenn/ob: verb goes to the END\n5. Reflexive: sich freuen, sich anmelden\n6. Adjective endings: ein neuer Laptop, das neue Tablet\n7. Konjunktiv II: würde + Infinitiv, wäre, hätte\n8. Conjunctions: aber, oder, denn, und (V2) vs. weil, dass, wenn (verb-final)"},
{type:"mc",q:"'Ich habe mich auf der Webseite angemeldet, weil ich eine Ermäßigung wollte.' Why did the person register?",opts:["Because they wanted a discount","Because they needed permission","Because they got a notification","Because they bought a laptop"],ans:"Because they wanted a discount",hint:"The 'weil' clause explains the reason. What does 'Ermäßigung' mean?"},
{type:"fb",s:"Wenn ich die Erlaubnis {1}, kann ich den Antrag stellen.",a:["bekomme"],opts:["bekomme","bekommen","bekam","bekommt"],hint:"In a 'wenn' clause, the conjugated verb goes to the end. Subject is 'ich.'",sSrc:"If I get permission, I can submit the application."},
{type:"drag_fill",s:"KD hat {1} auf {2} Laptop die Dokumente {3}.",blanks:{"1":"schnell","2":"ihrem","3":"geprüft"},pool:["schnell","ihrem","geprüft","langsam","seinem","geschrieben"],hint:"Perfekt + dative possessive + adverb. 'Auf' with static location takes dative.",sSrc:"KD has quickly checked the documents on her laptop."},
{type:"mc",q:"'Wenn das Wetter schöner wäre, würde ich draußen sitzen.' What tense is this?",opts:["Simple past (Präteritum)","Present tense (Präsens)","Konjunktiv II (subjunctive)","Future tense (Futur I)"],ans:"Konjunktiv II (subjunctive)",hint:"'Wäre' and 'würde' signal an unreal or hypothetical situation."},
{type:"drag_fill",s:"Er hat {1} über die neue Ermäßigung {2}, weil er {3} Paar Schuhe kaufen {4}.",blanks:{"1":"sich","2":"gefreut","3":"ein","4":"wollte"},pool:["sich","gefreut","ein","wollte","mich","gesucht","einen","konnte"],hint:"Reflexive Perfekt + weil-clause with modal verb at the end.",sSrc:"He was happy about the new discount because he wanted to buy a pair of shoes."},
{type:"fb",s:"Die Chefin hat den Bescheid an {1} neuen Babysitter geschickt.",a:["den"],opts:["den","dem","der","das"],hint:"'An' + accusative when indicating the recipient of a directed action.",sSrc:"The boss sent the notification to the new babysitter."},
{type:"mc",q:"'Ich hätte gern eine Ermäßigung.' What is the speaker doing?",opts:["Demanding a discount angrily","Politely requesting a discount","Refusing a discount","Complaining about a discount"],ans:"Politely requesting a discount",hint:"'Hätte gern' is the polite Konjunktiv II form for making requests."},
{type:"drag_fill",s:"Nachdem Verumius {1} auf der Webseite {2} hatte, bekam er {3} Bescheid per E-Mail.",blanks:{"1":"sich","2":"angemeldet","3":"einen"},pool:["sich","angemeldet","einen","mich","abgemeldet","einem"],hint:"Reflexive Plusquamperfekt in the nachdem clause. 'Bescheid' is masculine: einen.",sSrc:"After Verumius had registered on the website, he received a notification by email."},
{type:"fb",s:"Wenn ich ein Tablet {1}, würde ich die Webseite öffnen.",a:["hätte"],opts:["hätte","habe","hatte","hat"],hint:"This is an unreal condition. The 'wenn' clause needs Konjunktiv II of 'haben.'",sSrc:"If I had a tablet, I would open the website."},
{type:"mc",q:"'Stell den Laptop auf den Tisch!' What grammar is used here?",opts:["Konjunktiv II polite request form","Perfekt narration of a past event","Imperative with Wechselpräposition","Passive voice descriptive instruction"],ans:"Imperative with Wechselpräposition",hint:"'Stell!' is a command form. 'Auf den Tisch' shows direction (accusative)."},
{type:"drag_fill",s:"Die Chefin sagte, {1} der Service besser {2} {3}, wenn alle Mitarbeiter pünktlich {4}.",blanks:{"1":"dass","2":"sein","3":"würde","4":"kämen"},pool:["dass","sein","würde","kämen","weil","haben","konnte","kommen"],hint:"Dass-clause + Konjunktiv II. The subjunctive helper goes to the end of the clause.",sSrc:"The boss said that the service would be better if all employees came punctually."},
{type:"story",speaker:"narrator",mood:"warm",trg:"KD stempelt das letzte Dokument. Sie schaut Verumius an. 'Sie haben alles richtig gemacht. Das passiert selten.' Dann, ganz leise: 'Kommen Sie gut nach Hause.' War das... Freundlichkeit?",src:"KD stamps the last document. She looks at Verumius. 'You did everything right. That rarely happens.' Then, very quietly: 'Get home safely.' Was that... friendliness?"},
{type:"match",pairs:[{trg:"die Erlaubnis",src:"the permission"},{trg:"die Ermäßigung",src:"the discount"},{trg:"der Bescheid",src:"the notice"},{trg:"das Paar",src:"the pair/couple"},{trg:"die Webseite",src:"the website"},{trg:"der Laptop",src:"the laptop"},{trg:"das Tablet",src:"the tablet"},{trg:"der Service",src:"the service"},{trg:"der Babysitter",src:"the babysitter"},{trg:"die Chefin",src:"the female boss"}]}
]}
,

// U12 L7: Noch mehr Wörter - Remaining A2 verbs and adjectives
{id:"deu_r12l7",title:"Noch mehr Wörter",icon:"\uD83D\uDCDA",xp:15,board:true,steps:[
{type:"intro",title:"Noch mehr Wörter",desc:"Twenty more verbs that Germans use every day at work, in emails, and in difficult conversations. Master these and your A2 vocabulary is nearly complete.",goals:["Learn 20 essential A2 verbs","Use reflexive verbs with sich","Practice formal and informal register"]},

// ─── Group 1: Office & Work Verbs ───
{type:"teach",trg:"ändern",src:"to change",note:"Regular verb. Ich ändere, du änderst, er ändert.",example:"A: Können wir den Termin ändern?\nB: Ja, ich ändere ihn sofort.",exampleSrc:"A: Can we change the appointment?\nB: Yes, I'll change it right away.",funFact:"'Ändern' comes from 'ander' (other). To change something is literally to 'make it other.' The noun is 'die Änderung' (the change)."},
{type:"teach",trg:"beenden",src:"to end / to finish",note:"Regular. Ich beende, du beendest. The 'be-' prefix is inseparable.",example:"A: Wann beendest du das Projekt?\nB: Ich beende es morgen.",exampleSrc:"A: When will you finish the project?\nB: I'll finish it tomorrow.",funFact:"'Be-' is one of German's most common inseparable prefixes. Unlike 'auf-' or 'an-', it never splits off. Beenden, beginnen, bekommen: 'be-' always stays glued."},
{type:"teach",trg:"notieren",src:"to note down / to write down",note:"Regular. Ich notiere, du notierst. From Latin 'notare.'",example:"A: Notieren Sie bitte die Telefonnummer.\nB: Moment, ich notiere sie.",exampleSrc:"A: Please note down the phone number.\nB: One moment, I'm writing it down.",funFact:"German borrowed this from Latin via French. 'Notiz' (note), 'notieren' (to note), 'Notizbuch' (notebook). The Latin root 'nota' means a mark or sign."},
{type:"teach",trg:"kündigen",src:"to quit / to terminate (a contract)",note:"Regular. Ich kündige, du kündigst. Used for jobs and contracts.",example:"A: Warum hast du gekündigt?\nB: Ich habe eine bessere Stelle gefunden.",exampleSrc:"A: Why did you quit?\nB: I found a better position.",funFact:"'Kündigen' comes from 'kund' (known). To quit is to 'make known' your departure. The noun 'die Kündigung' appears in every German employment contract."},
{type:"mc",q:"Your colleague says 'Ich muss den Termin ändern.' What does she want to do?",opts:["Cancel the meeting","Change the appointment","Start the project","Finish the work"],ans:"Change the appointment",hint:"The verb means to make something different from what it was."},
{type:"fb",s:"Bitte {1} Sie die Adresse.",a:["notieren"],opts:["notieren","kündigen","beenden","ändern"],hint:"Which verb means to write something down for later reference?",sSrc:"Please note down the address."},

// ─── Group 2: Communication Verbs ───
{type:"teach",trg:"beantworten",src:"to answer (a question/email)",note:"Regular. Ich beantworte, du beantwortest. Inseparable 'be-' prefix.",example:"A: Hast du meine E-Mail beantwortet?\nB: Nein, ich beantworte sie heute Abend.",exampleSrc:"A: Did you answer my email?\nB: No, I'll answer it this evening.",funFact:"'Beantworten' always needs a direct object (the question/email). 'Antworten' (without 'be-') takes a dative person: 'Ich antworte dir' vs. 'Ich beantworte deine Frage.'"},
{type:"teach",trg:"berichten",src:"to report",note:"Regular. Ich berichte, du berichtest. Inseparable prefix.",example:"A: Die Zeitung berichtet über den Unfall.\nB: Was berichten sie genau?",exampleSrc:"A: The newspaper is reporting on the accident.\nB: What exactly are they reporting?",funFact:"'Bericht' (report) + '-en' makes the verb. Germans love turning nouns into verbs: Arbeit to arbeiten, Antwort to antworten, Bericht to berichten."},
{type:"teach",trg:"beraten",src:"to advise / to consult",note:"Irregular: er berät (stem change a to ä). Inseparable prefix.",example:"A: Wer berät Sie bei Steuerfragen?\nB: Mein Steuerberater berät mich.",exampleSrc:"A: Who advises you on tax questions?\nB: My tax advisor advises me.",funFact:"'Steuerberater' (tax advisor) is one of Germany's most important professions. Germans take taxes very seriously, and nearly everyone has one."},
{type:"teach",trg:"übersetzen",src:"to translate",note:"Regular with inseparable 'über-'. Ich übersetze, du übersetzt.",example:"A: Kannst du das ins Englische übersetzen?\nB: Ja, ich übersetze es dir.",exampleSrc:"A: Can you translate that into English?\nB: Yes, I'll translate it for you.",funFact:"Literally 'to set over' from one language to another. The noun 'der Übersetzer' means translator. Fun twist: 'übersetzen' with separable stress means 'to cross over' (a river)."},
{type:"mc",q:"'Können Sie meinen Brief beantworten?' What is being asked?",opts:["Can you write my letter?","Can you translate my letter?","Can you answer my letter?","Can you send my letter?"],ans:"Can you answer my letter?",hint:"The inseparable 'be-' prefix is attached to 'Antwort' (answer)."},
{type:"fb",s:"Kannst du den Text ins Deutsche {1}?",a:["übersetzen"],opts:["übersetzen","berichten","beantworten","beraten"],hint:"Which verb means converting words from one language to another?",sSrc:"Can you translate the text into German?"},

// ─── Group 3: Reflexive & Formal Verbs ───
{type:"teach",trg:"sich bedanken",src:"to thank / to express thanks",note:"Reflexive. Ich bedanke mich, du bedankst dich.",example:"A: Ich möchte mich bei Ihnen bedanken.\nB: Oh, das ist sehr nett von Ihnen!",exampleSrc:"A: I would like to thank you.\nB: Oh, that is very kind of you!",funFact:"The reflexive 'sich' makes it literally 'to thank oneself.' German reflexives often express actions you do for your own benefit. More formal than simply saying 'Danke.'"},
{type:"teach",trg:"sich beschweren",src:"to complain",note:"Reflexive. Ich beschwere mich, du beschwerst dich.",example:"A: Ich beschwere mich über den Lärm.\nB: Bei wem beschwerst du dich?",exampleSrc:"A: I'm complaining about the noise.\nB: Who are you complaining to?",funFact:"Uses 'über' (about) for the topic and 'bei' (to/at) for the person. 'Die Beschwerde' (complaint) is a word every German tenant knows well."},
{type:"teach",trg:"sich bewerben",src:"to apply (for a job/position)",note:"Irregular reflexive: er bewirbt sich (stem change e to i).",example:"A: Ich bewerbe mich um die Stelle.\nB: Viel Glück bei deiner Bewerbung!",exampleSrc:"A: I'm applying for the position.\nB: Good luck with your application!",funFact:"The noun 'die Bewerbung' (application) is sacred in German job culture. A proper Bewerbung includes a cover letter, CV with photo, and copies of all certificates. Missing one piece? Straight to the rejection pile."},
{type:"teach",trg:"begründen",src:"to justify / to give reasons for",note:"Regular. Ich begründe, du begründest. From 'Grund' (reason).",example:"A: Können Sie Ihre Entscheidung begründen?\nB: Ja, ich begründe sie gern.",exampleSrc:"A: Can you justify your decision?\nB: Yes, I'll gladly give my reasons.",funFact:"'Grund' means both 'reason' and 'ground/bottom.' To justify is to 'give it a ground to stand on.' Very German: even arguments need solid foundations."},
{type:"mc",q:"'Ich bewerbe mich um die Stelle als Lehrer.' What is the speaker doing?",opts:["Quitting a teaching job","Complaining about the teacher","Applying for a teaching position","Thanking the teacher"],ans:"Applying for a teaching position",hint:"The reflexive verb 'sich bewerben um' indicates seeking a specific role."},
{type:"fb",s:"Ich möchte mich bei Ihnen {1}.",a:["bedanken"],opts:["bedanken","beschweren","bewerben","begründen"],hint:"Which reflexive verb expresses gratitude formally?",sSrc:"I would like to thank you."},

// ─── Group 4: Remaining Essential Verbs ───
{type:"teach",trg:"bestehen",src:"to pass (an exam) / to exist",note:"Irregular: bestand, bestanden. 'Die Prüfung bestehen' = to pass the exam.",example:"A: Hast du die Prüfung bestanden?\nB: Ja, ich habe sie bestanden!",exampleSrc:"A: Did you pass the exam?\nB: Yes, I passed it!",funFact:"'Bestehen' has two very different meanings: 'to pass' (an exam) and 'to exist/consist of.' 'Das Problem besteht seit Jahren' = The problem has existed for years."},
{type:"teach",trg:"bestätigen",src:"to confirm",note:"Regular. Ich bestätige, du bestätigst. Very common in emails.",example:"A: Können Sie den Termin bestätigen?\nB: Ja, hiermit bestätige ich den Termin.",exampleSrc:"A: Can you confirm the appointment?\nB: Yes, I hereby confirm the appointment.",funFact:"'Hiermit bestätige ich...' (I hereby confirm...) is the classic opening of German business emails. Formal, precise, and very satisfying to write."},
{type:"teach",trg:"verbieten",src:"to forbid / to prohibit",note:"Irregular: verbot, verboten. 'Verboten' is Germany's favorite sign.",example:"A: Rauchen ist hier verboten.\nB: Oh, Entschuldigung! Ich wusste das nicht.",exampleSrc:"A: Smoking is forbidden here.\nB: Oh, sorry! I didn't know that.",funFact:"'Verboten' might be the most German word ever. Germans love rules and signs: Betreten verboten (no trespassing), Rauchen verboten (no smoking), Fotografieren verboten (no photos). If it exists, it can be verboten."},
{type:"teach",trg:"verschieben",src:"to postpone / to move to a later date",note:"Irregular: verschob, verschoben. Inseparable prefix.",example:"A: Wir müssen das Meeting verschieben.\nB: Auf wann verschieben wir es?",exampleSrc:"A: We have to postpone the meeting.\nB: To when shall we postpone it?",funFact:"Literally 'to push away.' 'Ver-' intensifies + 'schieben' (to push). Germans also say 'auf die lange Bank schieben' (to push onto the long bench) for procrastinating."},
{type:"mc",q:"A sign says 'Fotografieren verboten.' What must you NOT do?",opts:["Eat here","Park here","Take photos","Enter this area"],ans:"Take photos",hint:"'Fotografieren' looks very similar to its English equivalent."},
{type:"fb",s:"Können wir das Meeting auf Freitag {1}?",a:["verschieben"],opts:["verschieben","verbieten","bestehen","bestätigen"],hint:"Which verb means to push an event to a later time?",sSrc:"Can we postpone the meeting to Friday?"},

// ─── Group 5: Final Verbs ───
{type:"teach",trg:"lügen",src:"to lie (tell an untruth)",note:"Irregular: log, gelogen. Ich lüge, du lügst.",example:"A: Lügst du?\nB: Nein, ich lüge nie!",exampleSrc:"A: Are you lying?\nB: No, I never lie!",funFact:"'Lügen' and English 'lie' are direct cousins from the same Germanic root. The saying 'Lügen haben kurze Beine' (lies have short legs) means lies don't get you far."},
{type:"teach",trg:"merken",src:"to notice / to remember",note:"Regular. 'Sich merken' (reflexive) = to memorize.",example:"A: Hast du das gemerkt?\nB: Ja, ich habe es sofort gemerkt.",exampleSrc:"A: Did you notice that?\nB: Yes, I noticed it immediately.",funFact:"Two uses in one verb: 'merken' = to notice, 'sich merken' = to remember. 'Merk dir das!' (Remember that!) is something German parents say constantly."},
{type:"teach",trg:"nennen",src:"to name / to call",note:"Irregular: nannte, genannt. 'Man nennt ihn...' = They call him...",example:"A: Wie nennt man das auf Deutsch?\nB: Man nennt es 'Schmetterling.'",exampleSrc:"A: What do you call that in German?\nB: You call it 'Schmetterling' (butterfly).",funFact:"'Nennen' is related to English 'name.' The past participle 'genannt' appears in historical texts: 'Karl der Große, auch Karl I. genannt' (Charlemagne, also called Charles I)."},
{type:"teach",trg:"leidtun",src:"to be sorry",note:"Separable. 'Es tut mir leid' = I'm sorry. Literally: 'It does suffering to me.'",example:"A: Es tut mir leid, ich bin zu spät.\nB: Kein Problem!",exampleSrc:"A: I'm sorry, I'm late.\nB: No problem!",funFact:"One of German's most poetic phrases. 'Leid' means suffering/sorrow, 'tun' means to do. Saying sorry in German is admitting 'it causes me sorrow.' Deeply emotional for such a practical language."},
{type:"mc",q:"'Es tut mir leid, ich kann heute nicht kommen.' What is the speaker expressing?",opts:["Excitement about coming","A request to come later","An apology for not being able to come","A complaint about the event"],ans:"An apology for not being able to come",hint:"The phrase at the beginning expresses regret or sorrow."},
{type:"drag_fill",s:"Wie {1} man das auf Deutsch? Man {2} es 'Rathaus.'",blanks:{"1":"nennt","2":"nennt"},pool:["nennt","merkt","lügt","sagt"],hint:"Both blanks need the same verb meaning 'to call or name.'",sSrc:"How do you call that in German? You call it 'Rathaus.'"},
{type:"match",pairs:[{trg:"ändern",src:"to change"},{trg:"kündigen",src:"to quit"},{trg:"übersetzen",src:"to translate"},{trg:"sich bewerben",src:"to apply"},{trg:"verbieten",src:"to forbid"},{trg:"leidtun",src:"to be sorry"},{trg:"bestätigen",src:"to confirm"},{trg:"verschieben",src:"to postpone"}]},
{type:"match",pairs:[{trg:"beantworten",src:"to answer"},{trg:"berichten",src:"to report"},{trg:"beraten",src:"to advise"},{trg:"sich bedanken",src:"to thank"},{trg:"sich beschweren",src:"to complain"},{trg:"bestehen",src:"to pass (exam)"},{trg:"lügen",src:"to lie"},{trg:"merken",src:"to notice"}]},
{type:"teach",trg:"eintragen",src:"to register / to enter (data)",example:"A: Tragen Sie bitte Ihren Namen ein.\nB: Hier? In diese Zeile?\nA: Ja, genau dort.",exampleSrc:"A: Please enter your name.\nB: Here? On this line?\nA: Yes, right there.",note:"Separable: ich trage ein. Used for forms, lists, and calendars.",funFact:"Germans love forms. 'Bitte eintragen' (please fill in) appears on every official document."},
{type:"teach",trg:"ganz",src:"whole / quite / entirely",example:"A: Hast du das ganze Buch gelesen?\nB: Ja, ganz! Es war ganz toll.",exampleSrc:"A: Did you read the whole book?\nB: Yes, all of it! It was quite great.",note:"ganz = whole (adjective) or quite/entirely (adverb). Context decides the meaning.",funFact:"'Ganz und gar' means completely. 'Ganz und gar nicht' means not at all. Tiny word, big range."},
{type:"teach",trg:"preiswert",src:"affordable / good value",example:"A: Das Restaurant ist preiswert.\nB: Ja, und das Essen schmeckt gut!",exampleSrc:"A: The restaurant is affordable.\nB: Yes, and the food tastes good!",note:"Preis (price) + wert (worth). Literally: worth the price. Nicer than 'billig' (cheap).",funFact:"Germans avoid saying 'billig' for good deals because it implies low quality. 'Preiswert' or 'günstig' sound much better."},
{type:"teach",trg:"privat",src:"private",example:"A: Ist das eine private Frage?\nB: Ja, du musst nicht antworten.",exampleSrc:"A: Is that a private question?\nB: Yes, you don't have to answer.",note:"Cognate with English. Privat: for personal matters, not public.",funFact:"Germans value Privatsphäre (privacy) highly. Asking about salary or rent is considered very privat."},
{type:"teach",trg:"schriftlich",src:"written / in writing",example:"A: Bitte bestätigen Sie schriftlich.\nB: Ich schicke Ihnen eine Mail.",exampleSrc:"A: Please confirm in writing.\nB: I will send you an email.",note:"From Schrift (writing/font). Mündlich = oral, schriftlich = written.",funFact:"German bureaucracy loves the word 'schriftlich.' Nothing is official until it is schriftlich."},
{type:"teach",trg:"stressig",src:"stressful",example:"A: Wie war dein Tag?\nB: Sehr stressig! Ich brauche Ruhe.",exampleSrc:"A: How was your day?\nB: Very stressful! I need rest.",note:"Stress + -ig ending. Colloquial but widely used.",funFact:"'Stressig' entered German from English stress. The -ig suffix makes it an adjective, following the same pattern as sonnig, windig."},
{type:"teach",trg:"schrecklich",src:"terrible / dreadful",example:"A: Wie war das Wetter?\nB: Schrecklich! Es hat den ganzen Tag geregnet.",exampleSrc:"A: How was the weather?\nB: Terrible! It rained all day.",note:"From Schreck (fright/shock). Schrecklich = causing fright.",funFact:"Also used for emphasis: 'schrecklich nett' (terribly nice). Like English 'awfully good.'"},
{type:"teach",trg:"nirgends",src:"nowhere",example:"A: Wo ist mein Schlüssel?\nB: Nirgends! Ich habe überall gesucht.",exampleSrc:"A: Where is my key?\nB: Nowhere! I looked everywhere.",note:"Opposite of überall (everywhere). Also: nirgendwo (same meaning).",funFact:"Nirgends and überall are a natural pair. Germans love opposites: nirgends/überall, niemand/jemand, nichts/alles."},
{type:"teach",trg:"wenigstens",src:"at least",example:"A: Ich habe die Prüfung nicht bestanden.\nB: Wenigstens hast du es versucht!",exampleSrc:"A: I didn't pass the exam.\nB: At least you tried!",note:"From wenig (little) + -stens. Similar to mindestens but more emotional/consoling.",funFact:"'Wenigstens' is for consolation: 'at least this happened.' 'Mindestens' is for minimums: 'at least 3 hours.'"},
{type:"teach",trg:"einverstanden",src:"agreed / in agreement",example:"A: Treffen wir uns um drei?\nB: Einverstanden!\nA: Super, bis dann!",exampleSrc:"A: Shall we meet at three?\nB: Agreed!\nA: Great, see you then!",note:"Ein + verstanden (understood). 'Ich bin einverstanden' = I agree. Very formal.",funFact:"On contracts: 'Hiermit erkläre ich mich einverstanden' (I hereby declare my agreement). The most German sentence ever written."}
]}
,

{id:"deu_r12l8",title:"Das letzte Kapitel",icon:"📖",xp:15,board:true,steps:[
{type:"intro",title:"Das letzte Kapitel",desc:"Zwanzig neue Wörter zum Abschluss: Alltag, Schule und mehr.",goals:["20 neue Nomen und Adjektive lernen","Über Schule und Alltag sprechen","Wortschatz festigen"]},
{type:"teach",trg:"das Fach",src:"subject / compartment",phonetic:"fakh",example:"A: Welches Fach magst du am liebsten?\nB: Ich mag Mathe, das ist mein bestes Fach.",exampleSrc:"A: Which subject do you like best?\nB: I like maths, that's my best subject.",note:"Neuter. Plural: Fächer. Means both a school subject and a compartment.",funFact:"In Germany, students often have 12 or more Fächer on their timetable."},
{type:"teach",trg:"die Fundsache",src:"lost property",phonetic:"FOONT-za-khuh",example:"A: Ist das deine Fundsache?\nB: Ja, ich habe meinen Schirm im Bus vergessen.",exampleSrc:"A: Is that your lost property?\nB: Yes, I forgot my umbrella on the bus.",note:"Feminine. Compound: Fund (find) + Sache (thing).",funFact:"German trains have a central Fundbüro (lost property office) in every major station."},
{type:"teach",trg:"die Geldbörse",src:"wallet",phonetic:"GELT-beur-zuh",example:"A: Hast du deine Geldbörse dabei?\nB: Oh nein, sie liegt noch zu Hause!",exampleSrc:"A: Do you have your wallet with you?\nB: Oh no, it's still at home!",note:"Feminine. Compound: Geld (money) + Börse (purse).",funFact:"Germans still use cash more than most Europeans, so a good Geldbörse is essential."},
{type:"teach",trg:"die Note",src:"grade",phonetic:"NOH-tuh",example:"A: Welche Note hast du in Deutsch bekommen?\nB: Ich habe eine Zwei bekommen!",exampleSrc:"A: What grade did you get in German?\nB: I got a two!",note:"Feminine. German grades go from 1 (best) to 6 (worst).",funFact:"A German 1 is called 'sehr gut' (very good). Anything below 4 is a fail."},
{type:"teach",trg:"das Produkt",src:"product",phonetic:"pro-DUKT",example:"A: Ist das ein gutes Produkt?\nB: Ja, die Qualität ist wirklich toll.",exampleSrc:"A: Is that a good product?\nB: Yes, the quality is really great.",note:"Neuter. Plural: Produkte. Cognate with English 'product'.",funFact:"'Made in Germany' was originally a British warning label in 1887. Germans turned it into a quality mark."},
{type:"mc",q:"Was bedeutet 'die Note' auf Englisch?",opts:["grade","note (music only)","notebook","nothing"],ans:"grade",hint:"Think of school results, not music."},
{type:"teach",trg:"der Rentner",src:"retiree (male)",phonetic:"RENT-nuh",example:"A: Ist dein Opa schon Rentner?\nB: Ja, er ist seit zwei Jahren Rentner.",exampleSrc:"A: Is your grandpa retired already?\nB: Yes, he's been retired for two years.",note:"Masculine. Female form: die Rentnerin.",funFact:"Germany's retirement age is gradually rising to 67 by 2031."},
{type:"teach",trg:"die Rentnerin",src:"retiree (female)",phonetic:"RENT-nuh-rin",example:"A: Was macht die Rentnerin jeden Morgen?\nB: Sie geht im Park spazieren.",exampleSrc:"A: What does the retiree do every morning?\nB: She goes for a walk in the park.",note:"Feminine. The -in suffix marks female form, as with many German professions.",funFact:"Over 20% of Germany's population are Rentner or Rentnerinnen."},
{type:"teach",trg:"das Schlafzimmer",src:"bedroom",phonetic:"SHLAHF-tsim-uh",example:"A: Wie groß ist dein Schlafzimmer?\nB: Es ist ziemlich klein, aber gemütlich.",exampleSrc:"A: How big is your bedroom?\nB: It's quite small but cosy.",note:"Neuter. Compound: Schlaf (sleep) + Zimmer (room).",funFact:"Germans love airing their Schlafzimmer daily, even in winter. Fresh air is serious business."},
{type:"teach",trg:"das Schloss",src:"castle / lock",phonetic:"shloss",example:"A: Hast du das Schloss in Heidelberg gesehen?\nB: Ja, es war wunderschön!",exampleSrc:"A: Have you seen the castle in Heidelberg?\nB: Yes, it was beautiful!",note:"Neuter. Plural: Schlösser. Context tells you: castle or lock.",funFact:"Germany has over 20,000 Schlösser and castles. That's more than any other country in Europe."},
{type:"fb",s:"Mein {1} ist sehr klein, aber ich schlafe gut.",a:"Schlafzimmer",opts:["Schlafzimmer","Schloss","Fach","Supermarkt"],hint:"Where do you sleep at home?",sSrc:"My bedroom is very small, but I sleep well."},
{type:"teach",trg:"die Schülerin",src:"female student (school)",phonetic:"SHOO-luh-rin",example:"A: Ist Lisa eine gute Schülerin?\nB: Ja, sie bekommt immer gute Noten.",exampleSrc:"A: Is Lisa a good student?\nB: Yes, she always gets good grades.",note:"Feminine. Male form: der Schüler. For school students, not university.",funFact:"German Schüler and Schülerinnen typically don't wear school uniforms."},
{type:"teach",trg:"die Seite",src:"page / side",phonetic:"ZAI-tuh",example:"A: Auf welcher Seite ist die Übung?\nB: Auf Seite 42, ganz unten.",exampleSrc:"A: On which page is the exercise?\nB: On page 42, at the bottom.",note:"Feminine. Dual meaning: page of a book, or side of something.",funFact:"The German word Webseite (webpage) uses this same Seite for 'page'."},
{type:"teach",trg:"die Studentin",src:"female student (university)",phonetic:"shtoo-DEN-tin",example:"A: Was studiert die Studentin?\nB: Sie studiert Medizin in Berlin.",exampleSrc:"A: What does the student study?\nB: She studies medicine in Berlin.",note:"Feminine. Male form: der Student. Only for university students.",funFact:"German universities charge almost no tuition. Most Studenten pay under 300 EUR per semester."},
{type:"mc",q:"Welches Wort beschreibt eine Frau an der Universität?",opts:["die Studentin","die Schülerin","die Rentnerin","die Kollegin"],ans:"die Studentin",hint:"University, not school or workplace."},
{type:"teach",trg:"der Supermarkt",src:"supermarket",phonetic:"ZOO-puh-markt",example:"A: Gehst du heute zum Supermarkt?\nB: Ja, wir brauchen Milch und Brot.",exampleSrc:"A: Are you going to the supermarket today?\nB: Yes, we need milk and bread.",note:"Masculine. Plural: Supermärkte. Direct cognate with English.",funFact:"German supermarkets close on Sundays. Forgetting your Saturday shopping is a real problem."},
{type:"teach",trg:"das Taschengeld",src:"pocket money",phonetic:"TA-shen-gelt",example:"A: Bekommst du Taschengeld?\nB: Ja, zehn Euro pro Woche.",exampleSrc:"A: Do you get pocket money?\nB: Yes, ten euros per week.",note:"Neuter. Compound: Tasche (pocket/bag) + Geld (money).",funFact:"Studies show German children get an average of 25 EUR Taschengeld per month."},
{type:"teach",trg:"die Tasse",src:"cup",phonetic:"TA-suh",example:"A: Möchtest du eine Tasse Kaffee?\nB: Ja, gerne, mit Milch bitte.",exampleSrc:"A: Would you like a cup of coffee?\nB: Yes, please, with milk.",note:"Feminine. Plural: Tassen. Used for cups with handles (mugs too).",funFact:"Germans drink about 164 litres of coffee per person per year. That's a lot of Tassen."},
{type:"teach",trg:"die Universität",src:"university",phonetic:"oo-nee-ver-zee-TAYT",example:"A: An welcher Universität studierst du?\nB: Ich studiere an der Universität München.",exampleSrc:"A: At which university do you study?\nB: I study at the University of Munich.",note:"Feminine. Often shortened to Uni in everyday speech.",funFact:"The oldest German Universität is Heidelberg, founded in 1386."},
{type:"fb",s:"Möchtest du eine {1} Tee?",a:"Tasse",opts:["Tasse","Seite","Geldbörse","Note"],hint:"A container you drink from.",sSrc:"Would you like a cup of tea?"},
{type:"teach",trg:"die Werkstatt",src:"workshop / garage",phonetic:"VERK-shtat",example:"A: Wo ist dein Auto?\nB: Es ist in der Werkstatt, der Motor ist kaputt.",exampleSrc:"A: Where is your car?\nB: It's in the workshop, the engine is broken.",note:"Feminine. Plural: Werkstätten. Werk (work) + Statt (place).",funFact:"Germany's TÜV vehicle inspections are famously strict. Werkstätten are always busy before TÜV dates."},
{type:"teach",trg:"die Kollegin",src:"female colleague",phonetic:"ko-LAY-gin",example:"A: Kennst du meine Kollegin Frau Weber?\nB: Ja, sie arbeitet im dritten Stock.",exampleSrc:"A: Do you know my colleague Mrs Weber?\nB: Yes, she works on the third floor.",note:"Feminine. Male form: der Kollege (not Kolleg!).",funFact:"Germans typically use Sie (formal you) with Kollegen unless they agree to switch to du."},
{type:"teach",trg:"aktuell",src:"current / up-to-date",phonetic:"ak-too-ELL",example:"A: Ist das die aktuelle Speisekarte?\nB: Ja, wir haben sie letzte Woche geändert.",exampleSrc:"A: Is this the current menu?\nB: Yes, we changed it last week.",note:"False friend alert! Aktuell does NOT mean 'actual'. It means 'current'.",funFact:"This is the most famous German false friend. 'Tatsächlich' is the real word for 'actually'."},
{type:"teach",trg:"echt",src:"real / genuine / really",phonetic:"ekht",example:"A: Ist der Ring echt?\nB: Ja, das ist echtes Gold!",exampleSrc:"A: Is the ring real?\nB: Yes, that's real gold!",note:"Adjective and adverb. Also used colloquially: 'Echt?' means 'Really?'",funFact:"Young Germans use 'echt' constantly in speech, similar to 'literally' in English."},
{type:"teach",trg:"eigentlich",src:"actually / really",phonetic:"AI-gent-likh",example:"A: Was wolltest du eigentlich sagen?\nB: Ich wollte fragen, ob du morgen Zeit hast.",exampleSrc:"A: What did you actually want to say?\nB: I wanted to ask if you have time tomorrow.",note:"Adverb. Often softens a question: 'Wie heißt du eigentlich?' (What's your name, by the way?)",funFact:"Eigentlich is one of those untranslatable German words. It can mean 'actually', 'really', or 'by the way'."},
{type:"teach",trg:"total",src:"total / totally",example:"A: Das war total verrückt!\nB: Ja, total! Aber auch lustig.",exampleSrc:"A: That was totally crazy!\nB: Yes, totally! But also funny.",note:"Cognate. Used as adjective and adverb. Very colloquial when used for emphasis.",funFact:"Young Germans use 'total' like Americans use 'totally.' 'Das ist total cool!' Borrowed directly from English."},
{type:"teach",trg:"heraus",src:"out (from inside)",example:"A: Komm heraus!\nB: Ich komme gleich raus!",exampleSrc:"A: Come out!\nB: I am coming out right away!",note:"Direction adverb: movement from inside to outside. Short form: raus. Many compounds: herausfinden, herausgeben.",funFact:"'Heraus' is formal, 'raus' is everyday. 'Raus hier!' (Get out!) is one of the first commands kids learn."},
{type:"teach",trg:"herein",src:"in / inside (come in)",example:"A: Darf ich?\nB: Ja, herein!\nA: Danke!",exampleSrc:"A: May I?\nB: Yes, come in!\nA: Thank you!",note:"Direction adverb: movement from outside to inside. Short form: rein. Herein! = Come in!",funFact:"When you knock on an office door in Germany, the answer is often just 'Herein!' One word. No 'please.' Very efficient."},
{type:"teach",trg:"der/die Nächste",src:"the next person",example:"A: Der Nächste bitte!\nB: Das bin ich!",exampleSrc:"A: Next please!\nB: That is me!",note:"From nächst (next). Der Nächste (masc.) or die Nächste (fem.). Used at counters and waiting rooms.",funFact:"'Der Nächste bitte!' is the universal sound of German waiting rooms, post offices, and bakery counters."},
{type:"tip",title:"Das deutsche Notensystem",text:"German schools use grades 1 to 6:\n1 = sehr gut (very good)\n2 = gut (good)\n3 = befriedigend (satisfactory)\n4 = ausreichend (sufficient, the minimum pass)\n5 = mangelhaft (poor)\n6 = ungenügend (insufficient)\nAt university, grades range from 1.0 to 5.0, with 4.0 as the pass threshold.",deepDive:"German report cards (Zeugnisse) are issued twice a year. The Halbjahreszeugnis comes in January/February, the Jahreszeugnis at the end of the school year in summer. Grades are taken very seriously: the Abitur average (Numerus Clausus) determines which university programmes you can enter."},
{type:"mc",q:"'Aktuell' bedeutet auf Englisch...",opts:["current","actual","active","acute"],ans:"current",hint:"A famous false friend for English speakers."},
{type:"mc",q:"Welches Wort passt? 'Das Buch hat 200 ___.'",opts:["Seiten","Noten","Fächer","Tassen"],ans:"Seiten",hint:"Think about what books are made of."},
{type:"fb",s:"Der Ring ist nicht {1}, er ist nur aus Plastik.",a:"echt",opts:["echt","aktuell","eigentlich","gut"],hint:"Genuine, the real thing.",sSrc:"The ring is not genuine, it is only made of plastic."},
{type:"mc",q:"Was ist eine Geldbörse?",opts:["a wallet","a money tree","a bank","a stock exchange"],ans:"a wallet",hint:"You carry it and keep cash inside."},
{type:"drag_fill",s:"Meine {1} arbeitet an der {2} in Hamburg.",blanks:{"1":"Kollegin","2":"Universität"},pool:["Kollegin","Universität","Werkstatt","Rentnerin"],hint:"A female colleague at a place of higher education.",sSrc:"My female colleague works at the university in Hamburg."},
{type:"match",pairs:[{trg:"das Taschengeld",src:"pocket money"},{trg:"die Werkstatt",src:"workshop"},{trg:"der Supermarkt",src:"supermarket"},{trg:"die Fundsache",src:"lost property"},{trg:"das Schloss",src:"castle / lock"}]},
{type:"mc",q:"Lisa ist 16 und geht aufs Gymnasium. Wie nennt man sie?",opts:["eine Schülerin","eine Studentin","eine Rentnerin","eine Kollegin"],ans:"eine Schülerin",hint:"Someone who attends a school, not a university."},
{type:"fb",s:"Was hast du {1} heute Abend vor?",a:"eigentlich",opts:["eigentlich","aktuell","echt","endlich"],hint:"Softens the question, means 'actually' or 'by the way'.",sSrc:"What are you actually planning for this evening?"},
{type:"drag_fill",s:"Die {1} bekommt immer gute {2} in jedem {3}.",blanks:{"1":"Schülerin","2":"Noten","3":"Fach"},pool:["Schülerin","Noten","Fach","Seite","Studentin"],hint:"A school student gets good grades in every subject.",sSrc:"The female student always gets good grades in every subject."},
{type:"match",pairs:[{trg:"aktuell",src:"current"},{trg:"echt",src:"real / genuine"},{trg:"eigentlich",src:"actually"},{trg:"die Note",src:"grade"},{trg:"die Tasse",src:"cup"}]}
]},

{id:"deu_r12l9",title:"Die große Prüfung",icon:"✅",xp:30,board:true,steps:[
{type:"intro",title:"Die große Prüfung",desc:"Six months in Germany. Six units of grammar. Twenty-five constructs. This is the A2 capstone quiz. No new vocabulary, no hints from Hildi. Just you and the language.",goals:["Test ALL 25 A2 grammar constructs","Combine multiple constructs in single sentences","Prove you are ready for B1"]},

// 1. Perfekt haben + subordinate word order (multi)
{type:"fb",s:"Ich glaube, dass er das Buch schon {1} hat.",a:["gelesen"],opts:["gelesen","lesen","liest","las"],hint:"Perfekt in a dass-clause: the auxiliary goes to the very end.",sSrc:"I believe that he has already read the book."},

// 2. Perfekt sein + Partizip II (multi)
{type:"mc",q:"Mia sagt: 'Wir ___ gestern nach Hamburg ___.' Which pair completes the Perfekt?",opts:["sind ... gefahren","haben ... gefahren","sind ... fahren","haben ... fahrt"],ans:"sind ... gefahren",hint:"Motion verbs use a specific auxiliary in the Perfekt."},

// 3. Präteritum modals + dative (multi)
{type:"fb",s:"Der Arzt konnte {1} leider nicht helfen.",a:["mir"],opts:["mir","mich","ich","mein"],hint:"Helfen always takes a specific case for the person being helped.",sSrc:"The doctor unfortunately could not help me."},

// 4. Dative full + Wechselpräp (multi)
{type:"drag_fill",s:"Die Katze liegt {1} dem Tisch, aber der Hund springt {2} das Sofa.",blanks:{"1":"unter","2":"auf"},pool:["unter","auf","in","neben","über","an"],hint:"Lying somewhere is static (dative). Jumping somewhere is movement (accusative).",sSrc:"The cat is lying under the table, but the dog jumps at the sofa."},

// 5. Verbs with dative
{type:"mc",q:"'Das Essen ___ meiner Mutter sehr gut.' Which verb fits?",opts:["schmeckt","gefällt","braucht","gehört"],ans:"schmeckt",hint:"This dative verb describes how food tastes to someone."},

// 6. weil-clause + verb-final (multi)
{type:"fb",s:"Ich bleibe zu Hause, weil ich krank {1}.",a:["bin"],opts:["bin","ist","sein","bist"],hint:"In a weil-clause, the conjugated verb moves to which position?",sSrc:"I am staying at home because I am ill."},

// 7. dass-clause + reflexive verb (multi)
{type:"drag_fill",s:"Weißt du, dass {1} der Verein morgen {2}?",blanks:{"1":"sich","2":"trifft"},pool:["sich","mich","trifft","treffen","treffe","dich"],hint:"Sich treffen in a dass-clause: reflexive pronoun near the subject, verb at the end.",sSrc:"Do you know that the club itself is meeting tomorrow?"},

// 8. wenn-clause + Konjunktiv II (multi)
{type:"mc",q:"'Wenn ich mehr Zeit ___, ___ ich nach Italien fahren.' Fill both gaps.",opts:["hätte ... würde","habe ... werde","hatte ... wollte","hätte ... wollte"],ans:"hätte ... würde",hint:"This is an unreal condition about the present. Both verbs need a special mood."},

// 9. ob-clause + subordinate word order (multi)
{type:"fb",s:"Ich weiß nicht, ob er morgen {1}.",a:["kommt"],opts:["kommt","kommen","komme","kam"],hint:"After ob, the conjugated verb goes to a specific position in the clause.",sSrc:"I do not know whether he comes tomorrow."},

// 10. Adjective declension nominative (definite + indefinite)
{type:"mc",q:"Which is correct? 'Ein ___ Pullover hängt im Schrank.'",opts:["warmer","warme","warmes","warmen"],ans:"warmer",hint:"After ein with a masculine noun, the adjective must show the gender."},

// 11. Adjective declension accusative + dative (multi)
{type:"drag_fill",s:"Ich kaufe {1} Schal und gebe ihn {2} Freund.",blanks:{"1":"den roten","2":"meinem besten"},pool:["den roten","der rote","dem roten","meinem besten","meinen besten","mein bester"],hint:"Buying uses accusative. Giving to someone uses dative.",sSrc:"I buy the red scarf and give it to my best friend."},

// 12. Possessives across cases + temporal prep (multi)
{type:"fb",s:"Nach {1} Geburtstag hat sie ihre Geschenke geöffnet.",a:["ihrem"],opts:["ihrem","ihrer","ihr","ihren"],hint:"Nach takes dative. Geburtstag is masculine. Which possessive form fits?",sSrc:"After her birthday she opened her presents."},

// 13. Comparative + superlative (multi)
{type:"mc",q:"'Berlin ist größer als München, aber Hamburg hat den ___ Hafen.' Which superlative fits?",opts:["größten","größer","großen","großes"],ans:"größten",hint:"After a definite article in accusative, the superlative adjective needs a specific ending."},

// 14. Reflexive verbs + reflexive pronouns (multi)
{type:"drag_fill",s:"Wir freuen {1} auf die Ferien und erinnern {2} an den letzten Sommer.",blanks:{"1":"uns","2":"uns"},pool:["uns","euch","sich","mich","mir","dich"],hint:"Both verbs are reflexive. The subject is wir, so both pronouns match.",sSrc:"We are looking forward to the holidays and we remember last summer."},

// 15. Imperative expanded (separable + irregular)
{type:"mc",q:"Your friend is sleeping late. Which imperative is correct?",opts:["Steh auf!","Stehe auf!","Aufstehen du!","Du steh auf!"],ans:"Steh auf!",hint:"Separable verbs in imperative: the prefix separates and goes to the end."},

// 16. Coordinating conjunctions + Perfekt (multi)
{type:"fb",s:"Ich wollte ins Kino gehen, {1} ich habe den Film schon gesehen.",a:["aber"],opts:["aber","weil","dass","denn"],hint:"You need a conjunction that shows contrast and keeps normal word order.",sSrc:"I wanted to go to the cinema, but I have already seen the film."},

// 17. Adverbs (time/manner) + verb position
{type:"mc",q:"'Verumius lernt ___ ___ Deutsch.' Which adverb order is correct?",opts:["jetzt gern","gern jetzt","Deutsch gern","jetzt Deutsch"],ans:"jetzt gern",hint:"In German, time adverbs typically come before manner adverbs."},

// 18. Temporal prepositions + dative (multi)
{type:"drag_fill",s:"{1} zwei Wochen lerne ich Deutsch und {2} dem Unterricht übe ich zu Hause.",blanks:{"1":"Seit","2":"nach"},pool:["Seit","Nach","nach","Vor","Während","Bis"],hint:"One preposition means 'for an ongoing duration.' The other means 'after.'",sSrc:"For two weeks I have been learning German and after class I practise at home."},

// 19. Wechselpräp + adjective declension accusative (multi)
{type:"fb",s:"Ich stelle die Blumen auf {1} Tisch.",a:["den kleinen"],opts:["den kleinen","dem kleinen","der kleine","das kleine"],hint:"Placing something is movement (accusative). The table is masculine.",sSrc:"I put the flowers on the little table."},

// 20. Konjunktiv II + dative verb (multi)
{type:"mc",q:"'Es ___ mir besser, wenn ich mehr schlafen ___.' Fill both gaps.",opts:["ginge ... würde","geht ... werde","ging ... wollte","gehe ... würde"],ans:"ginge ... würde",hint:"Both verbs express an unreal wish. The first is an irregular Konjunktiv II form."},

// 21. Match: Grammar construct recognition
{type:"match",pairs:[{trg:"Ich habe das gemacht.",src:"Perfekt (haben)"},{trg:"Sie ist gefahren.",src:"Perfekt (sein)"},{trg:"Er konnte nicht kommen.",src:"Präteritum modal"},{trg:"Steh bitte auf!",src:"Imperative (separable)"},{trg:"Ich würde gern bleiben.",src:"Konjunktiv II"},{trg:"weil er müde ist",src:"Subordinate clause"}]},

// 22. weil + Perfekt sein + Partizip II (triple construct)
{type:"fb",s:"Er ist müde, weil er gestern spät nach Hause {1} ist.",a:["gekommen"],opts:["gekommen","kommen","kommt","kam"],hint:"This is Perfekt with sein inside a weil-clause. The auxiliary stays at the end.",sSrc:"He is tired because he came home late yesterday."},

// 23. Reflexive + wenn-clause + possessive (triple construct)
{type:"drag_fill",s:"Wenn ich {1} nicht beeile, verpasse ich {2} Zug.",blanks:{"1":"mich","2":"meinen"},pool:["mich","mir","sich","meinen","mein","meinem"],hint:"Sich beeilen takes accusative reflexive. The train is masculine accusative.",sSrc:"If I do not hurry myself, I will miss my train."},

// 24. Adjective declension (no article, strong) + comparative
{type:"mc",q:"'Bei ___ Wetter bleibe ich lieber drinnen.' Which form is correct?",opts:["kaltem","kaltes","kalter","kalte"],ans:"kaltem",hint:"Bei takes dative. Without an article, the adjective must show the case itself."},

// 25. dass-clause + Konjunktiv II + temporal prep (triple construct)
{type:"fb",s:"Er sagt, dass er seit einer Woche krank {1}.",a:["wäre"],opts:["wäre","ist","war","sei"],hint:"Inside a dass-clause expressing an unreal or reported claim. Which mood?",sSrc:"He says that he has been ill for a week."},

// 26. Full sentence reconstruction: 5 constructs
{type:"drag_fill",s:"Opa Heinrich erzählt, dass er {1} fünfzig Jahren {2} besten Bäcker {3} Stadt {4} hat.",blanks:{"1":"seit","2":"den","3":"der","4":"gefunden"},pool:["seit","den","der","gefunden","vor","dem","die","finden"],hint:"Temporal prep (ongoing) + accusative superlative + genitive article + Partizip II at clause end.",sSrc:"Opa Heinrich says that for fifty years he has found the best baker in the city."},

// 27. Multi-construct: imperative + dative + Wechselpräp
{type:"mc",q:"Hildi says to Verumius: 'Leg ___ Mantel auf ___ Stuhl!' Which pair is correct?",opts:["deinen ... den","deinem ... dem","dein ... der","deiner ... dem"],ans:"deinen ... den",hint:"Legen is movement (accusative for both the object and the Wechselpräposition)."},

// 28. Grand finale: ob + reflexive + comparative + Perfekt (quad construct)
{type:"drag_fill",s:"Ich frage mich, ob ich {1} schneller verbessert {2} als {3} anderen Studenten.",blanks:{"1":"mich","2":"habe","3":"die"},pool:["mich","mir","sich","habe","bin","hat","die","den","der"],hint:"Sich verbessern (acc reflexive) in Perfekt (haben) inside an ob-clause. Plural article for comparison.",sSrc:"I wonder whether I have improved myself faster than the other students."}
]}
,

{id:"deu_r12l10",title:"Ich will bleiben",icon:"🎉",xp:20,board:true,steps:[
{type:"intro",title:"Ich will bleiben",desc:"Six months in Germany. Group chat celebration. Verumius has decided: he wants to stay. Time to learn the final vocabulary batch.",goals:["Personality and opinion adjectives","Essential adverbs and particles","The A2 finale: bridge to B1"]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-couch-phone",trg:"Verumius sitzt auf dem Sofa. Das Handy leuchtet. Lukas: 'Sechs Monate! Wahnsinn!' Mia: 'Du bist jetzt fast ein Berliner.' Yilmaz: 'Ich bin stolz auf dich.' Unter der Tür: ein Zettel von Hildi. 'Gut gemacht. H.'",src:"Verumius sits on the sofa. The phone glows. Lukas: 'Six months! Crazy!' Mia: 'You are almost a Berliner now.' Yilmaz: 'I am proud of you.' Under the door: a note from Hildi. 'Well done. H.'"},
{type:"teach",trg:"freundlich",src:"friendly",note:"Freund (friend) + -lich. Ein freundlicher Mensch.",example:"A: Die Leute hier sind sehr freundlich.\nB: Ja, besonders die Nachbarn.",exampleSrc:"A: The people here are very friendly.\nB: Yes, especially the neighbors.",funFact:"Freundlich comes from Freund (friend). The -lich suffix turns nouns into adjectives, like English -ly."},
{type:"teach",trg:"traurig",src:"sad",note:"Ich bin traurig = I am sad. Trauer = grief/mourning.",example:"A: Warum bist du traurig?\nB: Mein Freund ist weggezogen.",exampleSrc:"A: Why are you sad?\nB: My friend moved away.",funFact:"Trauer (grief) is the root. Traurig is the adjective. Trauerfeier is a funeral. Heavy word family."},
{type:"teach",trg:"wirklich",src:"really / truly",note:"Wirklich? = Really? Very common response in conversation.",example:"A: Ich lerne seit sechs Monaten Deutsch.\nB: Wirklich? Dein Deutsch ist toll!",exampleSrc:"A: I have been learning German for six months.\nB: Really? Your German is great!",funFact:"From wirken (to have an effect). Something 'wirklich' truly has an effect, it truly exists."},
{type:"teach",trg:"wahrscheinlich",src:"probably",note:"Wahr (true) + scheinlich (seeming). Likely true.",example:"A: Kommt er morgen?\nB: Wahrscheinlich. Er hat es versprochen.",exampleSrc:"A: Is he coming tomorrow?\nB: Probably. He promised.",funFact:"17 letters! One of the longer everyday German words. Wahr-schein-lich: truth-seeming-ly."},
{type:"mc",q:"'Dein Deutsch ist wirklich gut!' This is:",opts:["a genuine compliment","a sarcastic comment","a question","a command"],ans:"a genuine compliment",hint:"Wirklich means truly, really. This person means it."},
{type:"teach",trg:"natürlich",src:"of course / natural",note:"Natürlich! = Of course! Also means 'natural' (natürliche Zutaten).",example:"A: Kannst du mir helfen?\nB: Natürlich! Was brauchst du?",exampleSrc:"A: Can you help me?\nB: Of course! What do you need?",funFact:"Natürlich is German's go-to 'of course.' More enthusiastic than 'ja' but less formal than 'selbstverständlich.'"},
{type:"teach",trg:"genau",src:"exact / exactly",note:"Genau! = Exactly! Used constantly in conversation to agree.",example:"A: Also treffen wir uns um drei?\nB: Genau! Am Hauptbahnhof.",exampleSrc:"A: So we meet at three?\nB: Exactly! At the main station.",funFact:"Germans say 'genau' like Americans say 'right' or 'exactly.' You'll hear it 50 times per conversation."},
{type:"teach",trg:"doch",src:"yet / but / actually (particle)",note:"The most German word. Contradicts a negative: 'Nein!' - 'Doch!'",example:"A: Du sprichst kein Deutsch.\nB: Doch! Ich spreche Deutsch!",exampleSrc:"A: You don't speak German.\nB: Yes I do! I speak German!",funFact:"Doch has no direct English equivalent. It contradicts negatives. 'You can't do that' - 'Doch!' (Yes I can!). Untranslatable."},
{type:"fb",s:"Du kannst das nicht! - {1}! Ich kann das!",a:["Doch"],opts:["Doch","Nein","Ja","Aber"],hint:"Contradicting a negative statement. The uniquely German word.",sSrc:"You cannot do that! - Yes I can! I can do that!"},
{type:"teach",trg:"schade",src:"shame / pity / too bad",note:"Das ist schade! = That's a shame! Wie schade! = What a pity!",example:"A: Ich kann morgen nicht kommen.\nB: Schade! Wir vermissen dich.",exampleSrc:"A: I can't come tomorrow.\nB: Too bad! We'll miss you.",funFact:"Schade originally meant 'damage/harm.' 'Es ist schade' = it is damaging, regrettable. Softened over centuries."},
{type:"teach",trg:"unbedingt",src:"absolutely / by all means",note:"Un- (not) + bedingt (conditional). Unconditionally!",example:"A: Musst du das unbedingt heute machen?\nB: Ja, unbedingt! Es ist dringend.",exampleSrc:"A: Do you absolutely have to do that today?\nB: Yes, absolutely! It's urgent.",funFact:"Unbedingt literally means 'unconditional.' When you say 'unbedingt!', you mean there are zero conditions: it MUST happen."},
{type:"teach",trg:"kostenlos",src:"free (no cost)",note:"Kosten (cost) + los (without). Also: gratis, umsonst.",example:"A: Ist der Eintritt kostenlos?\nB: Ja, am ersten Sonntag im Monat.",exampleSrc:"A: Is the entrance free?\nB: Yes, on the first Sunday of the month.",funFact:"German has 3 words for free: kostenlos (no cost), gratis (Latin loan), umsonst (also means 'in vain')."},
{type:"mc",q:"The museum is 'kostenlos' on Sundays. This means:",opts:["free entrance","closed","expensive","members only"],ans:"free entrance",hint:"Kosten = cost. Los = without. Without cost."},
{type:"teach",trg:"sonst",src:"otherwise / else",note:"Was möchtest du sonst? = What else would you like?",example:"A: Brauchst du sonst noch etwas?\nB: Nein, danke. Das ist alles.",exampleSrc:"A: Do you need anything else?\nB: No, thanks. That's everything.",funFact:"Sonst covers both 'otherwise' (condition) and 'else' (addition). Context: 'Beeil dich, sonst...' = hurry, otherwise..."},
{type:"teach",trg:"außerdem",src:"besides / moreover",note:"Außer (except) + dem. A formal connector for adding information.",example:"A: Warum lernst du Deutsch?\nB: Ich lebe in Berlin. Außerdem liebe ich die Sprache.",exampleSrc:"A: Why are you learning German?\nB: I live in Berlin. Besides, I love the language.",funFact:"Außerdem is a sentence adverb. It goes in position 1 or after the verb. Great for written arguments."},
{type:"teach",trg:"mindestens",src:"at least",note:"Mindest (least/minimum) + -ens. Mindestens eine Stunde = at least one hour.",example:"A: Wie lange übst du jeden Tag?\nB: Mindestens eine Stunde.\nA: Das ist viel!",exampleSrc:"A: How long do you practice every day?\nB: At least one hour.\nA: That's a lot!",funFact:"Mindestlohn = minimum wage. Mindestalter = minimum age. The prefix mindest- means 'minimum.'"},
{type:"teach",trg:"deshalb",src:"therefore / that's why",note:"Connector. Ich war krank, deshalb bin ich zu Hause geblieben.",example:"A: Warum bist du nicht gekommen?\nB: Ich war krank, deshalb bin ich geblieben.",exampleSrc:"A: Why didn't you come?\nB: I was sick, that's why I stayed.",funFact:"Deshalb, darum, deswegen all mean 'therefore.' Germans love having 3 words for the same connector."},
{type:"fb",s:"Ich war müde, {1} bin ich früh ins Bett gegangen.",a:["deshalb"],opts:["deshalb","trotzdem","außerdem","sonst"],hint:"I was tired, THEREFORE I went to bed early. Cause and effect.",sSrc:"I was tired, therefore I went to bed early."},
{type:"teach",trg:"einige",src:"some / several",note:"Einige Leute = some people. More than 'ein paar' but less than 'viele.'",example:"A: Hast du Freunde in Berlin?\nB: Ja, einige. Wir treffen uns oft.",exampleSrc:"A: Do you have friends in Berlin?\nB: Yes, some. We meet often.",funFact:"The scale: wenige (few) < ein paar (a couple) < einige (some) < viele (many) < alle (all)."},
{type:"teach",trg:"überall",src:"everywhere",note:"Über (over) + all (all). In every place.",example:"A: Wo findet man gutes Brot in Deutschland?\nB: Überall! Es gibt überall Bäckereien.",exampleSrc:"A: Where can you find good bread in Germany?\nB: Everywhere! There are bakeries everywhere.",funFact:"Überall is the opposite of nirgends (nowhere). Über (over) + all (all) = over all places."},
{type:"teach",trg:"zum Beispiel",src:"for example",note:"Abbreviated: z.B. Very common in writing and speech.",example:"A: Was machst du in deiner Freizeit?\nB: Viele Sachen. Zum Beispiel joggen und malen.",exampleSrc:"A: What do you do in your free time?\nB: Many things. For example, jogging and painting.",funFact:"z.B. is the German equivalent of 'e.g.' You see it everywhere in formal writing."},
{type:"drag_fill",s:"Ich lerne {1} eine Stunde Deutsch pro Tag. {2} lese ich deutsche Nachrichten.",blanks:{"1":"mindestens","2":"Außerdem"},pool:["mindestens","Außerdem","deshalb","sonst","überall","natürlich"],hint:"AT LEAST one hour. BESIDES that, I also read news.",sSrc:"I learn at least one hour of German per day. Besides I read German news."},
{type:"teach",trg:"der Ehepartner",src:"the spouse",gender:"m",example:"A: Kommt dein Ehepartner auch?\nB: Ja, wir kommen zusammen.\nA: Schön, ich freue mich!",exampleSrc:"A: Is your spouse coming too?\nB: Yes, we are coming together.\nA: Great, I am looking forward to it!",note:"Masculine. Feminine form: die Ehepartnerin. Ehe (marriage) + Partner.",funFact:"On official German forms, you must always state your Familienstand: ledig, verheiratet, geschieden, or verwitwet."},
{type:"teach",trg:"die Zitrone",src:"the lemon",gender:"f",example:"A: Möchtest du Zitrone im Tee?\nB: Ja, bitte! Mit Zitrone schmeckt er besser.",exampleSrc:"A: Would you like lemon in your tea?\nB: Yes, please! It tastes better with lemon.",note:"die Zitrone, feminine. Plural: die Zitronen. Also: Zitronensaft (lemon juice).",funFact:"Germans love Zitrone in water and tea. The phrase 'eine saure Zitrone' (a sour lemon) describes a grumpy person."},
{type:"teach",trg:"sich erinnern",src:"to remember",example:"A: Erinnerst du dich an den ersten Tag?\nB: Ja, ich erinnere mich gut daran!",exampleSrc:"A: Do you remember the first day?\nB: Yes, I remember it well!",note:"Reflexive verb: sich erinnern an + accusative. Ich erinnere mich, du erinnerst dich.",funFact:"'Erinnerung' (memory/souvenir) is one of the most emotional German words. 'Zur Erinnerung' means 'in memory of.'"},
{type:"teach",trg:"erreichen",src:"to reach / to achieve",example:"A: Hast du dein Ziel erreicht?\nB: Ja, endlich! Nach sechs Monaten.",exampleSrc:"A: Did you reach your goal?\nB: Yes, finally! After six months.",note:"Regular: ich erreiche, du erreichst. Er- prefix is inseparable.",funFact:"The noun 'die Erreichbarkeit' (reachability) appears on German business cards to indicate when someone can be contacted."},
{type:"teach",trg:"klappen",src:"to work out / to succeed",example:"A: Hat alles geklappt?\nB: Ja, es hat super geklappt!\nA: Das freut mich!",exampleSrc:"A: Did everything work out?\nB: Yes, it worked out great!\nA: I am glad!",note:"Regular: es klappt. Very common in everyday speech. 'Hat geklappt!' = It worked!",funFact:"'Klappt's?' is a casual way to ask 'Is it working?' Used constantly in offices and kitchens."},
{type:"teach",trg:"kontrollieren",src:"to check / to control",example:"A: Kontrollierst du bitte die Liste?\nB: Ja, ich kontrolliere sie sofort.",exampleSrc:"A: Can you check the list?\nB: Yes, I will check it right away.",note:"Regular: ich kontrolliere. From French 'contrôler.' Used for checking documents, tickets, etc.",funFact:"Ticket controllers (Kontrolleure) on German trains and buses are famous for their thoroughness."},
{type:"teach",trg:"ausgeben",src:"to spend (money)",example:"A: Wie viel gibst du pro Monat aus?\nB: Zu viel! Ich muss sparen.",exampleSrc:"A: How much do you spend per month?\nB: Too much! I need to save.",note:"Separable: ich gebe aus, du gibst aus. Irregular: stem change e to i.",funFact:"Germans track spending carefully. The word 'Ausgaben' (expenses) appears on every household budget plan."},
{type:"match",pairs:[{trg:"freundlich",src:"friendly"},{trg:"traurig",src:"sad"},{trg:"wirklich",src:"really"},{trg:"doch",src:"yes (contradicting)"},{trg:"deshalb",src:"therefore"},{trg:"überall",src:"everywhere"},{trg:"kostenlos",src:"free"},{trg:"genau",src:"exactly"}]},
{type:"story",speaker:"narrator",mood:"happy",art:"de-couch-night",trg:"Verumius legt das Handy hin. Sechs Monate. Eine Wohnung. Freunde. Eine Sprache, die langsam seine wird. Er denkt an die Ankunft am Flughafen. Den falschen Zug. Die 14-seitige Hausordnung. Den Müll. Den Arzt. Den Lauftreff. Die Deutsche Bahn. Den Glühwein. Und jetzt: KD hat gelacht. Alles ist möglich. Er will bleiben.",src:"Verumius puts down the phone. Six months. An apartment. Friends. A language that is slowly becoming his. He thinks about arriving at the airport. The wrong train. The 14-page house rules. The trash. The doctor. The running club. Deutsche Bahn. The Glühwein. And now: KD laughed. Anything is possible. He wants to stay."},
{type:"tip",title:"A2 Complete: Verumius Belongs",text:"Unit 12 is the end of A2.\n\nVerumius can now:\n1. Talk about the past (Perfekt, Prateritum modals)\n2. Express opinions (Ich denke, dass...)\n3. Compare things (besser als, am besten)\n4. Describe people and objects (adjective declension)\n5. Navigate German bureaucracy\n6. Have real conversations with friends\n\nBut A2 is just daily communication.\nB1 is where adventure begins.\n\n'Ich will bleiben. Das bedeutet: einen Job.'",deepDive:"A2 covered 612 Goethe words and 25 grammar constructs. Verumius has grown from tourist to resident. The next challenge: professional German, job applications, and deeper cultural integration."},
{type:"mc",q:"What has Verumius decided at the end of A2?",opts:["He wants to stay in Germany","He wants to go home","He wants to move to Munich","He wants to become a teacher"],ans:"He wants to stay in Germany",hint:"'Ich will bleiben.' The verb 'bleiben' is key. Think about what this requires."}
]}

]}
];

export default GERMAN_V2_A2;
